"""
============================================================
  MONOPOLY 3D - Game Tugas Algoritma
  Teknologi: Python + PyOpenGL + Pygame
  Mode: 4 Pemain Hotseat

  Konsep Algoritma yang Digunakan:
  1. Array 2D   - menyimpan data papan dan properti
  2. Kondisional (if/elif/else) - logika permainan
  3. Perulangan (for/while) - render frame dan giliran
  4. Fungsi Rekursif - kalkulasi sewa bangunan
  5. Random  - lemparan dadu
  6. Queue (antrian) - urutan giliran pemain
  7. Dictionary - database properti dan harga
============================================================
"""

# ─── IMPORT LIBRARY ───────────────────────────────────────
import pygame
from pygame.locals import *
import sys
import random
import math
import array                           # Untuk generate suara tanpa file eksternal
import struct                          # Untuk pack data audio
from collections import deque

try:
    from OpenGL.GL import *
    from OpenGL.GLU import *
    OPENGL_AVAILABLE = True
except ImportError:
    OPENGL_AVAILABLE = False
    print("PyOpenGL tidak ditemukan — jalankan mode 2D.")
    print("Install: pip install PyOpenGL PyOpenGL_accelerate")

# ─── GENERATOR SUARA ──────────────────────────────────────
def buat_suara(frekuensi, durasi_ms, volume=0.4, bentuk="sine", fade_out=True):
    """
    Konsep: Matematika Gelombang + Array
    Generate suara secara programatik tanpa file audio.
    Menggunakan rumus gelombang sinus: y = A * sin(2π * f * t)

    Parameter:
    - frekuensi : Hz (tinggi/rendah nada)
    - durasi_ms : panjang suara dalam milidetik
    - volume    : 0.0 - 1.0
    - bentuk    : "sine", "square", "noise"
    - fade_out  : apakah suara memudar di akhir
    """
    sample_rate = 44100                # Sampel per detik (standar audio)
    n_sampel    = int(sample_rate * durasi_ms / 1000)
    buf         = array.array('h', [0] * n_sampel)  # Array signed short (16-bit)
    amplitudo   = int(32767 * volume)  # Amplitudo maksimum 16-bit

    # Konsep PERULANGAN: generate tiap sampel audio
    for i in range(n_sampel):
        t = i / sample_rate            # Waktu dalam detik

        # Pilih bentuk gelombang (Konsep: KONDISIONAL)
        if bentuk == "sine":
            val = math.sin(2 * math.pi * frekuensi * t)
        elif bentuk == "square":
            val = 1.0 if math.sin(2 * math.pi * frekuensi * t) > 0 else -1.0
        elif bentuk == "noise":
            val = random.uniform(-1.0, 1.0)
        else:
            val = math.sin(2 * math.pi * frekuensi * t)

        # Fade out: volume berkurang menjelang akhir
        if fade_out:
            fade = 1.0 - (i / n_sampel) ** 0.5
            val *= fade

        buf[i] = int(amplitudo * val)

    try:
        import numpy as np
        arr = np.array(buf, dtype='int16').reshape(-1, 1).repeat(2, axis=1)
        suara = pygame.sndarray.make_sound(arr)
    except ImportError:
        suara = pygame.sndarray.make_sound(buf)
    return suara

def buat_suara_sederhana(frekuensi, durasi_ms, volume=0.4, fade_out=True):
    """
    Generator suara versi sederhana — tanpa numpy, selalu berhasil.
    Menggunakan pygame.mixer langsung dengan bytes array.
    """
    sample_rate = 22050
    n_sampel    = int(sample_rate * durasi_ms / 1000)
    amplitudo   = int(32767 * volume)
    data        = bytearray(n_sampel * 2)  # 2 bytes per sampel (16-bit)

    for i in range(n_sampel):
        t   = i / sample_rate
        val = math.sin(2 * math.pi * frekuensi * t)
        if fade_out:
            val *= max(0.0, 1.0 - (i / n_sampel) ** 0.4)
        s = max(-32767, min(32767, int(amplitudo * val)))
        # Pack ke little-endian signed short
        data[i*2]   =  s & 0xFF
        data[i*2+1] = (s >> 8) & 0xFF

    return pygame.mixer.Sound(buffer=bytes(data))

def buat_suara_multitone(nada_list, volume=0.35):
    """
    Konsep: Superposisi Gelombang
    Gabungkan beberapa frekuensi secara berurutan (melodi pendek).
    nada_list = [(frekuensi, durasi_ms), ...]
    """
    sample_rate = 22050
    total_sampel = sum(int(sample_rate * d / 1000) for _, d in nada_list)
    data = bytearray(total_sampel * 2)
    amplitudo = int(32767 * volume)
    pos = 0

    for frek, dur_ms in nada_list:
        n = int(sample_rate * dur_ms / 1000)
        for i in range(n):
            t   = i / sample_rate
            val = math.sin(2 * math.pi * frek * t)
            # Fade in + fade out tiap nada
            fade = min(i / max(1, n*0.1), 1.0) * max(0.0, 1.0 - i / max(1, n*0.85))
            val *= fade
            s = max(-32767, min(32767, int(amplitudo * val)))
            data[pos*2]   =  s & 0xFF
            data[pos*2+1] = (s >> 8) & 0xFF
            pos += 1

    return pygame.mixer.Sound(buffer=bytes(data))

def init_suara():
    """
    Inisialisasi semua efek suara game.
    Return dict berisi semua Sound object.
    """
    try:
        pygame.mixer.init(frequency=22050, size=-16, channels=1, buffer=512)
    except Exception:
        return {}

    suara = {}
    try:
        # Suara lempar dadu — noise + pitch naik
        suara["dadu_kocok"] = buat_suara_sederhana(300, 80,  0.25, fade_out=False)
        suara["dadu_berhenti"] = buat_suara_multitone(
            [(523, 80), (659, 80), (784, 120)], volume=0.4  # C-E-G chord naik
        )
        # Suara beli properti — melodi ceria
        suara["beli"] = buat_suara_multitone(
            [(523, 100), (659, 100), (784, 100), (1047, 200)], volume=0.45
        )
        # Suara lewat GO — fanfare pendek
        suara["go"] = buat_suara_multitone(
            [(784, 100), (880, 100), (988, 100), (1047, 250)], volume=0.4
        )
        # Suara bayar sewa — nada turun
        suara["sewa"] = buat_suara_multitone(
            [(440, 120), (330, 120), (262, 180)], volume=0.35
        )
        # Suara masuk penjara — nada suram
        suara["penjara"] = buat_suara_multitone(
            [(262, 200), (247, 200), (220, 300)], volume=0.4
        )
        # Suara bangkrut — nada sangat turun
        suara["bangkrut"] = buat_suara_multitone(
            [(330, 150), (294, 150), (262, 150), (196, 400)], volume=0.45
        )
        # Suara menang — fanfare besar
        suara["menang"] = buat_suara_multitone(
            [(523,100),(659,100),(784,100),(1047,100),(784,80),(1047,300)], volume=0.5
        )
        # Suara kartu — nada ringan
        suara["kartu"] = buat_suara_multitone(
            [(880, 80), (988, 80), (1047, 120)], volume=0.3
        )
        # Suara pajak — nada peringatan
        suara["pajak"] = buat_suara_multitone(
            [(392, 150), (370, 150), (349, 200)], volume=0.35
        )
        print("Efek suara berhasil dimuat!")
    except Exception as e:
        print(f"Sebagian suara gagal: {e}")
    return suara

def buat_musik_everything_you_are(durasi_detik=120, volume=0.18):
    """
    Original Soundtrack — inspired by Everything You Are (Hindia)
    Key: G Major | Tempo: 78 BPM | Duration: 2 menit

    Part A (0:00-0:30) : Piano melody + Guitar picking
    Part B (0:30-1:00) : Melody build up
    Part C (1:00-1:30) : Emotional chorus
    Outro  (1:30-2:00) : Calm ending
    """
    import numpy as np
    sample_rate = 22050
    n_total     = int(sample_rate * durasi_detik)
    BPM         = 78
    BEAT        = 60.0 / BPM   # 0.769s per beat
    BAR         = BEAT * 4     # 3.077s per bar
    Q  = BEAT                  # quarter note
    H  = BEAT * 2              # half note
    E8 = BEAT / 2              # eighth note
    W  = BEAT * 4              # whole note

    S = 2**(1/12)
    def hz(midi): return 440.0 * (S**(midi-69))

    # ── G Major scale + semua nada yang dipakai ──────────
    G2=hz(31); A2=hz(33); B2=hz(35); C3=hz(36)
    D3=hz(38); E3=hz(40); Fs3=hz(42); G3=hz(43)
    A3=hz(45); B3=hz(47); C4=hz(48); D4=hz(50)
    E4=hz(52); Fs4=hz(54); G4=hz(55); A4=hz(57)
    B4=hz(59); C5=hz(60); D5=hz(62); E5=hz(64)
    G5=hz(67)
    # Bass
    G1=hz(19); D2=hz(26); E2=hz(28); C2=hz(24); B1=hz(23)

    # ════════════════════════════════════════════════════
    # SYNTH FUNCTIONS
    # ════════════════════════════════════════════════════

    def piano_tone(freq, dur_s, amp=1.0):
        """Piano tone — bright attack, long decay, harmonik alami."""
        n = int(dur_s * sample_rate)
        t = np.linspace(0, dur_s, n, endpoint=False)
        decay = np.exp(-t * (1.8 + freq*0.0008))
        # Harmonik piano
        wave  = 1.00 * np.sin(2*math.pi*freq*1*t)
        wave += 0.50 * np.exp(-t*2.5) * np.sin(2*math.pi*freq*2*t)
        wave += 0.25 * np.exp(-t*4.0) * np.sin(2*math.pi*freq*3*t)
        wave += 0.12 * np.exp(-t*6.0) * np.sin(2*math.pi*freq*4*t)
        wave += 0.06 * np.exp(-t*9.0) * np.sin(2*math.pi*freq*5*t)
        # Attack click ringan
        attack = np.minimum(t / 0.006, 1.0)
        return wave * decay * attack * amp

    def guitar_tone(freq, dur_s, amp=1.0, bright=0.65):
        """Gitar akustik — fingerpicking warm tone."""
        n = int(dur_s * sample_rate)
        t = np.linspace(0, dur_s, n, endpoint=False)
        decay = np.exp(-t * (2.5 + freq*0.003))
        wave  = 1.00 * np.sin(2*math.pi*freq*1*t)
        wave += 0.60 * np.exp(-t*1.5) * np.sin(2*math.pi*freq*2*t)
        wave += 0.30 * np.exp(-t*3.0) * np.sin(2*math.pi*freq*3*t)
        wave += 0.15 * np.exp(-t*5.0) * np.sin(2*math.pi*freq*4*t)
        wave += 0.08 * np.exp(-t*8.0) * np.sin(2*math.pi*freq*5*t)
        # Body thump
        wave += 0.12 * np.exp(-t*12.0) * np.sin(2*math.pi*freq*0.5*t)
        attack = np.minimum(t/0.003, 1.0)
        return wave * decay * attack * amp

    def pad_tone(freq, dur_s, amp=1.0):
        """String/pad lembut — slow attack, lush."""
        n = int(dur_s * sample_rate)
        t = np.linspace(0, dur_s, n, endpoint=False)
        attack  = np.minimum(t/0.4, 1.0)
        release = np.minimum((dur_s-t)/0.3, 1.0)
        env = attack * np.maximum(release, 0)
        wave  = np.sin(2*math.pi*freq*t)
        wave += 0.4 * np.sin(2*math.pi*freq*1.003*t)  # detune
        wave += 0.4 * np.sin(2*math.pi*freq*0.997*t)  # detune
        wave += 0.2 * np.sin(2*math.pi*freq*2*t)
        return wave * env * amp * 0.4

    sig = np.zeros(n_total, dtype=np.float64)

    def stamp(wave, t_start):
        """Stamp wave ke signal mulai t_start detik."""
        i_s = int(t_start * sample_rate)
        i_e = min(i_s + len(wave), n_total)
        if i_s >= n_total or i_s >= i_e: return
        sig[i_s:i_e] += wave[:i_e-i_s]

    def p(freq, t, dur, amp=0.7):
        """Stamp piano note."""
        stamp(piano_tone(freq, dur, amp), t)

    def g(freq, t, dur, amp=0.55):
        """Stamp guitar note."""
        stamp(guitar_tone(freq, dur, amp), t)

    def pad(freq, t, dur, amp=0.18):
        """Stamp pad note."""
        stamp(pad_tone(freq, dur, amp), t)

    # ════════════════════════════════════════════════════
    # PART A — 0:00 - 0:30  (Piano melody + Guitar)
    # Melody: B D G A / G D B A (repeat)
    # Chord: Gmaj7-D / Em7-Cmaj7
    # ════════════════════════════════════════════════════
    t = 0.0

    # Bar 1-2: Gmaj7 - D
    # Melody: B D G A
    p(B4, t+0*Q, Q+E8, 0.72)
    p(D5, t+1*Q, Q,    0.68)
    p(G4, t+2*Q, Q,    0.65)
    p(A4, t+3*Q, H,    0.68)
    # Bass + chord pad
    pad(G1,  t, BAR*2, 0.22); pad(D3,  t, BAR*2, 0.14)
    pad(Fs3, t, BAR*2, 0.12); pad(B3,  t, BAR*2, 0.10)
    # Bar 2: D chord
    p(D5, t+BAR+0*Q, Q,    0.68)
    p(A4, t+BAR+1*Q, Q,    0.65)
    p(Fs4,t+BAR+2*Q, H,    0.62)

    # Bar 3-4: Em7 - Cmaj7
    # Melody: G D B A
    t2 = t + BAR*2
    p(G4, t2+0*Q, Q+E8, 0.70)
    p(D4, t2+1*Q, Q,    0.65)
    p(B3, t2+2*Q, Q,    0.65)
    p(A3, t2+3*Q, H,    0.68)
    pad(E2, t2, BAR*2, 0.22); pad(G3, t2, BAR*2, 0.14)
    pad(B3, t2, BAR*2, 0.12); pad(D4, t2, BAR*2, 0.10)
    t3 = t2 + BAR
    p(C4, t3+0*Q, Q,    0.65)
    p(E4, t3+1*Q, Q,    0.62)
    p(G4, t3+2*Q, H,    0.65)

    # Bar 5-8: Repeat Part A
    t4 = t + BAR*4
    # Melody: B D G A (sama)
    p(B4, t4+0*Q, Q+E8, 0.72); p(D5, t4+1*Q, Q, 0.68)
    p(G4, t4+2*Q, Q,    0.65); p(A4, t4+3*Q, H, 0.68)
    pad(G1, t4, BAR*2, 0.22); pad(D3, t4, BAR*2, 0.14)
    pad(Fs3,t4, BAR*2, 0.12); pad(B3, t4, BAR*2, 0.10)
    p(D5, t4+BAR+0*Q, Q, 0.68); p(A4, t4+BAR+1*Q, Q, 0.65)
    p(Fs4,t4+BAR+2*Q, H, 0.62)
    # Melody: B A G D
    t5 = t4 + BAR*2
    p(B4, t5+0*Q, Q+E8, 0.70); p(A4, t5+1*Q, Q, 0.65)
    p(G4, t5+2*Q, Q,    0.65); p(D4, t5+3*Q, H, 0.68)
    pad(E2, t5, BAR*2, 0.22); pad(G3, t5, BAR*2, 0.14)
    t6 = t5 + BAR
    p(G4, t6+0*Q, Q, 0.65); p(E4, t6+1*Q, Q, 0.62)
    p(C4, t6+2*Q, H, 0.65)

    # ── Guitar picking Part A (overlay) ──────────────────
    # Pattern: E-B-G string arpeggio
    # E|---2--- B|--3-3-- G|--0--0-- E|-3------
    # Gmaj7: G2-B3-D4 / D: D2-Fs3-A3
    gtr_start = 0.0
    chord_gtr = [
        # Gmaj7
        (G2,  gtr_start+0.0,  E8, 0.50),
        (B3,  gtr_start+E8,   E8, 0.40),
        (D4,  gtr_start+E8*2, E8, 0.38),
        (B3,  gtr_start+E8*3, E8, 0.36),
        (G3,  gtr_start+E8*4, E8, 0.38),
        (D4,  gtr_start+E8*5, E8, 0.36),
        (B3,  gtr_start+E8*6, E8, 0.35),
        (G3,  gtr_start+E8*7, E8, 0.34),
    ]
    for freq, gt, dur, amp in chord_gtr:
        g(freq, gt, dur+0.3, amp)
    # D chord bar 2
    d_start = BAR
    for i, (freq, amp) in enumerate([(D2,0.50),(Fs3,0.40),(A3,0.38),(Fs3,0.36),
                                      (D3,0.38),(A3,0.36),(Fs3,0.35),(D3,0.34)]):
        g(freq, d_start+i*E8, E8+0.3, amp)

    # ════════════════════════════════════════════════════
    # PART B — 0:30 - 1:00  (Melody Build Up)
    # Melody: D E G B / A G E D (repeat)
    # Chord: Em7-Bm7 / Cmaj7-D
    # ════════════════════════════════════════════════════
    tB = 30.0

    # Bar 1-2: Em7 - Bm7
    p(D4, tB+0*Q, Q,    0.70); p(E4, tB+1*Q, Q,    0.72)
    p(G4, tB+2*Q, Q,    0.74); p(B4, tB+3*Q, H,    0.76)
    pad(E2, tB, BAR*2, 0.24); pad(G3, tB, BAR*2, 0.16)
    pad(B3, tB, BAR*2, 0.14); pad(D4, tB, BAR*2, 0.12)
    p(A4, tB+BAR+0*Q, Q, 0.72); p(G4, tB+BAR+1*Q, Q, 0.70)
    p(E4, tB+BAR+2*Q, Q, 0.68); p(D4, tB+BAR+3*Q, H, 0.70)

    # Bar 3-4: Cmaj7 - D (build up)
    tB2 = tB + BAR*2
    p(D4, tB2+0*Q, Q,    0.72); p(E4, tB2+1*Q, Q,    0.74)
    p(G4, tB2+2*Q, Q,    0.76); p(A4, tB2+3*Q, H,    0.78)
    pad(C2, tB2, BAR*2, 0.24); pad(E3, tB2, BAR*2, 0.16)
    pad(G3, tB2, BAR*2, 0.14); pad(B3, tB2, BAR*2, 0.12)
    p(B4, tB2+BAR+0*Q, Q, 0.76); p(A4, tB2+BAR+1*Q, Q, 0.74)
    p(G4, tB2+BAR+2*Q, Q, 0.72); p(E4, tB2+BAR+3*Q, H, 0.70)

    # Repeat Part B (bar 5-8)
    tB3 = tB + BAR*4
    p(D4, tB3+0*Q, Q, 0.74); p(E4, tB3+1*Q, Q, 0.76)
    p(G4, tB3+2*Q, Q, 0.78); p(B4, tB3+3*Q, H, 0.80)
    pad(E2, tB3, BAR*2, 0.26); pad(G3, tB3, BAR*2, 0.18)
    p(A4, tB3+BAR+0*Q, Q, 0.76); p(G4, tB3+BAR+1*Q, Q, 0.74)
    p(E4, tB3+BAR+2*Q, Q, 0.72); p(D4, tB3+BAR+3*Q, H, 0.72)
    tB4 = tB3 + BAR*2
    p(D4, tB4+0*Q, Q, 0.76); p(E4, tB4+1*Q, Q, 0.78)
    p(G4, tB4+2*Q, Q, 0.80); p(A4, tB4+3*Q, H, 0.82)
    pad(C2, tB4, BAR*2, 0.26); pad(E3, tB4, BAR*2, 0.18)
    p(B4, tB4+BAR+0*Q, Q, 0.80); p(A4, tB4+BAR+1*Q, Q, 0.78)
    p(G4, tB4+BAR+2*Q, Q, 0.76); p(E4, tB4+BAR+3*Q, H, 0.74)

    # ════════════════════════════════════════════════════
    # PART C — 1:00 - 1:30  (Emotional Chorus)
    # Melody: G A B D / B A G E (repeat)
    # Chord: Gmaj7-D/F# / Em7-Cadd9
    # ════════════════════════════════════════════════════
    tC = 60.0

    # Bar 1-2: Gmaj7 - D/F#
    p(G4, tC+0*Q, Q,    0.80); p(A4, tC+1*Q, Q,    0.82)
    p(B4, tC+2*Q, Q,    0.84); p(D5, tC+3*Q, H,    0.86)
    pad(G1, tC, BAR*2, 0.28); pad(B3, tC, BAR*2, 0.20)
    pad(D4, tC, BAR*2, 0.18); pad(Fs3,tC, BAR*2, 0.16)
    p(B4, tC+BAR+0*Q, Q, 0.84); p(A4, tC+BAR+1*Q, Q, 0.82)
    p(G4, tC+BAR+2*Q, Q, 0.80); p(E4, tC+BAR+3*Q, H, 0.78)

    # Bar 3-4: Em7 - Cadd9
    tC2 = tC + BAR*2
    p(G4, tC2+0*Q, Q,    0.82); p(A4, tC2+1*Q, Q,    0.84)
    p(B4, tC2+2*Q, Q,    0.86); p(D5, tC2+3*Q, H,    0.88)
    pad(E2, tC2, BAR*2, 0.28); pad(G3, tC2, BAR*2, 0.20)
    pad(B3, tC2, BAR*2, 0.18); pad(D4, tC2, BAR*2, 0.16)
    p(E5, tC2+BAR+0*Q, Q, 0.86); p(D5, tC2+BAR+1*Q, Q, 0.84)
    p(B4, tC2+BAR+2*Q, Q, 0.82); p(A4, tC2+BAR+3*Q, H, 0.80)

    # Repeat Chorus (bar 5-8) — puncak emosional
    tC3 = tC + BAR*4
    p(G4, tC3+0*Q, Q, 0.84); p(A4, tC3+1*Q, Q, 0.86)
    p(B4, tC3+2*Q, Q, 0.88); p(D5, tC3+3*Q, H, 0.90)
    pad(G1, tC3, BAR*2, 0.30); pad(B3, tC3, BAR*2, 0.22)
    p(B4, tC3+BAR+0*Q, Q, 0.88); p(A4, tC3+BAR+1*Q, Q, 0.86)
    p(G4, tC3+BAR+2*Q, Q, 0.84); p(E4, tC3+BAR+3*Q, H, 0.82)
    tC4 = tC3 + BAR*2
    p(G4, tC4+0*Q, Q, 0.86); p(A4, tC4+1*Q, Q, 0.88)
    p(B4, tC4+2*Q, Q, 0.90); p(D5, tC4+3*Q, H, 0.90)
    pad(E2, tC4, BAR*2, 0.30); pad(C2, tC4+BAR, BAR, 0.30)
    p(E5, tC4+BAR+0*Q, Q, 0.88); p(D5, tC4+BAR+1*Q, Q, 0.86)
    p(B4, tC4+BAR+2*Q, Q, 0.84); p(A4, tC4+BAR+3*Q, H, 0.82)

    # ════════════════════════════════════════════════════
    # OUTRO — 1:30 - 2:00  (Calm Ending)
    # Melody: B A G / D E G / A G D / G
    # Chord: Em7-Cmaj7 / G-D / G
    # ════════════════════════════════════════════════════
    tO = 90.0

    # Bar 1-2: Em7 - Cmaj7
    p(B4, tO+0*Q, Q+E8, 0.76); p(A4, tO+1*Q, Q,  0.72)
    p(G4, tO+2*Q, H+Q,  0.70)
    pad(E2, tO, BAR*2, 0.26); pad(G3, tO, BAR*2, 0.18)
    p(D4, tO+BAR+0*Q, Q+E8, 0.72); p(E4, tO+BAR+1*Q, Q, 0.68)
    p(G4, tO+BAR+2*Q, H+Q,  0.66)
    pad(C2, tO+BAR, BAR, 0.24); pad(E3, tO+BAR, BAR, 0.16)

    # Bar 3-4: G - D
    tO2 = tO + BAR*2
    p(A4, tO2+0*Q, Q+E8, 0.70); p(G4, tO2+1*Q, Q,  0.66)
    p(D4, tO2+2*Q, H+Q,  0.64)
    pad(G1, tO2, BAR*2, 0.24); pad(D3, tO2, BAR*2, 0.16)
    p(G4, tO2+BAR+0*Q, W+H, 0.65)  # G panjang, tenang

    # Bar 5-8: pelan, fade
    tO3 = tO + BAR*4
    p(B4, tO3+0*Q, H,    0.55); p(A4, tO3+2*Q, H,    0.50)
    p(G4, tO3+4*Q, H,    0.48); p(D4, tO3+6*Q, H,    0.45)
    p(E4, tO3+8*Q, Q,    0.42); p(G4, tO3+9*Q, W+H,  0.40)
    pad(G1, tO3, BAR*4, 0.20)

    # ── Guitar overlay sepanjang lagu (tipis) ─────────────
    # Pattern fingerpicking di background
    def play_gtr_bar(chord_notes, t_bar, amp_scale=1.0):
        bass, mid, hi = chord_notes
        for beat_i in range(4):
            tb = t_bar + beat_i*BEAT
            g(bass, tb,         E8+0.3, 0.38*amp_scale)
            g(mid,  tb+E8,      E8+0.3, 0.30*amp_scale)
            g(hi,   tb+E8*2,    E8+0.3, 0.28*amp_scale)
            g(mid,  tb+E8*3,    E8+0.3, 0.26*amp_scale)

    gtr_chords = [
        # Part A (0-30s): Gmaj7-D-Em7-Cmaj7 x2
        (G2,  B3,  D4), (D2,  Fs3, A3), (E2,  G3,  B3), (C2,  E3,  G3),
        (G2,  B3,  D4), (D2,  Fs3, A3), (E2,  G3,  B3), (C2,  E3,  G3),
        # Part B (30-60s): Em7-Bm7-Cmaj7-D x2
        (E2,  G3,  B3), (B2,  D3,  Fs3),(C2,  E3,  G3), (D2,  Fs3, A3),
        (E2,  G3,  B3), (B2,  D3,  Fs3),(C2,  E3,  G3), (D2,  Fs3, A3),
        # Part C (60-90s): Gmaj7-D/F#-Em7-Cadd9 x2
        (G2,  B3,  D4), (Fs3, A3,  D4), (E2,  G3,  B3), (C2,  G3,  E4),
        (G2,  B3,  D4), (Fs3, A3,  D4), (E2,  G3,  B3), (C2,  G3,  E4),
        # Outro (90-120s): Em7-Cmaj7-G-D-G
        (E2,  G3,  B3), (C2,  E3,  G3), (G2,  B3,  D4), (D2,  Fs3, A3),
        (G2,  B3,  D4), (G2,  B3,  D4), (G2,  B3,  D4), (G2,  B3,  D4),
    ]

    for bar_i, chord in enumerate(gtr_chords):
        t_bar = bar_i * BAR
        # Guitar makin lembut di outro
        amp_s = 0.7 if t_bar < 90 else max(0.3, 0.7*(1-(t_bar-90)/30))
        play_gtr_bar(chord, t_bar, amp_s)

    # ── Normalize & Fade ──────────────────────────────────
    t_arr    = np.linspace(0, durasi_detik, n_total, endpoint=False)
    fade_in  = np.minimum(t_arr/2.0, 1.0)
    fade_out = np.maximum(0.0, np.minimum((durasi_detik-t_arr)/5.0, 1.0))
    sig     *= fade_in * fade_out

    mx = np.max(np.abs(sig))
    if mx > 0: sig = sig / mx * 0.88

    import numpy as np2
    samples = np.clip(sig * volume * 32767, -32767, 32767).astype(np.int16)
    stereo  = np.column_stack([samples, samples])
    try:
        return pygame.sndarray.make_sound(stereo)
    except Exception as e:
        print(f"Musik Level 2 gagal: {e}")
        return buat_musik_latar(64, volume)
    """
    Everything You Are — Hindia
    Sound: Gitar akustik fingerpicking saja.
    Key: F# minor | Tempo: 90 BPM
    """
    import numpy as np
    sample_rate = 22050
    n_total     = int(sample_rate * durasi_detik)
    amp_master  = volume
    BPM         = 90
    BEAT        = 60.0 / BPM    # 0.667s
    BAR         = BEAT * 4

    S = 2**(1/12)
    def hz(midi): return 440.0 * (S ** (midi - 69))

    # F# minor — semua nada yang dipakai
    Fs2=hz(30); A2=hz(33);  B2=hz(35);  Cs3=hz(37)
    D3=hz(38);  E3=hz(40);  Fs3=hz(42); Gs3=hz(44)
    A3=hz(45);  B3=hz(47);  Cs4=hz(49); D4=hz(50)
    E4=hz(52);  Fs4=hz(54); Gs4=hz(56); A4=hz(57)
    B4=hz(59);  Cs5=hz(61); D5=hz(62);  E5=hz(64)
    # Bass notes
    Fs1=hz(18); A1=hz(21);  B1=hz(23);  Cs2=hz(25)
    D2=hz(26);  E2=hz(28);  Fs2b=hz(30)

    def gitar(freq, t_arr, i_s, i_e, amp=1.0, brightness=0.6):
        """
        Simulasi gitar akustik — Karplus-Strong inspired.
        Karplus-Strong: pluck = impulse + decaying harmonics.
        """
        dur_s = (i_e - i_s) / sample_rate
        td    = t_arr[i_s:i_e] - t_arr[i_s]

        # Envelope gitar: attack instan, decay eksponensial (string decay)
        decay_rate = 2.8 + freq * 0.002  # nada tinggi decay lebih cepat
        env   = np.exp(-td * decay_rate)

        # Harmonik gitar akustik (overtone series)
        wave  = np.zeros(i_e - i_s)
        harmonic_amps = [1.0, 0.6, 0.35, 0.20, 0.12, 0.07, 0.04]
        harmonic_decay= [1.0, 1.3, 1.7,  2.2,  2.8,  3.5,  4.5]
        for k, (ha, hd) in enumerate(zip(harmonic_amps, harmonic_decay), 1):
            if k * freq > sample_rate / 2: break
            env_k = np.exp(-td * decay_rate * hd * (1 - brightness*0.3))
            wave += ha * env_k * np.sin(2*math.pi*freq*k*t_arr[i_s:i_e])

        # Body resonance — gitar akustik punya body thump
        body_f = freq * 0.5
        wave  += 0.15 * np.exp(-td * 8.0) * np.sin(2*math.pi*body_f*t_arr[i_s:i_e])

        # Normalisasi per nada
        mx = np.max(np.abs(wave))
        if mx > 0: wave = wave / mx * amp
        return wave

    try:
        t_arr = np.linspace(0, durasi_detik, n_total, endpoint=False)
        sig   = np.zeros(n_total, dtype=np.float64)

        def pluck(freq, t_beat, amp=1.0, bright=0.6):
            """Petik satu senar gitar pada waktu t_beat."""
            i_s = int(t_beat * sample_rate)
            i_e = min(i_s + int(2.5 * sample_rate), n_total)  # max 2.5s decay
            if i_s >= n_total or i_s >= i_e: return
            wave = gitar(freq, t_arr, i_s, i_e, amp, bright)
            sig[i_s:i_e] += wave

        # ════════════════════════════════════════════════
        # CHORD SHAPES — Fingerpicking pattern Hindia
        # Pattern: Bass → Mid → High → Mid (arpeggio)
        # Setiap bar = 4 beat, setiap beat = 1 petikan
        # ════════════════════════════════════════════════

        # Chord F#m:  Fs2-Fs3-A3-Cs4
        # Chord A:    A2-A3-Cs4-E4
        # Chord E:    E2-E3-Gs3-B3
        # Chord Bm:   B2-B3-D4-Fs4

        chord_shapes = {
            "Fsm": [(Fs2b, 0.90), (A3,  0.55), (Cs4, 0.50), (A3,  0.45)],
            "A":   [(A2,  0.85), (Cs4, 0.55), (E4,  0.50), (Cs4, 0.45)],
            "E":   [(E2,  0.85), (Gs3, 0.55), (B3,  0.50), (Gs3, 0.45)],
            "Bm":  [(B2,  0.85), (D4,  0.55), (Fs4, 0.50), (D4,  0.45)],
        }

        # Chord progression: Fsm - A - E - Bm (repeat)
        prog = ["Fsm","A","E","Bm"]

        # ── Fingerpicking pattern per bar ─────────────────
        def play_bar(bar_i, chord_name, t_start):
            notes = chord_shapes[chord_name]
            # Beat 1: bass note (kuat)
            pluck(notes[0][0], t_start + 0*BEAT, amp=notes[0][1]*1.1, bright=0.5)
            # Beat 1.5: mid string
            pluck(notes[1][0], t_start + 0.5*BEAT, amp=notes[1][1]*0.85, bright=0.65)
            # Beat 2: high string
            pluck(notes[2][0], t_start + 1*BEAT, amp=notes[2][1]*0.80, bright=0.70)
            # Beat 2.5: mid string lagi
            pluck(notes[3][0], t_start + 1.5*BEAT, amp=notes[3][1]*0.75, bright=0.65)
            # Beat 3: bass note lagi (sedikit lebih pelan)
            pluck(notes[0][0], t_start + 2*BEAT, amp=notes[0][1]*0.90, bright=0.50)
            # Beat 3.5: mid
            pluck(notes[1][0], t_start + 2.5*BEAT, amp=notes[1][1]*0.80, bright=0.65)
            # Beat 4: high
            pluck(notes[2][0], t_start + 3*BEAT, amp=notes[2][1]*0.75, bright=0.70)
            # Beat 4.5: mid (anticipation ke bar berikut)
            pluck(notes[3][0], t_start + 3.5*BEAT, amp=notes[3][1]*0.70, bright=0.65)

        # ── Main loop — play semua bar ──────────────────
        n_bars = int(durasi_detik / BAR) + 1
        for bar_i in range(n_bars):
            chord = prog[bar_i % len(prog)]
            t_bar = bar_i * BAR
            if t_bar >= durasi_detik: break
            play_bar(bar_i, chord, t_bar)

        # ── Melodi singkat di verse (bar 4-12) ──────────
        # Melody tipis di atas — seperti gitar solo ringan
        melody_notes = [
            # Bar 4: frase pembuka
            (Cs4, 4*BAR + 0*BEAT, 0.30),
            (D4,  4*BAR + 1*BEAT, 0.28),
            (Cs4, 4*BAR + 2*BEAT, 0.28),
            (A3,  4*BAR + 3*BEAT, 0.25),
            # Bar 5
            (B3,  5*BAR + 0*BEAT, 0.28),
            (Cs4, 5*BAR + 1*BEAT, 0.28),
            (B3,  5*BAR + 2*BEAT, 0.25),
            (Gs3, 5*BAR + 3*BEAT, 0.22),
            # Bar 6-7: turun
            (A3,  6*BAR + 0*BEAT, 0.28),
            (Fs3, 6*BAR + 2*BEAT, 0.25),
            (E3,  7*BAR + 0*BEAT, 0.22),
            (Fs3, 7*BAR + 2*BEAT, 0.25),
            # Bar 8: naik lagi
            (Cs4, 8*BAR + 0*BEAT, 0.30),
            (E4,  8*BAR + 1*BEAT, 0.28),
            (Fs4, 8*BAR + 2*BEAT, 0.32),
            (E4,  8*BAR + 3*BEAT, 0.28),
            # Bar 9-11: repeat frase
            (Cs4, 9*BAR  + 0*BEAT, 0.28),
            (D4,  9*BAR  + 1*BEAT, 0.26),
            (Cs4, 9*BAR  + 2*BEAT, 0.25),
            (A3,  10*BAR + 0*BEAT, 0.25),
            (B3,  10*BAR + 2*BEAT, 0.24),
            (Fs3, 11*BAR + 0*BEAT, 0.28),
        ]
        for freq, t_note, amp in melody_notes:
            if t_note < durasi_detik:
                pluck(freq, t_note, amp=amp, bright=0.75)

        # ── Fade in / Fade out ────────────────────────
        fade_in  = np.minimum(t_arr / 1.5, 1.0)
        fade_out = np.maximum(0.0, np.minimum((durasi_detik-t_arr)/3.0, 1.0))
        sig *= fade_in * fade_out

        # Normalize
        mx = np.max(np.abs(sig))
        if mx > 0: sig = sig / mx * 0.90

        samples = np.clip(sig*amp_master*32767, -32767, 32767).astype(np.int16)
        stereo  = np.column_stack([samples, samples])
        return pygame.sndarray.make_sound(stereo)

    except Exception as e:
        print(f"Gitar gagal: {e}")
        import traceback; traceback.print_exc()
        return buat_musik_latar(durasi_detik=64, volume=volume)
    """
    Everything You Are — Hindia (inspirasi)
    Key: F# minor | Tempo: ~90 BPM | Genre: Indie electronic dreamy

    Ciri khas sound Hindia:
    - Synth sawtooth + filter sweep (bukan sine murni)
    - Bass synth pulsating dengan sub-bass
    - Pad lush detuned layered
    - Melodi sederhana dengan gap/ruang banyak
    - Echo/reverb panjang
    - Drum elektronik minimalis
    """
    import numpy as np
    sample_rate = 22050
    n_total     = int(sample_rate * durasi_detik)
    amp_master  = volume
    BPM         = 90
    BEAT        = 60.0 / BPM       # 0.667 detik per beat
    BAR         = BEAT * 4         # 2.667 detik per bar

    # ── Nada dalam F# minor ──────────────────────────────
    # F#2, G#2, A2, B2, C#3, D3, E3, F#3...
    S = 2**(1/12)
    def hz(midi): return 440.0 * (S ** (midi - 69))

    # F# minor scale (MIDI)
    Fs2=hz(30); Gs2=hz(32); A2=hz(33);  B2=hz(35)
    Cs3=hz(37); D3=hz(38);  E3=hz(40);  Fs3=hz(42)
    Gs3=hz(44); A3=hz(45);  B3=hz(47);  Cs4=hz(49)
    D4=hz(50);  E4=hz(52);  Fs4=hz(54); Gs4=hz(56)
    A4=hz(57);  B4=hz(59);  Cs5=hz(61); D5=hz(62)
    E5=hz(64);  Fs5=hz(66)
    # Sub bass
    Fs1=hz(18); A1=hz(21); B1=hz(23); Cs2=hz(25); D2=hz(26); E2=hz(28)

    # ── Chord progression F#m - A - E - B (loop) ─────────
    # Setiap 2 bar (5.33 detik)
    chords = [
        (Fs2, [Fs3, A3,  Cs4]),  # F#m
        (A2,  [A3,  Cs4, E4 ]),  # A
        (E2,  [E3,  Gs3, B3 ]),  # E
        (B2,  [B3,  D4,  Fs4]),  # Bm
    ]

    # ── Melodi utama — sederhana, banyak ruang ─────────────
    # Dalam F# minor, tempo 90 BPM
    # Half note = 1.33s, Quarter = 0.667s, Eighth = 0.333s
    H = BEAT*2; Q = BEAT; E8 = BEAT/2; W = BEAT*4

    verse_a = [
        # Bar 1-2: melodi naik perlahan
        (Cs4, Q),   (D4,  Q),   (Cs4, H),
        (A3,  H),   (Fs3, H),
        # Bar 3-4: turun dengan ruang
        (E3,  Q),   (Fs3, Q),   (Gs3, H),
        (A3,  H),   (Cs4, H),
        # Bar 5-6: variasi
        (D4,  Q),   (Cs4, Q),   (B3,  H),
        (Gs3, H),   (Fs3, W),
        # Bar 7-8: naik ke puncak
        (A3,  Q),   (Cs4, Q),   (E4,  H),
        (Fs4, H),   (E4,  H),
        # Bar 9-10: turun romantic
        (D4,  Q),   (Cs4, Q),   (B3,  H),
        (A3,  H),   (Fs3, W),
    ]

    chorus = [
        # Chorus lebih ekspresif — naik ke Fs4
        (Fs4, H),   (E4,  Q),   (D4,  Q),
        (Cs4, H),   (B3,  H),
        (A3,  Q),   (Cs4, Q),   (E4,  H),
        (Fs4, W),
        (E4,  H),   (D4,  Q),   (Cs4, Q),
        (B3,  H),   (A3,  H),
        (Gs3, Q),   (A3,  Q),   (Cs4, H),
        (Fs3, W),
    ]

    def build_tl(seq, t_off):
        tl, t = [], t_off
        for f, d in seq:
            tl.append((f, t, t+d)); t += d
        return tl

    # Timeline: intro(8s) → verse(~27s) → chorus(~21s) → verse(~27s) → outro
    mel_tl = (build_tl(verse_a, 8.0) +
              build_tl(chorus,  35.0) +
              build_tl(verse_a, 56.0))

    try:
        t_arr = np.linspace(0, durasi_detik, n_total, endpoint=False)
        sig   = np.zeros(n_total, dtype=np.float64)

        # ════════════════════════════════════════════════
        # SYNTH FUNCTIONS
        # ════════════════════════════════════════════════

        def sawtooth(freq, t):
            """Sawtooth wave — ciri khas synth Hindia."""
            phase = (freq * t) % 1.0
            return 2.0 * phase - 1.0

        def soft_saw(freq, t, cutoff_ratio=0.4):
            """Sawtooth dengan low-pass filter simulasi (band-limited)."""
            wave = np.zeros_like(t)
            # Jumlah harmonik berdasarkan cutoff
            n_harmonics = max(1, int(cutoff_ratio * 12))
            for k in range(1, n_harmonics + 1):
                amp_k = 1.0 / k
                wave += amp_k * np.sin(2*math.pi*freq*k*t)
            return wave * (2.0/math.pi)

        # ════════════════════════════════════════════════
        # 1. SYNTH PAD INTRO — lush detuned
        # ════════════════════════════════════════════════
        for bar_i in range(3):  # 3 bar intro
            t_start = bar_i * BAR
            t_end   = t_start + BAR * 1.5  # overlap antar bar
            chord_i = bar_i % len(chords)
            bass_f, chord_notes = chords[chord_i]
            i_s = int(t_start * sample_rate)
            i_e = min(int(t_end * sample_rate), n_total)
            if i_s >= i_e: continue
            ta  = t_arr[i_s:i_e] - t_start
            dur = t_end - t_start
            # Envelope: slow attack, long sustain
            env = np.minimum(ta/1.0, 1.0) * np.minimum((dur-ta)/0.8, 1.0)
            env = np.maximum(env, 0)
            for cf in chord_notes:
                # Detuned pad — 3 layer
                sig[i_s:i_e] += 0.10*env*soft_saw(cf,       t_arr[i_s:i_e], 0.25)
                sig[i_s:i_e] += 0.08*env*soft_saw(cf*1.006, t_arr[i_s:i_e], 0.20)
                sig[i_s:i_e] += 0.08*env*soft_saw(cf*0.994, t_arr[i_s:i_e], 0.20)

        # ════════════════════════════════════════════════
        # 2. MELODI UTAMA — sawtooth lembut + vibrato
        # ════════════════════════════════════════════════
        for frek, ts, te in mel_tl:
            i_s = int(ts * sample_rate)
            i_e = min(int(te * sample_rate), n_total)
            if i_s >= i_e: continue
            dur = te - ts
            td  = t_arr[i_s:i_e] - ts

            # Envelope: attack cepat, release panjang (dreamy)
            att = np.minimum(td/0.08, 1.0)
            rel = np.maximum(0.0, 1.0 - np.maximum(0.0, td-dur*0.65)/max(dur*0.35, 1e-9))
            env = att * rel

            # Vibrato lembut — 4.5Hz, mulai setelah 0.15s
            vib_amt = np.minimum(td/0.15, 1.0) * 0.004
            vib = 1.0 + vib_amt * np.sin(2*math.pi*4.5*td)

            # Soft sawtooth — lebih hangat dari sine
            mel_wave  = soft_saw(frek, t_arr[i_s:i_e]*vib, cutoff_ratio=0.35)
            mel_wave += 0.3 * np.sin(2*math.pi*frek*vib*t_arr[i_s:i_e])  # sine blend
            mel_wave *= 0.38 * env

            sig[i_s:i_e] += mel_wave

            # ── Echo panjang (reverb simulasi Hindia) ────
            echo_delays = [(0.30, 0.28), (0.60, 0.14), (0.90, 0.07)]
            for delay, echo_amp in echo_delays:
                echo_s = i_s + int(delay * sample_rate)
                echo_e = min(echo_s + (i_e-i_s), n_total)
                if echo_s < n_total and echo_e > echo_s:
                    trim = min(i_e-i_s, echo_e-echo_s)
                    sig[echo_s:echo_s+trim] += mel_wave[:trim] * echo_amp

        # ════════════════════════════════════════════════
        # 3. CHORD PAD BACKGROUND (sepanjang lagu)
        # ════════════════════════════════════════════════
        chord_duration = BAR * 2  # 2 bar per chord
        for bar_i in range(int(durasi_detik / chord_duration) + 1):
            chord_i = bar_i % len(chords)
            bass_f, chord_notes = chords[chord_i]
            t_start = bar_i * chord_duration
            t_end   = t_start + chord_duration
            i_s = int(t_start * sample_rate)
            i_e = min(int(t_end * sample_rate), n_total)
            if i_s >= i_e: continue
            ta  = t_arr[i_s:i_e] - t_start
            dur = chord_duration
            env_c = (np.minimum(ta/0.4, 1.0) *
                     np.minimum((dur-ta)/0.4, 1.0))
            env_c = np.maximum(env_c, 0)
            for cf in chord_notes:
                sig[i_s:i_e] += 0.07*env_c*soft_saw(cf,       t_arr[i_s:i_e], 0.20)
                sig[i_s:i_e] += 0.05*env_c*soft_saw(cf*1.008, t_arr[i_s:i_e], 0.18)
                sig[i_s:i_e] += 0.05*env_c*soft_saw(cf*0.992, t_arr[i_s:i_e], 0.18)

        # ════════════════════════════════════════════════
        # 4. BASS SYNTH — pulsating elektronik
        # ════════════════════════════════════════════════
        for bar_i in range(int(durasi_detik / (BAR*2)) + 1):
            chord_i = bar_i % len(chords)
            bass_f  = chords[chord_i][0]
            for beat_i in range(8):  # 8 beat per 2 bar
                t_beat = bar_i*BAR*2 + beat_i*BEAT
                i_s = int(t_beat * sample_rate)
                i_e = min(int((t_beat+BEAT)*sample_rate), n_total)
                if i_s >= i_e: continue
                tb  = t_arr[i_s:i_e] - t_beat
                # Bass envelope: attack sangat cepat, decay medium
                env_b = np.exp(-tb * 3.5)
                # Beat 1 dan 3 lebih kuat
                amp_b = 0.32 if beat_i % 2 == 0 else 0.18
                sig[i_s:i_e] += amp_b * env_b * np.sin(2*math.pi*bass_f*t_arr[i_s:i_e])
                # Sub bass
                sig[i_s:i_e] += amp_b*0.4*env_b*np.sin(2*math.pi*bass_f*0.5*t_arr[i_s:i_e])
                # Harmonic distorsi ringan
                sig[i_s:i_e] += amp_b*0.15*env_b*np.sin(2*math.pi*bass_f*2*t_arr[i_s:i_e])

        # ════════════════════════════════════════════════
        # 5. DRUM ELEKTRONIK MINIMALIS
        # ════════════════════════════════════════════════
        for bar_i in range(int(durasi_detik/BAR) + 1):
            for beat_i in range(4):
                t_beat = bar_i*BAR + beat_i*BEAT
                i_s = int(t_beat * sample_rate)
                if i_s >= n_total: continue

                # Kick — beat 1 dan 3
                if beat_i in (0, 2):
                    kick_dur = int(0.15 * sample_rate)
                    i_e = min(i_s+kick_dur, n_total)
                    tk  = t_arr[i_s:i_e] - t_beat
                    # Kick: sine turun pitch cepat
                    pitch_sweep = 80 * np.exp(-tk*25)
                    env_k = np.exp(-tk*18)
                    sig[i_s:i_e] += 0.20*env_k*np.sin(2*math.pi*pitch_sweep*tk)

                # Snare ringan — beat 2 dan 4
                if beat_i in (1, 3):
                    snare_dur = int(0.10 * sample_rate)
                    i_e = min(i_s+snare_dur, n_total)
                    ts2 = t_arr[i_s:i_e] - t_beat
                    env_s = np.exp(-ts2*30)
                    noise_s = np.sin(2*math.pi*200*ts2) + np.sin(2*math.pi*400*ts2)
                    sig[i_s:i_e] += 0.06*env_s*noise_s

                # Hi-hat eighth note
                hat_dur = int(0.03 * sample_rate)
                i_e_h = min(i_s+hat_dur, n_total)
                if i_s < i_e_h:
                    th  = t_arr[i_s:i_e_h] - t_beat
                    env_h = np.exp(-th*80)
                    sig[i_s:i_e_h] += 0.015*env_h*np.sin(2*math.pi*8000*th)

        # ════════════════════════════════════════════════
        # 6. FADE IN / FADE OUT
        # ════════════════════════════════════════════════
        fade_in  = np.minimum(t_arr/2.5, 1.0)
        fade_out = np.maximum(0.0, np.minimum((durasi_detik-t_arr)/4.0, 1.0))
        sig *= fade_in * fade_out

        # Normalize
        max_val = np.max(np.abs(sig))
        if max_val > 0:
            sig = sig / max_val * 0.85

        samples = np.clip(sig*amp_master*32767, -32767, 32767).astype(np.int16)
        stereo  = np.column_stack([samples, samples])
        return pygame.sndarray.make_sound(stereo)

    except Exception as e:
        print(f"Everything You Are gagal: {e}")
        import traceback; traceback.print_exc()
        return buat_musik_latar(durasi_detik=64, volume=volume)

def buat_musik_la_vie_en_rose(durasi_detik=72, volume=0.18):
    """
    La Vie en Rose (Édith Piaf, 1947) — Musik latar Level 1.
    Melodi utama dalam E♭ major, diaransemen gaya piano jazz ringan.

    Struktur:
      Intro    (0-8s)   : Arpeggio pembuka lembut
      Verse A  (8-32s)  : Melodi utama La Vie en Rose
      Verse B  (32-56s) : Variasi & pengembangan melodi
      Outro    (56-72s) : Kembali ke melodi utama, fade out
    """
    import numpy as np
    sample_rate = 22050
    n_total     = int(sample_rate * durasi_detik)
    amp_master  = volume

    # Nada dalam Eb major (transposisi ke C untuk kemudahan, lalu naik 3 semitone)
    # Pakai E major untuk warna hangat piano
    S = 2 ** (1/12)  # Semitone ratio
    def note(name, octave):
        base = {"C":261.63,"D":293.66,"E":329.63,"F":349.23,
                "G":392.00,"A":440.00,"B":493.88}
        return base[name] * (2 ** (octave - 4))
    def eb(n, o): return note(n, o) * (S**3)   # Transpose +3 semitone ke Eb

    # ── Melodi La Vie en Rose (dalam Eb major) ─────────────
    # Frase ikonik: G - Bb - Eb - Eb - G - F - Eb...
    N = {
        "Eb3": eb("C",3)*S**3, "F3": eb("D",3)*S**3,  "G3": eb("E",3)*S**3,
        "Ab3": eb("F",3)*S**3, "Bb3":eb("G",3)*S**3,  "C4": eb("A",3)*S**3,
        "Db4":eb("B",3)*S**3,  "Eb4":eb("C",4)*S**3,  "F4": eb("D",4)*S**3,
        "G4": eb("E",4)*S**3,  "Ab4":eb("F",4)*S**3,  "Bb4":eb("G",4)*S**3,
        "C5": eb("A",4)*S**3,  "Db5":eb("B",4)*S**3,  "Eb5":eb("C",5)*S**3,
        "Bb2":eb("G",2)*S**3,  "Eb2":eb("C",2)*S**3,  "Ab2":eb("F",2)*S**3,
    }

    # Melodi utama La Vie en Rose — frase ikonik
    verse_a = [
        # "Quand il me prend dans ses bras..."
        (N["G4"],  0.35), (N["Bb4"], 0.35), (N["Eb5"], 0.70),
        (N["Eb5"], 0.35), (N["Db5"], 0.35), (N["C5"],  0.35),
        (N["Bb4"], 0.35), (N["G4"],  0.70),
        (N["G4"],  0.35), (N["F4"],  0.35), (N["Eb4"], 0.70),
        (N["Eb4"], 0.35), (N["F4"],  0.35), (N["G4"],  0.35),
        (N["Ab4"], 0.35), (N["Bb4"], 1.05),
        # "Il me parle tout bas..."
        (N["Bb4"], 0.35), (N["C5"],  0.35), (N["Bb4"], 0.70),
        (N["Ab4"], 0.35), (N["G4"],  0.35), (N["F4"],  0.70),
        (N["Eb4"], 0.35), (N["F4"],  0.35), (N["G4"],  0.35),
        (N["Ab4"], 0.35), (N["Eb4"], 1.40),
    ]
    # Variasi Verse B — lebih tinggi dan ekspresif
    verse_b = [
        (N["Eb5"], 0.35), (N["Eb5"], 0.35), (N["Db5"], 0.70),
        (N["C5"],  0.35), (N["Bb4"], 0.35), (N["Ab4"], 0.70),
        (N["G4"],  0.35), (N["Ab4"], 0.35), (N["Bb4"], 0.35),
        (N["C5"],  0.35), (N["Bb4"], 1.05),
        (N["Bb4"], 0.35), (N["Ab4"], 0.35), (N["G4"],  0.70),
        (N["F4"],  0.35), (N["Eb4"], 0.35), (N["F4"],  0.70),
        (N["G4"],  0.35), (N["Ab4"], 0.35), (N["Bb4"], 0.35),
        (N["Eb4"], 1.75),
        # Bridge — melodi turun romantis
        (N["C5"],  0.35), (N["Bb4"], 0.35), (N["Ab4"], 0.70),
        (N["G4"],  0.35), (N["F4"],  0.35), (N["Eb4"], 0.70),
        (N["F4"],  0.35), (N["G4"],  0.35), (N["Ab4"], 0.35),
        (N["Bb4"], 0.35), (N["Eb4"], 1.40),
    ]
    # Outro — kembali ke melodi awal, lebih pelan
    outro = [
        (N["G4"],  0.40), (N["Bb4"], 0.40), (N["Eb5"], 0.80),
        (N["Db5"], 0.40), (N["C5"],  0.40), (N["Bb4"], 0.80),
        (N["Ab4"], 0.40), (N["G4"],  0.40), (N["F4"],  0.40),
        (N["Eb4"], 0.40), (N["G4"],  0.40), (N["Bb4"], 0.40),
        (N["Eb5"], 2.00),
    ]

    def build_tl(seq, t_off):
        tl, t = [], t_off
        for f, d in seq:
            tl.append((f, t, t+d)); t += d
        return tl

    # Timeline melodi
    intro_arp_dur = 8.0
    mel_tl  = (build_tl(verse_a, intro_arp_dur) +
               build_tl(verse_b, intro_arp_dur + 24.0) +
               build_tl(outro,   intro_arp_dur + 48.0))
    harm_tl = [(f*1.498, ts, te) for f,ts,te in mel_tl]  # Harmoni quinta atas

    # Chord bass Eb major
    bass_chords = {
        0: N["Eb2"], 2: N["Eb2"], 4: N["Ab2"], 6: N["Ab2"],
        8: N["Bb2"], 10:N["Bb2"], 12:N["Eb2"], 14:N["Eb2"],
        16:N["Ab2"], 18:N["Ab2"], 20:N["Bb2"], 22:N["Bb2"],
        24:N["Eb2"], 26:N["Eb2"], 28:N["Ab2"], 30:N["Ab2"],
        32:N["Eb2"], 34:N["Eb2"], 36:N["Bb2"], 38:N["Bb2"],
        40:N["Ab2"], 42:N["Ab2"], 44:N["Eb2"], 46:N["Eb2"],
        48:N["Bb2"], 50:N["Bb2"], 52:N["Ab2"], 54:N["Ab2"],
        56:N["Eb2"], 58:N["Eb2"], 60:N["Bb2"], 62:N["Bb2"],
        64:N["Eb2"], 66:N["Eb2"], 68:N["Ab2"], 70:N["Ab2"],
    }

    try:
        t_arr = np.linspace(0, durasi_detik, n_total, endpoint=False)
        sig   = np.zeros(n_total)

        # ── Intro: arpeggio lembut Eb major ──────────────
        arp_notes = [N["Eb3"], N["G3"], N["Bb3"], N["Eb4"],
                     N["Bb3"], N["G3"], N["Eb3"], N["G3"]]
        arp_dur_each = intro_arp_dur / len(arp_notes)
        for ai, af in enumerate(arp_notes):
            i_s = int(ai * arp_dur_each * sample_rate)
            i_e = min(int((ai+1) * arp_dur_each * sample_rate), n_total)
            if i_s >= i_e: continue
            ta  = t_arr[i_s:i_e] - ai*arp_dur_each
            env = np.exp(-ta * 2.5)
            sig[i_s:i_e] += 0.25 * env * np.sin(2*math.pi*af*t_arr[i_s:i_e])
            sig[i_s:i_e] += 0.10 * env * np.sin(2*math.pi*af*2*t_arr[i_s:i_e])

        # ── Melodi utama — sine lembut dengan vibrato ────
        for frek, ts, te in mel_tl:
            i_s = int(ts * sample_rate)
            i_e = min(int(te * sample_rate), n_total)
            if i_s >= i_e: continue
            dur = te - ts
            td  = t_arr[i_s:i_e] - ts
            att = np.minimum(td / 0.04, 1.0)
            rel = np.maximum(0.0, 1.0 - np.maximum(0.0, td-dur*0.80)/max(dur*0.20,1e-9))
            vib = 1.0 + 0.004 * np.sin(2*math.pi*5.2*td)  # Vibrato 5.2Hz
            sig[i_s:i_e] += 0.45*att*rel*np.sin(2*math.pi*frek*vib*t_arr[i_s:i_e])
            # Overtone ringan untuk warna piano
            sig[i_s:i_e] += 0.12*att*rel*np.sin(2*math.pi*frek*2*t_arr[i_s:i_e])
            sig[i_s:i_e] += 0.05*att*rel*np.sin(2*math.pi*frek*3*t_arr[i_s:i_e])

        # ── Harmoni quinta ────────────────────────────────
        for frek, ts, te in harm_tl:
            i_s = int(ts * sample_rate)
            i_e = min(int(te * sample_rate), n_total)
            if i_s >= i_e: continue
            dur = te - ts
            td  = t_arr[i_s:i_e] - ts
            att = np.minimum(td / 0.06, 1.0)
            rel = np.maximum(0.0, 1.0 - np.maximum(0.0, td-dur*0.75)/max(dur*0.25,1e-9))
            sig[i_s:i_e] += 0.16*att*rel*np.sin(2*math.pi*frek*t_arr[i_s:i_e])

        # ── Bass — petikan piano gaya Piaf ────────────────
        for sec in range(0, int(durasi_detik), 2):
            bf  = bass_chords.get(sec, N["Eb2"])
            i_s = int(sec * sample_rate)
            i_e = min(int((sec+2)*sample_rate), n_total)
            if i_s >= i_e: continue
            tb  = t_arr[i_s:i_e] - sec
            env_b = np.exp(-tb * 3.0)
            sig[i_s:i_e] += 0.26*env_b*np.sin(2*math.pi*bf*t_arr[i_s:i_e])
            sig[i_s:i_e] += 0.08*env_b*np.sin(2*math.pi*bf*1.5*t_arr[i_s:i_e])
            # Beat ke-2 setiap bar — waltz feel (3/4)
            i_b2 = min(i_s + int(0.67*sample_rate), i_e)
            if i_b2 < i_e:
                tb2 = t_arr[i_b2:i_e] - (sec+0.67)
                env_b2 = np.exp(-tb2*5.0)*0.5
                sig[i_b2:i_e] += 0.10*env_b2*np.sin(2*math.pi*bf*1.498*t_arr[i_b2:i_e])

        # ── Pad — chord lembut di latar ───────────────────
        for sec in range(0, int(durasi_detik), 4):
            bf  = bass_chords.get(sec, N["Eb2"]) * 4
            i_s = int(sec * sample_rate)
            i_e = min(int((sec+4)*sample_rate), n_total)
            if i_s >= i_e: continue
            ta_p = t_arr[i_s:i_e] - sec
            env_p = np.minimum(ta_p/0.3, 1.0) * np.minimum((4.0-ta_p)/0.3, 1.0)
            sig[i_s:i_e] += 0.06*env_p*np.sin(2*math.pi*bf*t_arr[i_s:i_e])
            sig[i_s:i_e] += 0.04*env_p*np.sin(2*math.pi*bf*1.25*t_arr[i_s:i_e])

        # ── Fade in / Fade out ────────────────────────────
        fade_in  = np.minimum(t_arr/1.5, 1.0)
        fade_out = np.maximum(0.0, np.minimum((durasi_detik-t_arr)/2.0, 1.0))
        sig *= fade_in * fade_out

        samples = np.clip(sig*amp_master*32767, -32767, 32767).astype(np.int16)
        stereo  = np.column_stack([samples, samples])
        return pygame.sndarray.make_sound(stereo)

    except Exception as e:
        print(f"La Vie en Rose gagal: {e}")
        # Fallback ke musik latar biasa
        return buat_musik_latar(durasi_detik=64, volume=volume)

def buat_musik_latar(durasi_detik=64, volume=0.18):
    """
    Konsep: Komposisi Musik Prosedural Multi-Lapisan
    Musik latar santai & melodik dengan 4 seksi berbeda yang mengalir
    tanpa terasa berulang-ulang. Setiap seksi punya karakter sendiri:
      Seksi A (0-16s)  : Melodi utama C mayor, ringan & ceria
      Seksi B (16-32s) : Variasi ke G mayor, nada lebih tinggi
      Seksi C (32-48s) : Turun ke Am, lebih tenang & emosional
      Seksi D (48-64s) : Kembali C mayor dengan kontra-melodi

    Lapisan audio:
      1. Melodi utama (sine lembut, oktaf menengah)
      2. Kontra-melodi / harmoni (sine tipis, sedikit di bawah)
      3. Bass petikan (sine decay, satu oktaf bawah)
      4. Pad / sustain (sine sangat lembut, chord background)
      5. Arpegio (sine pendek-pendek, mengisi celah)
    """
    sample_rate = 22050
    n_total     = int(sample_rate * durasi_detik)
    amp_master  = volume

    # ── Frekuensi dasar (Hz) ──────────────────────────────
    NOTE = {
        "C2":65.4,  "D2":73.4,  "E2":82.4,  "F2":87.3,
        "G2":98.0,  "A2":110.0, "B2":123.5,
        "C3":130.8, "D3":146.8, "E3":164.8, "F3":174.6,
        "G3":196.0, "A3":220.0, "B3":246.9,
        "C4":261.6, "D4":293.7, "E4":329.6, "F4":349.2,
        "G4":392.0, "A4":440.0, "B4":493.9,
        "C5":523.3, "D5":587.3, "E5":659.3, "F5":698.5,
        "G5":784.0, "A5":880.0,
    }

    # ── Seksi A: C Mayor — ceria, ringan ─────────────────
    seksiA_melodi = [
        (NOTE["E4"], 0.4), (NOTE["G4"], 0.4), (NOTE["C5"], 0.6),
        (NOTE["B4"], 0.3), (NOTE["A4"], 0.3), (NOTE["G4"], 0.6),
        (NOTE["E4"], 0.4), (NOTE["F4"], 0.4), (NOTE["G4"], 0.4),
        (NOTE["A4"], 0.4), (NOTE["G4"], 0.3), (NOTE["E4"], 0.3),
        (NOTE["D4"], 0.4), (NOTE["E4"], 0.4), (NOTE["F4"], 0.4),
        (NOTE["G4"], 0.5), (NOTE["E4"], 0.3), (NOTE["C4"], 0.6),
        (NOTE["D4"], 0.4), (NOTE["E4"], 0.4), (NOTE["G4"], 0.4),
        (NOTE["A4"], 0.6), (NOTE["G4"], 0.4), (NOTE["F4"], 0.4),
        (NOTE["E4"], 0.5), (NOTE["D4"], 0.3), (NOTE["C4"], 0.8),
    ]
    # ── Seksi B: G Mayor — lebih semangat, lebih tinggi ──
    seksiB_melodi = [
        (NOTE["G4"], 0.4), (NOTE["A4"], 0.4), (NOTE["B4"], 0.4),
        (NOTE["D5"], 0.6), (NOTE["C5"], 0.3), (NOTE["B4"], 0.3),
        (NOTE["A4"], 0.4), (NOTE["B4"], 0.4), (NOTE["D5"], 0.6),
        (NOTE["E5"], 0.4), (NOTE["D5"], 0.4), (NOTE["B4"], 0.4),
        (NOTE["G4"], 0.4), (NOTE["A4"], 0.3), (NOTE["B4"], 0.3),
        (NOTE["G4"], 0.6), (NOTE["D4"], 0.4), (NOTE["G4"], 0.4),
        (NOTE["A4"], 0.5), (NOTE["G4"], 0.3), (NOTE["E4"], 0.4),
        (NOTE["D4"], 0.4), (NOTE["B3"], 0.4), (NOTE["G3"], 0.6),
        (NOTE["A3"], 0.4), (NOTE["B3"], 0.4), (NOTE["D4"], 0.8),
    ]
    # ── Seksi C: A Minor — tenang, sedikit melankolis ────
    seksiC_melodi = [
        (NOTE["A4"], 0.5), (NOTE["G4"], 0.3), (NOTE["E4"], 0.4),
        (NOTE["C4"], 0.6), (NOTE["D4"], 0.4), (NOTE["E4"], 0.4),
        (NOTE["A4"], 0.6), (NOTE["G4"], 0.4), (NOTE["F4"], 0.4),
        (NOTE["E4"], 0.5), (NOTE["D4"], 0.3), (NOTE["C4"], 0.4),
        (NOTE["E4"], 0.4), (NOTE["A4"], 0.4), (NOTE["G4"], 0.6),
        (NOTE["F4"], 0.4), (NOTE["E4"], 0.4), (NOTE["D4"], 0.4),
        (NOTE["C4"], 0.5), (NOTE["E4"], 0.3), (NOTE["G4"], 0.4),
        (NOTE["A4"], 0.6), (NOTE["G4"], 0.3), (NOTE["E4"], 0.3),
        (NOTE["C4"], 0.4), (NOTE["D4"], 0.4), (NOTE["A3"], 0.8),
    ]
    # ── Seksi D: Kembali C Mayor — kontra-melodi muncul ─
    seksiD_melodi = [
        (NOTE["C5"], 0.5), (NOTE["B4"], 0.3), (NOTE["G4"], 0.4),
        (NOTE["E4"], 0.4), (NOTE["F4"], 0.4), (NOTE["G4"], 0.4),
        (NOTE["A4"], 0.4), (NOTE["C5"], 0.6), (NOTE["B4"], 0.4),
        (NOTE["A4"], 0.4), (NOTE["G4"], 0.5), (NOTE["E4"], 0.3),
        (NOTE["F4"], 0.4), (NOTE["G4"], 0.4), (NOTE["A4"], 0.4),
        (NOTE["B4"], 0.4), (NOTE["C5"], 0.4), (NOTE["G4"], 0.4),
        (NOTE["E4"], 0.5), (NOTE["F4"], 0.3), (NOTE["G4"], 0.4),
        (NOTE["A4"], 0.4), (NOTE["F4"], 0.4), (NOTE["D4"], 0.4),
        (NOTE["E4"], 0.5), (NOTE["G4"], 0.3), (NOTE["C4"], 0.8),
    ]

    def build_timeline(seksi_list, t_offset):
        tl, t = [], t_offset
        for frek, dur in seksi_list:
            tl.append((frek, t, t + dur))
            t += dur
        return tl

    mel_tl  = (build_timeline(seksiA_melodi, 0.0)  +
               build_timeline(seksiB_melodi, 16.0) +
               build_timeline(seksiC_melodi, 32.0) +
               build_timeline(seksiD_melodi, 48.0))
    harm_tl = [(f * 0.749, ts, te) for f, ts, te in mel_tl]

    chord_roots = {
        0:  NOTE["C2"], 2:  NOTE["C2"], 4:  NOTE["F2"], 6:  NOTE["F2"],
        8:  NOTE["G2"], 10: NOTE["G2"], 12: NOTE["C2"], 14: NOTE["C2"],
        16: NOTE["G2"], 18: NOTE["G2"], 20: NOTE["D2"], 22: NOTE["D2"],
        24: NOTE["E2"], 26: NOTE["E2"], 28: NOTE["C2"], 30: NOTE["C2"],
        32: NOTE["A2"], 34: NOTE["A2"], 36: NOTE["F2"], 38: NOTE["F2"],
        40: NOTE["C2"], 42: NOTE["C2"], 44: NOTE["G2"], 46: NOTE["G2"],
        48: NOTE["C2"], 50: NOTE["C2"], 52: NOTE["F2"], 54: NOTE["F2"],
        56: NOTE["A2"], 58: NOTE["A2"], 60: NOTE["G2"], 62: NOTE["G2"],
    }
    arp_patterns = {
        "C": [NOTE["C4"], NOTE["E4"], NOTE["G4"]],
        "F": [NOTE["F3"], NOTE["A3"], NOTE["C4"]],
        "G": [NOTE["G3"], NOTE["B3"], NOTE["D4"]],
        "D": [NOTE["D3"], NOTE["F3"], NOTE["A3"]],
        "E": [NOTE["E3"], NOTE["G3"], NOTE["B3"]],
        "A": [NOTE["A3"], NOTE["C4"], NOTE["E4"]],
    }
    arp_seq = (
        ["C","C","F","F","G","G","C","C"] * 2 +
        ["G","G","D","D","E","E","C","C"] * 2 +
        ["A","A","F","F","C","C","G","G"] * 2 +
        ["C","C","F","F","A","A","G","G"] * 2
    )
    arp_dur = 2.0

    # ── Coba numpy untuk generate cepat ──────────────────
    try:
        import numpy as np
        t_arr = np.linspace(0, durasi_detik, n_total, endpoint=False)

        # Melodi & harmoni: buat signal per nada lalu stamp ke array
        mel_sig  = np.zeros(n_total)
        harm_sig = np.zeros(n_total)

        for frek, ts, te in mel_tl:
            i_s = int(ts * sample_rate)
            i_e = min(int(te * sample_rate), n_total)
            if i_s >= i_e: continue
            dur = te - ts
            td  = t_arr[i_s:i_e] - ts
            att = np.minimum(td / 0.03, 1.0)
            rel = np.maximum(0.0, 1.0 - np.maximum(0.0, td - dur * 0.78) / max(dur * 0.22, 1e-9))
            vib = 1.0 + 0.003 * np.sin(2 * math.pi * 5.5 * td)
            mel_sig[i_s:i_e] = 0.50 * att * rel * np.sin(2 * math.pi * frek * vib * t_arr[i_s:i_e])

        for frek, ts, te in harm_tl:
            i_s = int(ts * sample_rate)
            i_e = min(int(te * sample_rate), n_total)
            if i_s >= i_e: continue
            dur = te - ts
            td  = t_arr[i_s:i_e] - ts
            att = np.minimum(td / 0.05, 1.0)
            rel = np.maximum(0.0, 1.0 - np.maximum(0.0, td - dur * 0.75) / max(dur * 0.25, 1e-9))
            harm_sig[i_s:i_e] = 0.22 * att * rel * np.sin(2 * math.pi * frek * t_arr[i_s:i_e])

        # Bass per segmen 2 detik
        bass_sig = np.zeros(n_total)
        for sec in range(0, int(durasi_detik), 2):
            bf  = chord_roots.get(sec, NOTE["C2"])
            i_s = int(sec * sample_rate)
            i_e = min(int((sec + 2) * sample_rate), n_total)
            tb  = t_arr[i_s:i_e] - sec
            env_b = np.exp(-tb * 3.5)
            bass_sig[i_s:i_e] = (0.28 * env_b * np.sin(2 * math.pi * bf * t_arr[i_s:i_e]) +
                                  0.10 * env_b * np.sin(2 * math.pi * bf * 1.5 * t_arr[i_s:i_e]))

        # Pad
        pad_seg = int(2 * sample_rate)
        pad_sig = np.zeros(n_total)
        for sec in range(0, int(durasi_detik), 2):
            bf  = chord_roots.get(sec, NOTE["C2"]) * 4
            i_s = int(sec * sample_rate)
            i_e = min(i_s + pad_seg, n_total)
            pad_sig[i_s:i_e] = 0.09 * np.sin(2 * math.pi * bf * t_arr[i_s:i_e])

        # Arpegio
        arp_sig  = np.zeros(n_total)
        note_dur = arp_dur / 3
        for step_idx in range(int(durasi_detik / note_dur)):
            arp_chord_i = int(step_idx * note_dur / arp_dur) % len(arp_seq)
            note_in_pat = step_idx % 3
            af   = arp_patterns[arp_seq[arp_chord_i]][note_in_pat]
            i_s  = int(step_idx * note_dur * sample_rate)
            i_e  = min(int((step_idx + 1) * note_dur * sample_rate), n_total)
            if i_s >= i_e: continue
            ta   = t_arr[i_s:i_e] - step_idx * note_dur
            env_a = np.exp(-ta * 6.0) * 0.5
            arp_sig[i_s:i_e] = 0.13 * env_a * np.sin(2 * math.pi * af * t_arr[i_s:i_e])

        val = mel_sig + harm_sig + bass_sig + pad_sig + arp_sig

        # Fade
        fade_in  = np.minimum(t_arr / 0.5, 1.0)
        fade_out = np.maximum(0.0, np.minimum((durasi_detik - t_arr) / 1.0, 1.0))
        val *= fade_in * fade_out

        samples = np.clip(val * amp_master * 32767, -32767, 32767).astype(np.int16)
        # Stereo
        stereo  = np.column_stack([samples, samples])
        return pygame.sndarray.make_sound(stereo)

    except ImportError:
        pass   # Fallback ke Python murni di bawah

    # ── Fallback: Python murni (lebih lambat ~20-30 detik) ──
    data   = bytearray(n_total * 2)
    TWO_PI = 2 * math.pi
    inv_sr = 1.0 / sample_rate

    # Precompute mel & harm freq+env arrays
    mel_freq_arr  = [0.0] * n_total
    mel_env_arr   = [0.0] * n_total
    harm_freq_arr = [0.0] * n_total
    harm_env_arr  = [0.0] * n_total

    for frek, ts, te in mel_tl:
        i_s = int(ts * sample_rate)
        i_e = min(int(te * sample_rate), n_total)
        dur = max(te - ts, 1e-9)
        for i in range(i_s, i_e):
            td  = (i - i_s) * inv_sr
            att = min(td / 0.03, 1.0)
            rel = max(0.0, 1.0 - max(0.0, td - dur * 0.78) / (dur * 0.22))
            vib = 1.0 + 0.003 * math.sin(TWO_PI * 5.5 * td) if td > 0.08 else 1.0
            mel_freq_arr[i] = frek * vib
            mel_env_arr[i]  = att * rel

    for frek, ts, te in harm_tl:
        i_s = int(ts * sample_rate)
        i_e = min(int(te * sample_rate), n_total)
        dur = max(te - ts, 1e-9)
        for i in range(i_s, i_e):
            td  = (i - i_s) * inv_sr
            att = min(td / 0.05, 1.0)
            rel = max(0.0, 1.0 - max(0.0, td - dur * 0.75) / (dur * 0.25))
            harm_freq_arr[i] = frek
            harm_env_arr[i]  = att * rel

    mel_phase  = 0.0
    harm_phase = 0.0

    for i in range(n_total):
        t = i * inv_sr

        mf = mel_freq_arr[i]
        mel_phase  = (mel_phase  + TWO_PI * mf * inv_sr) % TWO_PI
        mel_val    = 0.50 * mel_env_arr[i] * math.sin(mel_phase) if mf > 0 else 0.0

        hf = harm_freq_arr[i]
        harm_phase = (harm_phase + TWO_PI * hf * inv_sr) % TWO_PI
        harm_val   = 0.22 * harm_env_arr[i] * math.sin(harm_phase) if hf > 0 else 0.0

        bass_key  = int(t / 2) * 2
        bass_frek = chord_roots.get(bass_key, NOTE["C2"])
        t_bass    = t % 2.0
        env_bass  = math.exp(-t_bass * 3.5)
        bass_val  = (0.28 * env_bass * math.sin(TWO_PI * bass_frek * t) +
                     0.10 * env_bass * math.sin(TWO_PI * bass_frek * 1.5 * t))

        pad_val   = 0.09 * math.sin(TWO_PI * bass_frek * 4 * t)

        arp_idx   = int(t / arp_dur) % len(arp_seq)
        arp_pat   = arp_patterns[arp_seq[arp_idx]]
        t_arp     = t % arp_dur
        arp_step  = int(t_arp / (arp_dur / 3)) % 3
        t_note_a  = t_arp % (arp_dur / 3)
        arp_val   = 0.13 * math.exp(-t_note_a * 6.0) * 0.5 * math.sin(TWO_PI * arp_pat[arp_step] * t)

        val = mel_val + harm_val + bass_val + pad_val + arp_val

        fade_in  = min(t / 0.5, 1.0)
        fade_out = max(0.0, min((durasi_detik - t) / 1.0, 1.0))
        val     *= fade_in * fade_out

        s = max(-32767, min(32767, int(amp_master * 32767 * val)))
        data[i * 2]     =  s & 0xFF
        data[i * 2 + 1] = (s >> 8) & 0xFF

    return pygame.mixer.Sound(buffer=bytes(data))

