# ─── HELPER ───────────────────────────────────────────────
def rp(n):
    return f"Rp {int(n):,}".replace(",", ".")

def cr(n):
    """Format Galaxy Credits untuk Level 2"""
    return f"{int(n):,} Cr".replace(",", ".")

def kr(n):
    """Format Koral untuk Level 3"""
    return f"{int(n):,} Ko".replace(",", ".")

def get_font(size, bold=True):
    """Font helper: pygame built-in font (selalu ada) sebagai prioritas."""
    # pygame.font.Font(None, size) = built-in font, SELALU tersedia
    # Ukuran built-in lebih kecil dari SysFont, jadi scale up sedikit
    try:
        return pygame.font.Font(None, int(size * 1.35))
    except Exception:
        try:
            return pygame.font.SysFont("Arial", size, bold=bold)
        except Exception:
            return pygame.font.SysFont(None, size, bold=bold)

def posisi_3d(idx):
    """Konsep: Array 2D + Koordinat. Ubah index 0-39 ke (x,y,z)."""
    sisi   = idx // 10
    offset = idx % 10
    if   sisi == 0: return ( BOFF - offset*TILE, 0.0,  BOFF)
    elif sisi == 1: return (-BOFF,               0.0,  BOFF - offset*TILE)
    elif sisi == 2: return (-BOFF + offset*TILE, 0.0, -BOFF)
    else:           return ( BOFF,               0.0, -BOFF + offset*TILE)

def hitung_sewa(sewa_dasar, rumah):
    """
    Konsep: REKURSI
    Base case: 0 rumah = sewa_dasar
    Recursive: tiap rumah x2.5 dari sebelumnya
    """
    if rumah == 0:
        return sewa_dasar
    return int(hitung_sewa(sewa_dasar, rumah - 1) * 2.5)


