class Pemain:
    def __init__(self, pid, nama, is_ai=False):
        self.id          = pid
        self.nama        = nama
        self.posisi      = 0
        self.uang        = 1_500_000
        self.properti    = []
        self.di_penjara  = False
        self.gilpenjara  = 0
        self.kartu_bebas = 0
        self.aktif       = True
        self.is_ai       = is_ai
        self.warna_gl    = PLAYER_COLORS_GL[pid]
        self.warna_py    = PLAYER_COLORS_PY[pid]
        # ── Skill Battle (Level 2) ────────────────────────
        self.skill_fire   = 0   # Jumlah Fire Attack dimiliki
        self.skill_freeze = 0   # Jumlah Freeze Attack dimiliki
        self.skill_arus   = 0   # Jumlah Arus Deras dimiliki (L3)
        self.skill_badai  = 0   # Jumlah Badai Laut dimiliki (L3)
        self.frozen_turn  = 0   # Sisa turn tidak bisa bergerak
        self.arus_turn    = 0   # Sisa turn terkena Arus Deras
        self.freeze_t     = 0.0
        self.on_fire      = 0.0


# ─── LAYAR PEMBUKA (SPLASH SCREEN) ───────────────────────
class SplashScreen:
    """
    Konsep: State Machine + Animasi Timer
    Layar pembuka dengan animasi sebelum game dimulai.
    Fase: intro → judul → pilih_nama → mulai
    """
    def __init__(self, screen, clock):
        self.screen  = screen
        self.clock   = clock
        self.fase    = "intro"
        self.timer   = 0.0
        self.selesai = False

        self.fase_layar      = "pilih_mode"
        self.jumlah_manusia  = 2
        self.hover_mode_btn  = -1
        self._mode_rects     = []
        self._mode_selesai   = False
        self.level           = 1
        self._level_rects    = []

        # Nama pemain (bisa diedit)
        self.nama_pemain = list(PLAYER_NAMES)
        self.edit_idx    = -1
        self.edit_buf    = ""

        # ── Musik Menu — Dandelions ────────────────────────
        try:
            import os
            script_dir = os.path.dirname(os.path.abspath(__file__))
            mp3_names  = ["dandelions.mp3","dandelion.mp3"]
            mp3_path   = next((os.path.join(script_dir,n)
                               for n in mp3_names
                               if os.path.exists(os.path.join(script_dir,n))), None)
            if mp3_path:
                pygame.mixer.music.load(mp3_path)
                pygame.mixer.music.set_volume(0.45)
                pygame.mixer.music.play(loops=-1)
                print("Dandelions - Ruth B siap! (menu)")
        except Exception as e:
            print(f"Musik menu gagal: {e}")

        # Partikel dekoratif (efek visual)
        # Konsep: Array of Dictionary untuk data partikel
        self.partikel = []
        for _ in range(60):
            self.partikel.append({
                "x"    : random.uniform(0, WIN_W),
                "y"    : random.uniform(0, WIN_H),
                "vy"   : random.uniform(-30, -80),   # Naik ke atas
                "vx"   : random.uniform(-15, 15),
                "r"    : random.uniform(2, 6),
                "warna": random.choice([
                    (255,215,0), (255,100,100), (100,180,255),
                    (100,255,150), (255,180,50), (200,150,255)
                ]),
                "alpha": random.randint(100, 255),
                "hidup": random.uniform(0, 10),      # Fase hidup partikel
            })

        # Font
        try:
            self.fJudul  = get_font(64, bold=True)
            self.fSub    = pygame.font.SysFont("Arial", 28, bold=True)
            self.fNormal = pygame.font.SysFont("Arial", 20)
            self.fKecil  = pygame.font.SysFont("Arial", 15)
        except Exception:
            self.fJudul  = pygame.font.SysFont(None, 64)
            self.fSub    = pygame.font.SysFont(None, 28)
            self.fNormal = pygame.font.SysFont(None, 20)
            self.fKecil  = pygame.font.SysFont(None, 15)

        # Animasi judul
        self.judul_y     = WIN_H + 100   # Mulai dari bawah layar
        self.judul_y_tgt = 55            # Judul di bagian atas, tidak tumpang tindih panel
        self.sub_alpha   = 0
        self.panel_alpha = 0

    def _update_partikel(self, dt):
        """
        Konsep: PERULANGAN + Simulasi Fisika Sederhana
        Update posisi partikel dekoratif setiap frame.
        """
        for p in self.partikel:
            p["x"]    += p["vx"] * dt
            p["y"]    += p["vy"] * dt
            p["hidup"] += dt
            p["alpha"] = int(180 * abs(math.sin(p["hidup"] * 0.8)))

            # Wrap: jika keluar layar, muncul lagi dari bawah
            if p["y"] < -10:
                p["y"] = WIN_H + 10
                p["x"] = random.uniform(0, WIN_W)
            if p["x"] < -10: p["x"] = WIN_W + 10
            if p["x"] > WIN_W+10: p["x"] = -10

    def _render(self, dt):
        """Render splash screen sesuai fase saat ini"""
        surf = pygame.Surface((WIN_W, WIN_H))
        surf.fill((5, 8, 20))

        # ── Latar gradien (simulasi dengan rect berlapis) ──
        for i in range(20):
            alpha_layer = int(40 * (1 - i/20))
            r = int(20 + i * 8)
            s = pygame.Surface((WIN_W, WIN_H), pygame.SRCALPHA)
            s.fill((0, 20+i*3, 60+i*5, alpha_layer))
            surf.blit(s, (0, 0))

        # ── Partikel ───────────────────────────────────────
        for p in self.partikel:
            ps = pygame.Surface((int(p["r"]*2), int(p["r"]*2)), pygame.SRCALPHA)
            pygame.draw.circle(ps, (*p["warna"], p["alpha"]),
                               (int(p["r"]), int(p["r"])), int(p["r"]))
            surf.blit(ps, (int(p["x"]-p["r"]), int(p["y"]-p["r"])))

        # ── Judul animasi masuk ────────────────────────────
        # Easing: judul meluncur dari bawah
        self.judul_y += (self.judul_y_tgt - self.judul_y) * min(1.0, dt * 6)

        # Shadow judul
        tj_shadow = self.fJudul.render("MONOPOLY 3D", True, (0, 0, 0))
        surf.blit(tj_shadow, (WIN_W//2 - tj_shadow.get_width()//2 + 4,
                               int(self.judul_y) + 4))
        # Judul utama (kuning emas)
        tj = self.fJudul.render("MONOPOLY 3D", True, (255, 215, 0))
        surf.blit(tj, (WIN_W//2 - tj.get_width()//2, int(self.judul_y)))

        # Garis bawah judul
        garis_y = int(self.judul_y) + tj.get_height() + 8
        pygame.draw.line(surf, (255, 215, 0),
                         (WIN_W//2 - 200, garis_y),
                         (WIN_W//2 + 200, garis_y), 2)

        # Subtitle — hanya tampil di fase pilih_nama (panel mode sudah punya judulnya sendiri)
        if self.timer > 0.8 and self.fase_layar == "pilih_nama":
            self.sub_alpha = min(255, self.sub_alpha + dt * 300)
            nm = self.jumlah_manusia
            na = 4 - nm
            sub_teks = f"{nm} Pemain Manusia  +  {na} AI" if na > 0 else "4 Pemain Hotseat (Tanpa AI)"
            ts = self.fSub.render(sub_teks, True, (180, 200, 255))
            ts.set_alpha(int(self.sub_alpha))
            surf.blit(ts, (WIN_W//2 - ts.get_width()//2, int(self.judul_y) + tj.get_height() + 10))

        # ── Panel mode / nama pemain ──────────────────────
        if self.timer > 1.4:
            self.panel_alpha = min(240, self.panel_alpha + dt * 280)
            if self.fase_layar == "pilih_mode":
                self._render_panel_mode(surf)
            else:
                self._render_panel_nama(surf)

        self.screen.blit(surf, (0, 0))
        pygame.display.flip()

    def _render_panel_nama(self, surf):
        """Render panel input nama pemain (manusia bisa edit, AI otomatis)"""
        PW, PH = 620, 380
        px = WIN_W//2 - PW//2
        py = WIN_H//2 - PH//2 + 30

        # Panel background
        panel = pygame.Surface((PW, PH), pygame.SRCALPHA)
        panel.fill((8, 14, 35, int(self.panel_alpha)))
        pygame.draw.rect(panel, (255, 215, 0, min(200, int(self.panel_alpha))),
                         (0, 0, PW, PH), 2, border_radius=14)

        # Judul panel
        nm = self.jumlah_manusia
        th = self.fNormal.render(f"Masukkan Nama Pemain  ({nm} Manusia + {4-nm} AI)", True, (200, 210, 255))
        panel.blit(th, (PW//2 - th.get_width()//2, 16))
        pygame.draw.line(panel, (60, 80, 140), (20, 44), (PW-20, 44), 1)

        # Input nama tiap pemain
        for i in range(4):
            iy    = 60 + i * 66
            wr    = PLAYER_COLORS_PY[i]
            aktif = (self.edit_idx == i)
            is_ai = (i >= self.jumlah_manusia)

            # Dot warna pemain
            pygame.draw.circle(panel, wr if not is_ai else (80,80,100), (30, iy + 19), 13)
            if is_ai:
                ta = self.fKecil.render("AI", True, (200,200,220))
                panel.blit(ta, (30 - ta.get_width()//2, iy + 19 - ta.get_height()//2))

            if is_ai:
                # Slot AI — tidak bisa diedit, tampil nama default + label "Dikendalikan AI"
                box_col = (10, 18, 40, 140)
                box_bor = (50, 60, 100, 120)
                pygame.draw.rect(panel, box_col, (56, iy, PW-76, 38), border_radius=6)
                pygame.draw.rect(panel, box_bor, (56, iy, PW-76, 38), 1, border_radius=6)
                tn = self.fNormal.render(self.nama_pemain[i], True, (100, 110, 140))
                panel.blit(tn, (68, iy + 9))
                tk = self.fKecil.render("🤖 Dikendalikan AI", True, (80, 100, 150))
                panel.blit(tk, (PW-tk.get_width()-10, iy+11))
            else:
                # Slot Manusia — bisa diedit
                box_col = (30, 50, 100, 200) if aktif else (15, 25, 55, 180)
                box_bor = (*wr, 220) if aktif else (60, 80, 140, 160)
                pygame.draw.rect(panel, box_col, (56, iy, PW-76, 38), border_radius=6)
                pygame.draw.rect(panel, box_bor, (56, iy, PW-76, 38), 2, border_radius=6)

                nama_tampil = self.edit_buf if aktif else self.nama_pemain[i]
                if aktif and int(pygame.time.get_ticks() / 500) % 2 == 0:
                    nama_tampil += "|"
                tn = self.fNormal.render(nama_tampil, True, (255,255,255) if aktif else (180,180,220))
                panel.blit(tn, (68, iy + 9))

                if not aktif:
                    tk = self.fKecil.render("klik untuk edit", True, (80, 100, 160))
                    panel.blit(tk, (PW-tk.get_width()-10, iy+11))

        # Tombol MULAI
        mw, mh = 220, 44
        mx2 = PW//2 - mw//2
        my2 = PH - 58
        mulai_col = (30, 160, 80)
        pygame.draw.rect(panel, mulai_col, (mx2, my2, mw, mh), border_radius=10)
        pygame.draw.rect(panel, (255,255,255,100), (mx2, my2, mw, mh), 2, border_radius=10)
        tm = self.fNormal.render("MULAI  [ENTER]", True, (255, 255, 255))
        panel.blit(tm, (mx2 + mw//2 - tm.get_width()//2, my2 + mh//2 - tm.get_height()//2))

        # Petunjuk
        tp = self.fKecil.render("Klik nama untuk edit  |  ESC untuk batal edit", True, (80,100,160))
        panel.blit(tp, (PW//2 - tp.get_width()//2, PH - 20))

        surf.blit(panel, (px, py))

        # Simpan koordinat tombol MULAI untuk deteksi klik
        self._mulai_rect = pygame.Rect(px+PW//2-110, py+PH-58, 220, 44)
        # Simpan rect tiap nama
        self._nama_rects = [
            pygame.Rect(px+56, py+60+i*66, PW-76, 38) for i in range(4)
        ]

    def _render_panel_mode(self, surf):
        """
        Konsep: State Machine + UI Interaktif
        Render panel pemilihan mode: berapa pemain manusia vs AI.
        Ditampilkan sebelum panel input nama.
        """
        # Panel lebih compact, naik ke tengah agar tidak terpotong
        PW, PH = 700, 390
        px = WIN_W//2 - PW//2
        # Posisi panel: turunkan judul dulu, lalu panel mulai di bawahnya
        judul_bottom = int(self.judul_y) + self.fJudul.get_height() + 14
        py = max(judul_bottom + 8, WIN_H//2 - PH//2)
        # Pastikan panel tidak keluar bawah layar
        if py + PH > WIN_H - 10:
            py = WIN_H - PH - 10

        # Panel background
        panel = pygame.Surface((PW, PH), pygame.SRCALPHA)
        panel.fill((8, 14, 35, int(self.panel_alpha)))
        pygame.draw.rect(panel, (255, 215, 0, min(200, int(self.panel_alpha))),
                         (0, 0, PW, PH), 2, border_radius=14)

        # ── Header panel ──────────────────────────────────
        th = self.fNormal.render("Pilih Mode Permainan", True, (255, 215, 0))
        panel.blit(th, (PW//2 - th.get_width()//2, 14))
        ts2 = self.fKecil.render("Atur berapa pemain manusia — sisanya dikendalikan AI", True, (140, 160, 210))
        panel.blit(ts2, (PW//2 - ts2.get_width()//2, 38))
        pygame.draw.line(panel, (60, 80, 140), (20, 58), (PW-20, 58), 1)

        # ── Tombol pilihan 1–4 pemain ──────────────────────
        BW, BH = 148, 108
        gap    = 12
        total_w = 4 * BW + 3 * gap
        bx_start = PW//2 - total_w//2
        by = 68

        self._mode_rects = []
        mx_local, my_local = pygame.mouse.get_pos()
        mx_local -= px
        my_local -= py

        for i in range(4):
            bx = bx_start + i * (BW + gap)
            rect_local = pygame.Rect(bx, by, BW, BH)
            self._mode_rects.append(pygame.Rect(px + bx, py + by, BW, BH))

            dipilih = (self.jumlah_manusia == i + 1)
            hover   = rect_local.collidepoint(mx_local, my_local)

            if dipilih:
                bg_col  = (20, 120, 200, 220)
                bor_col = (255, 215, 0, 255)
                bor_w   = 3
            elif hover:
                bg_col  = (30, 60, 130, 190)
                bor_col = (150, 175, 255, 220)
                bor_w   = 2
            else:
                bg_col  = (15, 28, 60, 160)
                bor_col = (60, 80, 140, 130)
                bor_w   = 1

            pygame.draw.rect(panel, bg_col,  (bx, by, BW, BH), border_radius=10)
            pygame.draw.rect(panel, bor_col, (bx, by, BW, BH), bor_w, border_radius=10)

            # Baris atas: dot pemain manusia
            dot_colors = PLAYER_COLORS_PY
            dot_r = 9
            row1_y = by + 16
            n_human = i + 1
            spacing = dot_r * 2 + 5
            start_x = bx + BW//2 - ((n_human - 1) * spacing)//2
            for j in range(n_human):
                cx_dot = start_x + j * spacing
                pygame.draw.circle(panel, dot_colors[j], (cx_dot, row1_y + dot_r), dot_r)
                pygame.draw.circle(panel, (255, 255, 255), (cx_dot, row1_y + dot_r), dot_r, 1)

            # Baris bawah: dot AI
            ai_count = 3 - i
            row2_y = row1_y + dot_r * 2 + 8
            if ai_count > 0:
                start_x2 = bx + BW//2 - ((ai_count - 1) * spacing)//2
                for j in range(ai_count):
                    cx_dot = start_x2 + j * spacing
                    pygame.draw.circle(panel, (90, 90, 115), (cx_dot, row2_y + dot_r), dot_r)
                    pygame.draw.circle(panel, (160, 160, 185), (cx_dot, row2_y + dot_r), dot_r, 1)
                    ta = self.fKecil.render("A", True, (200, 200, 225))
                    panel.blit(ta, (cx_dot - ta.get_width()//2, row2_y + dot_r - ta.get_height()//2))

            # Label teks
            n_ai = 3 - i
            warna_label = (255, 215, 0) if dipilih else (200, 225, 255)
            warna_sub   = (220, 240, 255) if dipilih else (160, 175, 210)
            lbl1 = f"{n_human} Manusia"
            lbl2 = f"{n_ai} AI" if n_ai > 0 else "Tanpa AI"
            tl1 = self.fNormal.render(lbl1, True, warna_label)
            tl2 = self.fKecil.render(lbl2,  True, warna_sub)
            panel.blit(tl1, (bx + BW//2 - tl1.get_width()//2, by + BH - 38))
            panel.blit(tl2, (bx + BW//2 - tl2.get_width()//2, by + BH - 18))

        # ── Info slot ─────────────────────────────────────
        info_y = by + BH + 16
        nm = self.jumlah_manusia
        ti_lbl = self.fKecil.render("Slot pemain:", True, (140, 155, 200))
        total_slot_w = 4 * 56 + 3 * 6
        slot_start_x = PW//2 - total_slot_w//2
        panel.blit(ti_lbl, (slot_start_x - ti_lbl.get_width() - 8,
                             info_y + 13 - ti_lbl.get_height()//2))
        for j in range(4):
            col = PLAYER_COLORS_PY[j] if j < nm else (85, 85, 105)
            lbl = f"P{j+1}" if j < nm else f"AI{j-nm+1}"
            sx = slot_start_x + j * 62
            pygame.draw.rect(panel, col, (sx, info_y, 56, 26), border_radius=5)
            tsl = self.fKecil.render(lbl, True, (255, 255, 255))
            panel.blit(tsl, (sx + 28 - tsl.get_width()//2, info_y + 13 - tsl.get_height()//2))

        # ── Pilih Level ───────────────────────────────────
        lev_y = by + BH + 54
        tl_lev = self.fNormal.render("Pilih Level:", True, (200, 220, 255))
        panel.blit(tl_lev, (PW//2 - tl_lev.get_width()//2, lev_y))
        lev_btns = [
            (1, "Level 1 — Monopoli Klasik",   (30, 130, 70)),
            (2, "Level 2 — Monopoli Galaksi", (50,  50, 180)),
            (3, "Level 3 — Monopoli Bahari",   (140, 30, 140)),
        ]
        self._level_rects = []
        for li, (lv, lbl, lc) in enumerate(lev_btns):
            lbx = PW//2 - 320 + li * 220
            lby = lev_y + 28
            lbw, lbh = 200, 36
            dipilih_lv = (self.level == lv)
            bc2 = lc if dipilih_lv else (20, 20, 50)
            brd = (*lc, 255) if dipilih_lv else (60, 60, 100, 180)
            pygame.draw.rect(panel, bc2, (lbx, lby, lbw, lbh), border_radius=8)
            pygame.draw.rect(panel, brd, (lbx, lby, lbw, lbh), 2, border_radius=8)
            if dipilih_lv:
                pygame.draw.rect(panel, (255,255,255,40), (lbx, lby, lbw, 18), border_radius=8)
            tl2 = self.fKecil.render(lbl, True, (255,255,255) if dipilih_lv else (140,140,180))
            panel.blit(tl2, (lbx + lbw//2 - tl2.get_width()//2, lby + lbh//2 - tl2.get_height()//2))
            self._level_rects.append(pygame.Rect(px + lbx, py + lby, lbw, lbh))

        # ── Tombol LANJUT ──────────────────────────────────
        lw, lh = 260, 40
        lx = PW//2 - lw//2
        ly = PH - 52
        pygame.draw.rect(panel, (25, 155, 75), (lx, ly, lw, lh), border_radius=10)
        pygame.draw.rect(panel, (255, 255, 255, 80), (lx, ly, lw, lh), 2, border_radius=10)
        tl_btn = self.fNormal.render("LANJUT  [ENTER]  →  Input Nama", True, (255, 255, 255))
        # Jika teks terlalu lebar, gunakan font kecil
        if tl_btn.get_width() > lw - 16:
            tl_btn = self.fKecil.render("LANJUT  [ENTER]  →  Input Nama", True, (255, 255, 255))
        panel.blit(tl_btn, (lx + lw//2 - tl_btn.get_width()//2,
                             ly + lh//2 - tl_btn.get_height()//2))

        # Petunjuk kecil
        tp = self.fKecil.render("Klik tombol atau tekan 1 / 2 / 3 / 4  |  ENTER untuk lanjut  |  Level: 1=Klasik  2=Galaksi  3=Bahari",
                                 True, (80, 100, 155))
        panel.blit(tp, (PW//2 - tp.get_width()//2, PH - 16))

        surf.blit(panel, (px, py))
        self._lanjut_rect = pygame.Rect(px + lx, py + ly, lw, lh)

    def handle_event(self, ev):
        """Handle input keyboard dan mouse di splash screen"""
        if ev.type == QUIT:
            pygame.quit(); sys.exit()

        # ── Fase pilih mode ────────────────────────────────
        if self.fase_layar == "pilih_mode":
            if ev.type == MOUSEBUTTONDOWN and ev.button == 1:
                mx, my = ev.pos
                for i, rect in enumerate(self._mode_rects):
                    if rect.collidepoint(mx, my):
                        self.jumlah_manusia = i + 1
                        return
                # Cek klik tombol level
                for i, rect in enumerate(self._level_rects):
                    if rect.collidepoint(mx, my):
                        self.level = i + 1
                        return
                if hasattr(self, '_lanjut_rect') and self._lanjut_rect.collidepoint(mx, my):
                    self.fase_layar = "pilih_nama"
                    self.panel_alpha = 0
                    return

            if ev.type == KEYDOWN:
                if ev.key in (K_1, K_2, K_3, K_4):
                    self.jumlah_manusia = ev.key - K_0
                elif ev.key == K_RETURN and self.timer > 1.4:
                    self.fase_layar = "pilih_nama"
                    self.panel_alpha = 0
            return

        # ── Fase pilih nama (original handler) ────────────
        if ev.type == MOUSEBUTTONDOWN and ev.button == 1:
            mx, my = ev.pos
            # Cek klik tombol MULAI
            if hasattr(self, '_mulai_rect') and self._mulai_rect.collidepoint(mx, my):
                if self.edit_idx >= 0:
                    self._simpan_edit()
                self.selesai = True
                return
            # Cek klik kotak nama
            if hasattr(self, '_nama_rects'):
                for i, rect in enumerate(self._nama_rects):
                    if rect.collidepoint(mx, my):
                        # Hanya slot manusia yang bisa diedit
                        if i >= self.jumlah_manusia:
                            return   # Slot AI, abaikan
                        if self.edit_idx >= 0:
                            self._simpan_edit()
                        self.edit_idx = i
                        self.edit_buf = self.nama_pemain[i]
                        return
            # Klik di luar: batalkan edit
            if self.edit_idx >= 0:
                self._simpan_edit()

        # Input keyboard
        if ev.type == KEYDOWN:
            if ev.key == K_RETURN:
                if self.edit_idx >= 0:
                    self._simpan_edit()
                elif self.timer > 1.4:
                    self.selesai = True
            elif ev.key == K_ESCAPE:
                if self.edit_idx >= 0:
                    self.edit_idx = -1
                    self.edit_buf = ""
            elif self.edit_idx >= 0:
                if ev.key == K_BACKSPACE:
                    self.edit_buf = self.edit_buf[:-1]
                elif len(self.edit_buf) < 16:
                    if ev.unicode.isprintable():
                        self.edit_buf += ev.unicode

    def _simpan_edit(self):
        """Simpan nama hasil edit"""
        if self.edit_idx >= 0:
            nama_baru = self.edit_buf.strip()
            if nama_baru:
                self.nama_pemain[self.edit_idx] = nama_baru
            self.edit_idx = -1
            self.edit_buf = ""

    def jalankan(self):
        """
        Konsep: PERULANGAN + State Machine
        Loop splash screen sampai pemain tekan MULAI.
        """
        while not self.selesai:
            dt = self.clock.tick(FPS) / 1000.0
            self.timer += dt
            self._update_partikel(dt)

            for ev in pygame.event.get():
                self.handle_event(ev)

            self._render(dt)

        # Return nama pemain + jumlah pemain manusia
        return self.nama_pemain, self.jumlah_manusia, self.level


# ─── KELAS GAME ───────────────────────────────────────────
class MonopolyGame:
    def __init__(self, nama_pemain=None, jumlah_manusia=1, level=1):
        pygame.init()

        if OPENGL_AVAILABLE:
            self.screen = pygame.display.set_mode(
                (WIN_W, WIN_H), DOUBLEBUF | OPENGL
            )
            self._setup_opengl()
        else:
            self.screen = pygame.display.set_mode((WIN_W, WIN_H))

        na = 4 - jumlah_manusia
        caption = f"MONOPOLY 3D  |  {jumlah_manusia} Manusia + {na} AI" if na > 0 else "MONOPOLY 3D  |  4 Pemain Hotseat"
        if level == 2:
            caption += "  |  🌌 Level 2: Galaksi"
        if level == 3:
            caption += "  |  🌊 Level 3: Bahari"
        pygame.display.set_caption(caption)
        self.clock = pygame.time.Clock()

        # ── Level & Board ─────────────────────────────────
        self.level = level
        self.board_data = BOARD_DATA_L3 if level == 3 else (BOARD_DATA_L2 if level == 2 else BOARD_DATA)
        self.kartu_peluang   = KARTU_PARADOKS if level == 3 else (KARTU_NEBULA   if level == 2 else KARTU_PELUANG)
        self.kartu_komunitas = KARTU_KRONIK   if level == 3 else (KARTU_GALAKSI  if level == 2 else KARTU_KOMUNITAS)
        self.modal_awal     = 2000           if level == 3 else (1500 if level == 2 else 1500)
        self.kas_galaksi    = 0              # Parkir Orbit (Level 2) / Nexus Waktu (Level 3)
        self.kembar_berturut= 0              # Wormhole counter (Level 2)
        self.neon_t         = 0.0            # Timer animasi neon (Level 2)
        self._go_sudah_bonus = False         # Flag anti-double bonus GO

        # ── Animasi Roket Peluncuran ──────────────────────
        self.roket_t          = 0.0    # Timer animasi (loop untuk idle)
        self.roket_launch_aktif = False # Animasi peluncuran aktif
        self.roket_launch_t   = 0.0    # Timer peluncuran (0→1)
        self.roket_fase       = "idle" # idle/naik/turun/landing
        self.roket_pid        = -1     # Pemain yang naik roket
        self.roket_y          = 0.0    # Posisi Y roket saat ini

        # ── Animasi Wormhole Portal + UFO ────────────────
        self.portal_t         = 0.0    # Timer rotasi portal (loop)
        self.portal_aktif     = False  # Animasi "pemain masuk portal" aktif
        # Animasi Arus Deras (Level 3)
        self.arusderas_aktif        = False
        self.arusderas_t            = 0.0
        self.arusderas_dari         = (0,0,0)
        self.arusderas_ke           = (0,0,0)
        self.arusderas_target_id    = 0
        self.arusderas_mundur       = 0
        self.arusderas_pos_lama     = (0,0,0)
        self.arusderas_pos_baru     = (0,0,0)
        self.arusderas_pos_baru_idx = 0
        self.arusderas_sudah_pindah = True
        # Badai Laut
        self.badai_aktif  = False
        self.badai_t      = 0.0
        self.badai_hits   = []
        self.popup_badai  = None
        self.badai_hit_timer = 0.0
        self._pending_notif_arus    = {}  # {player_id: {mundur, attacker}}
        self._pending_notif_fire    = {}  # {player_id: {dmg, attacker}}
        self._pending_notif_freeze  = {}  # {player_id: {attacker}}
        # Popup kartu Arus Deras (sistem terpisah dari notif_kotak_khusus)
        self.popup_arus_deras = None
        # Animasi Hiu Atlantis (Level 3)
        self.hiu_aktif    = False
        self.hiu_t        = 0.0
        self.hiu_pid      = 0
        self.hiu_fase     = "idle"
        self.hiu_x        = 0.0
        self.hiu_y        = 0.0
        self.hiu_z        = 0.0
        self.hiu_start_x  = 0.0
        self.hiu_start_z  = 0.0
        self.hiu_target_x = 0.0
        self.hiu_target_z = 0.0
        self.hiu_mulut    = 0.0
        self.hiu_pion_visi = True
        self.portal_close_t   = 0.0   # Timer portal menutup (0→1)
        self.portal_pid       = -1    # ID pemain yang masuk portal
        self.ufo_aktif        = False  # UFO sedang terbang + sinar
        self.ufo_t            = 0.0   # Timer animasi UFO (0→1)
        self.ufo_fase         = ""    # "terbang","sinar","keluar"
        self.ufo_x            = 0.0   # Posisi UFO X
        self.ufo_z            = 0.0   # Posisi UFO Z
        self.ufo_target_x     = 0.0   # Target (kotak penjara)
        self.ufo_target_z     = 0.0

        # ── Skill Battle (Level 2) ────────────────────────
        self.fireball_aktif     = False
        self.fireball_t         = 0.0
        self.fireball_dari      = (0.0, 0.0, 0.0)
        self.fireball_ke        = (0.0, 0.0, 0.0)
        self.fireball_target_id = -1
        # ── Freeze Attack ──────────────────────────────────
        self.freezeball_aktif     = False
        self.freezeball_t         = 0.0
        self.freezeball_dari      = (0.0, 0.0, 0.0)
        self.freezeball_ke        = (0.0, 0.0, 0.0)
        self.freezeball_target_id = -1
        self.freeze_efek          = {}   # pid -> timer efek beku visual
        self.show_freeze_icon     = {}   # pid -> timer ikon
        self.fire_hit_timer     = 0.0
        self.arus_hit_timer     = 0.0  # Efek layar Arus Deras
        self.fire_partikel      = []
        self.skill_panel_aktif  = False
        self.freeze_panel_aktif = False
        self.arus_panel_aktif   = False
        self.badai_panel_aktif  = False
        self.freeze_panel_aktif = False   # Panel pilih target Freeze Attack
        self.show_fire_icon     = {}   # {pid: timer}

        # Surface untuk UI (akan diupload sebagai texture)
        self.ui_surf = pygame.Surface((WIN_W, WIN_H), pygame.SRCALPHA)
        if OPENGL_AVAILABLE:
            self.ui_tex = glGenTextures(1)

        # ── State game ────────────────────────────────────
        # Gunakan nama custom dari splash screen jika ada
        nama_list = nama_pemain if nama_pemain else PLAYER_NAMES
        self.pemain = []
        ai_counter = 1
        for i in range(4):
            # Pemain 0 s/d jumlah_manusia-1 = manusia, sisanya = AI
            is_ai = (i >= jumlah_manusia)
            # Otomatis prefix nama AI jika masih pakai nama default
            nama = nama_list[i]
            if is_ai and nama in PLAYER_NAMES:
                nama = f"AI {ai_counter}"
                ai_counter += 1
            self.pemain.append(Pemain(i, nama, is_ai=is_ai))

        # Level 2: set uang awal 1500 Cr (bukan 1.500.000)
        if level == 2:
            for p in self.pemain:
                p.uang        = 1500
                p.skill_fire  = 2   # Skill awal: 2 Fire Attack
                p.skill_freeze = 2  # Skill awal: 2 Freeze Attack

        # Level 3: set uang awal 2000 Kr + semua skill battle
        if level == 3:
            for p in self.pemain:
                p.uang         = 2000
                p.skill_fire   = 2   # Skill awal: 2 Fire Attack Api
                p.skill_freeze = 3   # Skill awal: 3 Cryo Storm
                p.skill_arus   = 2   # Skill awal: 2 Arus Deras
                p.skill_badai  = 1   # Skill awal: 1 Badai Laut

        # ── State AI ──────────────────────────────────────
        # Konsep: Timer delay agar AI terlihat "berpikir"
        self.ai_timer       = 0.0
        self.ai_speed       = "normal"  # "lambat" / "normal" / "cepat"
        self.ai_delay_dadu  = 0.9   # Detik sebelum AI lempar dadu
        self.ai_delay_aksi  = 0.4   # Detik sebelum AI putuskan beli/lewati
        self.ai_delay_akhir = 0.4   # Detik sebelum AI akhiri giliran
        self.antrian     = deque(range(4))      # Konsep: QUEUE
        self.giliran     = 0
        self.kepemilikan = [-1] * BOARD_SIZE    # Konsep: ARRAY
        self.rumah       = [0]  * BOARD_SIZE
        self.fase        = "lempar_dadu"
        self.dadu        = [0, 0]
        self.log         = []
        self.game_over   = False
        self.pemenang    = None

        # ── Statistik game ────────────────────────────────
        self.total_giliran    = 0
        self.total_properti_dibeli = 0
        self.total_sewa_dibayar    = 0
        self.total_bangunan        = 0
        self.stat_sewa_terbesar    = 0   # sewa tunggal terbesar
        self.stat_sewa_terbesar_info = ""
        self.stat_kembar = {i:0 for i in range(4)}  # dadu kembar per pemain
        self.stat_penjara= {i:0 for i in range(4)}  # masuk penjara per pemain
        self.stat_kartu  = {i:0 for i in range(4)}  # kartu diambil per pemain
        self.stat_gadai  = {i:0 for i in range(4)}  # gadai per pemain
        self.stat_sewa_diterima = {i:0 for i in range(4)}
        self.stat_uang_min  = {i:1_500_000 for i in range(4)}  # uang minimum pernah dicapai
        self.stat_uang_awal = {i:1_500_000 for i in range(4)}
        self.stat_waktu_bangkrut = {}  # pid: giliran bangkrut
        self.stat_grafik_kekayaan = {i:[] for i in range(4)}  # list uang per giliran
        self.stat_tab_aktif = 0  # 0=podium, 1=grafik, 2=properti, 3=penghargaan
        self.popup       = None
        self.popup_rumah = None
        self.popup_gadai = None
        self.popup_jual  = None
        self.tergadai    = [False] * BOARD_SIZE
        self.notif_beli  = None
        self.notif_penjara = None
        self.notif_kotak_khusus = None

        # ── Fade out popup tawaran properti ──────────────
        # Konsep: Exponential Decay alpha 255→0 secara lembut
        self.popup_fade_alpha  = 255.0
        self.popup_fading      = False
