    def _set_ai_speed(self, speed):
        """Set kecepatan AI: 'lambat' / 'normal' / 'cepat'."""
        self.ai_speed = speed
        if speed == "lambat":
            self.ai_delay_dadu  = 4.0
            self.ai_delay_aksi  = 2.0
            self.ai_delay_akhir = 2.0
        elif speed == "cepat":
            self.ai_delay_dadu  = 0.3
            self.ai_delay_aksi  = 0.15
            self.ai_delay_akhir = 0.15
        else:  # normal
            self.ai_delay_dadu  = 0.9
            self.ai_delay_aksi  = 0.4
            self.ai_delay_akhir = 0.4

    def _pmult(self):
        """Multiplier jumlah partikel berdasarkan kualitas setting."""
        kq = getattr(self,'setting_kualitas','sedang')
        return {'rendah':0.4,'sedang':1.0,'tinggi':1.8}.get(kq,1.0)

    def _prange(self, n):
        """Range partikel yang disesuaikan kualitas."""
        return range(max(1, int(n * self._pmult())))

    def _play(self, nama):
        """Helper: mainkan suara dengan volume SFX yang bisa diatur."""
        if nama in self.suara:
            try:
                snd = self.suara[nama]
                snd.set_volume(getattr(self,'sfx_volume',0.7))
                snd.play()
            except Exception:
                pass

    # ─── SISTEM PARTIKEL ──────────────────────────────────
    def _spawn_kembang_api(self, cx, cy, warna, jumlah=40):
        """
        Konsep: Simulasi Fisika + Random
        Spawn partikel kembang api dari titik (cx, cy).
        Tiap partikel punya kecepatan arah acak, gravitasi,
        dan masa hidup (lifetime) yang berkurang tiap frame.
        """
        for _ in range(jumlah):
            sudut  = random.uniform(0, 2 * math.pi)
            kecepatan = random.uniform(80, 280)
            self.partikel.append({
                "tipe"  : "kembang",
                "x"     : float(cx),
                "y"     : float(cy),
                "vx"    : math.cos(sudut) * kecepatan,
                "vy"    : math.sin(sudut) * kecepatan - random.uniform(50, 150),
                "ay"    : 320.0,           # Gravitasi (pixel/s²)
                "hidup" : 1.0,             # Lifetime penuh
                "max_hidup": random.uniform(0.6, 1.2),
                "r"     : random.uniform(2, 5),
                "warna" : warna,
                "trail" : [],              # Jejak partikel
            })

    def _spawn_konfeti(self, jumlah=80):
        """
        Konsep: Array of Dictionary + Fisika
        Spawn konfeti warna-warni dari atas layar — efek menang besar.
        Konfeti jatuh dengan rotasi dan angin ringan.
        """
        warna_konfeti = [
            (255,50,50), (50,200,50), (50,100,255),
            (255,215,0), (255,100,200), (100,255,220),
            (255,150,50), (200,50,255),
        ]
        for _ in range(jumlah):
            self.partikel.append({
                "tipe"  : "konfeti",
                "x"     : random.uniform(0, WIN_W - WIN_W//4),  # Hanya area 3D
                "y"     : random.uniform(-100, -10),
                "vx"    : random.uniform(-40, 40),
                "vy"    : random.uniform(80, 200),
                "ay"    : 0.0,
                "rotasi": random.uniform(0, 360),
                "rot_spd": random.uniform(-180, 180),
                "hidup" : 1.0,
                "max_hidup": random.uniform(2.0, 4.0),
                "w"     : random.randint(6, 14),
                "h"     : random.randint(3, 7),
                "warna" : random.choice(warna_konfeti),
                "trail" : [],
            })

    def _spawn_bintang(self, cx, cy, warna):
        """Spawn efek bintang kecil — untuk beli properti"""
        for i in range(8):
            sudut = i * (math.pi / 4)
            self.partikel.append({
                "tipe"  : "bintang",
                "x"     : float(cx),
                "y"     : float(cy),
                "vx"    : math.cos(sudut) * 120,
                "vy"    : math.sin(sudut) * 120 - 60,
                "ay"    : 200.0,
                "hidup" : 1.0,
                "max_hidup": 0.8,
                "r"     : 4.0,
                "warna" : warna,
                "trail" : [],
            })

    def _update_partikel(self, dt):
        """
        Konsep: SIMULASI FISIKA + PERULANGAN
        Update posisi dan state semua partikel aktif.
        Gunakan persamaan gerak: x += vx*dt, vy += ay*dt
        Hapus partikel yang sudah habis masa hidupnya.
        """
        masih_hidup = []
        for p in self.partikel:
            # Update fisika
            p["x"]  += p["vx"] * dt
            p["y"]  += p["vy"] * dt
            p["vy"] += p["ay"] * dt      # Gravitasi
            p["vx"] *= (1 - dt * 0.8)   # Hambatan udara (drag)
            p["hidup"] -= dt / p["max_hidup"]

            if p["tipe"] == "konfeti":
                p["rotasi"] += p["rot_spd"] * dt

            # Simpan jejak (trail) untuk efek ekor
            if p["tipe"] == "kembang":
                p["trail"].append((p["x"], p["y"]))
                if len(p["trail"]) > 5:
                    p["trail"].pop(0)

            # Konsep KONDISIONAL: hapus jika mati atau keluar layar
            if p["hidup"] > 0 and p["y"] < WIN_H + 50:
                masih_hidup.append(p)

        self.partikel = masih_hidup   # Konsep: Filter array

    def _render_partikel(self, surf):
        """
        Konsep: PERULANGAN + Manipulasi Surface
        Render semua partikel aktif ke surface UI.
        Alpha disesuaikan dengan sisa lifetime (fade out).
        """
        for p in self.partikel:
            alpha = max(0, int(255 * p["hidup"]))
            warna = p["warna"]

            if p["tipe"] == "kembang":
                # Gambar jejak (trail) yang memudar
                for ti, (tx, ty) in enumerate(p["trail"]):
                    t_alpha = int(alpha * ti / max(len(p["trail"]), 1) * 0.5)
                    t_r     = max(1, int(p["r"] * ti / max(len(p["trail"]), 1)))
                    if t_alpha > 10:
                        ps = pygame.Surface((t_r*2+2, t_r*2+2), pygame.SRCALPHA)
                        pygame.draw.circle(ps, (*warna, t_alpha), (t_r+1, t_r+1), t_r)
                        surf.blit(ps, (int(tx)-t_r, int(ty)-t_r))
                # Partikel utama
                r = max(1, int(p["r"] * p["hidup"]))
                ps = pygame.Surface((r*2+2, r*2+2), pygame.SRCALPHA)
                pygame.draw.circle(ps, (*warna, alpha), (r+1, r+1), r)
                surf.blit(ps, (int(p["x"])-r, int(p["y"])-r))

            elif p["tipe"] == "konfeti":
                # Gambar persegi panjang berotasi
                w2, h2 = p["w"], p["h"]
                cos_r  = math.cos(math.radians(p["rotasi"]))
                sin_r  = math.sin(math.radians(p["rotasi"]))
                # 4 titik sudut persegi panjang berotasi
                corners_raw = [(-w2/2,-h2/2),(w2/2,-h2/2),(w2/2,h2/2),(-w2/2,h2/2)]
                corners = [
                    (p["x"] + cx*cos_r - cy*sin_r,
                     p["y"] + cx*sin_r + cy*cos_r)
                    for cx, cy in corners_raw
                ]
                ps = pygame.Surface((w2*3+4, h2*3+4), pygame.SRCALPHA)
                offset_x = min(c[0] for c in corners)
                offset_y = min(c[1] for c in corners)
                local_pts = [(c[0]-offset_x+2, c[1]-offset_y+2) for c in corners]
                pygame.draw.polygon(ps, (*warna, alpha), local_pts)
                surf.blit(ps, (int(offset_x), int(offset_y)))

            elif p["tipe"] == "bintang":
                r = max(1, int(p["r"] * p["hidup"]))
                ps = pygame.Surface((r*2+2, r*2+2), pygame.SRCALPHA)
                pygame.draw.circle(ps, (*warna, alpha), (r+1, r+1), r)
                surf.blit(ps, (int(p["x"])-r, int(p["y"])-r))

    def _spawn_uang_terbang(self, dari_pemain, ke_pemain, jumlah):
        """
        Konsep: Interpolasi Bezier + Animasi
        Spawn partikel uang melayang dari posisi bidak pembayar
        ke posisi bidak penerima sewa — mengikuti kurva melengkung.
        """
        # Jumlah ikon uang: 3-8 tergantung besarnya sewa
        n_uang = min(8, max(3, jumlah // 50000))
        for i in range(n_uang):
            self.uang_terbang.append({
                "dari_pid" : dari_pemain.id,
                "ke_pid"   : ke_pemain.id,
                "t"        : 0.0,                    # Progress 0→1
                "delay"    : i * 0.08,               # Delay antar ikon
                "durasi"   : 0.9 + random.uniform(0, 0.3),
                "offset_x" : random.uniform(-15, 15), # Jitter horizontal
                "offset_y" : random.uniform(-20, 0),  # Jitter vertikal
                "warna"    : dari_pemain.warna_py,
                "jumlah"   : jumlah,
                "aktif"    : False,
            })

    def _update_uang_terbang(self, dt):
        """
        Konsep: PERULANGAN + Interpolasi Kuadratik (Bezier)
        Update posisi tiap partikel uang berdasarkan delta time.
        Hapus yang sudah sampai tujuan.
        """
        masih_hidup = []
        for u in self.uang_terbang:
            u["delay"] -= dt
            if u["delay"] > 0:
                masih_hidup.append(u)
                continue
            u["aktif"] = True
            u["t"]    += dt / u["durasi"]
            if u["t"] < 1.0:
                masih_hidup.append(u)
        self.uang_terbang = masih_hidup

    def _render_uang_terbang(self, surf):
        """
        Konsep: Interpolasi Bezier Kuadratik
        Posisi uang dihitung dengan kurva Bezier:
        P(t) = (1-t)²·P0 + 2(1-t)t·P1 + t²·P2
        P0 = posisi awal, P1 = titik kontrol (melengkung), P2 = tujuan

        Menggunakan pos2d_cache untuk mendapat posisi layar bidak.
        """
        if not self.pos2d_cache:
            return

        fU = pygame.font.SysFont("Arial", 16, bold=True)
        GL_W = WIN_W - UI_W

        for u in self.uang_terbang:
            if not u["aktif"]:
                continue

            # Posisi awal: posisi bidak pembayar di layar
            pos_dari = self.pemain[u["dari_pid"]].posisi
            pos_ke   = self.pemain[u["ke_pid"]].posisi

            if pos_dari not in self.pos2d_cache or pos_ke not in self.pos2d_cache:
                continue

            x0, y0 = self.pos2d_cache[pos_dari]
            x2, y2 = self.pos2d_cache[pos_ke]

            # Titik kontrol: di atas kedua titik (kurva melengkung ke atas)
            x1 = (x0 + x2) / 2 + u["offset_x"]
            y1 = min(y0, y2) - 120 + u["offset_y"]

            # Bezier quadratic
            t  = u["t"]
            mt = 1 - t
            bx = mt*mt*x0 + 2*mt*t*x1 + t*t*x2
            by = mt*mt*y0 + 2*mt*t*y1 + t*t*y2

            # Skip jika di luar area 3D
            if not (0 < bx < GL_W and 0 < by < WIN_H):
                continue

            # Fade in + fade out
            alpha = int(255 * min(t*4, 1.0, (1-t)*4))
            if alpha < 10:
                continue

            # Gambar ikon uang
            warna = u["warna"]
            ikon_surf = pygame.Surface((36, 22), pygame.SRCALPHA)

            # Latar hijau uang
            pygame.draw.rect(ikon_surf, (*warna, alpha//2), (0,0,36,22), border_radius=4)
            pygame.draw.rect(ikon_surf, (*warna, alpha),    (0,0,36,22), 1, border_radius=4)

            # Teks mata uang sesuai level tema
            if self.level == 2:
                label_uang = "Cr"   # Galaxy Credits — tema Galaxy
            elif self.level == 3:
                label_uang = "Ko"   # Koral — tema Atlantis Bawah Laut
            else:
                label_uang = "Rp"   # Rupiah — tema default
            tu = fU.render(label_uang, True, (255, 255, 255))
            tu.set_alpha(alpha)
            ikon_surf.blit(tu, (6, 3))

            surf.blit(ikon_surf, (int(bx)-18, int(by)-11))

    # ─── EFEK VISUAL BARU ────────────────────────────────

    def _tutup_kartu(self):
        """Tutup popup kartu flip."""
        # Jalankan fase setelah kartu jika ada
        fase_setelah = None
        if self.kartu_flip_data:
            fase_setelah = self.kartu_flip_data.get("fase_setelah")
        self.kartu_flip_aktif = False
        self.kartu_flip_t     = 0.0
        self.kartu_flip_fase  = "tutup"
        self.kartu_flip_data  = None
        self.kartu_flip_idle  = 0.0
        if fase_setelah:
            self.fase = fase_setelah

    def _trigger_kilat_penjara(self):
        """Aktifkan efek kilat merah saat masuk penjara"""
        self.kilat_alpha = 255.0
        self.kilat_warna = (220, 30, 30)

    def _trigger_camera_shake(self, intensitas=3.0):
        """
        Konsep: Noise Acak + Exponential Decay
        Mulai animasi goyang kamera. Intensitas berkurang setiap frame.
        """
        self.shake_intensitas = intensitas

    def _tampil_notif_fire_frozen(self, p):
        """Tampilkan notifikasi pemain kena fire frozen."""
        if not (self.notif_kotak_khusus and self.notif_kotak_khusus.get("prioritas")):
            self.notif_kotak_khusus = {
            "jenis"  : "fire_frozen",
            "nama"   : p.nama,
            "warna"  : (255, 80, 20),
            "timer"  : 2.5,
            "durasi" : 2.5,
            "slide_x": WIN_W,
        }

    def _tampil_notif_freeze_frozen(self, p):
        """Tampilkan notifikasi pemain kena freeze/cryo attack."""
        if not (self.notif_kotak_khusus and self.notif_kotak_khusus.get("prioritas")):
            self.notif_kotak_khusus = {
            "jenis"  : "freeze_frozen",
            "nama"   : p.nama,
            "warna"  : (60, 160, 255),
            "timer"  : 2.5,
            "durasi" : 2.5,
            "slide_x": WIN_W,
        }

    def _update_efek(self, dt):
        """Update semua efek visual per frame."""
        self.neon_t += dt
        if hasattr(self, "save_notif") and self.save_notif:
            self.save_notif["timer"] -= dt
        # Update skill battle
        self._update_skill(dt)

        # ── Update timer roket idle ───────────────────────
        self.roket_t = getattr(self,'roket_t',0.0) + dt

        # ── Update animasi peluncuran roket ───────────────
        if getattr(self,'roket_launch_aktif',False):
            self.roket_launch_t = getattr(self,'roket_launch_t',0.0) + dt
            fase = getattr(self,'roket_fase','idle')
            if fase == "naik":
                self.roket_y = min(1.0, self.roket_launch_t/4.0)
                if self.roket_launch_t >= 4.0:
                    self.roket_fase     = "turun"
                    self.roket_launch_t = 0.0
            elif fase == "turun":
                self.roket_y = 1.0 - min(1.0, self.roket_launch_t/3.0)
                if self.roket_launch_t >= 3.0:
                    self.roket_fase         = "landing"
                    self.roket_launch_t     = 0.0
                    self.roket_y            = 0.0
                    self._trigger_camera_shake(2.5)
            elif fase == "landing":
                if self.roket_launch_t >= 1.5:
                    self.roket_launch_aktif = False
                    self.roket_fase         = "idle"
                    self.roket_launch_t     = 0.0

        # ── Update portal + UFO animasi ───────────────────
        self.portal_t = getattr(self,'portal_t',0.0) + dt * 1.2

        if getattr(self,'portal_aktif',False):
            self.portal_close_t = getattr(self,'portal_close_t',0.0) + dt/1.5
            if self.portal_close_t >= 1.0:
                self.portal_aktif   = False
                self.portal_close_t = 1.0

        # ── Update animasi Hiu Atlantis (Level 3) ──────────────
        if getattr(self,'hiu_aktif',False):
            self.hiu_t += dt
            t_h = self.hiu_t
            if self.hiu_fase == "muncul":
                # 0-1.2s: hiu naik dari pusaran, mulut terbuka
                self.hiu_y     = -0.8 + (t_h/1.2)*1.0
                self.hiu_mulut = min(1.0, t_h/0.5)
                if t_h > 1.2:
                    self.hiu_fase = "makan"
                    self.hiu_t   = 0.0
            elif self.hiu_fase == "makan":
                # 0-0.8s: mulut tutup — makan pion
                self.hiu_mulut = max(0.0, 1.0 - t_h/0.35)
                if t_h > 0.25:
                    self.hiu_pion_visi = False
                if t_h > 0.8:
                    self.hiu_fase = "terbang"
                    self.hiu_t   = 0.0
            elif self.hiu_fase == "terbang":
                # 0-5.0s: hiu terbang arc ke Palung Mariana
                prog = min(1.0, t_h/5.0)
                ease = prog*prog*(3-2*prog)
                self.hiu_x = self.hiu_start_x + (self.hiu_target_x-self.hiu_start_x)*ease
                self.hiu_z = self.hiu_start_z + (self.hiu_target_z-self.hiu_start_z)*ease
                self.hiu_y = math.sin(prog*math.pi)*2.2 - 0.2
                self.hiu_mulut = 0.08*abs(math.sin(t_h*8))
                if t_h > 5.0:
                    self.hiu_fase = "keluarkan"
                    self.hiu_t   = 0.0
            elif self.hiu_fase == "keluarkan":
                # 0-1.8s: hiu buka mulut, keluarkan pion di palung
                self.hiu_mulut = min(1.0, t_h/0.4)
                self.hiu_y     = -0.2 + math.sin(t_h*2)*0.08
                if t_h > 0.7:
                    self.hiu_pion_visi = True
                if t_h > 2.0:
                    self.hiu_aktif     = False
                    self.hiu_pion_visi = True
                    self.hiu_fase      = "idle"
                    # UFO tidak digunakan di Level 3 — hiu yang handle animasi

        if getattr(self,'ufo_aktif',False):
            self.ufo_t = getattr(self,'ufo_t',0.0) + dt
            fase = self.ufo_fase

            if fase == "datang":
                # UFO turun dari atas ke posisi portal
                t2  = min(1.0, self.ufo_t/1.2)
                ts  = t2*t2*(3-2*t2)
                self.ufo_x = getattr(self,'_ufo_start_x', 0.0)
                self.ufo_z = getattr(self,'_ufo_start_z', 0.0)
                # UFO datang dari ketinggian 8 turun ke 1.8
                self._ufo_y = 8.0 - ts * 6.2
                if self.ufo_t >= 1.2:
                    self.ufo_fase = "hisap"
                    self.ufo_t    = 0.0
                    self._trigger_camera_shake(1.5)

            elif fase == "hisap":
                # Sinar muncul, pemain naik ke UFO
                self._ufo_y = 1.8 + math.sin(self.neon_t*3)*0.04
                if self.ufo_t >= 2.2:
                    self.ufo_fase = "terbang"
                    self.ufo_t    = 0.0

            elif fase == "terbang":
                # UFO terbang ke Zona Hitam sambil naik tinggi
                t2  = min(1.0, self.ufo_t/2.5)
                ts  = t2*t2*(3-2*t2)
                sx  = getattr(self,'_ufo_start_x',0.0)
                sz  = getattr(self,'_ufo_start_z',0.0)
                self.ufo_x = sx + (self.ufo_target_x - sx)*ts
                self.ufo_z = sz + (self.ufo_target_z - sz)*ts
                # Arc tinggi saat terbang (naik lalu turun)
                arc = math.sin(ts * math.pi) * 4.0
                self._ufo_y = 1.8 + arc
                if self.ufo_t >= 2.5:
                    self.ufo_fase = "turun"
                    self.ufo_t    = 0.0
                    self._trigger_kilat_penjara()
                    self._trigger_camera_shake(2.5)

            elif fase == "turun":
                # Sinar turun, lepaskan pemain ke Zona Hitam
                t2 = min(1.0, self.ufo_t/1.0)
                self._ufo_y = 1.8 - t2 * 0.6  # Hover turun sedikit
                if self.ufo_t >= 2.0:
                    self.ufo_fase = "keluar"
                    self.ufo_t    = 0.0
                    pid = getattr(self,'portal_pid',-1)
                    if pid >= 0 and pid < 4:
                        if self.level != 2:
                            self.notif_penjara = {
                                "nama"   : self.pemain[pid].nama,
                                "warna"  : self.pemain[pid].warna_py,
                                "timer"  : 2.5,
                                "durasi" : 2.5,
                                "slide_x": WIN_W,
                            }

            elif fase == "keluar":
                # UFO naik cepat dan pergi
                self._ufo_y = 1.2 + self.ufo_t * 3.5
                if self.ufo_t >= 1.5:
                    self.ufo_aktif      = False
                    self.ufo_fase       = ""
                    self.portal_close_t = 0.0
        # Decay kilat penjara
        if self.kilat_alpha > 0:
            self.kilat_alpha = max(0.0, self.kilat_alpha - dt * 280)

        # Camera shake: update offset acak, decay intensitas
        if self.shake_intensitas > 0.01:
            self.shake_offset_ry = random.uniform(-1, 1) * self.shake_intensitas
            self.shake_offset_rx = random.uniform(-1, 1) * self.shake_intensitas * 0.5
            self.shake_intensitas *= (1 - self.shake_decay * dt)
        else:
            self.shake_intensitas = 0.0
            self.shake_offset_ry  = 0.0
            self.shake_offset_rx  = 0.0

        # ── Timer auto-lewati tawaran properti ───────────
        if self.popup and self.fase == "tawaran_beli":
            p_popup = self.popup["pemain"]

            if p_popup.is_ai:
                # AI putuskan setelah delay singkat
                self.popup_timer -= dt
                if self.popup_timer <= 0:
                    self.popup_timer = 0.0
                    self._ai_putuskan_beli(p_popup)
                    if self.popup and self.fase == "tawaran_beli":
                        self.lewati()
            else:
                # Manusia: countdown hanya saat animasi bidak SUDAH selesai
                if not self.pawn_anim_aktif and not self.popup_fading:
                    self.popup_timer -= dt
                    if self.popup_timer <= 0:
                        self.popup_timer  = 0.0
                        self.popup_fading = True
                        self.popup_fade_alpha = 255.0

        # Fase fade out — hanya untuk manusia
        if self.popup_fading and self.popup:
            self.popup_fade_alpha -= dt * (255.0 / self.popup_fade_durasi)
            if self.popup_fade_alpha <= 0:
                self.popup_fade_alpha = 0
                self.popup_fading     = False
                if self.popup:   # Pastikan popup masih ada
                    p_aktif = self.popup["pemain"]
                    if not p_aktif.is_ai:   # Hanya untuk manusia
                        self._log(f"Waktu habis! {p_aktif.nama} lewati otomatis.")
                        self.lewati()

        # Safety: jika AI masih stuck di tawaran_beli lebih dari 3 detik, paksa lewati
        if (self.popup and self.fase == "tawaran_beli"
                and self.popup["pemain"].is_ai
                and self.ai_timer > 3.0):
            self._log(f"⚠ Safety: paksa lewati {self.popup['pemain'].nama}")
            self.lewati()

        # Update flip kartu
        if self.kartu_flip_aktif:
            # Jika yang giliran AI — tutup kartu langsung
            p_now = self.pemain[self.giliran] if 0 <= self.giliran < len(self.pemain) else None
            if p_now and p_now.is_ai:
                self._tutup_kartu()
            elif self.kartu_flip_fase in ("tutup", "buka"):
                # Fase animasi flip — naikkan t terus sampai 1.0
                self.kartu_flip_t += dt / self.kartu_flip_durasi
                if self.kartu_flip_t >= 0.5:
                    self.kartu_flip_fase = "buka"
                if self.kartu_flip_t >= 1.0:
                    self.kartu_flip_t    = 1.0
                    self.kartu_flip_fase = "tampil"  # Kartu terbuka, tunggu input
            elif self.kartu_flip_fase == "tampil":
                # Kartu tampil, tunggu input
                # Auto-tutup setelah 8 detik jika pemain tidak menekan tombol
                self.kartu_flip_idle = getattr(self, "kartu_flip_idle", 0.0) + dt if hasattr(self, "kartu_flip_idle") else dt
                if self.kartu_flip_idle >= 8.0:
                    self._tutup_kartu()
                    self.kartu_flip_idle = 0.0

        # Update timer notifikasi beli
        if self.notif_beli:
            self.notif_beli["timer"] -= dt
            if self.notif_beli["timer"] <= 0:
                self.notif_beli = None

        # Update animasi notifikasi penjara (slide kanan → kiri)
        if self.notif_penjara:
            np = self.notif_penjara
            np["timer"] -= dt
            sisa   = np["timer"]
            durasi = np["durasi"]
            nw     = 540   # lebar popup

            # Fase slide in (0.45 dtk pertama): meluncur dari kanan
            if sisa > durasi - 0.45:
                t_in = 1.0 - (sisa - (durasi - 0.45)) / 0.45
                # Ease out cubic
                t_in = 1 - (1 - t_in) ** 3
                target_x = (WIN_W - UI_W) // 2 - nw // 2
                np["slide_x"] = int(WIN_W + (target_x - WIN_W) * t_in)
            # Fase diam (tengah)
            elif sisa > 0.5:
                np["slide_x"] = (WIN_W - UI_W) // 2 - nw // 2
            # Fase slide out (0.5 dtk terakhir): meluncur ke kiri
            else:
                t_out = sisa / 0.5
                t_out = t_out * t_out   # ease in quad
                target_x = (WIN_W - UI_W) // 2 - nw // 2
                np["slide_x"] = int(target_x + (-WIN_W - target_x) * (1 - t_out))

            if np["timer"] <= 0:
                self.notif_penjara = None

        # Update animasi notifikasi kotak khusus (komunitas/parkir/pajak mewah)
        if self.notif_kotak_khusus:
            nk = self.notif_kotak_khusus
            nk["timer"] -= dt
            durasi = nk["durasi"]
            sisa   = nk["timer"]
            nw     = 520

            if sisa > durasi - 0.45:
                t_in = 1.0 - (sisa - (durasi - 0.45)) / 0.45
                t_in = 1 - (1 - t_in) ** 3   # ease out cubic
                target_x = (WIN_W - UI_W) // 2 - nw // 2
                nk["slide_x"] = int(WIN_W + (target_x - WIN_W) * t_in)
            elif sisa > 0.5:
                nk["slide_x"] = (WIN_W - UI_W) // 2 - nw // 2
            else:
                t_out = sisa / 0.5
                t_out = t_out * t_out
                target_x = (WIN_W - UI_W) // 2 - nw // 2
                nk["slide_x"] = int(target_x + (-WIN_W - target_x) * (1 - t_out))

            if nk["timer"] <= 0:
                self.notif_kotak_khusus = None

    def _render_kilat(self, surf):
        """
        Konsep: Alpha Blending — overlay warna dengan transparansi.
        Kilat merah muncul sesaat saat masuk penjara.
        """
        if self.kilat_alpha < 5:
            return
        GL_W  = WIN_W - UI_W
        alpha = int(self.kilat_alpha)
        kilat = pygame.Surface((GL_W, WIN_H), pygame.SRCALPHA)
        kilat.fill((*self.kilat_warna, alpha))
        surf.blit(kilat, (0, 0))

        # Teks "MASUK PENJARA!" saat kilat terang
        if self.kilat_alpha > 150:
            fK  = get_font(30, bold=True)
            txt = fK.render("MASUK PENJARA!", True, (255, 255, 255))
            txt.set_alpha(int((self.kilat_alpha - 150) * 2.5))
            surf.blit(txt, (GL_W//2 - txt.get_width()//2, WIN_H//2 - txt.get_height()//2))

