        """Kartu properti Level 3 — tema Atlantis bawah laut, octagon sci-fi."""
        def make_oct(w, h, cut):
            c = min(cut, w//4, h//4)
            return [(c,0),(w-c,0),(w,c),(w,h-c),(w-c,h),(c,h),(0,h-c),(0,c)]

        # ── Tema per properti L3 ──────────────────────────────
