        def make_oct(w, h, cut):
            """Buat titik octagon — sudut terpotong sebesar cut px."""
            c = min(cut, w//4, h//4)
            return [
                (c, 0), (w-c, 0),
                (w, c), (w, h-c),
                (w-c, h), (c, h),
                (0, h-c), (0, c)
            ]

