                        for layer in range(pr, 0, -3):
                            frac = layer / pr
                            pr2 = int(planet_col[0]*frac + 5*(1-frac))
                            pg2 = int(planet_col[1]*frac + 10*(1-frac))
                            pb2 = int(planet_col[2]*frac + 30*(1-frac))
                            pygame.draw.circle(kartu,(pr2,pg2,pb2,230),(px3,py3),layer)
