                        pygame.draw.circle(atm,(*warna_aksen,40),(px3,py3),pr+6)
                        pygame.draw.circle(atm,(*warna_aksen,15),(px3,py3),pr+12)
                        kartu.blit(atm,(0,0),special_flags=pygame.BLEND_RGBA_ADD)
