    def _update_cahaya(self, dt):
        """Pencahayaan dinamis — terang dan berwarna."""
        self.cahaya_timer += dt * 0.25
        angle = self.cahaya_timer
        lx = math.sin(angle) * 9.0
        lz = math.cos(angle) * 9.0
        ly = 15.0 + math.sin(angle * 0.4) * 2.0

        if self.level == 3:
            # Level 3: cahaya bawah laut — beriak lambat, biru-hijau toska
            ripple = 0.08 * math.sin(angle * 0.7)
            amb = 0.32 + 0.06 * math.sin(angle * 0.3) + ripple
            glLightfv(GL_LIGHT0, GL_POSITION, [lx * 0.5, ly, lz * 0.5, 1.0])
            glLightfv(GL_LIGHT0, GL_AMBIENT,  [amb * 0.25, amb * 0.70, amb * 0.90, 1.0])
            glLightfv(GL_LIGHT0, GL_DIFFUSE,  [0.20, 0.65, 0.85, 1.0])
            # Cahaya isi bioluminesen — toska hijau
            glLightfv(GL_LIGHT1, GL_POSITION, [-lx * 0.3, 6.0, -lz * 0.3, 1.0])
            glLightfv(GL_LIGHT1, GL_DIFFUSE,  [0.05, 0.55, 0.50, 1.0])
        else:
            # Cahaya utama — terang
            glLightfv(GL_LIGHT0, GL_POSITION, [lx, ly, lz, 1.0])
            amb = 0.52 + 0.06 * math.sin(angle * 0.2)
            glLightfv(GL_LIGHT0, GL_AMBIENT,  [amb, amb*0.96, amb*0.90, 1.0])
            glLightfv(GL_LIGHT0, GL_DIFFUSE,  [1.0, 0.95, 0.88, 1.0])
            # Cahaya isi — biru
            glLightfv(GL_LIGHT1, GL_POSITION, [-lx*0.4, 8.0, -lz*0.4, 1.0])
            glLightfv(GL_LIGHT1, GL_DIFFUSE,  [0.30, 0.38, 0.55, 1.0])

    def _draw_city_background(self):
        """
        Background 3D kota senja Level 1.
        Gedung, pohon, jalan digambar di DUNIA 3D mengelilingi papan
        sehingga saat kamera diputar, kota tetap mengelilingi dari semua sisi.
        """
        import math as _m, random as _r

        t_now = pygame.time.get_ticks() / 1000.0
        GL_W  = WIN_W - UI_W

        # ── Langit senja dulu (orthographic 2D di belakang) ──
        glPushAttrib(GL_ALL_ATTRIB_BITS)
        glMatrixMode(GL_PROJECTION); glPushMatrix(); glLoadIdentity()
        glOrtho(0, GL_W, 0, WIN_H, -1, 1)
        glMatrixMode(GL_MODELVIEW);  glPushMatrix(); glLoadIdentity()
        glDisable(GL_DEPTH_TEST)
        glDisable(GL_LIGHTING)
        glEnable(GL_BLEND)
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

        W, H = GL_W, WIN_H

        # Langit gradasi
        glBegin(GL_QUADS)
        glColor3f(0.18,0.10,0.28); glVertex2f(0,H); glVertex2f(W,H)
        glColor3f(0.68,0.25,0.08); glVertex2f(W,int(H*0.52)); glVertex2f(0,int(H*0.52))
        glEnd()
        glBegin(GL_QUADS)
        glColor3f(0.68,0.25,0.08); glVertex2f(0,int(H*0.52)); glVertex2f(W,int(H*0.52))
        glColor3f(0.95,0.72,0.18); glVertex2f(W,int(H*0.38)); glVertex2f(0,int(H*0.38))
        glEnd()
        glBegin(GL_QUADS)
        glColor3f(0.95,0.72,0.18); glVertex2f(0,int(H*0.38)); glVertex2f(W,int(H*0.38))
        glColor3f(0.88,0.55,0.22); glVertex2f(W,int(H*0.28)); glVertex2f(0,int(H*0.28))
        glEnd()
        glBegin(GL_QUADS)
        glColor3f(0.88,0.55,0.22); glVertex2f(0,int(H*0.28)); glVertex2f(W,int(H*0.28))
        glColor3f(0.50,0.30,0.12); glVertex2f(W,0); glVertex2f(0,0)
        glEnd()

        # Matahari
        SX,SY = int(W*0.75), int(H*0.55)
        glBlendFunc(GL_SRC_ALPHA, GL_ONE)
        for r_h in [110,80,55,35]:
            a_h = 0.04+0.06*(1-r_h/110)
            glBegin(GL_TRIANGLE_FAN)
            glColor4f(1.,.78,.25,0.); glVertex2f(SX,SY)
            for ii in range(37):
                ag=2*_m.pi*ii/36
                glColor4f(1.,.78,.25,a_h)
                glVertex2f(SX+_m.cos(ag)*r_h, SY+_m.sin(ag)*r_h)
            glEnd()
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
        glBegin(GL_TRIANGLE_FAN)
        glColor3f(1.,.96,.80); glVertex2f(SX,SY)
        for ii in range(37):
            ag=2*_m.pi*ii/36
            glColor3f(1.,.88,.52)
            glVertex2f(SX+_m.cos(ag)*20,SY+_m.sin(ag)*20)
        glEnd()

        # Sinar matahari animasi
        glBlendFunc(GL_SRC_ALPHA, GL_ONE)
        pulse = 0.8+0.2*_m.sin(t_now*0.8)
        for ii in range(12):
            ag = 2*_m.pi*ii/12 + t_now*0.03
            rl = int((50+15*_m.sin(t_now+ii))*pulse)
            glBegin(GL_TRIANGLES)
            glColor4f(1.,.85,.35,.18); glVertex2f(SX,SY)
            glColor4f(1.,.85,.35,0.)
            glVertex2f(SX+_m.cos(ag-.06)*rl, SY+_m.sin(ag-.06)*rl)
            glVertex2f(SX+_m.cos(ag+.06)*rl, SY+_m.sin(ag+.06)*rl)
            glEnd()
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

        # Awan senja
        def awan2d(cx,cy,sk,ct,cb,al):
            blobs=[(0,0,sk),(-sk*.50,-sk*.12,sk*.65),(sk*.52,-sk*.10,sk*.63),
                   (-sk*.22,-sk*.32,sk*.50),(sk*.25,-sk*.30,sk*.48),(0,-sk*.45,sk*.40)]
            for bx,by,br in blobs:
                tt=min(1,max(0,(by/sk+0.5)))
                rv=cb[0]+(ct[0]-cb[0])*tt; gv=cb[1]+(ct[1]-cb[1])*tt; bv=cb[2]+(ct[2]-cb[2])*tt
                glBegin(GL_TRIANGLE_FAN)
                glColor4f(rv,gv,bv,al); glVertex2f(cx+bx,cy+by)
                for ii in range(25):
                    ag2=2*_m.pi*ii/24
                    glColor4f(rv,gv,bv,al*.4)
                    glVertex2f(cx+bx+_m.cos(ag2)*br, cy+by+_m.sin(ag2)*br*.55)
                glEnd()

        for cx2,cy2,sk2,ct2,cb2,al2 in [
            (int(W*.08),int(H*.68),50,(.98,.76,.46),(.86,.56,.32),.78),
            (int(W*.24),int(H*.72),64,(.99,.79,.48),(.87,.59,.34),.74),
            (int(W*.42),int(H*.66),44,(.96,.72,.42),(.82,.54,.28),.72),
            (int(W*.60),int(H*.70),58,(.99,.78,.48),(.86,.58,.33),.70),
            (int(W*.82),int(H*.67),48,(.97,.74,.44),(.84,.56,.31),.68),
            (int(W*.14),int(H*.78),34,(.94,.68,.38),(.80,.50,.25),.60),
            (int(W*.70),int(H*.74),40,(.95,.70,.40),(.81,.52,.27),.63),
        ]:
            awan2d(cx2,cy2,sk2,ct2,cb2,al2)

        glMatrixMode(GL_PROJECTION); glPopMatrix()
        glMatrixMode(GL_MODELVIEW);  glPopMatrix()
        glPopAttrib()

        # ── Sekarang gambar kota di dunia 3D ──────────────
        glEnable(GL_DEPTH_TEST)
        glEnable(GL_LIGHTING)
        glEnable(GL_LIGHT0)
        glEnable(GL_COLOR_MATERIAL)
        glColorMaterial(GL_FRONT_AND_BACK, GL_AMBIENT_AND_DIFFUSE)
        glEnable(GL_BLEND)
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

        # Cahaya senja dari kanan-atas
        glLightfv(GL_LIGHT0, GL_POSITION, (8.0, 6.0, 4.0, 0.0))
        glLightfv(GL_LIGHT0, GL_DIFFUSE,  (1.0, 0.72, 0.35, 1.0))
        glLightfv(GL_LIGHT0, GL_AMBIENT,  (0.28, 0.18, 0.10, 1.0))
        glLightfv(GL_LIGHT0, GL_SPECULAR, (0.8, 0.5, 0.2, 1.0))

        # Gunakan Random instance terpisah agar tidak merusak global random (dadu!)
        if not hasattr(self, '_city_rng'):
            import random as _rand_mod
            self._city_rng = _rand_mod.Random(42)
        _r = self._city_rng
        _r.seed(42)  # reset tiap frame agar gedung konsisten posisinya

        # ══ TANAH & JALAN MENGELILINGI PAPAN ══════════════
        # Ground plane hijau luas
        glDisable(GL_LIGHTING)
        glBegin(GL_QUADS)
        sz = 45.0
        # Rumput gelap senja
        glColor3f(0.15, 0.28, 0.10)
        glVertex3f(-sz, -0.52, -sz); glVertex3f( sz, -0.52, -sz)
        glVertex3f( sz, -0.52,  sz); glVertex3f(-sz, -0.52,  sz)
        glEnd()

        # Jalan berbentuk + mengelilingi papan
        jalan_w = 2.8   # lebar jalan
        jalan_d = 45.0  # panjang jalan ke luar
        glColor3f(0.22, 0.20, 0.18)
        # Jalan utara-selatan
        glBegin(GL_QUADS)
        glVertex3f(-jalan_w, -0.50, -jalan_d); glVertex3f(jalan_w, -0.50, -jalan_d)
        glVertex3f( jalan_w, -0.50,  jalan_d); glVertex3f(-jalan_w, -0.50,  jalan_d)
        glEnd()
        # Jalan timur-barat
        glBegin(GL_QUADS)
        glVertex3f(-jalan_d, -0.50, -jalan_w); glVertex3f( jalan_d, -0.50, -jalan_w)
        glVertex3f( jalan_d, -0.50,  jalan_w); glVertex3f(-jalan_d, -0.50,  jalan_w)
        glEnd()

        # Marka jalan putus-putus
        glColor3f(0.88, 0.80, 0.28)
        mark_w = 0.12
        for mk in range(-8, 9):
            if mk == 0: continue
            mz = mk * 2.8
            if -5.5 < mz < 5.5: continue  # skip area persimpangan
            # N-S
            glBegin(GL_QUADS)
            glVertex3f(-mark_w,-0.49, mz-.8); glVertex3f(mark_w,-0.49, mz-.8)
            glVertex3f( mark_w,-0.49, mz+.8); glVertex3f(-mark_w,-0.49, mz+.8)
            glEnd()
            # E-W
            glBegin(GL_QUADS)
            glVertex3f(mz-.8,-0.49,-mark_w); glVertex3f(mz+.8,-0.49,-mark_w)
            glVertex3f(mz+.8,-0.49, mark_w); glVertex3f(mz-.8,-0.49, mark_w)
            glEnd()

        # Trotoar (abu cerah) mengelilingi jalan
        glColor3f(0.55, 0.50, 0.44)
        for side, sign in [(1,1),(-1,-1)]:
            tw = jalan_w + 0.6; tw2 = tw + 1.2
            # N-S trotoar kiri/kanan
            glBegin(GL_QUADS)
            glVertex3f(sign*tw, -0.50, -jalan_d)
            glVertex3f(sign*tw2,-0.50, -jalan_d)
            glVertex3f(sign*tw2,-0.50,  jalan_d)
            glVertex3f(sign*tw, -0.50,  jalan_d)
            glEnd()
            # E-W trotoar atas/bawah
            glBegin(GL_QUADS)
            glVertex3f(-jalan_d,-0.50, sign*tw)
            glVertex3f( jalan_d,-0.50, sign*tw)
            glVertex3f( jalan_d,-0.50, sign*tw2)
            glVertex3f(-jalan_d,-0.50, sign*tw2)
            glEnd()

        glEnable(GL_LIGHTING)

        # ══ GEDUNG 3D MENGELILINGI PAPAN ══════════════════
        def gedung3d_world(x, z, w_g, d_g, h_g, rw, gw, bw):
            """Gedung di posisi (x,z) dunia 3D, tumbuh ke atas dari Y=-0.5."""
            rs = rw*.52; gs = gw*.52; bs = bw*.52
            rr = rw*.72; gr = gw*.72; br = bw*.72
            y0 = -0.50; y1 = y0 + h_g
            # Dinding depan (menghadap ke arah negatif Z)
            glColor3f(rw, gw, bw)
            glBegin(GL_QUADS)
            glVertex3f(x,    y0, z);     glVertex3f(x+w_g, y0, z)
            glVertex3f(x+w_g,y1, z);    glVertex3f(x,     y1, z)
            glEnd()
            # Dinding belakang
            glColor3f(rw*.82, gw*.82, bw*.82)
            glBegin(GL_QUADS)
            glVertex3f(x,    y0, z+d_g); glVertex3f(x+w_g, y0, z+d_g)
            glVertex3f(x+w_g,y1, z+d_g); glVertex3f(x,    y1, z+d_g)
            glEnd()
            # Sisi kiri
            glColor3f(rs, gs, bs)
            glBegin(GL_QUADS)
            glVertex3f(x, y0, z);     glVertex3f(x, y0, z+d_g)
            glVertex3f(x, y1, z+d_g); glVertex3f(x, y1, z)
            glEnd()
            # Sisi kanan (lit senja)
            glColor3f(min(1,rw*1.15), gw*.78, bw*.45)
            glBegin(GL_QUADS)
            glVertex3f(x+w_g, y0, z);     glVertex3f(x+w_g, y0, z+d_g)
            glVertex3f(x+w_g, y1, z+d_g); glVertex3f(x+w_g, y1, z)
            glEnd()
            # Atap
            glColor3f(rr, gr, br)
            glBegin(GL_QUADS)
            glVertex3f(x,    y1, z);     glVertex3f(x+w_g, y1, z)
            glVertex3f(x+w_g,y1, z+d_g); glVertex3f(x,    y1, z+d_g)
            glEnd()
            # Jendela bercahaya — grid sederhana
            win_rows = max(2, int(h_g*2.2))
            win_cols = max(1, int(w_g*1.5))
            gw_w = w_g/(win_cols*2.2)
            gw_h = h_g/(win_rows*2.2)
            _r.seed(int((x+z)*37+h_g*13))
            for row in range(win_rows):
                wy = y0 + (row+0.8)*h_g/(win_rows+0.2)
                for col in range(win_cols):
                    wx = x + (col+0.5)*w_g/(win_cols+0.3)
                    lit = _r.random() > 0.30
                    glDisable(GL_LIGHTING)
                    glBegin(GL_QUADS)
                    if lit:
                        glColor4f(1.0, 0.88, 0.45, 0.92)
                    else:
                        glColor4f(0.06, 0.06, 0.14, 0.85)
                    glVertex3f(wx,       wy,      z-.01)
                    glVertex3f(wx+gw_w,  wy,      z-.01)
                    glVertex3f(wx+gw_w,  wy+gw_h, z-.01)
                    glVertex3f(wx,       wy+gw_h, z-.01)
                    glEnd()
                    glEnable(GL_LIGHTING)

        # Layout gedung di 4 sisi mengelilingi papan
        # Papan ukuran ~12x12 unit, gedung mulai dari jarak ~9 unit
        _r.seed(42)

        # Konfigurasi: (x_start, z_start, n_gedung, arah, dist_dari_pusat)
        # Sisi UTARA (z negatif)
        for i in range(14):
            gx = -28 + i*4.2 + _r.uniform(-0.5,0.5)
            gz = -10 - _r.uniform(1.5,4.5)
            gw2 = _r.uniform(2.2,4.0); gd = _r.uniform(1.8,3.2)
            gh  = _r.uniform(3.5,8.5)
            dim = _r.uniform(0.72,0.90)
            rw2 = _r.uniform(0.28,0.42)*dim
            gw3 = _r.uniform(0.20,0.32)*dim
            bw2 = _r.uniform(0.12,0.22)*dim
            gedung3d_world(gx, gz-gd, gw2, gd, gh, rw2,gw3,bw2)

        # Sisi SELATAN (z positif)
        for i in range(14):
            gx = -28 + i*4.2 + _r.uniform(-0.5,0.5)
            gz =  10 + _r.uniform(1.5,4.5)
            gw2 = _r.uniform(2.2,4.0); gd = _r.uniform(1.8,3.2)
            gh  = _r.uniform(3.5,8.5)
            dim = _r.uniform(0.72,0.90)
            rw2 = _r.uniform(0.28,0.42)*dim
            gw3 = _r.uniform(0.20,0.32)*dim
            bw2 = _r.uniform(0.12,0.22)*dim
            gedung3d_world(gx, gz, gw2, gd, gh, rw2,gw3,bw2)

        # Sisi BARAT (x negatif)
        for i in range(14):
            gz = -28 + i*4.2 + _r.uniform(-0.5,0.5)
            gx = -10 - _r.uniform(1.5,4.5)
            gw2 = _r.uniform(1.8,3.2); gd = _r.uniform(2.2,4.0)
            gh  = _r.uniform(3.5,8.5)
            dim = _r.uniform(0.72,0.90)
            rw2 = _r.uniform(0.28,0.42)*dim
            gw3 = _r.uniform(0.20,0.32)*dim
            bw2 = _r.uniform(0.12,0.22)*dim
            gedung3d_world(gx-gw2, gz, gw2, gd, gh, rw2,gw3,bw2)

        # Sisi TIMUR (x positif)
        for i in range(14):
            gz = -28 + i*4.2 + _r.uniform(-0.5,0.5)
            gx =  10 + _r.uniform(1.5,4.5)
            gw2 = _r.uniform(1.8,3.2); gd = _r.uniform(2.2,4.0)
            gh  = _r.uniform(3.5,8.5)
            dim = _r.uniform(0.72,0.90)
            rw2 = _r.uniform(0.28,0.42)*dim
            gw3 = _r.uniform(0.20,0.32)*dim
            bw2 = _r.uniform(0.12,0.22)*dim
            gedung3d_world(gx, gz, gw2, gd, gh, rw2,gw3,bw2)

        # Gedung sudut (4 sudut)
        for sx,sz2 in [(-28,-28),(-28,22),(22,-28),(22,22)]:
            for j in range(3):
                gw2=_r.uniform(3.0,5.5); gd=_r.uniform(2.5,4.5)
                gh=_r.uniform(5.0,10.0)
                dx=_r.uniform(0,3); dz=_r.uniform(0,3)
                dim=_r.uniform(0.70,0.88)
                rw2=_r.uniform(0.30,0.45)*dim
                gw3=_r.uniform(0.22,0.35)*dim
                bw2=_r.uniform(0.14,0.24)*dim
                gedung3d_world(sx+dx, sz2+dz, gw2, gd, gh, rw2,gw3,bw2)

        # ══ POHON 3D DI PINGGIR JALAN ═════════════════════
        def pohon3d_world(cx, cz, h_p, r_p):
            # Batang silinder kasar
            glDisable(GL_LIGHTING)
            bw3 = 0.12
            glColor3f(0.24, 0.15, 0.08)
            glBegin(GL_QUADS)
            glVertex3f(cx-bw3,-0.50,cz-bw3); glVertex3f(cx+bw3,-0.50,cz-bw3)
            glVertex3f(cx+bw3,-0.50+h_p*0.4,cz-bw3)
            glVertex3f(cx-bw3,-0.50+h_p*0.4,cz-bw3)
            glEnd()
            # Daun — piramida berlapis
            for lyr in range(3):
                ly   = -0.50 + h_p*0.28 + lyr*h_p*0.22
                lr   = r_p*(1.0 - lyr*0.28)
                lh   = h_p*0.38
                tt   = lyr/2
                rv3  = 0.15+0.12*tt; gv3 = 0.30+0.16*tt; bv3 = 0.08+0.06*tt
                # 4 sisi
                for side2 in range(4):
                    ag3 = side2*_m.pi/2
                    ag4 = ag3 + _m.pi/2
                    x1 = cx+_m.cos(ag3)*lr; z1 = cz+_m.sin(ag3)*lr
                    x2 = cx+_m.cos(ag4)*lr; z2 = cz+_m.sin(ag4)*lr
                    # Highlight senja (sisi yang menghadap matahari)
                    bright = 0.5 + 0.5*max(0,_m.cos(ag3-0.5))
                    glColor3f(min(1,rv3*bright+0.08*bright),
                              gv3*bright, bv3*bright*.7)
                    glBegin(GL_TRIANGLES)
                    glVertex3f(x1,ly,z1); glVertex3f(x2,ly,z2)
                    glVertex3f(cx,ly+lh,cz)
                    glEnd()
            glEnable(GL_LIGHTING)

        # Pohon di setiap sudut jalan
        for side3, positions in [
            ('N', [(-8,-8.5),(-4,-8.5),(0,-8.5),(4,-8.5),(8,-8.5)]),
            ('S', [(-8, 8.5),(-4, 8.5),(0, 8.5),(4, 8.5),(8, 8.5)]),
            ('W', [(-8.5,-8),(-8.5,-4),(-8.5,0),(-8.5,4),(-8.5,8)]),
            ('E', [( 8.5,-8),( 8.5,-4),( 8.5,0),( 8.5,4),( 8.5,8)]),
        ]:
            for px2,pz2 in positions:
                hp = _r.uniform(1.2,2.0)
                rp = _r.uniform(0.8,1.3)
                pohon3d_world(px2, pz2, hp, rp)

        # ══ LAMPU JALAN 3D ════════════════════════════════
        def lampu3d_world(cx, cz, tinggi=2.2):
            glDisable(GL_LIGHTING)
            tw2 = 0.08
            # Tiang
            glColor3f(0.22,0.19,0.16)
            glBegin(GL_QUADS)
            glVertex3f(cx-tw2,-0.50,cz-tw2); glVertex3f(cx+tw2,-0.50,cz-tw2)
            glVertex3f(cx+tw2,-0.50+tinggi,cz-tw2)
            glVertex3f(cx-tw2,-0.50+tinggi,cz-tw2)
            glEnd()
            # Kepala
            hx=cx+0.6; hy=-0.50+tinggi
            glColor3f(0.20,0.18,0.14)
            glBegin(GL_QUADS)
            glVertex3f(cx,hy-.05,cz); glVertex3f(hx+.15,hy-.05,cz)
            glVertex3f(hx+.15,hy+.05,cz); glVertex3f(cx,hy+.05,cz)
            glEnd()
            # Bola lampu
            glBlendFunc(GL_SRC_ALPHA, GL_ONE)
            glBegin(GL_TRIANGLE_FAN)
            glColor4f(1.,.92,.60,.0); glVertex3f(hx,hy,cz)
            for ii in range(13):
                ag5=2*_m.pi*ii/12
                glColor4f(1.,.92,.60,.15)
                glVertex3f(hx+_m.cos(ag5)*.18,hy+_m.sin(ag5)*.18,cz)
            glEnd()
            glBegin(GL_TRIANGLE_FAN)
            glColor4f(1.,.98,.85,1.); glVertex3f(hx,hy,cz)
            for ii in range(13):
                ag5=2*_m.pi*ii/12
                glColor4f(1.,.95,.80,0.9)
                glVertex3f(hx+_m.cos(ag5)*.08,hy+_m.sin(ag5)*.08,cz)
            glEnd()
            glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
            glEnable(GL_LIGHTING)

        # Lampu di sepanjang 4 sisi trotoar
        for lz3 in [-7,-3.5,0,3.5,7]:
            lampu3d_world(-9.2, lz3)   # barat
            lampu3d_world( 9.2, lz3)   # timur
        for lx3 in [-7,-3.5,0,3.5,7]:
            lampu3d_world(lx3, -9.2)   # utara
            lampu3d_world(lx3,  9.2)   # selatan

    def _draw_space_background(self):
        """
        Latar angkasa Level 2: bintang + 7 planet berputar di sekitar papan.
        Planet terletak di sekitar papan pada jarak yang terlihat dari kamera.
        """
        glDisable(GL_LIGHTING)
        glEnable(GL_DEPTH_TEST)
        glEnable(GL_BLEND)
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

        t = self.neon_t if hasattr(self, 'neon_t') else 0.0

        # ── Bintang latar ──────────────────────────────────────
        if not hasattr(self, '_bg_stars'):
            import random as _r
            self._bg_stars = []
            for _ in range(900):
                theta = _r.uniform(0, 2*math.pi)
                phi   = _r.uniform(0.02, math.pi * 0.98)
                r     = _r.uniform(80, 200)
                self._bg_stars.append((
                    r * math.sin(phi) * math.cos(theta),
                    r * math.cos(phi),
                    r * math.sin(phi) * math.sin(theta),
                    _r.uniform(0.5, 1.0),
                    _r.uniform(0.3, 2.5),
                ))

        glPointSize(2.0)
        glBegin(GL_POINTS)
        for sx, sy, sz, bright, spd in self._bg_stars:
            tw = 0.55 + 0.45 * abs(math.sin(t * spd + sx * 0.07))
            b  = bright * tw
            glColor3f(b, b, min(1.0, b + 0.18))
            glVertex3f(sx, sy, sz)
        glEnd()

        # ── Data planet ──────────────────────────────────────────
        # (nama, radius_orbit, orbit_speed, tilt_deg,
        #  planet_radius, rot_speed, axial_tilt,
        #  bands: list of (R,G,B))
        planets = [
            ("Venus",    13,  0.041, 15,
             1.4, -0.004, 2.6,
             [(0.95,0.88,0.65),(0.90,0.80,0.55),(0.85,0.75,0.50),(0.80,0.70,0.45)]),

            ("Bumi",     19,  0.063, -8,
             1.5,  0.290, 23.4,
             [(0.10,0.30,0.80),(0.15,0.55,0.25),(0.10,0.35,0.75),(0.20,0.55,0.20),(0.08,0.25,0.70)]),

            ("Mars",     25,  0.053, 20,
             1.1,  0.244, 25.2,
             [(0.80,0.30,0.10),(0.72,0.24,0.08),(0.60,0.20,0.06),(0.50,0.15,0.05)]),

            ("Jupiter",  34,  0.031, -5,
             3.5,  0.413,  3.1,
             [(0.80,0.60,0.40),(0.70,0.50,0.30),(0.85,0.65,0.45),
              (0.65,0.45,0.28),(0.80,0.58,0.38),(0.70,0.50,0.32),
              (0.60,0.42,0.25),(0.78,0.56,0.36)]),

            ("Saturnus", 45,  0.022, 10,
             2.8,  0.380, 26.7,
             [(0.90,0.80,0.55),(0.82,0.72,0.48),(0.78,0.68,0.44),(0.85,0.75,0.50)]),

            ("Uranus",   56,  0.018,-18,
             2.2, -0.140, 97.8,
             [(0.40,0.80,0.90),(0.35,0.75,0.85),(0.30,0.70,0.82),(0.38,0.78,0.88)]),

            ("Neptunus", 67,  0.014,  5,
             2.1,  0.150, 28.3,
             [(0.10,0.20,0.85),(0.08,0.18,0.78),(0.12,0.22,0.90),(0.06,0.15,0.75)]),
        ]

        # Warna atmosfer tiap planet
        atm_colors = {
            "Venus":    (0.95,0.85,0.40,0.25),
            "Bumi":     (0.20,0.45,1.00,0.22),
            "Mars":     (0.80,0.25,0.10,0.18),
            "Jupiter":  (0.80,0.55,0.30,0.14),
            "Saturnus": (0.88,0.78,0.50,0.14),
            "Uranus":   (0.35,0.80,0.90,0.22),
            "Neptunus": (0.10,0.20,0.90,0.22),
        }

        q = gluNewQuadric()
        gluQuadricNormals(q, GLU_SMOOTH)

        for (name, orb_r, orb_spd, tilt_deg,
             p_r, rot_spd, axial, bands) in planets:

            # Hitung posisi orbit di bidang yang miring
            angle_orb = t * orb_spd
            tilt_r    = math.radians(tilt_deg)
            cos_t, sin_t = math.cos(tilt_r), math.sin(tilt_r)

            ox = orb_r * math.cos(angle_orb)
            oz = orb_r * math.sin(angle_orb)
            # Orbit sedikit naik-turun (eliptik ringan)
            oy = orb_r * 0.08 * math.sin(angle_orb * 1.3)

            # Putar bidang orbit
            px_w =  ox * cos_t + oy * sin_t
            py_w = -ox * sin_t + oy * cos_t
            pz_w =  oz

            self_rot = (t * rot_spd * 57.2958) % 360.0

            # ── Bola planet ────────────────────────────
            glPushMatrix()
            glTranslatef(px_w, py_w, pz_w)
            glRotatef(axial,    0, 0, 1)
            glRotatef(self_rot, 0, 1, 0)

            STACKS = 28
            SLICES = 40
            n_bands = len(bands)
            for si in range(STACKS):
                lat0 = math.pi * (-0.5 + si     / STACKS)
                lat1 = math.pi * (-0.5 + (si+1) / STACKS)
                frac = si / STACKS
                bi   = min(int(frac * (n_bands-1)), n_bands-2)
                tf   = frac * (n_bands-1) - bi
                c0, c1 = bands[bi], bands[bi+1]
                r_ = c0[0]*(1-tf) + c1[0]*tf
                g_ = c0[1]*(1-tf) + c1[1]*tf
                b_ = c0[2]*(1-tf) + c1[2]*tf
                # Shading dari sisi: terang di atas, gelap di bawah
                lit = 0.50 + 0.50 * math.sin(lat0 + math.pi/2)
                glColor3f(min(1.0,r_*lit), min(1.0,g_*lit), min(1.0,b_*lit))
                glBegin(GL_QUAD_STRIP)
                for sli in range(SLICES+1):
                    lng = 2*math.pi * sli / SLICES
                    for lat in (lat0, lat1):
                        nx = math.cos(lat) * math.cos(lng)
                        ny = math.sin(lat)
                        nz = math.cos(lat) * math.sin(lng)
                        glVertex3f(nx*p_r, ny*p_r, nz*p_r)
                glEnd()

            # Atmosfer glow
            ac = atm_colors.get(name, (0.8,0.8,1.0,0.15))
            glColor4f(*ac)
            gluSphere(q, p_r*1.10, 24, 24)
            glPopMatrix()

            # ── Ring Saturnus ──────────────────────────
            if name == "Saturnus":
                glPushMatrix()
                glTranslatef(px_w, py_w, pz_w)
                glRotatef(axial + 15, 1, 0, 0)
                ring_bands = [
                    (p_r*1.25, p_r*1.55, 0.85,0.76,0.56, 0.60),
                    (p_r*1.58, p_r*1.95, 0.80,0.70,0.50, 0.45),
                    (p_r*1.98, p_r*2.30, 0.74,0.64,0.44, 0.30),
                    (p_r*2.33, p_r*2.55, 0.68,0.58,0.38, 0.18),
                ]
                RING_SEG = 80
                glBegin(GL_QUADS)
                for r_in, r_out, rr,gg,bb,aa in ring_bands:
                    glColor4f(rr, gg, bb, aa)
                    for i in range(RING_SEG):
                        a0 = 2*math.pi * i     / RING_SEG
                        a1 = 2*math.pi * (i+1) / RING_SEG
                        glVertex3f(r_in  * math.cos(a0), 0, r_in  * math.sin(a0))
                        glVertex3f(r_in  * math.cos(a1), 0, r_in  * math.sin(a1))
                        glVertex3f(r_out * math.cos(a1), 0, r_out * math.sin(a1))
                        glVertex3f(r_out * math.cos(a0), 0, r_out * math.sin(a0))
                glEnd()
                glPopMatrix()

        gluDeleteQuadric(q)
        glEnable(GL_LIGHTING)

    def _draw_ocean_background(self):
        """
        Latar bawah laut Level 3: Atlantis & Lautan Dalam.
        Lapisan:
          1. Dasar laut berpasir + bebatuan karang jauh
          2. Partikel plankton bioluminesen melayang
          3. Sinar cahaya matahari menembus permukaan (god rays)
          4. Gelembung naik perlahan
          5. Ikan & ubur-ubur siluet di kejauhan
          6. Pilar Atlantis & reruntuhan kota jauh
        """
        # Reset cache posisi jika masih pakai posisi lama (dekat papan)
        if hasattr(self, '_jellyfish') and len(self._jellyfish) > 0:
            jx, jy, jz = self._jellyfish[0][:3]
            if abs(jx) < 15:  # posisi lama terlalu dekat
                del self._jellyfish
        if hasattr(self, '_fish_schools') and len(self._fish_schools) > 0:
            if self._fish_schools[0][0] < 20:  # radius lama terlalu dekat
                del self._fish_schools
        if hasattr(self, '_jellyfish') and hasattr(self, '_jellyfish') and \
           hasattr(self, '_ocean_floor') and hasattr(self, '_god_rays'):
            pass  # cache valid

        glDisable(GL_LIGHTING)
        glEnable(GL_DEPTH_TEST)
        glEnable(GL_BLEND)
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

        t = self.neon_t if hasattr(self, 'neon_t') else 0.0

        # ── 1. DASAR LAUT — pasir & lumpur ────────────────────
        # Lapisan jauh (fog bawah laut)
        glColor4f(0.02, 0.06, 0.14, 1.0)
        glBegin(GL_QUADS)
        glVertex3f(-200, -60, -200); glVertex3f(200, -60, -200)
        glVertex3f(200, -60, 200);   glVertex3f(-200, -60, 200)
        glEnd()

        # Reset cache jika batu terlalu besar (dari versi lama)
        if hasattr(self, '_ocean_rocks') and self._ocean_rocks:
            if self._ocean_rocks[0][2] > 2.0:  # rs lama terlalu besar
                del self._ocean_rocks
                if hasattr(self,'_ocean_floor'): del self._ocean_floor

        # Dasar laut bergelombang — pasir dan lumpur
        if not hasattr(self, '_ocean_floor'):
            import random as _rf
            self._ocean_floor = [
                (_rf.uniform(-120, 120), _rf.uniform(-120, 120),
                 _rf.uniform(0.3, 1.5), _rf.uniform(0.4, 1.8),
                 _rf.uniform(0, 2*math.pi))
                for _ in range(80)
            ]
            # Batu-batu karang — kecil dan jauh di bawah
            self._ocean_rocks = [
                (_rf.uniform(-100, 100), _rf.uniform(-100, 100),
                 _rf.uniform(0.4, 1.8),  # Scale max 1.8 (bukan 5.0)
                 _rf.uniform(0, 2*math.pi),
                 _rf.choice([(0.05,0.18,0.22),(0.08,0.22,0.18),(0.12,0.25,0.20)]))
                for _ in range(30)
            ]

        # Hamparan pasir — di bawah papan
        glColor4f(0.06, 0.12, 0.18, 0.85)
        glBegin(GL_QUADS)
        glVertex3f(-150, -30, -150); glVertex3f(150, -30, -150)
        glVertex3f(150, -30, 150);   glVertex3f(-150, -30, 150)
        glEnd()

        # Batu karang dasar — dikurangi skala, ditenggelamkan lebih dalam
        for rx3, rz3, rs, ra, rc in self._ocean_rocks:
            ry3 = -30.0  # Tetap di bawah, tidak naik
            glColor4f(*rc, 0.7)
            glPushMatrix()
            glTranslatef(rx3, ry3, rz3)
            glRotatef(math.degrees(ra), 0, 1, 0)
            glScalef(rs, rs*0.4, rs)  # Lebih pipih (0.4 bukan 0.6)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0, 0.6, 0)  # Puncak lebih rendah
            for i in range(9):
                a2 = i * (2*math.pi/8)
                glVertex3f(math.cos(a2), -0.2, math.sin(a2))
            glEnd()
            glPopMatrix()

        # ── 2. GOD RAYS — sinar matahari menembus air ─────────
        if not hasattr(self, '_god_rays'):
            import random as _rg
            self._god_rays = [
                (_rg.uniform(-80, 80), _rg.uniform(-80, 80),
                 _rg.uniform(0.6, 1.5), _rg.uniform(0.3, 1.2))
                for _ in range(12)
            ]

        glEnable(GL_BLEND)
        glBlendFunc(GL_SRC_ALPHA, GL_ONE)  # Additive blend untuk glow
        for rx4, rz4, rw, rspd in self._god_rays:
            pulse_r = 0.04 + 0.025 * math.sin(t * rspd + rx4 * 0.05)
            # Sinar dari atas (y=200) ke bawah (y=-20), memudar ke bawah
            for seg in range(5):
                frac_top = 1.0 - seg * 0.18
                frac_bot = 1.0 - (seg+1) * 0.18
                y_top = 200 - seg * 45
                y_bot = 200 - (seg+1) * 45
                alpha_top = pulse_r * frac_top
                alpha_bot = pulse_r * frac_bot
                hw = rw * (1.0 + seg * 0.3)
                glBegin(GL_QUADS)
                glColor4f(0.25, 0.60, 0.85, alpha_top)
                glVertex3f(rx4 - hw, y_top, rz4)
                glVertex3f(rx4 + hw, y_top, rz4)
                glColor4f(0.15, 0.45, 0.70, alpha_bot)
                glVertex3f(rx4 + hw*1.4, y_bot, rz4)
                glVertex3f(rx4 - hw*1.4, y_bot, rz4)
                glEnd()
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

        # ── 3. PLANKTON BIOLUMINESEN — titik-titik cahaya melayang ──
        if not hasattr(self, '_plankton'):
            import random as _rp2
            self._plankton = [
                (_rp2.uniform(-90, 90),
                 _rp2.uniform(-25, 150),
                 _rp2.uniform(-90, 90),
                 _rp2.uniform(0, 2*math.pi),
                 _rp2.uniform(0.2, 0.8),
                 _rp2.choice([
                     (0.0, 0.9, 0.8),   # Toska
                     (0.2, 0.7, 1.0),   # Biru muda
                     (0.0, 1.0, 0.6),   # Hijau neon
                     (0.4, 0.8, 1.0),   # Biru langit
                 ]))
                for _ in range(200)
            ]

        glEnable(GL_BLEND)
        glBlendFunc(GL_SRC_ALPHA, GL_ONE)
        glPointSize(2.5)
        glBegin(GL_POINTS)
        for px5, py5, pz5, poff, pspd, (pr, pg, pb) in self._plankton:
            # Naik perlahan dan bergoyang
            drift_y = (py5 + t * pspd * 3.0) % 180 - 30
            drift_x = px5 + math.sin(t * pspd + poff) * 1.5
            # Kedip lembut bioluminesen
            bright = 0.3 + 0.4 * abs(math.sin(t * pspd * 1.5 + poff))
            alpha  = 0.4 + 0.3 * bright
            # Makin jauh dari papan makin redup
            dist_fade = max(0, 1.0 - (abs(drift_y - 30) / 150))
            glColor4f(pr * bright, pg * bright, pb * bright, alpha * dist_fade)
            glVertex3f(drift_x, drift_y, pz5)
        glEnd()
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

        # ── 4. GELEMBUNG UDARA — naik dekat pinggir papan ────────────────
        if not hasattr(self, '_bubbles'):
            import random as _rb
            self._bubbles = [
                (_rb.uniform(-9, 9),        # x dekat papan (±9)
                 _rb.uniform(-5, 20),        # y mulai dari bawah papan
                 _rb.uniform(-9, 9),         # z dekat papan
                 _rb.uniform(0.05, 0.20),    # radius kecil (skala papan)
                 _rb.uniform(1.5, 5.0),      # kecepatan naik
                 _rb.uniform(0, 2*math.pi))  # phase
                for _ in range(60)
            ]

        glBlendFunc(GL_SRC_ALPHA, GL_ONE)
        for bx, by, bz, br, bspd, bph in self._bubbles:
            brise = (by + t * bspd * 0.8) % 28 - 5   # loop dari y=-5 s/d y=23
            bx2   = bx + math.sin(t * 0.5 + bph) * 0.3
            # Makin tinggi makin redup (hilang di atas)
            alpha_b = max(0, 0.35 * (1.0 - max(0, brise - 8) / 15.0))
            if alpha_b < 0.01: continue
            glColor4f(0.4, 0.85, 1.0, alpha_b)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(bx2, brise, bz)
            for i in range(9):
                a2 = i * (2*math.pi/8)
                glVertex3f(bx2 + math.cos(a2)*br,
                           brise + math.sin(a2)*br*0.5,
                           bz + math.sin(a2)*br)
            glEnd()
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

        # ── 5. PILAR ATLANTIS — silinder 3D natural bawah laut ──────────
        pillar_data = [
            (-38.0, -3.0, -35.0,  0.55, 5.5,  (0.12, 0.32, 0.36)),
            ( 40.0, -3.0, -32.0,  0.45, 7.0,  (0.09, 0.26, 0.32)),
            (-42.0, -3.0,  30.0,  0.65, 4.5,  (0.14, 0.34, 0.38)),
            ( 36.0, -3.0,  40.0,  0.50, 6.0,  (0.10, 0.28, 0.33)),
            (-30.0, -3.0, -42.0,  0.40, 4.0,  (0.08, 0.24, 0.30)),
            ( 44.0, -3.0,  22.0,  0.60, 5.5,  (0.13, 0.30, 0.35)),
            ( 32.0, -3.0, -40.0,  0.45, 4.5,  (0.09, 0.25, 0.31)),
            (-45.0, -3.0,   8.0,  0.62, 6.0,  (0.11, 0.29, 0.34)),
            (  0.0, -3.0, -48.0,  0.48, 5.0,  (0.10, 0.27, 0.32)),
            (  0.0, -3.0,  48.0,  0.55, 6.0,  (0.11, 0.28, 0.33)),
            (-48.0, -3.0, -18.0,  0.38, 4.0,  (0.08, 0.22, 0.28)),
            ( 48.0, -3.0,  16.0,  0.42, 5.0,  (0.10, 0.26, 0.31)),
        ]

        SEGS = 12
        for px6, py6, pz6, pr6, ph6, col6 in pillar_data:
            algae_p  = 0.22 + 0.10 * math.sin(t * 0.35 + px6 * 0.25)
            bio_glow = 0.18 + 0.10 * math.sin(t * 0.55 + pz6 * 0.20)

            # ── Badan silinder utama ──────────────────────────
            for seg in range(SEGS):
                a0 = seg       * (2*math.pi / SEGS)
                a1 = (seg + 1) * (2*math.pi / SEGS)
                x0 = math.cos(a0) * pr6;  z0 = math.sin(a0) * pr6
                x1 = math.cos(a1) * pr6;  z1 = math.sin(a1) * pr6
                light = 0.55 + 0.45 * math.cos(a0 + math.pi * 0.3)
                r = min(1.0, col6[0] * light * 1.8)
                g = min(1.0, col6[1] * light * 1.8)
                b = min(1.0, col6[2] * light * 1.8)
                glBegin(GL_QUADS)
                glColor4f(r * 1.15, g * 1.15, b * 1.15, 0.88)
                glVertex3f(px6+x0, py6+ph6, pz6+z0)
                glVertex3f(px6+x1, py6+ph6, pz6+z1)
                glColor4f(r * 0.55, g * 0.55, b * 0.55, 0.95)
                glVertex3f(px6+x1, py6,      pz6+z1)
                glVertex3f(px6+x0, py6,      pz6+z0)
                glEnd()

            # ── Tutup atas ────────────────────────────────────
            glColor4f(col6[0]*1.6, col6[1]*1.6, col6[2]*1.6, 0.80)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(px6, py6+ph6, pz6)
            for seg in range(SEGS + 1):
                a = seg * (2*math.pi / SEGS)
                glVertex3f(px6+math.cos(a)*pr6, py6+ph6, pz6+math.sin(a)*pr6)
            glEnd()

            # ── Mahkota pilar Atlantis ────────────────────────
            crown_r = pr6 * 1.35
            crown_h = 0.28
            glColor4f(col6[0]*1.4, col6[1]*2.0, col6[2]*2.2, 0.75)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(px6, py6+ph6+crown_h, pz6)
            for seg in range(SEGS + 1):
                a = seg * (2*math.pi / SEGS)
                glVertex3f(px6+math.cos(a)*crown_r, py6+ph6, pz6+math.sin(a)*crown_r)
            glEnd()
            for seg in range(SEGS):
                a0 = seg       * (2*math.pi / SEGS)
                a1 = (seg + 1) * (2*math.pi / SEGS)
                glBegin(GL_QUADS)
                glColor4f(col6[0]*1.2, col6[1]*1.8, col6[2]*2.0, 0.60)
                glVertex3f(px6+math.cos(a0)*crown_r, py6+ph6,      pz6+math.sin(a0)*crown_r)
                glVertex3f(px6+math.cos(a1)*crown_r, py6+ph6,      pz6+math.sin(a1)*crown_r)
                glColor4f(col6[0]*0.8, col6[1]*1.2, col6[2]*1.4, 0.40)
                glVertex3f(px6+math.cos(a1)*pr6,     py6+ph6-0.18, pz6+math.sin(a1)*pr6)
                glVertex3f(px6+math.cos(a0)*pr6,     py6+ph6-0.18, pz6+math.sin(a0)*pr6)
                glEnd()

            # ── Alas pilar — fondasi batu ─────────────────────
            base_r = pr6 * 1.5
            base_h = 0.35
            for seg in range(SEGS):
                a0 = seg       * (2*math.pi / SEGS)
                a1 = (seg + 1) * (2*math.pi / SEGS)
                light_b = 0.5 + 0.35 * math.cos(a0)
                glBegin(GL_QUADS)
                glColor4f(col6[0]*light_b*1.1, col6[1]*light_b*1.1, col6[2]*light_b*1.1, 0.90)
                glVertex3f(px6+math.cos(a0)*base_r, py6+base_h, pz6+math.sin(a0)*base_r)
                glVertex3f(px6+math.cos(a1)*base_r, py6+base_h, pz6+math.sin(a1)*base_r)
                glColor4f(col6[0]*0.5, col6[1]*0.5, col6[2]*0.5, 0.95)
                glVertex3f(px6+math.cos(a1)*base_r, py6,        pz6+math.sin(a1)*base_r)
                glVertex3f(px6+math.cos(a0)*base_r, py6,        pz6+math.sin(a0)*base_r)
                glEnd()
            glColor4f(col6[0]*1.2, col6[1]*1.2, col6[2]*1.2, 0.85)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(px6, py6+base_h, pz6)
            for seg in range(SEGS + 1):
                a = seg * (2*math.pi / SEGS)
                glVertex3f(px6+math.cos(a)*base_r, py6+base_h, pz6+math.sin(a)*base_r)
            glEnd()

            # ── Lumut alga berlapis ───────────────────────────
            algae_h = ph6 * 0.55
            for seg in range(SEGS):
                a0 = seg       * (2*math.pi / SEGS)
                a1 = (seg + 1) * (2*math.pi / SEGS)
                x0 = math.cos(a0)*(pr6+0.04); z0 = math.sin(a0)*(pr6+0.04)
                x1 = math.cos(a1)*(pr6+0.04); z1 = math.sin(a1)*(pr6+0.04)
                wave_a = algae_p + 0.05*math.sin(t*0.4 + a0*3)
                glBegin(GL_QUADS)
                glColor4f(0.02, wave_a*0.7,  wave_a*0.45, 0.55)
                glVertex3f(px6+x0, py6+algae_h, pz6+z0)
                glVertex3f(px6+x1, py6+algae_h, pz6+z1)
                glColor4f(0.03, wave_a*0.5,  wave_a*0.30, 0.70)
                glVertex3f(px6+x1, py6+base_h,  pz6+z1)
                glVertex3f(px6+x0, py6+base_h,  pz6+z0)
                glEnd()
            algae_h2 = ph6 * 0.30
            for seg in range(SEGS):
                a0 = seg       * (2*math.pi / SEGS)
                a1 = (seg + 1) * (2*math.pi / SEGS)
                x0 = math.cos(a0)*(pr6+0.03); z0 = math.sin(a0)*(pr6+0.03)
                x1 = math.cos(a1)*(pr6+0.03); z1 = math.sin(a1)*(pr6+0.03)
                wave_b = bio_glow + 0.06*math.sin(t*0.6 + a0*2 + 1.5)
                glBegin(GL_QUADS)
                glColor4f(0.0, wave_b*1.1, wave_b*0.9, 0.35)
                glVertex3f(px6+x0, py6+algae_h+algae_h2, pz6+z0)
                glVertex3f(px6+x1, py6+algae_h+algae_h2, pz6+z1)
                glColor4f(0.0, wave_b*0.8, wave_b*0.6,   0.50)
                glVertex3f(px6+x1, py6+algae_h,           pz6+z1)
                glVertex3f(px6+x0, py6+algae_h,           pz6+z0)
                glEnd()

            # ── Retakan batu kuno ─────────────────────────────
            for crack_h in [ph6*0.25, ph6*0.50, ph6*0.75]:
                glColor4f(col6[0]*0.4, col6[1]*0.4, col6[2]*0.4, 0.50)
                glBegin(GL_LINE_LOOP)
                for seg in range(SEGS):
                    a = seg * (2*math.pi / SEGS)
                    wiggle = 0.015 * math.sin(seg * 2.3 + px6)
                    glVertex3f(px6+math.cos(a)*(pr6+0.01+wiggle),
                               py6+crack_h,
                               pz6+math.sin(a)*(pr6+0.01+wiggle))
                glEnd()

            # ── Glow bioluminesen di puncak ───────────────────
            glBlendFunc(GL_SRC_ALPHA, GL_ONE)
            tip_glow = 0.5 + 0.4 * math.sin(t * 1.2 + px6 * 0.3)
            glColor4f(0.0, tip_glow*0.9, tip_glow*0.8, tip_glow*0.6)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(px6, py6+ph6+crown_h+0.12, pz6)
            for seg in range(SEGS + 1):
                a = seg * (2*math.pi / SEGS)
                glVertex3f(px6+math.cos(a)*0.25, py6+ph6+crown_h, pz6+math.sin(a)*0.25)
            glEnd()
            glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)


        # ── 6. UBUR-UBUR — melayang tepat di sekeliling papan ────────────
        if not hasattr(self, '_jellyfish'):
            import random as _rj
            # Letakkan di radius 22–35 agar tidak menutupi papan
            jellyfish_positions = [
                (-24.0, 4.0, -20.0),
                ( 26.0, 6.0, -22.0),
                (-28.0, 3.0,  22.0),
                ( 22.0, 8.0,  26.0),
                (-30.0, 5.0,   3.0),
                ( 30.0, 4.0,  -5.0),
                (  6.0, 7.0, -28.0),
                ( -9.0, 5.0,  30.0),
                ( 20.0, 9.0,  14.0),
                (-22.0, 6.0, -24.0),
                (  2.0, 4.5, -30.0),
                (-32.0, 7.0,  14.0),
                ( 14.0, 3.5,  28.0),
                (-16.0, 8.0,  26.0),
                ( 28.0, 5.0,  18.0),
            ]
            self._jellyfish = [
                (*jellyfish_positions[i],
                 _rj.uniform(0.4, 1.2),   # ukuran (skala papan)
                 _rj.uniform(0.3, 1.0),   # kecepatan
                 _rj.uniform(0, 2*math.pi),
                 _rj.choice([
                     (0.2, 0.8, 1.0),
                     (0.6, 0.2, 0.9),
                     (0.0, 0.9, 0.7),
                     (0.8, 0.3, 0.6),
                 ]))
                for i in range(15)
            ]

        glBlendFunc(GL_SRC_ALPHA, GL_ONE)
        for jx, jy, jz, js, jspd, jph, (jr, jg, jb) in self._jellyfish:
            # Melayang naik-turun di tempat, bergoyang ke samping
            jy2 = jy + math.sin(t * jspd * 0.5 + jph) * 1.8
            jx2 = jx + math.sin(t * jspd * 0.25 + jph + 1) * 0.8
            pulse_j = 0.45 + 0.30 * math.sin(t * jspd * 2.0 + jph)

            # Kubah ubur-ubur
            glColor4f(jr*pulse_j, jg*pulse_j, jb*pulse_j, 0.50)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(jx2, jy2, jz)
            for i in range(17):
                a2 = i * (2*math.pi/16)
                yscale = 0.45 + 0.20 * math.sin(t * jspd * 1.5 + jph)
                glVertex3f(jx2 + math.cos(a2)*js,
                           jy2 - yscale*js,
                           jz  + math.sin(a2)*js)
            glEnd()
            # Cincin bawah kubah — sedikit lebih terang
            glColor4f(jr*pulse_j*1.2, jg*pulse_j*1.2, jb*pulse_j*1.2, 0.30)
            glBegin(GL_LINE_LOOP)
            for i in range(17):
                a2 = i * (2*math.pi/16)
                yscale = 0.45 + 0.20 * math.sin(t * jspd * 1.5 + jph)
                glVertex3f(jx2 + math.cos(a2)*js,
                           jy2 - yscale*js,
                           jz  + math.sin(a2)*js)
            glEnd()
            # Tentakel — melambai mengikuti arus
            glColor4f(jr*pulse_j*0.8, jg*pulse_j*0.8, jb*pulse_j*0.8, 0.30)
            for ti in range(6):
                ta = ti * (2*math.pi/6) + jph
                tx = jx2 + math.cos(ta) * js * 0.5
                tz = jz  + math.sin(ta) * js * 0.5
                for seg in range(5):
                    frac = seg / 5.0
                    wave = math.sin(t * jspd * 1.8 + jph + seg * 1.0) * 0.3
                    glBegin(GL_QUADS)
                    glVertex3f(tx + wave, jy2 - frac*js*2.5,       tz)
                    glVertex3f(tx + wave + 0.04, jy2 - frac*js*2.5, tz)
                    glVertex3f(tx + wave + 0.04, jy2 - (frac+0.2)*js*2.5, tz)
                    glVertex3f(tx + wave,        jy2 - (frac+0.2)*js*2.5, tz)
                    glEnd()
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

        # ── 7. IKAN — berputar mengelilingi papan ──────────────────────────
        if not hasattr(self, '_fish_schools'):
            import random as _rfs
            # Radius orbit 28–40 unit, jauh dari papan
            self._fish_schools = [
                (_rfs.uniform(28, 40),      # radius orbit
                 _rfs.uniform(1.5, 7.0),   # tinggi y
                 _rfs.uniform(0.4, 1.2),   # kecepatan orbit
                 _rfs.randint(6, 12),      # jumlah ikan
                 _rfs.uniform(0, 2*math.pi),# fase awal
                 _rfs.uniform(-1, 1))      # arah
                for _ in range(6)
            ]

        for frad, fy, fspd, fcount, fph, fdir in self._fish_schools:
            # Pusat kelompok berputar mengelilingi papan
            school_angle = t * fspd * 0.12 * fdir + fph
            cx_school = math.cos(school_angle) * frad
            cz_school = math.sin(school_angle) * frad
            fy2 = fy + math.sin(t * fspd * 0.3 + fph) * 1.0

            for fi in range(fcount):
                fi_off = fi * (2*math.pi/fcount)
                fish_x = cx_school + math.cos(fi_off) * 1.2
                fish_z = cz_school + math.sin(fi_off) * 1.2
                fish_y = fy2 + math.sin(fi_off * 2 + t * 0.8) * 0.4

                # Arah gerak ikan (menghadap arah orbit)
                face_angle = school_angle + math.pi/2 * fdir
                fdx = math.cos(face_angle) * 0.55
                fdz = math.sin(face_angle) * 0.55

                # Badan ikan — warna toska transparan
                glColor4f(0.05, 0.45, 0.55, 0.65)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(fish_x, fish_y, fish_z)
                for i in range(7):
                    a2 = i * (2*math.pi/6)
                    glVertex3f(fish_x + math.cos(a2)*0.45,
                               fish_y + math.sin(a2)*0.18,
                               fish_z + math.sin(a2)*0.08)
                glEnd()
                # Sirip ekor — segitiga
                glColor4f(0.0, 0.55, 0.65, 0.50)
                glBegin(GL_TRIANGLES)
                glVertex3f(fish_x - fdx, fish_y, fish_z - fdz)
                glVertex3f(fish_x - fdx*1.8, fish_y + 0.28, fish_z - fdz*1.8)
                glVertex3f(fish_x - fdx*1.8, fish_y - 0.28, fish_z - fdz*1.8)
                glEnd()

        # ── 8. FOG BAWAH LAUT — gradien kedalaman ─────────────
        # Overlay biru gelap transparan di lapisan jauh untuk efek kedalaman
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
        fog_layers = [
            (-200, 200, 80,  0.28),
            (-200, 200, 120, 0.20),
            (-200, 200, 160, 0.15),
        ]
        for fy3, fsize, fdist, falpha in fog_layers:
            glColor4f(0.01, 0.05, 0.15, falpha)
            glBegin(GL_QUADS)
            glVertex3f(-fsize, fy3, -fdist)
            glVertex3f( fsize, fy3, -fdist)
            glVertex3f( fsize, fy3,  fdist)
            glVertex3f(-fsize, fy3,  fdist)
            glEnd()

        glEnable(GL_LIGHTING)
        # Reset GL state penuh setelah ocean background
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
        glDepthMask(True)
        glEnable(GL_DEPTH_TEST)
        glPointSize(1.0)
        glLineWidth(1.0)

    def _draw_board(self):
        """Papan 3D — Level 1: hijau klasik, Level 2: galaksi neon gelap, Level 3: Atlantis bawah laut."""
        glDisable(GL_LIGHTING)

        BD  = 0.30
        TOP = 0.0
        BOT = -BD
        BV  = 0.18
        F   = 0.002

        L2 = (self.level == 2)
        L3 = (self.level == 3)
        t_now = self.neon_t if hasattr(self, 'neon_t') else 0.0

        # ── Alas bawah ────────────────────────────────────
        if L3:
            glColor3f(0.03, 0.10, 0.16)   # Biru laut dalam
        elif L2:
            glColor3f(0.02, 0.02, 0.02)
        else:
            glColor3f(0.28, 0.18, 0.09)
        glBegin(GL_QUADS)
        glVertex3f(-6.3,BOT,-6.3); glVertex3f(6.3,BOT,-6.3)
        glVertex3f(6.3,BOT,6.3);   glVertex3f(-6.3,BOT,6.3)
        glEnd()

        # ── Sisi papan ────────────────────────────────────
        if L3:
            # Atlantis — batu karang tua biru-hijau gelap
            sides_l3 = [
                ((0.06, 0.18, 0.22), [(-6.3,BOT,6.3),(6.3,BOT,6.3),(6.3,TOP,6.3),(-6.3,TOP,6.3)]),
                ((0.05, 0.15, 0.20), [(6.3,BOT,-6.3),(-6.3,BOT,-6.3),(-6.3,TOP,-6.3),(6.3,TOP,-6.3)]),
                ((0.05, 0.16, 0.21), [(-6.3,BOT,-6.3),(-6.3,BOT,6.3),(-6.3,TOP,6.3),(-6.3,TOP,-6.3)]),
                ((0.05, 0.16, 0.21), [(6.3,BOT,6.3),(6.3,BOT,-6.3),(6.3,TOP,-6.3),(6.3,TOP,6.3)]),
            ]
            for col, verts in sides_l3:
                glColor3f(*col)
                glBegin(GL_QUADS)
                for v in verts: glVertex3f(*v)
                glEnd()
        elif L2:
            glColor3f(0.18, 0.05, 0.35)  # Ungu neon gelap
            for verts in [
                [(-6.3,BOT,6.3),(6.3,BOT,6.3),(6.3,TOP,6.3),(-6.3,TOP,6.3)],
                [(6.3,BOT,-6.3),(-6.3,BOT,-6.3),(-6.3,TOP,-6.3),(6.3,TOP,-6.3)],
                [(-6.3,BOT,-6.3),(-6.3,BOT,6.3),(-6.3,TOP,6.3),(-6.3,TOP,-6.3)],
                [(6.3,BOT,6.3),(6.3,BOT,-6.3),(6.3,TOP,-6.3),(6.3,TOP,6.3)],
            ]:
                glBegin(GL_QUADS)
                for v in verts: glVertex3f(*v)
                glEnd()
        else:
            sides = [
                ((0.35,0.22,0.10), [(-6.3,BOT,6.3),(6.3,BOT,6.3),(6.3,TOP,6.3),(-6.3,TOP,6.3)]),
                ((0.30,0.19,0.09), [(6.3,BOT,-6.3),(-6.3,BOT,-6.3),(-6.3,TOP,-6.3),(6.3,TOP,-6.3)]),
                ((0.32,0.20,0.09), [(-6.3,BOT,-6.3),(-6.3,BOT,6.3),(-6.3,TOP,6.3),(-6.3,TOP,-6.3)]),
                ((0.32,0.20,0.09), [(6.3,BOT,6.3),(6.3,BOT,-6.3),(6.3,TOP,-6.3),(6.3,TOP,6.3)]),
            ]
            for col, verts in sides:
                glColor3f(*col)
                glBegin(GL_QUADS)
                for v in verts: glVertex3f(*v)
                glEnd()

        # ── Tepi bevel ────────────────────────────────────
        if L3:
            # Emas Atlantis berkilauan — toska + emas
            pulse_bv = 0.5 + 0.2 * math.sin(t_now * 0.8)
            bevel_col = (pulse_bv * 0.20, pulse_bv * 0.70, pulse_bv * 0.75)
        elif L2:
            bevel_col = (0.40, 0.12, 0.70)
        else:
            bevel_col = (0.90, 0.86, 0.74)
        glColor3f(*bevel_col)
        # Sisi depan (z+)
        glBegin(GL_QUADS)
        glVertex3f(-6.3,    TOP,  6.3)
        glVertex3f( 6.3,    TOP,  6.3)
        glVertex3f( 6.3-BV, TOP,  6.3-BV)
        glVertex3f(-6.3+BV, TOP,  6.3-BV)
        glEnd()
        # Sisi belakang (z-)
        glBegin(GL_QUADS)
        glVertex3f( 6.3,    TOP, -6.3)
        glVertex3f(-6.3,    TOP, -6.3)
        glVertex3f(-6.3+BV, TOP, -6.3+BV)
        glVertex3f( 6.3-BV, TOP, -6.3+BV)
        glEnd()
        # Sisi kiri (x-)
        glBegin(GL_QUADS)
        glVertex3f(-6.3, TOP, -6.3)
        glVertex3f(-6.3, TOP,  6.3)
        glVertex3f(-6.3+BV, TOP,  6.3-BV)
        glVertex3f(-6.3+BV, TOP, -6.3+BV)
        glEnd()
        # Sisi kanan (x+)
        glBegin(GL_QUADS)
        glVertex3f( 6.3, TOP,  6.3)
        glVertex3f( 6.3, TOP, -6.3)
        glVertex3f( 6.3-BV, TOP, -6.3+BV)
        glVertex3f( 6.3-BV, TOP,  6.3-BV)
        glEnd()
        glBegin(GL_TRIANGLES)
        glVertex3f(-6.3,    TOP,  6.3);    glVertex3f(-6.3+BV, TOP, 6.3-BV); glVertex3f(-6.3+BV, TOP, 6.3-BV)
        glVertex3f( 6.3,    TOP,  6.3);    glVertex3f( 6.3-BV, TOP, 6.3-BV); glVertex3f( 6.3-BV, TOP, 6.3-BV)
        glVertex3f(-6.3,    TOP, -6.3);    glVertex3f(-6.3+BV, TOP,-6.3+BV); glVertex3f(-6.3+BV, TOP,-6.3+BV)
        glVertex3f( 6.3,    TOP, -6.3);    glVertex3f( 6.3-BV, TOP,-6.3+BV); glVertex3f( 6.3-BV, TOP,-6.3+BV)
        glEnd()

        # ── Permukaan utama papan ─────────────────────────
        if L3:
            # Dasar laut berlumpur — biru-hijau gelap, sedikit beriak
            ripple_surf = 0.04 * math.sin(t_now * 0.6)
            glColor3f(0.04 + ripple_surf, 0.14, 0.20)
        elif L2:
            glColor3f(0.10, 0.14, 0.35)
        else:
            glColor3f(0.13, 0.28, 0.15)
        glBegin(GL_QUADS)
        glVertex3f(-6.3+BV,TOP+F,-6.3+BV); glVertex3f(6.3-BV,TOP+F,-6.3+BV)
        glVertex3f(6.3-BV,TOP+F,6.3-BV);   glVertex3f(-6.3+BV,TOP+F,6.3-BV)
        glEnd()

        # ── Area tengah ───────────────────────────────────
        if L3:
            glColor3f(0.03, 0.12, 0.18)
        elif L2:
            glColor3f(0.08, 0.12, 0.30)
        else:
            glColor3f(0.16, 0.35, 0.18)
        glBegin(GL_QUADS)
        glVertex3f(-4.0,TOP+F*2,-4.0); glVertex3f(4.0,TOP+F*2,-4.0)
        glVertex3f(4.0,TOP+F*2,4.0);   glVertex3f(-4.0,TOP+F*2,4.0)
        glEnd()

        # ── Dekorasi tengah ───────────────────────────────
        if L3:
            # ── ATLANTIS CENTER — kota melingkar, pilar, cahaya bioluminesen ──

            # Lantai Atlantis — batu kuno mozaik
            glColor3f(0.06, 0.18, 0.22)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0, TOP+F*3, 0)
            for i in range(33):
                a = i * (2*math.pi/32)
                glVertex3f(math.cos(a)*3.2, TOP+F*3, math.sin(a)*3.2)
            glEnd()

            # Ring karang luar — bergetar perlahan
            ring_pulse = 0.5 + 0.15 * math.sin(t_now * 0.5)
            glColor3f(0.08 * ring_pulse, 0.35 * ring_pulse, 0.40 * ring_pulse)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0, TOP+F*3+0.001, 0)
            for i in range(33):
                a = i * (2*math.pi/32)
                r_outer = 2.8 + 0.04 * math.sin(t_now * 0.7 + i * 0.4)
                glVertex3f(math.cos(a)*r_outer, TOP+F*3+0.001, math.sin(a)*r_outer)
            glEnd()

            # Ring tengah bioluminesen
            bio_pulse = 0.4 + 0.3 * math.sin(t_now * 1.2)
            glColor3f(0.0, bio_pulse * 0.8, bio_pulse * 0.7)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0, TOP+F*4, 0)
            for i in range(33):
                a = i * (2*math.pi/32)
                glVertex3f(math.cos(a)*2.0, TOP+F*4, math.sin(a)*2.0)
            glEnd()

            # Pola mozaik lantai Atlantis — garis geometris kuno
            glColor3f(0.10, 0.30, 0.35)
            for spoke in range(8):
                angle_s = spoke * (math.pi / 4) + t_now * 0.05
                x1 = math.cos(angle_s) * 0.3
                z1 = math.sin(angle_s) * 0.3
                x2 = math.cos(angle_s) * 2.6
                z2 = math.sin(angle_s) * 2.6
                glBegin(GL_QUADS)
                glVertex3f(x1 - 0.04, TOP+F*4+0.001, z1 - 0.04)
                glVertex3f(x1 + 0.04, TOP+F*4+0.001, z1 + 0.04)
                glVertex3f(x2 + 0.04, TOP+F*4+0.001, z2 + 0.04)
                glVertex3f(x2 - 0.04, TOP+F*4+0.001, z2 - 0.04)
                glEnd()

            # Simbol Atlantis — bintang laut 5 lengan berputar perlahan
            star_rot = t_now * 0.15
            glColor3f(0.15, 0.55, 0.60)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0, TOP+F*5, 0)
            for i in range(11):
                a = i * (2*math.pi/10) + star_rot
                r_star = 1.4 if i % 2 == 0 else 0.55
                glVertex3f(math.cos(a)*r_star, TOP+F*5, math.sin(a)*r_star)
            glEnd()

            # Inti Atlantis — glow bioluminesen berkilau
            core_glow = 0.6 + 0.35 * math.sin(t_now * 2.0)
            glColor3f(0.0, core_glow * 0.9, core_glow * 0.8)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0, TOP+F*6, 0)
            for i in range(33):
                a = i * (2*math.pi/32)
                glVertex3f(math.cos(a)*0.45, TOP+F*6, math.sin(a)*0.45)
            glEnd()

            # Cahaya inti paling terang
            core2 = 0.8 + 0.2 * math.sin(t_now * 3.5)
            glColor3f(core2 * 0.4, core2, core2 * 0.95)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0, TOP+F*3+0.02, 0)
            for i in range(17):
                a = i * (2*math.pi/16)
                glVertex3f(math.cos(a)*0.18, TOP+F*3+0.02, math.sin(a)*0.18)
            glEnd()

            # 4 pilar mini Atlantis di sudut tengah — sangat kecil, tidak mengganggu
            pilar_pos = [(-1.5,-1.5),(1.5,-1.5),(-1.5,1.5),(1.5,1.5)]
            for ppx, ppz in pilar_pos:
                pilar_pulse = 0.3 + 0.15 * math.sin(t_now * 0.8 + ppx)
                glColor3f(0.08, pilar_pulse * 0.6, pilar_pulse * 0.7)
                # Badan pilar tipis
                for seg in range(6):
                    a0=seg*(2*math.pi/6); a1=(seg+1)*(2*math.pi/6)
                    lt=0.5+0.5*math.cos(a0+0.3)
                    glColor3f(0.06*lt, pilar_pulse*0.5*lt, pilar_pulse*0.6*lt)
                    glBegin(GL_QUADS)
                    glVertex3f(ppx+math.cos(a0)*0.06, TOP+F*3+0.08, ppz+math.sin(a0)*0.06)
                    glVertex3f(ppx+math.cos(a1)*0.06, TOP+F*3+0.08, ppz+math.sin(a1)*0.06)
                    glVertex3f(ppx+math.cos(a1)*0.055,TOP+F*3,      ppz+math.sin(a1)*0.055)
                    glVertex3f(ppx+math.cos(a0)*0.055,TOP+F*3,      ppz+math.sin(a0)*0.055)
                    glEnd()
                # Mahkota kecil
                glColor3f(0.0, pilar_pulse * 0.9, pilar_pulse * 0.85)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(ppx, TOP+F*3+0.095, ppz)
                for i in range(7):
                    a3 = i*(2*math.pi/6)
                    glVertex3f(ppx+math.cos(a3)*0.09, TOP+F*3+0.08, ppz+math.sin(a3)*0.09)
                glEnd()

            # Tepi neon toska bercahaya di pinggir papan
            for neon_c, neon_z in [
                ((0.0, 0.5, 0.55), 6.3-BV-0.05),
                ((0.0, 0.4, 0.50), -6.3+BV+0.05),
            ]:
                glColor3f(*neon_c)
                glBegin(GL_QUADS)
                glVertex3f(-6.3+BV, TOP+F*2, neon_z-0.04)
                glVertex3f( 6.3-BV, TOP+F*2, neon_z-0.04)
                glVertex3f( 6.3-BV, TOP+F*2, neon_z+0.04)
                glVertex3f(-6.3+BV, TOP+F*2, neon_z+0.04)
                glEnd()
            for neon_c, neon_x in [
                ((0.0, 0.55, 0.50), 6.3-BV-0.05),
                ((0.0, 0.45, 0.55), -6.3+BV+0.05),
            ]:
                glColor3f(*neon_c)
                glBegin(GL_QUADS)
                glVertex3f(neon_x-0.04, TOP+F*2, -6.3+BV)
                glVertex3f(neon_x+0.04, TOP+F*2, -6.3+BV)
                glVertex3f(neon_x+0.04, TOP+F*2,  6.3-BV)
                glVertex3f(neon_x-0.04, TOP+F*2,  6.3-BV)
                glEnd()

            # Partikel plankton di permukaan papan
            if not hasattr(self, '_board_plankton'):
                import random as _rpl
                self._board_plankton = [
                    (_rpl.uniform(-3.5, 3.5),
                     _rpl.uniform(-3.5, 3.5),
                     _rpl.uniform(0.5, 2.5),
                     _rpl.choice([(0,0.9,0.8),(0.2,0.7,1.0),(0,1.0,0.6)]))
                    for _ in range(70)
                ]
            glEnable(GL_BLEND); glBlendFunc(GL_SRC_ALPHA, GL_ONE)
            for bpx, bpz, bspd, (bpr, bpg, bpb) in self._board_plankton:
                twinkle = 0.3 + 0.4 * abs(math.sin(t_now * bspd + bpx * 0.5))
                glColor4f(bpr * twinkle * 0.6, bpg * twinkle * 0.6, bpb * twinkle * 0.6, twinkle * 0.7)
                glBegin(GL_QUADS)
                glVertex3f(bpx-0.022, TOP+F*3+0.001, bpz-0.022)
                glVertex3f(bpx+0.022, TOP+F*3+0.001, bpz-0.022)
                glVertex3f(bpx+0.022, TOP+F*3+0.001, bpz+0.022)
                glVertex3f(bpx-0.022, TOP+F*3+0.001, bpz+0.022)
                glEnd()
            # Reset blend state setelah L3 block
            glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
            glEnable(GL_LIGHTING)

        elif L2:
            # Grid neon galaksi — biru terang natural
            glColor3f(0.25, 0.35, 0.75)
            for xi in [-3.0,-2.0,-1.0,0.0,1.0,2.0,3.0]:
                glBegin(GL_QUADS)
                glVertex3f(xi-0.02,TOP+F*3,-3.8); glVertex3f(xi+0.02,TOP+F*3,-3.8)
                glVertex3f(xi+0.02,TOP+F*3, 3.8); glVertex3f(xi-0.02,TOP+F*3, 3.8)
                glEnd()
                glBegin(GL_QUADS)
                glVertex3f(-3.8,TOP+F*3,xi-0.02); glVertex3f(3.8,TOP+F*3,xi-0.02)
                glVertex3f( 3.8,TOP+F*3,xi+0.02); glVertex3f(-3.8,TOP+F*3,xi+0.02)
                glEnd()

            # Lingkaran nebula animasi
            pulse = 0.35 + 0.10*math.sin(t_now*1.5)
            glColor3f(pulse*0.5, pulse*0.3, pulse*1.8)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0,TOP+F*4,0)
            for i in range(33):
                a=i*(2*math.pi/32)
                glVertex3f(math.cos(a)*2.5,TOP+F*4,math.sin(a)*2.5)
            glEnd()

            pulse2 = 0.25 + 0.10*math.sin(t_now*2.0+1)
            glColor3f(pulse2*1.2, pulse2*0.6, pulse2*2.2)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0,TOP+F*5,0)
            for i in range(33):
                a=i*(2*math.pi/32)
                glVertex3f(math.cos(a)*1.8,TOP+F*5,math.sin(a)*1.8)
            glEnd()

            # Bintang di tengah
            glColor3f(0.55, 0.30, 1.00)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0,TOP+F*6,0)
            for i in range(17):
                a=i*(2*math.pi/16)
                r=1.2 if i%2==0 else 0.5
                glVertex3f(math.cos(a)*r,TOP+F*6,math.sin(a)*r)
            glEnd()

            # Inti bintang
            glow = 0.7+0.3*math.sin(t_now*3.0)
            glColor3f(glow, glow*0.6, 1.0)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0,TOP+F*7,0)
            for i in range(33):
                a=i*(2*math.pi/32)
                glVertex3f(math.cos(a)*0.4,TOP+F*7,math.sin(a)*0.4)
            glEnd()

            # Tepi neon bercahaya di pinggir papan
            for neon_c, neon_z in [
                ((0.0,0.3,1.0),  6.3-BV-0.05),
                ((0.5,0.0,1.0), -6.3+BV+0.05),
            ]:
                glColor3f(*neon_c)
                glBegin(GL_QUADS)
                glVertex3f(-6.3+BV,TOP+F*2, neon_z-0.04)
                glVertex3f(6.3-BV, TOP+F*2, neon_z-0.04)
                glVertex3f(6.3-BV, TOP+F*2, neon_z+0.04)
                glVertex3f(-6.3+BV,TOP+F*2, neon_z+0.04)
                glEnd()
            for neon_c, neon_x in [
                ((0.0,0.8,0.8),  6.3-BV-0.05),
                ((1.0,0.3,0.0), -6.3+BV+0.05),
            ]:
                glColor3f(*neon_c)
                glBegin(GL_QUADS)
                glVertex3f(neon_x-0.04,TOP+F*2,-6.3+BV)
                glVertex3f(neon_x+0.04,TOP+F*2,-6.3+BV)
                glVertex3f(neon_x+0.04,TOP+F*2, 6.3-BV)
                glVertex3f(neon_x-0.04,TOP+F*2, 6.3-BV)
                glEnd()

            # Stars di permukaan papan — posisi dihitung sekali di __init__
            if not hasattr(self, '_board_stars'):
                import random as _rnd2
                self._board_stars = [
                    (_rnd2.uniform(-3.5, 3.5),
                     _rnd2.uniform(-3.5, 3.5),
                     _rnd2.uniform(1.0, 3.0))  # kecepatan kedip
                    for _ in range(60)
                ]
            for sx2, sz2, spd in self._board_stars:
                twinkle = 0.3 + 0.3*abs(math.sin(t_now*spd+sx2))
                glColor3f(twinkle, twinkle, min(1,twinkle+0.2))
                glBegin(GL_QUADS)
                glVertex3f(sx2-0.025,TOP+F*3,sz2-0.025)
                glVertex3f(sx2+0.025,TOP+F*3,sz2-0.025)
                glVertex3f(sx2+0.025,TOP+F*3,sz2+0.025)
                glVertex3f(sx2-0.025,TOP+F*3,sz2+0.025)
                glEnd()

        else:
            # Level 1: dekorasi lingkaran hijau klasik
            glColor3f(0.14, 0.32, 0.16)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0,TOP+F*3,0)
            for i in range(33):
                a=i*(2*math.pi/32)
                glVertex3f(math.cos(a)*2.8,TOP+F*3,math.sin(a)*2.8)
            glEnd()
            glColor3f(0.18, 0.40, 0.20)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0,TOP+F*4,0)
            for i in range(33):
                a=i*(2*math.pi/32)
                glVertex3f(math.cos(a)*2.2,TOP+F*4,math.sin(a)*2.2)
            glEnd()
            glColor3f(0.15, 0.33, 0.17)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0,TOP+F*5,0)
            for i in range(17):
                a=i*(2*math.pi/16)
                r=1.5 if i%2==0 else 0.8
                glVertex3f(math.cos(a)*r,TOP+F*5,math.sin(a)*r)
            glEnd()
            glColor3f(0.20, 0.44, 0.22)
            glBegin(GL_TRIANGLE_FAN)
            glVertex3f(0,TOP+F*6,0)
            for i in range(33):
                a=i*(2*math.pi/32)
                glVertex3f(math.cos(a)*0.55,TOP+F*6,math.sin(a)*0.55)
            glEnd()

        # ── 4 kotak sudut dekoratif ───────────────────────
        sz = 0.7
        for cx2, cz2 in [(-3.0,-3.0),(3.0,-3.0),(-3.0,3.0),(3.0,3.0)]:
            if L3:
                # Karang bioluminesen di sudut
                p3 = 0.12 + 0.06 * math.sin(t_now * 0.6 + cx2)
                glColor3f(p3 * 0.3, p3 * 2.5, p3 * 2.8)
            elif L2:
                p2 = 0.15+0.05*math.sin(t_now*2.0+cx2)
                glColor3f(p2*0.5, p2*0.2, p2*2.0)
            else:
                glColor3f(0.12, 0.30, 0.14)
            glBegin(GL_QUADS)
            glVertex3f(cx2-sz,TOP+F*3,cz2-sz); glVertex3f(cx2+sz,TOP+F*3,cz2-sz)
            glVertex3f(cx2+sz,TOP+F*3,cz2+sz); glVertex3f(cx2-sz,TOP+F*3,cz2+sz)
            glEnd()
            if L3:
                # Ornamen bintang laut di sudut
                glColor3f(0.0, 0.6, 0.65)
            elif L2:
                glColor3f(0.5, 0.2, 1.0)
            else:
                glColor3f(0.15, 0.36, 0.17)
            glBegin(GL_QUADS)
            glVertex3f(cx2,      TOP+F*4, cz2-0.35)
            glVertex3f(cx2+0.35, TOP+F*4, cz2)
            glVertex3f(cx2,      TOP+F*4, cz2+0.35)
            glVertex3f(cx2-0.35, TOP+F*4, cz2)
            glEnd()

        # ── Tumpukan kartu Monopoly di tengah papan ───────
        F2 = TOP + F*3 + 0.02
        cw3, cd3 = 0.70, 0.50
        n_layers  = 8

        # Peluang (oranye) di kiri tengah
        # Komunitas (biru) di kanan tengah
        posisi_kartu = [
            (-1.2, 0.0, 0.95, 0.55, 0.08, "peluang"),   # Peluang
            ( 1.2, 0.0, 0.12, 0.42, 0.82, "komunitas"),  # Komunitas
        ]

        for pk in posisi_kartu:
            px3, pz3, r, g, b, jenis = pk
            for li in range(n_layers):
                ly = F2 + li * 0.018
                lox = (li % 2) * 0.012 - 0.006
                loz = (li % 3) * 0.008 - 0.004
                if li == n_layers - 1:
                    glColor3f(0.98, 0.94, 0.88)
                elif li % 2 == 0:
                    glColor3f(r, g, b)
                else:
                    glColor3f(r*0.88, g*0.88, b*0.88)
                glBegin(GL_QUADS)
                glVertex3f(px3-cw3/2+lox, ly, pz3-cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly, pz3-cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly, pz3+cd3/2+loz)
                glVertex3f(px3-cw3/2+lox, ly, pz3+cd3/2+loz)
                glVertex3f(px3-cw3/2+lox, ly-0.018, pz3+cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly-0.018, pz3+cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly,       pz3+cd3/2+loz)
                glVertex3f(px3-cw3/2+lox, ly,       pz3+cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly-0.018, pz3-cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly-0.018, pz3+cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly,       pz3+cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly,       pz3-cd3/2+loz)
                glEnd()

            ty2 = F2 + n_layers * 0.018 + 0.002
            if jenis == "peluang":
                glColor3f(0.80, 0.32, 0.02)
                glBegin(GL_QUADS)
                glVertex3f(px3-0.12, ty2, pz3-0.08)
                glVertex3f(px3+0.12, ty2, pz3-0.08)
                glVertex3f(px3+0.12, ty2, pz3+0.08)
                glVertex3f(px3-0.12, ty2, pz3+0.08)
                glEnd()
            else:
                glColor3f(0.08, 0.28, 0.60)
                glBegin(GL_QUADS)
                glVertex3f(px3-0.14, ty2, pz3-0.09)
                glVertex3f(px3+0.14, ty2, pz3-0.09)
                glVertex3f(px3+0.14, ty2, pz3+0.09)
                glVertex3f(px3-0.14, ty2, pz3+0.09)
                glEnd()
                glColor3f(0.20, 0.50, 0.90)
                glBegin(GL_TRIANGLES)
                glVertex3f(px3-0.14, ty2+0.001, pz3-0.09)
                glVertex3f(px3+0.14, ty2+0.001, pz3-0.09)
                glVertex3f(px3,      ty2+0.001, pz3+0.02)
                glEnd()
            # Tumpukan Peluang (oranye) — agak ke tengah
            for li in range(n_layers):
                ly = F2 + li * 0.018
                lox = (li % 2) * 0.012 - 0.006
                loz = (li % 3) * 0.008 - 0.004

                if li == n_layers - 1:
                    glColor3f(0.98, 0.94, 0.82)   # Kartu atas putih krem
                elif li % 2 == 0:
                    glColor3f(0.95, 0.52, 0.08)   # Oranye
                else:
                    glColor3f(0.88, 0.46, 0.06)   # Oranye gelap

                glBegin(GL_QUADS)
                # Atas
                glVertex3f(px3-cw3/2+lox, ly, pz3-cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly, pz3-cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly, pz3+cd3/2+loz)
                glVertex3f(px3-cw3/2+lox, ly, pz3+cd3/2+loz)
                # Depan
                glVertex3f(px3-cw3/2+lox, ly-0.018, pz3+cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly-0.018, pz3+cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly,       pz3+cd3/2+loz)
                glVertex3f(px3-cw3/2+lox, ly,       pz3+cd3/2+loz)
                # Kanan
                glVertex3f(px3+cw3/2+lox, ly-0.018, pz3-cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly-0.018, pz3+cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly,       pz3+cd3/2+loz)
                glVertex3f(px3+cw3/2+lox, ly,       pz3-cd3/2+loz)
                glEnd()

        # ── Garis grid kotak papan (tipis, gelap) ─────────
        glColor3f(0.08, 0.20, 0.10)
        glLineWidth(1.0)
        # Garis horizontal luar (sisi atas & bawah papan)
        for z_pos in [-5.5 + BV, 5.5 - BV]:
            glBegin(GL_LINES)
            glVertex3f(-5.5+BV, TOP+F*7,  z_pos)
            glVertex3f( 5.5-BV, TOP+F*7,  z_pos)
            glEnd()
        # Garis vertikal luar (sisi kiri & kanan papan)
        for x_pos in [-5.5 + BV, 5.5 - BV]:
            glBegin(GL_LINES)
            glVertex3f(x_pos, TOP+F*7, -5.5+BV)
            glVertex3f(x_pos, TOP+F*7,  5.5-BV)
            glEnd()
        # Batas area tengah
        for z_pos in [-4.0, 4.0]:
            glBegin(GL_LINES)
            glVertex3f(-4.0, TOP+F*7, z_pos)
            glVertex3f( 4.0, TOP+F*7, z_pos)
            glEnd()
        for x_pos in [-4.0, 4.0]:
            glBegin(GL_LINES)
            glVertex3f(x_pos, TOP+F*7, -4.0)
            glVertex3f(x_pos, TOP+F*7,  4.0)
            glEnd()

        glEnable(GL_LIGHTING)

    def _draw_tile(self, idx):
        x, y, z = posisi_3d(idx)
        k   = self.board_data[idx]
        w   = GROUP_COLORS.get(k["grup"], (0.2, 0.2, 0.2, 1.0))
        own = self.kepemilikan[idx]
        glPushMatrix()
        glTranslatef(x, y, z)

        L2 = (self.level == 2)
        L3 = (self.level == 3)
        t_now = self.neon_t if hasattr(self,'neon_t') else 0.0
        pulse = 0.85 + 0.15*math.sin(t_now*2.0+idx*0.4) if (L2 or L3) else 1.0

        # Level 3: Kotak sudut (khusus) SKIP — digambar penuh oleh _draw_special_icons
        if L3 and k["tipe"] == "khusus":
            glPopMatrix()
            return

        # Override warna base tile Level 3
        if L3:
            nama_l3 = k["nama"]
            if nama_l3 == "Singgasana Neptunus":
                w = (0.38, 0.28, 0.04, 1.0)   # Emas kuat — override biru_t
            elif nama_l3 in ("Menara Mercusuar",):
                w = (0.14, 0.14, 0.18, 1.0)
            elif nama_l3 == "Delta Sungai":
                w = (0.18, 0.14, 0.06, 1.0)
            elif nama_l3 == "Muara Khatulistiwa":
                w = (0.04, 0.22, 0.26, 1.0)
            elif nama_l3 == "Gua Koral":
                w = (0.22, 0.06, 0.04, 1.0)
            elif nama_l3 == "Padang Lamun":
                w = (0.04, 0.20, 0.10, 1.0)
            elif nama_l3 in ("Terumbu Karang",):
                w = (0.04, 0.22, 0.28, 1.0)
            elif "Dermaga" in nama_l3:
                w = (0.22, 0.16, 0.06, 1.0)
            elif nama_l3 == "Kartu Arus":
                w = (0.02, 0.12, 0.32, 1.0)
            elif nama_l3 == "Pajak Pasang Surut":
                w = (0.30, 0.22, 0.08, 1.0)
            elif nama_l3 == "Laguna Biru":
                w = (0.03, 0.25, 0.50, 1.0)
            elif nama_l3 == "Gulungan Ombak":
                w = (0.03, 0.18, 0.42, 1.0)
            elif nama_l3 == "Pantai Karang":
                w = (0.40, 0.32, 0.12, 1.0)
            elif nama_l3 == "Denda Badai Laut":
                w = (0.06, 0.06, 0.18, 1.0)
            elif nama_l3 == "Tahta Raja Lautan":
                w = (0.12, 0.04, 0.28, 1.0)
            elif nama_l3 in ("Kota Atlantis", "Istana Atlantis"):
                w = (0.03, 0.18, 0.24, 1.0)
            elif nama_l3 == "Permukaan Laut":
                w = (0.04, 0.28, 0.48, 1.0)
            elif nama_l3 == "Palung Mariana":
                w = (0.01, 0.03, 0.10, 1.0)
            elif nama_l3 == "Pusaran Arus":
                w = (0.02, 0.06, 0.14, 1.0)   # Biru laut dalam — bukan ungu
            elif nama_l3 == "Laut Dangkal":
                w = (0.04, 0.28, 0.42, 1.0)
            elif nama_l3 == "Kolam Bioluminesen":
                w = (0.0, 0.06, 0.14, 1.0)
            elif nama_l3 == "Istana Karang":
                w = (0.22, 0.08, 0.04, 1.0)

        # Override warna untuk tile spesial Level 2
        is_wormhole     = L2 and k["nama"] == "Wormhole Portal"
        is_parkir_orbit = L2 and k["nama"] == "Parkir Orbit"
        is_launch_pad   = L2 and k["nama"] == "Peluncuran Roket"

        if is_wormhole:
            w = (0.08, 0.0, 0.15, 1.0)
        elif is_parkir_orbit:
            w = (0.02, 0.04, 0.18, 1.0)
        elif is_launch_pad:
            # Tile beton gelap — roket dan pad digambar oleh _draw_roket_peluncuran
            glColor4f(0.20, 0.20, 0.22, 1.0)
            h2 = 0.07
            glBegin(GL_QUADS)
            glNormal3f(0,1,0)
            glVertex3f(-.47,h2, .47); glVertex3f(.47,h2, .47)
            glVertex3f( .47,h2,-.47); glVertex3f(-.47,h2,-.47)
            glNormal3f(0,0,1)
            glVertex3f(-.47,0, .47); glVertex3f(.47,0, .47)
            glVertex3f( .47,h2, .47); glVertex3f(-.47,h2, .47)
            glNormal3f(0,0,-1)
            glVertex3f( .47,0,-.47); glVertex3f(-.47,0,-.47)
            glVertex3f(-.47,h2,-.47); glVertex3f( .47,h2,-.47)
            glNormal3f(-1,0,0)
            glVertex3f(-.47,0,-.47); glVertex3f(-.47,0, .47)
            glVertex3f(-.47,h2, .47); glVertex3f(-.47,h2,-.47)
            glNormal3f(1,0,0)
            glVertex3f( .47,0, .47); glVertex3f( .47,0,-.47)
            glVertex3f( .47,h2,-.47); glVertex3f( .47,h2, .47)
            glEnd()
            glPopMatrix()
            return  # Skip semua render lain

        if self.tergadai[idx]:
            glColor4f(0.65, 0.62, 0.60, 1.0)
        elif own != -1:
            if L2 or L3:
                glColor4f(min(w[0]*3.0,1), min(w[1]*3.0,1), min(w[2]*3.0,1), 1)
            else:
                glColor4f(min(w[0]*1.5+0.1,1), min(w[1]*1.5+0.1,1), min(w[2]*1.5+0.1,1), 1)
        else:
            if L2 or L3:
                glColor4f(min(w[0]*2.5,1), min(w[1]*2.5,1), min(w[2]*2.5,1), 1.0)
            else:
                glColor4f(min(w[0]*1.2,1), min(w[1]*1.2,1), min(w[2]*1.2,1), 1.0)

        h = 0.07
        glBegin(GL_QUADS)
        glNormal3f(0, 1, 0)
        glVertex3f(-.47,h, .47); glVertex3f(.47,h, .47)
        glVertex3f( .47,h,-.47); glVertex3f(-.47,h,-.47)
        glNormal3f(0, 0, 1)
        glVertex3f(-.47,0, .47); glVertex3f(.47,0, .47)
        glVertex3f( .47,h, .47); glVertex3f(-.47,h, .47)
        glNormal3f(0, 0,-1)
        glVertex3f( .47,0,-.47); glVertex3f(-.47,0,-.47)
        glVertex3f(-.47,h,-.47); glVertex3f( .47,h,-.47)
        glNormal3f(-1, 0, 0)
        glVertex3f(-.47,0,-.47); glVertex3f(-.47,0, .47)
        glVertex3f(-.47,h, .47); glVertex3f(-.47,h,-.47)
        glNormal3f(1, 0, 0)
        glVertex3f( .47,0, .47); glVertex3f( .47,0,-.47)
        glVertex3f( .47,h,-.47); glVertex3f( .47,h, .47)
        glEnd()

        # ── Border terang agar kotak selalu terlihat ───────
        bw = min(w[0]*3.5, 1.0)
        bg2 = min(w[1]*3.5, 1.0)
        bb = min(w[2]*3.5, 1.0)
        glColor4f(bw, bg2, bb, 1.0)
        glLineWidth(2.0)
        glBegin(GL_LINE_LOOP)
        glVertex3f(-.48, h+0.004,  .48)
        glVertex3f( .48, h+0.004,  .48)
        glVertex3f( .48, h+0.004, -.48)
        glVertex3f(-.48, h+0.004, -.48)
        glEnd()
        glLineWidth(1.0)

        # ── Glow ring neon di tepi tile (level 2) ─────────
        if L2 and not is_wormhole and not is_parkir_orbit and not is_launch_pad:
            glDisable(GL_LIGHTING)
            glow_a = 0.4 + 0.3*math.sin(t_now*3.0+idx*0.7)
            glColor4f(w[0]*glow_a, w[1]*glow_a, w[2]*glow_a, 0.6)
            glBegin(GL_QUADS)
            glVertex3f(-.49,h+0.001, .49); glVertex3f(.49,h+0.001, .49)
            glVertex3f(.49,h+0.001,-.49); glVertex3f(-.49,h+0.001,-.49)
            glEnd()
            glColor4f(w[0], w[1], w[2], 0.8)
            glBegin(GL_QUADS)
            glVertex3f(-.49,h+0.002, .49); glVertex3f( .49,h+0.002, .49)
            glVertex3f( .49,h+0.002, .47); glVertex3f(-.49,h+0.002, .47)
            glVertex3f(-.49,h+0.002,-.47); glVertex3f( .49,h+0.002,-.47)
            glVertex3f( .49,h+0.002,-.49); glVertex3f(-.49,h+0.002,-.49)
            glVertex3f(-.49,h+0.002,-.49); glVertex3f(-.49,h+0.002, .49)
            glVertex3f(-.47,h+0.002, .49); glVertex3f(-.47,h+0.002,-.49)
            glVertex3f( .47,h+0.002,-.49); glVertex3f( .47,h+0.002, .49)
            glVertex3f( .49,h+0.002, .49); glVertex3f( .49,h+0.002,-.49)
            glEnd()
            glEnable(GL_LIGHTING)

        # ── Efek animasi unik per tile Level 3 ────────────
        if L3:
            glDisable(GL_LIGHTING)
            glEnable(GL_BLEND)
            glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
            nama = k["nama"]
            ph   = idx * 0.42   # fase unik per tile

            # ── Helper: gambar overlay warna + border ──
            def _tile_overlay(r, g, b, a):
                glColor4f(r, g, b, a)
                glBegin(GL_QUADS)
                glVertex3f(-.47, h+0.003,  .47)
                glVertex3f( .47, h+0.003,  .47)
                glVertex3f( .47, h+0.003, -.47)
                glVertex3f(-.47, h+0.003, -.47)
                glEnd()

            def _tile_border(r, g, b, a, width=0.06):
                glColor4f(r, g, b, a)
                hw = 0.47; iw = hw - width
                glBegin(GL_QUADS)
                # atas
                glVertex3f(-hw,h+0.005, hw); glVertex3f(hw,h+0.005, hw)
                glVertex3f(hw,h+0.005,iw);   glVertex3f(-hw,h+0.005,iw)
                # bawah
                glVertex3f(-hw,h+0.005,-iw); glVertex3f(hw,h+0.005,-iw)
                glVertex3f(hw,h+0.005,-hw);  glVertex3f(-hw,h+0.005,-hw)
                # kiri
                glVertex3f(-hw,h+0.005,-hw); glVertex3f(-hw,h+0.005,hw)
                glVertex3f(-iw,h+0.005,hw);  glVertex3f(-iw,h+0.005,-hw)
                # kanan
                glVertex3f(iw,h+0.005,-hw);  glVertex3f(iw,h+0.005,hw)
                glVertex3f(hw,h+0.005,hw);   glVertex3f(hw,h+0.005,-hw)
                glEnd()

            def _tile_dots(count, r, g, b, base_alpha, dot_r=0.05):
                """Titik-titik berkedip di atas tile."""
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                for di in range(count):
                    da = di*(2*math.pi/count) + ph
                    dx = math.cos(da)*0.28; dz = math.sin(da)*0.28
                    bri = 0.4 + 0.5*abs(math.sin(t_now*1.5 + ph + di*1.1))
                    glColor4f(r*bri, g*bri, b*bri, base_alpha*bri)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(dx, h+0.008, dz)
                    for si in range(9):
                        sa = si*(2*math.pi/8)
                        glVertex3f(dx+math.cos(sa)*dot_r,
                                   h+0.008,
                                   dz+math.sin(sa)*dot_r)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            def _tile_ripples(r, g, b):
                """Lingkaran beriak air mengembang."""
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                for ri in range(3):
                    rph = (t_now*0.6 + ri*0.33) % 1.0
                    rad = rph * 0.42
                    alpha = (1.0-rph) * 0.55
                    glColor4f(r, g, b, alpha)
                    glBegin(GL_LINE_LOOP)
                    for si in range(24):
                        sa = si*(2*math.pi/24)
                        glVertex3f(math.cos(sa)*rad, h+0.007, math.sin(sa)*rad)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            def _tile_bubbles(count, r, g, b):
                """Gelembung naik dari lantai tile."""
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                for bi in range(count):
                    bph2 = (t_now*0.8 + bi*0.37 + ph) % 1.0
                    bx = math.cos(bi*2.1+ph)*0.25
                    bz = math.sin(bi*1.7+ph)*0.25
                    bh2 = bph2 * 0.25
                    ba  = (1.0-bph2)*0.6
                    br  = 0.025 + bph2*0.03
                    glColor4f(r, g, b, ba)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(bx, h+bh2, bz)
                    for si in range(9):
                        sa = si*(2*math.pi/8)
                        glVertex3f(bx+math.cos(sa)*br, h+bh2, bz+math.sin(sa)*br)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            def _tile_wave_lines(r, g, b, count=5):
                """Garis ombak horizontal bergerak."""
                for li in range(count):
                    lph = li / count
                    lx  = -0.38 + li*(0.76/count)
                    wave_z = math.sin(t_now*1.2 + lph*2*math.pi + ph)*0.12
                    alpha  = 0.3 + 0.25*math.sin(t_now + lph*math.pi)
                    glColor4f(r, g, b, alpha)
                    glBegin(GL_LINE_STRIP)
                    for si in range(12):
                        sx = lx + si*0.07 - 0.35
                        sz = wave_z*math.sin(si*0.8 + t_now*1.5 + ph)
                        glVertex3f(sx, h+0.006, sz)
                    glEnd()

            def _tile_glow_center(r, g, b, a):
                """Lingkaran glow di tengah tile."""
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                gl2 = 0.25 + 0.15*math.sin(t_now*1.8+ph)
                glColor4f(r*gl2, g*gl2, b*gl2, a*gl2)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.006, 0)
                for si in range(17):
                    sa = si*(2*math.pi/16)
                    glVertex3f(math.cos(sa)*0.35, h+0.006, math.sin(sa)*0.35)
                glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            # ═══════════════════════════════════════════════
            # EFEK PER NAMA KOTAK
            # ═══════════════════════════════════════════════

            if nama == "Gua Koral":
                # ── GUA KORAL — mulut goa + animasi ikan ──

                # Inisialisasi data statis sekali
                if not hasattr(self, '_gua_rocks'):
                    import random as _rg
                    self._gua_rocks = [
                        (_rg.uniform(-0.38,0.38), _rg.uniform(-0.38,0.38),
                         _rg.uniform(0.02,0.055),
                         _rg.choice([(0.35,0.10,0.06),(0.28,0.08,0.05),
                                     (0.40,0.12,0.07),(0.20,0.15,0.08)]))
                        for _ in range(20)
                    ]
                    self._gua_fish = [
                        {'ph': _rg.uniform(0,6.28), 'spd': _rg.uniform(0.18,0.42),
                         'lane': _rg.uniform(-0.12,0.12),
                         'sz': _rg.uniform(0.028,0.050), 'dir': _rg.choice([-1,1]),
                         'col': _rg.choice([(1.0,0.5,0.1),(0.8,0.9,0.2),
                                            (0.2,0.8,0.9),(1.0,0.3,0.4),(0.5,0.3,1.0)])}
                        for _ in range(7)
                    ]

                # Lantai coklat-batu (overlay di atas tile yg sudah digambar)
                _tile_overlay(0.28, 0.08, 0.04, 0.92)

                # Bintik batu karang
                for rx2,rz2,rr2,(rr3,rg3,rb3) in self._gua_rocks:
                    glColor4f(rr3+0.05, rg3+0.02, rb3, 0.85)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(rx2, h+0.003, rz2)
                    for si in range(7):
                        sa = si*(2*math.pi/6)
                        glVertex3f(rx2+math.cos(sa)*rr2, h+0.003, rz2+math.sin(sa)*rr2)
                    glEnd()

                # Mulut goa — oval gelap di tengah-atas tile
                # Pinggiran karang
                glColor4f(0.22, 0.07, 0.03, 1.0)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.004, 0.05)
                for si in range(33):
                    a = si*(2*math.pi/32)
                    warp = 1.0 + 0.07*math.sin(a*5 + ph)
                    glVertex3f(math.cos(a)*0.19*warp, h+0.004, 0.05+math.sin(a)*0.13*warp)
                glEnd()
                # Lubang gelap
                glColor4f(0.01, 0.01, 0.02, 1.0)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.006, 0.05)
                for si in range(33):
                    a = si*(2*math.pi/32)
                    glVertex3f(math.cos(a)*0.15, h+0.006, 0.05+math.sin(a)*0.10)
                glEnd()

                # Stalaktit di bibir goa
                for sti in range(7):
                    sta = sti*(2*math.pi/7)
                    stx = math.cos(sta)*0.15
                    stz = 0.05+math.sin(sta)*0.10
                    sth = 0.025+0.015*math.sin(sti*1.3+ph)
                    stp = 0.010+0.004*math.sin(sti*0.9)
                    glColor4f(0.32, 0.09, 0.04, 0.90)
                    glBegin(GL_TRIANGLES)
                    glVertex3f(stx,     h+0.007+sth, stz)
                    glVertex3f(stx-stp, h+0.007,     stz)
                    glVertex3f(stx+stp, h+0.007,     stz)
                    glEnd()

                # Glow bioluminesen dari dalam goa
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                glow_g = 0.30+0.22*math.sin(t_now*1.4+ph)
                glColor4f(0.0, glow_g*0.85, glow_g, glow_g*0.6)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.007, 0.05)
                for si in range(17):
                    a = si*(2*math.pi/16)
                    glVertex3f(math.cos(a)*0.12, h+0.007, 0.05+math.sin(a)*0.08)
                glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

                # Karang dekoratif 4 sudut
                for cdx,cdz,(cdr,cdg,cdb) in [
                    (-0.32,-0.32,(0.9,0.3,0.15)),( 0.32,-0.32,(0.2,0.75,0.85)),
                    (-0.32, 0.32,(0.85,0.6,0.1)),( 0.32, 0.32,(0.7,0.2,0.75))]:
                    ch3 = 0.04+0.02*math.sin(t_now*1.1+cdx*2+ph)
                    bri3 = 0.5+0.4*abs(math.sin(t_now*0.9+cdx))
                    glColor4f(cdr*bri3, cdg*bri3, cdb*bri3, 0.85)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(cdx, h+ch3, cdz)
                    for si in range(7):
                        sa = si*(2*math.pi/6)
                        glVertex3f(cdx+math.cos(sa)*0.06, h+0.003, cdz+math.sin(sa)*0.06)
                    glEnd()

                # Animasi ikan masuk-keluar goa
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                for fish in self._gua_fish:
                    prog = (t_now*fish['spd'] + fish['ph']) % 2.0
                    t_f  = prog/2.0 if fish['dir']==1 else 1.0-prog/2.0
                    if t_f < 0.5:
                        frac = t_f*2.0
                        fz = 0.40 - frac*0.35
                        fx = fish['lane']*(1.0-frac*0.5)
                        fs = fish['sz']*(0.7+frac*0.4)
                        fa = min(1.0, frac*2.5)
                    else:
                        frac = (t_f-0.5)*2.0
                        fz = 0.05 - frac*0.14
                        fx = fish['lane']*0.5*(1.0-frac)
                        fs = fish['sz']*(1.1-frac*0.7)
                        fa = 1.0-frac*0.9
                    if fa < 0.05 or fs < 0.004: continue
                    fr,fg,fb = fish['col']
                    bri_f = 0.55+0.4*abs(math.sin(t_now*2.5+fish['ph']))
                    # Badan
                    glColor4f(fr*bri_f, fg*bri_f, fb*bri_f, fa)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(fx, h+0.010, fz)
                    for si in range(9):
                        sa = si*(2*math.pi/8)
                        glVertex3f(fx+math.cos(sa)*fs, h+0.010, fz+math.sin(sa)*fs*0.55)
                    glEnd()
                    # Ekor
                    td = 1 if fish['dir']==1 else -1
                    glColor4f(fr*bri_f*0.75, fg*bri_f*0.75, fb*bri_f*0.75, fa*0.85)
                    glBegin(GL_TRIANGLES)
                    glVertex3f(fx,        h+0.010, fz+td*fs)
                    glVertex3f(fx-fs*0.45, h+0.010, fz+td*fs*1.7)
                    glVertex3f(fx+fs*0.45, h+0.010, fz+td*fs*1.7)
                    glEnd()
                    # Mata
                    glColor4f(1.0, 1.0, 1.0, fa*0.9)
                    glBegin(GL_TRIANGLE_FAN)
                    ex2 = fx+fs*0.35; ez2 = fz-fs*0.18
                    glVertex3f(ex2, h+0.012, ez2)
                    for si in range(7):
                        sa = si*(2*math.pi/6)
                        glVertex3f(ex2+math.cos(sa)*fs*0.10, h+0.012, ez2+math.sin(sa)*fs*0.10)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            elif nama == "Padang Lamun":
                # Padang rumput laut — hijau bergoyang
                _tile_overlay(0.02, 0.22, 0.12, 0.40)
                _tile_border(0.1, 0.7, 0.3, 0.65)
                # Helai rumput laut
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                for gi in range(12):
                    gx = math.cos(gi*0.52+ph)*0.32
                    gz = math.sin(gi*0.52+ph)*0.32
                    sway = math.sin(t_now*1.3+gi*0.7+ph)*0.08
                    gh = 0.12 + 0.04*math.sin(gi*1.1)
                    bright = 0.4+0.4*abs(math.sin(t_now*0.8+gi*0.5))
                    glColor4f(0.05, bright*0.9, bright*0.4, 0.7)
                    glBegin(GL_TRIANGLES)
                    glVertex3f(gx,    h+0.004, gz)
                    glVertex3f(gx+sway+0.02, h+gh, gz)
                    glVertex3f(gx+sway-0.02, h+gh, gz)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
                _tile_ripples(0.1, 0.8, 0.4)

            elif nama == "Terumbu Karang":
                # Terumbu warna-warni
                _tile_overlay(0.05, 0.25, 0.30, 0.35)
                _tile_border(0.0, 0.75, 0.85, 0.70)
                # Karang bercabang warna-warni
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                colors_coral = [(1.0,0.3,0.2),(0.2,0.8,0.9),(1.0,0.7,0.1),(0.8,0.2,0.8)]
                for ci, (cr2,cg2,cb2) in enumerate(colors_coral):
                    cx2 = math.cos(ci*math.pi/2+ph)*0.22
                    cz2 = math.sin(ci*math.pi/2+ph)*0.22
                    ch2 = 0.08+0.04*math.sin(t_now*1.2+ci+ph)
                    bri = 0.5+0.4*abs(math.sin(t_now+ci*0.8))
                    glColor4f(cr2*bri, cg2*bri, cb2*bri, 0.75)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(cx2, h+ch2, cz2)
                    for si in range(7):
                        sa = si*(2*math.pi/6)
                        glVertex3f(cx2+math.cos(sa)*0.08, h+0.004, cz2+math.sin(sa)*0.08)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
                _tile_bubbles(4, 0.5, 1.0, 1.0)

            elif "Dermaga" in nama:
                # Dermaga — papan kayu, lampu mercusuar
                _tile_overlay(0.25, 0.18, 0.08, 0.50)
                _tile_border(0.8, 0.6, 0.2, 0.75)
                # Garis papan kayu
                for li in range(5):
                    lz2 = -0.35 + li*0.175
                    bright = 0.6+0.2*math.sin(t_now*0.5+li+ph)
                    glColor4f(0.4, 0.28+bright*0.1, 0.10, 0.5)
                    glBegin(GL_QUADS)
                    glVertex3f(-0.44, h+0.004, lz2)
                    glVertex3f( 0.44, h+0.004, lz2)
                    glVertex3f( 0.44, h+0.004, lz2+0.03)
                    glVertex3f(-0.44, h+0.004, lz2+0.03)
                    glEnd()
                # Lampu dermaga berkedip
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                lamp = 0.5+0.5*abs(math.sin(t_now*2.5+ph))
                glColor4f(1.0, 0.9, 0.3, lamp*0.8)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.01, 0)
                for si in range(9):
                    sa = si*(2*math.pi/8)
                    glVertex3f(math.cos(sa)*0.12, h+0.01, math.sin(sa)*0.12)
                glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            elif nama == "Kartu Arus":
                # Arus laut — spiral berputar
                _tile_overlay(0.02, 0.15, 0.35, 0.40)
                _tile_border(0.1, 0.5, 1.0, 0.70)
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                # Spiral arus
                rot = t_now*0.8 + ph
                for si in range(30):
                    frac = si/30
                    sa = frac*4*math.pi + rot
                    sr = frac*0.38
                    bright = 0.4+0.5*(1-frac)
                    glColor4f(0.2, 0.6*bright, bright, 0.6*(1-frac*0.5))
                    glBegin(GL_POINTS)
                    glVertex3f(math.cos(sa)*sr, h+0.007, math.sin(sa)*sr)
                    glEnd()
                glPointSize(3.0)
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
                _tile_ripples(0.2, 0.6, 1.0)

            elif nama == "Pajak Pasang Surut":
                # Pasang surut — air surut meninggalkan pasir
                wave_f = (math.sin(t_now*0.5+ph)+1)/2
                _tile_overlay(0.35*wave_f+0.10, 0.22*wave_f+0.12, 0.05, 0.45)
                _tile_border(0.8, 0.6, 0.1, 0.65)
                # Garis pasang
                _tile_wave_lines(0.2, 0.55, 0.85)
                _tile_ripples(0.3, 0.7, 0.9)

            elif nama == "Laguna Biru":
                # Laguna — air biru jernih berkilau
                _tile_overlay(0.03, 0.30, 0.55, 0.45)
                _tile_border(0.2, 0.7, 1.0, 0.75)
                _tile_ripples(0.3, 0.75, 1.0)
                _tile_ripples(0.5, 0.9, 1.0)  # double ripple lebih kaya
                # Kilau permukaan
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                for ki in range(8):
                    kx2 = math.cos(ki*0.8+ph+t_now*0.3)*0.30
                    kz2 = math.sin(ki*0.8+ph+t_now*0.3)*0.30
                    ks  = 0.3+0.6*abs(math.sin(t_now*2+ki*0.9+ph))
                    glColor4f(0.7, 0.95, 1.0, ks*0.5)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(kx2, h+0.008, kz2)
                    for si in range(5):
                        sa = si*(2*math.pi/4)
                        glVertex3f(kx2+math.cos(sa)*0.04, h+0.008, kz2+math.sin(sa)*0.04)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            elif nama == "Kolam Bioluminesen":
                # ── KOLAM BIOLUMINESEN — kolam gelap misterius + ikan loncat ──
                if not hasattr(self, '_kolam_data'):
                    import random as _rk
                    self._kolam_plankton = [
                        (_rk.uniform(-0.36,0.36), _rk.uniform(-0.36,0.36),
                         _rk.uniform(0,6.28), _rk.uniform(0.3,1.8),
                         _rk.choice([(0.0,0.9,0.8),(0.2,0.7,1.0),(0.0,1.0,0.6),(0.4,0.5,1.0),(0.8,0.2,1.0)]))
                        for _ in range(26)
                    ]
                    self._kolam_fish = [
                        {'ph': _rk.uniform(0,6.28), 'spd': _rk.uniform(0.20,0.40),
                         'lx': _rk.uniform(-0.25,0.25), 'sz': _rk.uniform(0.030,0.050),
                         'col': _rk.choice([(0.0,0.9,0.8),(0.2,0.8,1.0),(0.7,0.2,1.0),(0.0,1.0,0.6)])}
                        for _ in range(5)
                    ]
                    self._kolam_data = True

                # Paksa body tile jadi hitam laut
                glDisable(GL_LIGHTING)
                glColor4f(0.01,0.04,0.10,1.0)
                glBegin(GL_QUADS)
                glNormal3f(0,1,0)
                glVertex3f(-.47,h,.47);  glVertex3f(.47,h,.47)
                glVertex3f(.47,h,-.47);  glVertex3f(-.47,h,-.47)
                glNormal3f(0,0,1)
                glVertex3f(-.47,0,.47);  glVertex3f(.47,0,.47)
                glVertex3f(.47,h,.47);   glVertex3f(-.47,h,.47)
                glNormal3f(0,0,-1)
                glVertex3f(.47,0,-.47);  glVertex3f(-.47,0,-.47)
                glVertex3f(-.47,h,-.47); glVertex3f(.47,h,-.47)
                glNormal3f(-1,0,0)
                glVertex3f(-.47,0,-.47); glVertex3f(-.47,0,.47)
                glVertex3f(-.47,h,.47);  glVertex3f(-.47,h,-.47)
                glNormal3f(1,0,0)
                glVertex3f(.47,0,.47);   glVertex3f(.47,0,-.47)
                glVertex3f(.47,h,-.47);  glVertex3f(.47,h,.47)
                glEnd()
                glEnable(GL_LIGHTING)

                # Permukaan air kolam gelap
                glColor4f(0.01,0.06,0.16,0.95)
                glBegin(GL_QUADS)
                glVertex3f(-0.44,h+0.005, 0.44); glVertex3f(0.44,h+0.005, 0.44)
                glVertex3f( 0.44,h+0.005,-0.44); glVertex3f(-0.44,h+0.005,-0.44)
                glEnd()

                # Glow dasar kolam
                glEnable(GL_BLEND); glBlendFunc(GL_SRC_ALPHA,GL_ONE)
                cb2=0.38+0.30*math.sin(t_now*0.9+ph)
                glColor4f(0.0,cb2*0.75,cb2*0.95,cb2*0.55)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0,h+0.006,0)
                for si in range(33):
                    sa=si*(2*math.pi/32)
                    glVertex3f(math.cos(sa)*0.28,h+0.006,math.sin(sa)*0.28)
                glEnd()

                # Riak bioluminesen
                for ri in range(5):
                    rph2=(t_now*0.40+ri*0.20)%1.0
                    rad2=0.05+rph2*0.38; alp2=(1-rph2)*0.72
                    cr3,cg3,cb3=[(0.0,0.9,0.8),(0.2,0.5,1.0),(0.7,0.1,1.0)][ri%3]
                    glColor4f(cr3,cg3,cb3,alp2)
                    glBegin(GL_LINE_LOOP)
                    for si in range(32):
                        sa=si*(2*math.pi/32)
                        wp=1.0+0.05*math.sin(sa*4+t_now*1.5+ph)
                        glVertex3f(math.cos(sa)*rad2*wp,h+0.007,math.sin(sa)*rad2*wp)
                    glEnd()

                # Plankton berkedip
                for pkx,pkz,pkph,pkspd,(pkr,pkg,pkb) in self._kolam_plankton:
                    bk=0.35+0.60*abs(math.sin(t_now*pkspd+pkph))
                    sk=0.007+0.009*bk
                    glColor4f(pkr*bk,pkg*bk,pkb*bk,bk*0.88)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(pkx,h+0.009,pkz)
                    for si in range(7):
                        sa=si*(2*math.pi/6)
                        glVertex3f(pkx+math.cos(sa)*sk,h+0.009,pkz+math.sin(sa)*sk)
                    glEnd()
                    glColor4f(pkr*bk*0.3,pkg*bk*0.3,pkb*bk*0.3,bk*0.22)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(pkx,h+0.007,pkz)
                    for si in range(9):
                        sa=si*(2*math.pi/8)
                        glVertex3f(pkx+math.cos(sa)*sk*4.5,h+0.007,pkz+math.sin(sa)*sk*4.5)
                    glEnd()

                # Simbol kuno
                for sp in range(6):
                    a_s=sp*(math.pi/3)+t_now*0.04+ph
                    spg=0.14+0.07*math.sin(t_now*0.7+sp+ph)
                    glColor4f(0.0,spg*3.5,spg*3.0,0.60)
                    glBegin(GL_LINES)
                    glVertex3f(math.cos(a_s)*0.04,h+0.010,math.sin(a_s)*0.04)
                    glVertex3f(math.cos(a_s)*0.24,h+0.010,math.sin(a_s)*0.24)
                    glEnd()

                # ── IKAN LONCAT KELUAR KOLAM ─────────────────
                for fish in self._kolam_fish:
                    prog=(t_now*fish['spd']+fish['ph'])%1.0
                    # 0-0.75: loncat, 0.75-1.0: diam di dalam
                    if prog >= 0.75:
                        continue
                    half=0.375
                    if prog < half:
                        tf=prog/half
                        jump_h=math.sin(tf*math.pi)*0.55
                        fz=fish['lx']
                        fa=min(1.0,tf*5)
                        td=1
                    else:
                        tf=(prog-half)/half
                        jump_h=math.sin((1-tf)*math.pi)*0.55
                        fz=fish['lx']
                        fa=1.0-tf*0.8
                        td=-1

                    if fa<0.05 or jump_h<0: continue
                    fx=fish['lx']*0.4
                    fs=fish['sz']
                    fr,fg,fb=fish['col']
                    bri_f=0.65+0.30*abs(math.sin(t_now*3+fish['ph']))
                    fy_f=h+0.012+jump_h

                    # Jejak cahaya
                    glColor4f(fr*0.35,fg*0.55,fb*0.55,fa*0.30)
                    glBegin(GL_LINE_STRIP)
                    for tri in range(6):
                        tprog=max(0,prog-tri*0.012)
                        thalf=0.375
                        ttf=tprog/thalf if tprog<thalf else (1-(tprog-thalf)/thalf)
                        th=max(0,math.sin(max(0,min(1,ttf))*math.pi)*0.55)
                        glVertex3f(fx,h+0.012+th,fz+tri*0.010*td)
                    glEnd()

                    # Badan ikan
                    glColor4f(fr*bri_f,fg*bri_f,fb*bri_f,fa)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(fx,fy_f,fz)
                    for si in range(9):
                        sa=si*(2*math.pi/8)
                        glVertex3f(fx+math.cos(sa)*fs,fy_f+math.sin(sa)*fs*0.38,fz+math.sin(sa)*fs*0.28)
                    glEnd()

                    # Sirip ekor
                    glColor4f(fr*bri_f*0.7,fg*bri_f*0.7,fb*bri_f*0.7,fa*0.85)
                    glBegin(GL_TRIANGLES)
                    glVertex3f(fx,         fy_f,          fz+td*fs)
                    glVertex3f(fx-fs*0.45, fy_f-fs*0.45, fz+td*fs*1.8)
                    glVertex3f(fx+fs*0.45, fy_f-fs*0.45, fz+td*fs*1.8)
                    glEnd()

                    # Percikan saat dekat permukaan
                    if jump_h < 0.10 and fa > 0.25:
                        spr=0.04+jump_h*0.5
                        glColor4f(0.5,0.9,1.0,fa*0.60)
                        glBegin(GL_LINE_LOOP)
                        for spi in range(10):
                            spa=spi*(2*math.pi/10)
                            glVertex3f(fx+math.cos(spa)*spr,h+0.012,fz+math.sin(spa)*spr)
                        glEnd()

                    # Mata
                    glColor4f(1.0,1.0,1.0,fa*0.92)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(fx+fs*0.38,fy_f+fs*0.10,fz-fs*0.18)
                    for si in range(6):
                        sa=si*(2*math.pi/5)
                        glVertex3f(fx+fs*0.38+math.cos(sa)*fs*0.11,
                                   fy_f+fs*0.10+math.sin(sa)*fs*0.11,
                                   fz-fs*0.18)
                    glEnd()

                glBlendFunc(GL_SRC_ALPHA,GL_ONE_MINUS_SRC_ALPHA)
                glColor4f(0.0,0.45,0.55,0.88)
                glLineWidth(2.0)
                glBegin(GL_LINE_LOOP)
                glVertex3f(-.47,h+0.007,.47);  glVertex3f(.47,h+0.007,.47)
                glVertex3f(.47,h+0.007,-.47);  glVertex3f(-.47,h+0.007,-.47)
                glEnd()
                glLineWidth(1.0)

            elif nama == "Istana Karang":
                # ── ISTANA KARANG — benteng bawah laut dari karang hidup ──
                if not hasattr(self, '_karang_data'):
                    import random as _rik
                    self._karang_corals = [
                        (_rik.uniform(-0.40,0.40), _rik.uniform(-0.40,0.40),
                         _rik.uniform(0.025,0.065), _rik.uniform(0,6.28),
                         _rik.uniform(0.4,1.2),
                         _rik.choice([(0.95,0.30,0.15),(0.90,0.55,0.10),(0.15,0.80,0.75),
                                      (0.85,0.15,0.60),(0.20,0.75,0.35),(0.70,0.20,0.90)]))
                        for _ in range(16)
                    ]
                    self._karang_base = [
                        (_rik.uniform(-0.43,0.43), _rik.uniform(-0.43,0.43),
                         _rik.uniform(0.03,0.07), _rik.uniform(0.3,0.6))
                        for _ in range(18)
                    ]
                    self._karang_data = True

                _tile_overlay(0.28,0.07,0.03,0.95)

                # Tekstur batu karang dasar
                for bkx,bkz,bkr,bkbri in self._karang_base:
                    bc2=bkbri*(0.75+0.20*math.sin(bkx*4+t_now*0.2))
                    glColor4f(bc2*0.38,bc2*0.10,bc2*0.05,0.88)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(bkx,h+0.002,bkz)
                    for si in range(7):
                        sa=si*(2*math.pi/6)
                        glVertex3f(bkx+math.cos(sa)*bkr,h+0.002,bkz+math.sin(sa)*bkr*0.65)
                    glEnd()

                # Dinding benteng karang — 4 sisi
                wall_h=0.055
                for wz2 in [0.42,-0.42]:
                    wp2=0.45+0.25*abs(math.sin(t_now*0.4+ph))
                    glColor4f(0.40*wp2,0.12*wp2,0.05*wp2,0.90)
                    glBegin(GL_QUADS)
                    glVertex3f(-0.44,h+0.003,wz2); glVertex3f(0.44,h+0.003,wz2)
                    glVertex3f( 0.44,h+wall_h,wz2); glVertex3f(-0.44,h+wall_h,wz2)
                    glEnd()
                    for mi in range(6):
                        mx2=-0.38+mi*0.15
                        mh2=wall_h+0.020+0.008*math.sin(t_now*0.6+mi*0.7)
                        glColor4f(0.50*wp2,0.14*wp2,0.06*wp2,0.88)
                        glBegin(GL_QUADS)
                        glVertex3f(mx2-0.05,h+wall_h,wz2); glVertex3f(mx2+0.05,h+wall_h,wz2)
                        glVertex3f(mx2+0.05,h+mh2,   wz2); glVertex3f(mx2-0.05,h+mh2,   wz2)
                        glEnd()
                for wx2 in [-0.44,0.44]:
                    wp3=0.40+0.25*abs(math.sin(t_now*0.5+ph+1))
                    glColor4f(0.35*wp3,0.10*wp3,0.04*wp3,0.88)
                    glBegin(GL_QUADS)
                    glVertex3f(wx2,h+0.003,-0.44); glVertex3f(wx2,h+0.003, 0.44)
                    glVertex3f(wx2,h+wall_h,0.44); glVertex3f(wx2,h+wall_h,-0.44)
                    glEnd()

                # Menara 4 sudut
                TSEG=8
                for tx2,tz2 in [(-0.36,-0.36),(0.36,-0.36),(-0.36,0.36),(0.36,0.36)]:
                    th2=0.095+0.018*abs(math.sin(t_now*0.5+tx2+ph)); tr2=0.055
                    tp2=0.50+0.30*abs(math.sin(t_now*0.6+tx2*2+ph))
                    for seg in range(TSEG):
                        a0=seg*(2*math.pi/TSEG); a1=(seg+1)*(2*math.pi/TSEG)
                        lt=0.55+0.45*math.cos(a0+0.5)
                        glColor4f(0.42*lt*tp2,0.13*lt*tp2,0.05*lt*tp2,0.95)
                        glBegin(GL_QUADS)
                        glVertex3f(tx2+math.cos(a0)*tr2,h+th2,   tz2+math.sin(a0)*tr2)
                        glVertex3f(tx2+math.cos(a1)*tr2,h+th2,   tz2+math.sin(a1)*tr2)
                        glVertex3f(tx2+math.cos(a1)*tr2,h+0.003, tz2+math.sin(a1)*tr2)
                        glVertex3f(tx2+math.cos(a0)*tr2,h+0.003, tz2+math.sin(a0)*tr2)
                        glEnd()
                    # Kerucut atap
                    glColor4f(0.55*tp2,0.16*tp2,0.07*tp2,0.90)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(tx2,h+th2+0.040,tz2)
                    for seg in range(TSEG+1):
                        a=seg*(2*math.pi/TSEG)
                        glVertex3f(tx2+math.cos(a)*tr2*1.2,h+th2,tz2+math.sin(a)*tr2*1.2)
                    glEnd()
                    # Glow puncak menara
                    glEnable(GL_BLEND); glBlendFunc(GL_SRC_ALPHA,GL_ONE)
                    tg3=0.35+0.35*math.sin(t_now*1.8+tx2*3+ph)
                    glColor4f(tg3*0.9,tg3*0.4,0.1,tg3*0.65)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(tx2,h+th2+0.055,tz2)
                    for seg in range(9):
                        a=seg*(2*math.pi/8)
                        glVertex3f(tx2+math.cos(a)*0.025,h+th2+0.040,tz2+math.sin(a)*0.025)
                    glEnd()
                    glBlendFunc(GL_SRC_ALPHA,GL_ONE_MINUS_SRC_ALPHA)

                # Karang hidup di lantai & dinding
                glEnable(GL_BLEND); glBlendFunc(GL_SRC_ALPHA,GL_ONE)
                for ckx,ckz,ckr,ckrot,ckspd,(ckr2,ckg2,ckb2) in self._karang_corals:
                    ckbri=0.50+0.45*abs(math.sin(t_now*ckspd+ckrot+ph))
                    for ci in range(3):
                        ca=ci*(2*math.pi/3)+ckrot+t_now*0.04
                        ch_b=ckr*1.2+0.015*math.sin(t_now*ckspd+ci+ph)
                        glColor4f(ckr2*ckbri,ckg2*ckbri,ckb2*ckbri,0.80)
                        glBegin(GL_TRIANGLES)
                        glVertex3f(ckx,h+0.003,ckz)
                        glVertex3f(ckx+math.cos(ca+0.2)*ckr,h+ch_b,ckz+math.sin(ca+0.2)*ckr)
                        glVertex3f(ckx+math.cos(ca-0.2)*ckr,h+ch_b,ckz+math.sin(ca-0.2)*ckr)
                        glEnd()
                    # Kepala karang bulat
                    glColor4f(min(1,ckr2*ckbri*1.1),min(1,ckg2*ckbri*1.1),min(1,ckb2*ckbri*1.1),0.75)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(ckx,h+0.003+ckr*1.2,ckz)
                    for si in range(7):
                        sa=si*(2*math.pi/6)
                        glVertex3f(ckx+math.cos(sa)*ckr*0.5,h+0.003+ckr*1.0,ckz+math.sin(sa)*ckr*0.5)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA,GL_ONE_MINUS_SRC_ALPHA)

                _tile_border(0.80,0.20,0.06,0.85,0.06)

            elif nama == "Laut Dangkal":
                # ── LAUT DANGKAL — air jernih, pasir, karang, god rays ──

                if not hasattr(self, '_dangkal_data'):
                    import random as _rld
                    # Pasir berbutir
                    self._dangkal_sand = [
                        (_rld.uniform(-0.42,0.42), _rld.uniform(-0.42,0.42),
                         _rld.uniform(0.015,0.045),
                         _rld.uniform(0.55,0.85))
                        for _ in range(28)
                    ]
                    # Batu & karang kecil di dasar
                    self._dangkal_rocks = [
                        (_rld.uniform(-0.38,0.38), _rld.uniform(-0.38,0.38),
                         _rld.uniform(0.02,0.05),
                         _rld.choice([
                             (0.25,0.18,0.08),  # batu coklat
                             (0.35,0.12,0.06),  # karang merah
                             (0.08,0.28,0.22),  # karang hijau
                             (0.20,0.15,0.30),  # batu ungu
                         ]))
                        for _ in range(14)
                    ]
                    # Posisi god rays
                    self._dangkal_rays = [
                        (_rld.uniform(-0.35,0.35), _rld.uniform(0.1,0.9),
                         _rld.uniform(0.03,0.08))
                        for _ in range(6)
                    ]
                    # Bintang laut & kerang
                    self._dangkal_deco = [
                        (_rld.uniform(-0.36,0.36), _rld.uniform(-0.36,0.36),
                         _rld.choice(['star','shell','coral']),
                         _rld.uniform(0,6.28),
                         _rld.choice([(0.9,0.4,0.2),(0.9,0.7,0.1),(0.7,0.2,0.6),(0.2,0.7,0.5)]))
                        for _ in range(8)
                    ]
                    self._dangkal_data = True

                # ── Layer 1: Dasar pasir ──────────────────────
                _tile_overlay(0.52, 0.42, 0.18, 0.88)

                # Butiran pasir
                for sx2,sz2,sr2,sbri in self._dangkal_sand:
                    sc2 = sbri * (0.85 + 0.12*math.sin(t_now*0.3 + sx2*3))
                    glColor4f(sc2*0.72, sc2*0.58, sc2*0.20, 0.75)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(sx2, h+0.002, sz2)
                    for si in range(5):
                        sa = si*(2*math.pi/4)
                        glVertex3f(sx2+math.cos(sa)*sr2, h+0.002, sz2+math.sin(sa)*sr2)
                    glEnd()

                # Batu & karang dasar
                for rx2,rz2,rr2,(rr3,rg3,rb3) in self._dangkal_rocks:
                    bri3 = 0.7+0.25*math.sin(t_now*0.5+rx2*2)
                    glColor4f(rr3*bri3, rg3*bri3, rb3*bri3, 0.85)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(rx2, h+0.003, rz2)
                    for si in range(7):
                        sa = si*(2*math.pi/6)
                        glVertex3f(rx2+math.cos(sa)*rr2, h+0.003, rz2+math.sin(sa)*rr2*0.7)
                    glEnd()

                # ── Layer 2: Dekorasi laut dangkal ───────────
                for ddx,ddz,dtype,drot,dcol in self._dangkal_deco:
                    dr,dg,db = dcol
                    dbri = 0.55+0.40*abs(math.sin(t_now*0.8+ddx*2+ph))
                    glColor4f(dr*dbri, dg*dbri, db*dbri, 0.88)
                    if dtype == 'star':
                        # Bintang laut 5 lengan
                        rot_s = drot + t_now*0.05
                        glBegin(GL_TRIANGLE_FAN)
                        glVertex3f(ddx, h+0.005, ddz)
                        for si in range(11):
                            sa = si*(2*math.pi/10) + rot_s
                            rs = 0.07 if si%2==0 else 0.03
                            glVertex3f(ddx+math.cos(sa)*rs, h+0.005, ddz+math.sin(sa)*rs)
                        glEnd()
                    elif dtype == 'shell':
                        # Kerang spiral
                        for si in range(12):
                            frac = si/12
                            sa = frac*4*math.pi + drot
                            sr3 = frac*0.055
                            glBegin(GL_POINTS)
                            glVertex3f(ddx+math.cos(sa)*sr3, h+0.005, ddz+math.sin(sa)*sr3*0.6)
                            glEnd()
                    else:
                        # Karang kecil cabang
                        for bi3 in range(4):
                            ba3 = bi3*(math.pi/2)+drot
                            bx3 = ddx+math.cos(ba3)*0.045
                            bz3 = ddz+math.sin(ba3)*0.045
                            bh3 = 0.025+0.010*math.sin(t_now*1.2+bi3)
                            glBegin(GL_TRIANGLE_FAN)
                            glVertex3f(bx3, h+0.004+bh3, bz3)
                            for si in range(5):
                                sa = si*(2*math.pi/4)
                                glVertex3f(bx3+math.cos(sa)*0.018, h+0.004, bz3+math.sin(sa)*0.018)
                            glEnd()

                # ── Layer 3: Air dangkal — overlay biru jernih ─
                glEnable(GL_BLEND); glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
                wave_a = 0.28 + 0.06*math.sin(t_now*0.7+ph)
                glColor4f(0.10, 0.55, 0.78, wave_a)
                glBegin(GL_QUADS)
                glVertex3f(-0.46, h+0.010,  0.46)
                glVertex3f( 0.46, h+0.010,  0.46)
                glVertex3f( 0.46, h+0.010, -0.46)
                glVertex3f(-0.46, h+0.010, -0.46)
                glEnd()

                # ── Layer 4: God rays — sinar matahari tembus air ─
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                for rx5,rspd,rw5 in self._dangkal_rays:
                    rpulse = (t_now*rspd + rx5*2) % 1.0
                    # Sinar menyapu maju-mundur
                    rz5 = -0.40 + rpulse*0.80
                    ray_a = (1.0-abs(rpulse*2-1)) * 0.32
                    glColor4f(0.80, 0.95, 1.0, ray_a)
                    glBegin(GL_TRIANGLES)
                    glVertex3f(rx5,       h+0.011,  rz5)
                    glVertex3f(rx5-rw5,   h+0.011,  rz5+0.25)
                    glVertex3f(rx5+rw5,   h+0.011,  rz5+0.25)
                    glEnd()

                # ── Layer 5: Riak permukaan air beriak ────────
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
                for ri in range(4):
                    rph3 = (t_now*0.45 + ri*0.25) % 1.0
                    rad3 = 0.06 + rph3*0.40
                    alpha3 = (1-rph3) * 0.55
                    glColor4f(0.65, 0.92, 1.0, alpha3)
                    glBegin(GL_LINE_LOOP)
                    for si in range(24):
                        sa = si*(2*math.pi/24)
                        warp3 = 1.0 + 0.06*math.sin(sa*3 + t_now*1.2 + ph)
                        glVertex3f(math.cos(sa)*rad3*warp3, h+0.012,
                                   math.sin(sa)*rad3*warp3)
                    glEnd()

                # ── Layer 6: Kilau permukaan — caustic pattern ─
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                for ki in range(12):
                    ka = ki*(2*math.pi/12) + t_now*0.18 + ph
                    kr2 = 0.15 + 0.18*math.sin(ki*0.7+t_now*0.4)
                    kx3 = math.cos(ka)*kr2; kz3 = math.sin(ka)*kr2
                    ks2 = 0.25+0.65*abs(math.sin(t_now*1.8+ki*0.8+ph))
                    glColor4f(0.70, 0.95, 1.0, ks2*0.45)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(kx3, h+0.013, kz3)
                    for si in range(5):
                        sa2 = si*(2*math.pi/4)
                        glVertex3f(kx3+math.cos(sa2)*0.022, h+0.013, kz3+math.sin(sa2)*0.022)
                    glEnd()

                # ── Border batu karang di tepi tile ──────────
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
                _tile_border(0.1, 0.7, 0.85, 0.80)
                _tile_overlay(0.03, 0.20, 0.45, 0.40)
                _tile_border(0.2, 0.65, 1.0, 0.70)
                # Ombak berjalan dari kiri ke kanan
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                for wi in range(4):
                    wph2 = (t_now*0.7 + wi*0.25) % 1.0
                    wx2  = -0.45 + wph2 * 0.90
                    wa   = (1-abs(wph2*2-1))*0.7
                    wc   = 0.6+0.4*wph2
                    glColor4f(0.3, wc*0.7, wc, wa)
                    glBegin(GL_QUADS)
                    glVertex3f(wx2-0.08, h+0.006, -0.30)
                    glVertex3f(wx2+0.08, h+0.006, -0.30)
                    glVertex3f(wx2+0.05, h+0.006,  0.30)
                    glVertex3f(wx2-0.05, h+0.006,  0.30)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            elif nama == "Pantai Karang":
                # Pantai — pasir dan ombak kecil
                _tile_overlay(0.45, 0.38, 0.15, 0.45)
                _tile_border(0.9, 0.75, 0.3, 0.65)
                # Butir pasir
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                for si2 in range(20):
                    sx2 = math.cos(si2*0.31+ph)*0.35
                    sz2 = math.sin(si2*0.31+ph)*0.35
                    sc2 = 0.5+0.4*abs(math.sin(t_now*0.5+si2*0.7))
                    glColor4f(sc2*0.9, sc2*0.75, sc2*0.25, 0.5)
                    glBegin(GL_POINTS)
                    glVertex3f(sx2, h+0.006, sz2)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
                _tile_wave_lines(0.3, 0.7, 1.0)

            elif nama == "Singgasana Neptunus":
                # ── SINGGASANA NEPTUNUS — kursi tahta 3D Atlantis ──
                crown = 0.6+0.35*math.sin(t_now*1.5+ph)
                gold  = 0.7+0.28*math.sin(t_now*2.0+ph)
                bio   = 0.5+0.35*math.sin(t_now*1.2+ph+1.0)

                # Lantai dasar — batu emas gelap
                _tile_overlay(0.22*gold, 0.15*gold, 0.03, 0.95)

                # Pola lantai — hanya garis emas halus, TANPA biru
                for ri_t in range(3):
                    rr_t=0.38-ri_t*0.11
                    rp_t=0.35+0.18*math.sin(t_now*0.4+ri_t+ph)
                    glColor4f(rp_t*0.85, rp_t*0.68, rp_t*0.05, 0.55)
                    glBegin(GL_LINE_LOOP)
                    for si in range(32):
                        sa=si*(2*math.pi/32)
                        glVertex3f(math.cos(sa)*rr_t, h+0.003, math.sin(sa)*rr_t)
                    glEnd()
                # Jari-jari emas sangat tipis
                for sp in range(8):
                    a_sp=sp*(math.pi/4)+t_now*0.015
                    sg_sp=0.08+0.04*math.sin(t_now*0.5+sp+ph)
                    glColor4f(sg_sp*5.5, sg_sp*4.2, sg_sp*0.4, 0.45)
                    glBegin(GL_LINES)
                    glVertex3f(math.cos(a_sp)*0.07, h+0.004, math.sin(a_sp)*0.07)
                    glVertex3f(math.cos(a_sp)*0.36, h+0.004, math.sin(a_sp)*0.36)
                    glEnd()

                # ── SINGGASANA 3D ─────────────────────────────
                TSEG=10  # Segmen silinder

                # Platform / tumpuan singgasana
                glColor4f(0.35*gold,0.25*gold,0.04,1.0)
                glBegin(GL_QUADS)
                glVertex3f(-0.20,h+0.003, 0.15); glVertex3f( 0.20,h+0.003, 0.15)
                glVertex3f( 0.20,h+0.003,-0.20); glVertex3f(-0.20,h+0.003,-0.20)
                glEnd()
                # Sisi platform
                for px_t,pz_t,pw_t,pd_t in [
                    (0, 0.15, 0.40,0.005), (0,-0.20, 0.40,0.005),
                    (-0.20,0,0.005,0.35), (0.20,0,0.005,0.35)]:
                    glColor4f(0.28*gold,0.20*gold,0.03,1.0)
                    glBegin(GL_QUADS)
                    glVertex3f(px_t-pw_t/2,h+0.003,pz_t-pd_t/2)
                    glVertex3f(px_t+pw_t/2,h+0.003,pz_t-pd_t/2)
                    glVertex3f(px_t+pw_t/2,h+0.015,pz_t+pd_t/2)
                    glVertex3f(px_t-pw_t/2,h+0.015,pz_t+pd_t/2)
                    glEnd()

                # Kaki singgasana — 4 kaki karang emas
                for kx,kz in [(-0.14,-0.15),(0.14,-0.15),(-0.14,0.09),(0.14,0.09)]:
                    # Kaki silinder
                    for si in range(TSEG):
                        a0=si*(2*math.pi/TSEG); a1=(si+1)*(2*math.pi/TSEG)
                        lt=0.5+0.5*math.cos(a0+0.3)
                        glColor4f(0.45*lt*gold,0.32*lt*gold,0.05*lt,1.0)
                        glBegin(GL_QUADS)
                        glVertex3f(kx+math.cos(a0)*0.030,h+0.015,kz+math.sin(a0)*0.030)
                        glVertex3f(kx+math.cos(a1)*0.030,h+0.015,kz+math.sin(a1)*0.030)
                        glVertex3f(kx+math.cos(a1)*0.028,h+0.003,kz+math.sin(a1)*0.028)
                        glVertex3f(kx+math.cos(a0)*0.028,h+0.003,kz+math.sin(a0)*0.028)
                        glEnd()
                    # Alas kaki
                    glColor4f(0.38*gold,0.26*gold,0.04,1.0)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(kx,h+0.003,kz)
                    for si in range(TSEG+1):
                        a=si*(2*math.pi/TSEG)
                        glVertex3f(kx+math.cos(a)*0.040,h+0.003,kz+math.sin(a)*0.040)
                    glEnd()

                # Dudukan / seat kursi
                glColor4f(0.40*gold,0.28*gold,0.04,1.0)
                glBegin(GL_QUADS)
                # Atas seat
                glVertex3f(-0.17,h+0.015, 0.10); glVertex3f(0.17,h+0.015, 0.10)
                glVertex3f( 0.17,h+0.015,-0.16); glVertex3f(-0.17,h+0.015,-0.16)
                glEnd()
                # Tepi seat — rounded look
                for si in range(TSEG):
                    a0=si*(2*math.pi/TSEG); a1=(si+1)*(2*math.pi/TSEG)
                    # Hanya sisi depan-kiri-kanan (z+, x-, x+)
                for edge_verts in [
                    [(-0.17,h+0.003,0.10),( 0.17,h+0.003,0.10),(0.17,h+0.015,0.10),(-0.17,h+0.015,0.10)],
                    [(-0.17,h+0.003,-0.16),(-0.17,h+0.003,0.10),(-0.17,h+0.015,0.10),(-0.17,h+0.015,-0.16)],
                    [( 0.17,h+0.003,0.10),( 0.17,h+0.003,-0.16),( 0.17,h+0.015,-0.16),( 0.17,h+0.015,0.10)],
                ]:
                    glColor4f(0.35*gold,0.24*gold,0.03,1.0)
                    glBegin(GL_QUADS)
                    for v in edge_verts: glVertex3f(*v)
                    glEnd()

                # ── Sandaran punggung — tegak megah ──────────
                back_h=0.20  # tinggi sandaran
                # Panel utama sandaran
                glColor4f(0.42*gold,0.30*gold,0.04,1.0)
                glBegin(GL_QUADS)
                glVertex3f(-0.17,h+0.015,-0.16); glVertex3f(0.17,h+0.015,-0.16)
                glVertex3f( 0.17,h+0.015+back_h,-0.16); glVertex3f(-0.17,h+0.015+back_h,-0.16)
                glEnd()
                # Sisi kiri sandaran
                glColor4f(0.36*gold,0.25*gold,0.03,1.0)
                glBegin(GL_QUADS)
                glVertex3f(-0.17,h+0.015,-0.16); glVertex3f(-0.17,h+0.015,-0.13)
                glVertex3f(-0.17,h+0.015+back_h,-0.13); glVertex3f(-0.17,h+0.015+back_h,-0.16)
                glEnd()
                # Sisi kanan sandaran
                glBegin(GL_QUADS)
                glVertex3f(0.17,h+0.015,-0.13); glVertex3f(0.17,h+0.015,-0.16)
                glVertex3f(0.17,h+0.015+back_h,-0.16); glVertex3f(0.17,h+0.015+back_h,-0.13)
                glEnd()

                # Dekorasi sandaran — pola karang ukiran
                deco_y=h+0.015+back_h*0.55
                glEnable(GL_BLEND); glBlendFunc(GL_SRC_ALPHA,GL_ONE)
                # Bintang Atlantis di sandaran
                star_g=0.45+0.35*math.sin(t_now*1.5+ph)
                glColor4f(star_g,star_g*0.85,0.08,0.85)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0,deco_y,-0.159)
                for si in range(11):
                    sa=si*(2*math.pi/10)+t_now*0.08
                    rs=0.065 if si%2==0 else 0.028
                    glVertex3f(math.cos(sa)*rs,deco_y+math.sin(sa)*rs,-0.159)
                glEnd()
                # Lingkaran dekorasi
                for dr in [0.10,0.075,0.050]:
                    rp_d=0.4+0.3*math.sin(t_now*0.8+dr*10+ph)
                    glColor4f(rp_d*0.8,rp_d*0.68,0.06,0.60)
                    glBegin(GL_LINE_LOOP)
                    for si in range(24):
                        sa=si*(2*math.pi/24)
                        glVertex3f(math.cos(sa)*dr,deco_y+math.sin(sa)*dr,-0.158)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA,GL_ONE_MINUS_SRC_ALPHA)

                # ── Lengan singgasana kiri & kanan ────────────
                for ax,az_s,az_e in [(-0.17,0.10,-0.16),(0.17,0.10,-0.16)]:
                    # Lengan horizontal
                    glColor4f(0.38*gold,0.27*gold,0.04,1.0)
                    glBegin(GL_QUADS)
                    glVertex3f(ax-0.02,h+0.062,az_s); glVertex3f(ax+0.02,h+0.062,az_s)
                    glVertex3f(ax+0.02,h+0.062,az_e); glVertex3f(ax-0.02,h+0.062,az_e)
                    glEnd()
                    # Tiang lengan
                    arm_sign = -1 if ax < 0 else 1
                    for si in range(TSEG):
                        a0=si*(2*math.pi/TSEG); a1=(si+1)*(2*math.pi/TSEG)
                        lt=0.5+0.5*math.cos(a0+0.3)
                        glColor4f(0.40*lt*gold,0.28*lt*gold,0.04,1.0)
                        glBegin(GL_QUADS)
                        glVertex3f(ax+arm_sign*0.015+math.cos(a0)*0.018,h+0.062,az_s-0.06+math.sin(a0)*0.018)
                        glVertex3f(ax+arm_sign*0.015+math.cos(a1)*0.018,h+0.062,az_s-0.06+math.sin(a1)*0.018)
                        glVertex3f(ax+arm_sign*0.015+math.cos(a1)*0.018,h+0.015,az_s-0.06+math.sin(a1)*0.018)
                        glVertex3f(ax+arm_sign*0.015+math.cos(a0)*0.018,h+0.015,az_s-0.06+math.sin(a0)*0.018)
                        glEnd()

                # ── Trisula Neptunus di puncak sandaran ───────
                tri_y=h+0.015+back_h+0.005
                tri_x=0.0; tri_z=-0.160
                # Tangkai trisula vertikal
                glColor4f(0.55*gold,0.42*gold,0.06,1.0)
                for si in range(TSEG):
                    a0=si*(2*math.pi/TSEG); a1=(si+1)*(2*math.pi/TSEG)
                    lt=0.5+0.5*math.cos(a0)
                    glColor4f(0.50*lt*gold,0.38*lt*gold,0.05,1.0)
                    glBegin(GL_QUADS)
                    glVertex3f(tri_x+math.cos(a0)*0.012,tri_y+0.09,tri_z+math.sin(a0)*0.012)
                    glVertex3f(tri_x+math.cos(a1)*0.012,tri_y+0.09,tri_z+math.sin(a1)*0.012)
                    glVertex3f(tri_x+math.cos(a1)*0.010,tri_y,      tri_z+math.sin(a1)*0.010)
                    glVertex3f(tri_x+math.cos(a0)*0.010,tri_y,      tri_z+math.sin(a0)*0.010)
                    glEnd()
                # 3 ujung trisula
                glEnable(GL_BLEND); glBlendFunc(GL_SRC_ALPHA,GL_ONE)
                for ti in range(3):
                    ta_tri=ti*(2*math.pi/3)+math.pi/6
                    tx_tri=tri_x+math.cos(ta_tri)*0.040
                    tz_tri=tri_z
                    ty_tri=tri_y+0.09+ti*0.0
                    # Batang ujung
                    tg_tri=0.5+0.4*math.sin(t_now*2.0+ti*1.2+ph)
                    glColor4f(tg_tri*0.9,tg_tri*0.75,0.08,0.88)
                    glBegin(GL_QUADS)
                    glVertex3f(tx_tri-0.006,ty_tri,    tz_tri)
                    glVertex3f(tx_tri+0.006,ty_tri,    tz_tri)
                    glVertex3f(tx_tri+0.006,ty_tri+0.06,tz_tri)
                    glVertex3f(tx_tri-0.006,ty_tri+0.06,tz_tri)
                    glEnd()
                    # Ujung lancip
                    glColor4f(min(1,tg_tri+0.2),min(1,tg_tri*0.9+0.1),0.10,0.90)
                    glBegin(GL_TRIANGLES)
                    glVertex3f(tx_tri,      ty_tri+0.06+0.04,tz_tri)
                    glVertex3f(tx_tri-0.010,ty_tri+0.06,     tz_tri)
                    glVertex3f(tx_tri+0.010,ty_tri+0.06,     tz_tri)
                    glEnd()
                    # Glow ujung
                    tg2=0.55+0.40*math.sin(t_now*2.5+ti*1.5+ph)
                    glColor4f(tg2*0.8,tg2,0.2,tg2*0.70)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(tx_tri,ty_tri+0.06+0.04,tz_tri)
                    for si in range(7):
                        sa=si*(2*math.pi/6)
                        glVertex3f(tx_tri+math.cos(sa)*0.016,ty_tri+0.06+0.04,tz_tri+math.sin(sa)*0.010)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA,GL_ONE_MINUS_SRC_ALPHA)

                # Sinar emas menyebar dari singgasana — lebih redup & hangat
                glEnable(GL_BLEND); glBlendFunc(GL_SRC_ALPHA,GL_ONE)
                for ri2 in range(8):
                    ra2=ri2*(math.pi/4)+t_now*0.12+ph
                    rlen2=0.34+0.04*math.sin(t_now*1.5+ri2)
                    rg2=0.18+0.10*math.sin(t_now+ri2)
                    glColor4f(rg2*3.2, rg2*2.5, 0.06, rg2*1.5)
                    glBegin(GL_TRIANGLES)
                    glVertex3f(0, h+0.005, 0)
                    glVertex3f(math.cos(ra2+0.10)*rlen2, h+0.005, math.sin(ra2+0.10)*rlen2)
                    glVertex3f(math.cos(ra2-0.10)*rlen2, h+0.005, math.sin(ra2-0.10)*rlen2)
                    glEnd()
                # Glow aura emas hangat — tidak biru
                ag=0.28+0.18*math.sin(t_now*1.2+ph)
                glColor4f(ag*0.95, ag*0.75, 0.05, ag*0.50)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.005, 0)
                for si in range(17):
                    sa=si*(2*math.pi/16)
                    glVertex3f(math.cos(sa)*0.20, h+0.005, math.sin(sa)*0.20)
                glEnd()
                glBlendFunc(GL_SRC_ALPHA,GL_ONE_MINUS_SRC_ALPHA)

                # Border emas megah
                _tile_border(gold,gold*0.82,0.08,0.92,0.06)

            elif nama == "Denda Badai Laut":
                # Badai — langit gelap, kilat
                storm = 0.4+0.3*math.sin(t_now*3.0+ph)
                _tile_overlay(0.08, 0.08, 0.20, 0.55)
                _tile_border(0.6, 0.6, 0.9, 0.70)
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                # Kilat berkedip
                if math.sin(t_now*4+ph) > 0.6:
                    glColor4f(0.9, 0.95, 1.0, 0.85)
                    # Zigzag kilat
                    pts = [(0,0),(0.08,-0.12),(-0.04,-0.18),(0.10,-0.30),(0,-0.40)]
                    glBegin(GL_LINE_STRIP)
                    for px2,pz2 in pts:
                        glVertex3f(px2, h+0.009, pz2)
                    glEnd()
                # Awan abu
                for ci3 in range(5):
                    ca3 = ci3*(2*math.pi/5)+ph
                    cx4 = math.cos(ca3)*0.25; cz4 = math.sin(ca3)*0.25
                    cb4 = 0.3+0.2*math.sin(t_now*0.8+ci3)
                    glColor4f(cb4*0.6, cb4*0.6, cb4*0.8, 0.45)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(cx4, h+0.007, cz4)
                    for si4 in range(9):
                        sa4 = si4*(2*math.pi/8)
                        glVertex3f(cx4+math.cos(sa4)*0.12, h+0.007, cz4+math.sin(sa4)*0.12)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            elif nama == "Menara Mercusuar":
                # ── MENARA MERCUSUAR 3D — di atas lantai ──────
                _tile_overlay(0.08, 0.12, 0.18, 0.92)
                q_mm = gluNewQuadric()

                # Lantai batu karang — fondasi menara
                glColor4f(0.12, 0.16, 0.20, 1.0)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.002, 0)
                for si in range(9):
                    sa = si*(2*math.pi/8)
                    glVertex3f(math.cos(sa)*0.20, h+0.002, math.sin(sa)*0.20)
                glEnd()

                # Alas fondasi — batu karang melingkar
                for ai in range(8):
                    aa = ai*(2*math.pi/8)
                    ax3 = math.cos(aa)*0.18; az3 = math.sin(aa)*0.18
                    ab3 = 0.35+0.20*math.sin(t_now*0.4+ai)
                    glColor4f(0.08*ab3, 0.20*ab3, 0.26*ab3, 1.0)
                    glPushMatrix(); glTranslatef(ax3, h+0.003, az3)
                    gluSphere(q_mm, 0.030, 5, 3)
                    glPopMatrix()

                # ── Badan menara — silinder bertingkat ────────
                MSEG = 10
                # Tingkat 1: Dasar lebar
                for si in range(MSEG):
                    a0=si*(2*math.pi/MSEG); a1=(si+1)*(2*math.pi/MSEG)
                    lt = 0.55+0.45*math.cos(a0+0.3)
                    glColor4f(0.22*lt, 0.16*lt, 0.08*lt, 1.0)  # Batu abu-coklat
                    glBegin(GL_QUADS)
                    glVertex3f(math.cos(a0)*0.085, h+0.072, math.sin(a0)*0.085)
                    glVertex3f(math.cos(a1)*0.085, h+0.072, math.sin(a1)*0.085)
                    glVertex3f(math.cos(a1)*0.080, h+0.004, math.sin(a1)*0.080)
                    glVertex3f(math.cos(a0)*0.080, h+0.004, math.sin(a0)*0.080)
                    glEnd()
                # Tutup tingkat 1
                glColor4f(0.28, 0.20, 0.10, 1.0)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.072, 0)
                for si in range(MSEG+1):
                    a=si*(2*math.pi/MSEG)
                    glVertex3f(math.cos(a)*0.085, h+0.072, math.sin(a)*0.085)
                glEnd()

                # Cincin dekoratif tingkat 1
                glColor4f(0.35, 0.25, 0.10, 1.0)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.075, 0)
                for si in range(MSEG+1):
                    a=si*(2*math.pi/MSEG)
                    glVertex3f(math.cos(a)*0.098, h+0.075, math.sin(a)*0.098)
                glEnd()

                # Tingkat 2: Badan tengah lebih ramping
                for si in range(MSEG):
                    a0=si*(2*math.pi/MSEG); a1=(si+1)*(2*math.pi/MSEG)
                    lt = 0.50+0.50*math.cos(a0+0.4)
                    # Pola bergaris — batu putih & merah bergantian
                    stripe = (si % 2 == 0)
                    if stripe:
                        glColor4f(0.85*lt, 0.80*lt, 0.75*lt, 1.0)  # Putih batu
                    else:
                        glColor4f(0.75*lt, 0.22*lt, 0.15*lt, 1.0)  # Merah karang
                    glBegin(GL_QUADS)
                    glVertex3f(math.cos(a0)*0.060, h+0.157, math.sin(a0)*0.060)
                    glVertex3f(math.cos(a1)*0.060, h+0.157, math.sin(a1)*0.060)
                    glVertex3f(math.cos(a1)*0.065, h+0.075, math.sin(a1)*0.065)
                    glVertex3f(math.cos(a0)*0.065, h+0.075, math.sin(a0)*0.065)
                    glEnd()

                # Tutup tingkat 2
                glColor4f(0.30, 0.22, 0.10, 1.0)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.157, 0)
                for si in range(MSEG+1):
                    a=si*(2*math.pi/MSEG)
                    glVertex3f(math.cos(a)*0.060, h+0.157, math.sin(a)*0.060)
                glEnd()
                # Cincin dekoratif tingkat 2
                glColor4f(0.32, 0.24, 0.10, 1.0)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.160, 0)
                for si in range(MSEG+1):
                    a=si*(2*math.pi/MSEG)
                    glVertex3f(math.cos(a)*0.072, h+0.160, math.sin(a)*0.072)
                glEnd()

                # Tingkat 3: Ruang lampu — paling sempit
                for si in range(MSEG):
                    a0=si*(2*math.pi/MSEG); a1=(si+1)*(2*math.pi/MSEG)
                    lt = 0.55+0.45*math.cos(a0+0.3)
                    glColor4f(0.30*lt, 0.22*lt, 0.10*lt, 1.0)
                    glBegin(GL_QUADS)
                    glVertex3f(math.cos(a0)*0.042, h+0.208, math.sin(a0)*0.042)
                    glVertex3f(math.cos(a1)*0.042, h+0.208, math.sin(a1)*0.042)
                    glVertex3f(math.cos(a1)*0.045, h+0.160, math.sin(a1)*0.045)
                    glVertex3f(math.cos(a0)*0.045, h+0.160, math.sin(a0)*0.045)
                    glEnd()

                # ── Kaca jendela lampu — transparan kuning ────
                lp_pulse = 0.7+0.3*abs(math.sin(t_now*2.0+ph))
                glEnable(GL_BLEND); glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
                for si in range(MSEG):
                    a0=si*(2*math.pi/MSEG); a1=(si+1)*(2*math.pi/MSEG)
                    glColor4f(lp_pulse*0.95, lp_pulse*0.85, 0.20, 0.55)
                    glBegin(GL_QUADS)
                    glVertex3f(math.cos(a0)*0.043, h+0.205, math.sin(a0)*0.043)
                    glVertex3f(math.cos(a1)*0.043, h+0.205, math.sin(a1)*0.043)
                    glVertex3f(math.cos(a1)*0.043, h+0.165, math.sin(a1)*0.043)
                    glVertex3f(math.cos(a0)*0.043, h+0.165, math.sin(a0)*0.043)
                    glEnd()

                # ── Atap kerucut ──────────────────────────────
                glColor4f(0.18, 0.14, 0.06, 1.0)
                glPushMatrix(); glTranslatef(0, h+0.208, 0)
                gluCylinder(q_mm, 0.050, 0.0, 0.040, MSEG, 1)
                glPopMatrix()
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(0, h+0.208, 0)
                for si in range(MSEG+1):
                    a=si*(2*math.pi/MSEG)
                    glVertex3f(math.cos(a)*0.050, h+0.208, math.sin(a)*0.050)
                glEnd()

                # ── Sinar lampu berputar ──────────────────────
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                beam_ang = t_now*1.8+ph
                for bi2 in range(2):
                    ba2 = beam_ang + bi2*math.pi
                    bl2 = 0.38
                    bw2 = 0.08
                    bright = 0.6+0.35*abs(math.sin(t_now*3+bi2))
                    glColor4f(lp_pulse*0.95, lp_pulse*0.88, 0.15, bright*0.45)
                    glBegin(GL_TRIANGLES)
                    glVertex3f(0, h+0.189, 0)
                    glVertex3f(math.cos(ba2+bw2)*bl2, h+0.189, math.sin(ba2+bw2)*bl2)
                    glVertex3f(math.cos(ba2-bw2)*bl2, h+0.189, math.sin(ba2-bw2)*bl2)
                    glEnd()

                # Glow lampu di puncak
                glColor4f(lp_pulse*0.9, lp_pulse*0.82, 0.12, lp_pulse*0.80)
                glPushMatrix(); glTranslatef(0, h+0.189, 0)
                gluSphere(q_mm, 0.022, 8, 6)
                glPopMatrix()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

                # Puncak antena
                glColor4f(0.30, 0.24, 0.10, 1.0)
                glPushMatrix(); glTranslatef(0, h+0.272, 0); glRotatef(90,1,0,0)
                gluCylinder(q_mm, 0.006, 0.003, 0.040, 5, 1)
                glPopMatrix()

                gluDeleteQuadric(q_mm)

            elif nama == "Tahta Raja Lautan":
                # Tahta — ungu-biru kerajaan
                royal = 0.5+0.3*math.sin(t_now*1.5+ph)
                _tile_overlay(0.15, 0.05, 0.35*royal, 0.45)
                _tile_border(0.6, 0.2, 1.0, 0.80)
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                # Permata di sekeliling
                for ji in range(6):
                    ja = ji*(2*math.pi/6) + t_now*0.1+ph
                    jx2 = math.cos(ja)*0.28; jz2 = math.sin(ja)*0.28
                    jg2 = 0.5+0.5*abs(math.sin(t_now*2+ji))
                    jcols = [(0.3,0.1,1.0),(0.1,0.6,1.0),(0.8,0.1,0.8)]
                    jr2,jg3,jb2 = jcols[ji%3]
                    glColor4f(jr2*jg2, jg3*jg2, jb2*jg2, 0.80)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(jx2, h+0.010, jz2)
                    for si5 in range(5):
                        sa5 = si5*(2*math.pi/4)
                        glVertex3f(jx2+math.cos(sa5)*0.06, h+0.010, jz2+math.sin(sa5)*0.06)
                    glEnd()
                _tile_glow_center(0.5, 0.2, 1.0, 0.7)
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            elif "Atlantis" in nama or "Kota Atlantis" in nama or "Istana Atlantis" in nama:
                # ── KOTA / ISTANA ATLANTIS — reruntuhan 3D bawah laut ──
                is_istana = ("Istana" in nama)

                if not hasattr(self, '_atl_data'):
                    import random as _ra
                    self._atl_mosaic = [
                        (_ra.uniform(-0.42,0.42), _ra.uniform(-0.42,0.42),
                         _ra.uniform(0.03,0.08), _ra.uniform(0.04,0.09),
                         _ra.uniform(0,6.28))
                        for _ in range(22)
                    ]
                    self._atl_particles = [
                        (_ra.uniform(-0.36,0.36), _ra.uniform(-0.36,0.36),
                         _ra.uniform(0,6.28), _ra.uniform(0.4,1.5))
                        for _ in range(16)
                    ]
                    self._atl_data = True

                # Dasar lantai batu kuno
                _tile_overlay(0.04, 0.14, 0.20, 0.95)

                # Mozaik batu kuno
                for mx,mz,mw,md,mrot in self._atl_mosaic:
                    age = 0.45+0.20*math.sin(mx*3+mz*2)
                    glColor4f(0.08*age, 0.30*age, 0.36*age, 0.90)
                    glPushMatrix()
                    glTranslatef(mx, h+0.002, mz)
                    glRotatef(math.degrees(mrot),0,1,0)
                    glBegin(GL_QUADS)
                    glVertex3f(-mw,0,-md); glVertex3f(mw,0,-md)
                    glVertex3f(mw,0,md);   glVertex3f(-mw,0,md)
                    glEnd()
                    glColor4f(0.02,0.06,0.09,0.95)
                    glBegin(GL_LINE_LOOP)
                    glVertex3f(-mw,0.001,-md); glVertex3f(mw,0.001,-md)
                    glVertex3f(mw,0.001,md);   glVertex3f(-mw,0.001,md)
                    glEnd()
                    glPopMatrix()

                # Ring konsentris lantai
                for ri_i,(ring_r,ring_col) in enumerate([
                    (0.38,(0.10,0.40,0.46)),
                    (0.27,(0.06,0.32,0.38)),
                    (0.16,(0.04,0.24,0.30)),
                ]):
                    rp3 = 0.6+0.3*math.sin(t_now*0.4+ri_i*1.2+ph)
                    glColor4f(ring_col[0]*rp3,ring_col[1]*rp3,ring_col[2]*rp3,0.85)
                    glBegin(GL_LINE_LOOP)
                    for si in range(48):
                        sa = si*(2*math.pi/48)
                        warp = 1.0+0.04*math.sin(sa*6+t_now*0.3)
                        glVertex3f(math.cos(sa)*ring_r*warp,h+0.003,math.sin(sa)*ring_r*warp)
                    glEnd()

                # Jari-jari mozaik
                spoke_g = 0.12+0.06*math.sin(t_now*0.5+ph)
                n_spoke = 8 if is_istana else 6
                glColor4f(0.05,spoke_g*2.8,spoke_g*3.2,0.75)
                for sp in range(n_spoke):
                    a_s = sp*(2*math.pi/n_spoke)+t_now*0.03
                    x1=math.cos(a_s)*0.06; z1=math.sin(a_s)*0.06
                    x2=math.cos(a_s)*0.37; z2=math.sin(a_s)*0.37
                    perp=a_s+math.pi/2; pw2=0.012
                    glBegin(GL_QUADS)
                    glVertex3f(x1+math.cos(perp)*pw2,h+0.004,z1+math.sin(perp)*pw2)
                    glVertex3f(x1-math.cos(perp)*pw2,h+0.004,z1-math.sin(perp)*pw2)
                    glVertex3f(x2-math.cos(perp)*pw2,h+0.004,z2-math.sin(perp)*pw2)
                    glVertex3f(x2+math.cos(perp)*pw2,h+0.004,z2+math.sin(perp)*pw2)
                    glEnd()

                # Pilar mini 3D
                PSEG=8; n_pilar=6 if is_istana else 4
                for pi_i in range(n_pilar):
                    pa = pi_i*(2*math.pi/n_pilar)+ph*0.1
                    px4=math.cos(pa)*0.30; pz4=math.sin(pa)*0.30
                    ph4=(0.12 if is_istana else 0.09)+0.015*math.sin(t_now*0.6+pi_i*1.1)
                    pr4=0.032 if is_istana else 0.028
                    pp4=0.45+0.30*abs(math.sin(t_now*0.5+pi_i*0.8))
                    for seg in range(PSEG):
                        a0=seg*(2*math.pi/PSEG); a1=(seg+1)*(2*math.pi/PSEG)
                        light=0.6+0.4*math.cos(a0+0.5)
                        glColor4f(0.06*light,0.28*pp4*light,0.34*pp4*light,0.92)
                        glBegin(GL_QUADS)
                        glVertex3f(px4+math.cos(a0)*pr4,h+ph4,pz4+math.sin(a0)*pr4)
                        glVertex3f(px4+math.cos(a1)*pr4,h+ph4,pz4+math.sin(a1)*pr4)
                        glVertex3f(px4+math.cos(a1)*pr4,h+0.003,pz4+math.sin(a1)*pr4)
                        glVertex3f(px4+math.cos(a0)*pr4,h+0.003,pz4+math.sin(a0)*pr4)
                        glEnd()
                    glColor4f(0.08,pp4*0.65,pp4*0.75,0.88)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(px4,h+ph4,pz4)
                    for seg in range(PSEG+1):
                        a=seg*(2*math.pi/PSEG)
                        glVertex3f(px4+math.cos(a)*pr4,h+ph4,pz4+math.sin(a)*pr4)
                    glEnd()
                    cr4=pr4*1.6; ch4=0.018
                    glColor4f(0.04,pp4*0.80,pp4*0.90,0.82)
                    for seg in range(PSEG):
                        a0=seg*(2*math.pi/PSEG); a1=(seg+1)*(2*math.pi/PSEG)
                        glBegin(GL_QUADS)
                        glVertex3f(px4+math.cos(a0)*cr4,h+ph4+ch4,pz4+math.sin(a0)*cr4)
                        glVertex3f(px4+math.cos(a1)*cr4,h+ph4+ch4,pz4+math.sin(a1)*cr4)
                        glVertex3f(px4+math.cos(a1)*pr4,h+ph4,    pz4+math.sin(a1)*pr4)
                        glVertex3f(px4+math.cos(a0)*pr4,h+ph4,    pz4+math.sin(a0)*pr4)
                        glEnd()
                    glBlendFunc(GL_SRC_ALPHA,GL_ONE)
                    tg=0.40+0.35*math.sin(t_now*1.5+pi_i*0.9+ph)
                    glColor4f(0.0,tg*0.9,tg*0.85,tg*0.65)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(px4,h+ph4+ch4+0.025,pz4)
                    for seg in range(PSEG+1):
                        a=seg*(2*math.pi/PSEG)
                        glVertex3f(px4+math.cos(a)*cr4*0.8,h+ph4+ch4,pz4+math.sin(a)*cr4*0.8)
                    glEnd()
                    glBlendFunc(GL_SRC_ALPHA,GL_ONE_MINUS_SRC_ALPHA)

                # Kubah (Istana) atau Obelisk (Kota)
                if is_istana:
                    DSEG=16; dr=0.13; dh=0.10
                    dp=0.5+0.3*math.sin(t_now*0.8+ph)
                    for di in range(8):
                        lat0=di*(math.pi/2/8); lat1=(di+1)*(math.pi/2/8)
                        r0=math.sin(lat0)*dr; y0=math.cos(lat0)*dh
                        r1=math.sin(lat1)*dr; y1=math.cos(lat1)*dh
                        ld=0.5+0.5*(di/8)
                        glColor4f(0.05*ld,dp*0.55*ld,dp*0.65*ld,0.80)
                        glBegin(GL_QUADS)
                        for seg in range(DSEG):
                            a0=seg*(2*math.pi/DSEG); a1=(seg+1)*(2*math.pi/DSEG)
                            glVertex3f(math.cos(a0)*r0,h+0.003+y0,math.sin(a0)*r0)
                            glVertex3f(math.cos(a1)*r0,h+0.003+y0,math.sin(a1)*r0)
                            glVertex3f(math.cos(a1)*r1,h+0.003+y1,math.sin(a1)*r1)
                            glVertex3f(math.cos(a0)*r1,h+0.003+y1,math.sin(a0)*r1)
                        glEnd()
                    for di in range(1,5):
                        lat=di*(math.pi/2/5)
                        rd=math.sin(lat)*dr*1.01; yd=math.cos(lat)*dh
                        lp=0.12+0.06*math.sin(t_now*0.6+di*0.8+ph)
                        glColor4f(0.0,lp*2.8,lp*3.2,0.70)
                        glBegin(GL_LINE_LOOP)
                        for seg in range(DSEG):
                            a=seg*(2*math.pi/DSEG)
                            glVertex3f(math.cos(a)*rd,h+0.004+yd,math.sin(a)*rd)
                        glEnd()
                    glBlendFunc(GL_SRC_ALPHA,GL_ONE)
                    td=0.55+0.40*math.sin(t_now*2.0+ph)
                    glColor4f(0.3*td,td,td*0.95,td*0.75)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(0,h+0.003+dh+0.04,0)
                    for seg in range(9):
                        a=seg*(2*math.pi/8)
                        glVertex3f(math.cos(a)*0.025,h+0.003+dh,math.sin(a)*0.025)
                    glEnd()
                    glBlendFunc(GL_SRC_ALPHA,GL_ONE_MINUS_SRC_ALPHA)
                else:
                    sg=0.45+0.30*math.sin(t_now*1.0+ph)
                    glBlendFunc(GL_SRC_ALPHA,GL_ONE)
                    glColor4f(0.0,sg*0.9,sg*0.85,0.75)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(0,h+0.005,0)
                    for si in range(17):
                        sa=si*(2*math.pi/16)+t_now*0.15+ph
                        rs=0.12 if si%2==0 else 0.05
                        glVertex3f(math.cos(sa)*rs,h+0.005,math.sin(sa)*rs)
                    glEnd()
                    glBlendFunc(GL_SRC_ALPHA,GL_ONE_MINUS_SRC_ALPHA)
                    ob_h=0.09; ob_r=0.020
                    ob_p=0.5+0.3*math.sin(t_now*0.9+ph)
                    for seg in range(8):
                        a0=seg*(2*math.pi/8); a1=(seg+1)*(2*math.pi/8)
                        lo=0.55+0.45*math.cos(a0+0.4)
                        glColor4f(0.06*lo,ob_p*0.60*lo,ob_p*0.70*lo,0.90)
                        glBegin(GL_QUADS)
                        glVertex3f(math.cos(a0)*ob_r,h+ob_h,math.sin(a0)*ob_r)
                        glVertex3f(math.cos(a1)*ob_r,h+ob_h,math.sin(a1)*ob_r)
                        glVertex3f(math.cos(a1)*ob_r*0.3,h+ob_h+0.04,math.sin(a1)*ob_r*0.3)
                        glVertex3f(math.cos(a0)*ob_r*0.3,h+ob_h+0.04,math.sin(a0)*ob_r*0.3)
                        glEnd()
                        glBegin(GL_QUADS)
                        glVertex3f(math.cos(a0)*ob_r*1.5,h+0.003,math.sin(a0)*ob_r*1.5)
                        glVertex3f(math.cos(a1)*ob_r*1.5,h+0.003,math.sin(a1)*ob_r*1.5)
                        glVertex3f(math.cos(a1)*ob_r,h+ob_h,math.sin(a1)*ob_r)
                        glVertex3f(math.cos(a0)*ob_r,h+ob_h,math.sin(a0)*ob_r)
                        glEnd()
                    glBlendFunc(GL_SRC_ALPHA,GL_ONE)
                    og=0.50+0.40*math.sin(t_now*2.2+ph)
                    glColor4f(0.2*og,og,og*0.95,og*0.70)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(0,h+ob_h+0.05,0)
                    for seg in range(9):
                        a=seg*(2*math.pi/8)
                        glVertex3f(math.cos(a)*0.018,h+ob_h+0.04,math.sin(a)*0.018)
                    glEnd()
                    glBlendFunc(GL_SRC_ALPHA,GL_ONE_MINUS_SRC_ALPHA)

                # Partikel emas melayang
                glBlendFunc(GL_SRC_ALPHA,GL_ONE)
                for px5,pz5,pph,pspd in self._atl_particles:
                    dy5=h+0.006+0.025*math.sin(t_now*pspd+pph)
                    dx5=px5+math.sin(t_now*pspd*0.5+pph)*0.02
                    pg2=0.30+0.55*abs(math.sin(t_now*pspd+pph))
                    glColor4f(pg2,pg2*0.82,0.08,pg2*0.65)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(dx5,dy5,pz5)
                    for si in range(5):
                        sa=si*(2*math.pi/4)
                        glVertex3f(dx5+math.cos(sa)*0.012,dy5,pz5+math.sin(sa)*0.012)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA,GL_ONE_MINUS_SRC_ALPHA)

                _tile_bubbles(4,0.0,0.75,0.85)
                bg3=0.55+0.20*math.sin(t_now*0.7+ph)
                _tile_border(0.0,bg3,bg3*0.95,0.90)

            elif nama == "Permukaan Laut":
                # GO — air berkilau, cahaya matahari dari atas
                _tile_overlay(0.05, 0.30, 0.50, 0.40)
                _tile_border(0.3, 0.85, 1.0, 0.80)
                _tile_ripples(0.3, 0.8, 1.0)
                _tile_glow_center(0.5, 0.9, 1.0, 0.7)

            elif nama == "Palung Mariana":
                # Penjara — biru hitam, gelap dalam
                _tile_overlay(0.01, 0.04, 0.12, 0.60)
                _tile_border(0.3, 0.3, 0.8, 0.65)
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                # Mata di kegelapan
                for ei in range(3):
                    ea = ei*(2*math.pi/3)+ph
                    ex2 = math.cos(ea)*0.22; ez2 = math.sin(ea)*0.22
                    eg2 = 0.3+0.4*abs(math.sin(t_now*1.5+ei+ph))
                    glColor4f(0.1, eg2, 0.5, 0.7)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(ex2, h+0.008, ez2)
                    for si8 in range(9):
                        sa8 = si8*(2*math.pi/8)
                        glVertex3f(ex2+math.cos(sa8)*0.07, h+0.008, ez2+math.sin(sa8)*0.07)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            elif nama == "Terumbu Karang" and idx == 20:
                # Parkir Gratis / Terumbu — toska tenang
                _tile_overlay(0.04, 0.28, 0.32, 0.40)
                _tile_border(0.0, 0.8, 0.85, 0.70)
                _tile_ripples(0.0, 0.7, 0.8)
                _tile_dots(8, 0.0, 0.9, 0.8, 0.6)

            elif nama == "Pusaran Arus":
                # Pusaran Arus digambar penuh oleh _draw_special_icons
                # Tile overlay dikosongkan agar tidak menimpa animasi pusaran air
                pass

            elif nama == "Delta Sungai":
                # Delta — pertemuan sungai & laut, lumpur coklat-hijau, aliran bercabang
                _tile_overlay(0.18, 0.14, 0.06, 0.55)
                _tile_border(0.4, 0.6, 0.2, 0.70)
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                # Aliran sungai — 3 cabang delta bergerak
                for bi in range(3):
                    ba = -0.3 + bi*0.3   # posisi x tiap cabang
                    flow = math.sin(t_now*0.8 + bi*1.2 + ph)*0.06
                    bri  = 0.4 + 0.35*abs(math.sin(t_now*0.6 + bi*0.9))
                    glColor4f(0.15, bri*0.65, bri*0.85, 0.65)
                    glBegin(GL_QUADS)
                    glVertex3f(ba-0.05+flow, h+0.005,  0.42)
                    glVertex3f(ba+0.05+flow, h+0.005,  0.42)
                    glVertex3f(ba+0.08,      h+0.005, -0.42)
                    glVertex3f(ba-0.08,      h+0.005, -0.42)
                    glEnd()
                # Sedimen lumpur — titik-titik coklat
                for si2 in range(14):
                    sx2 = math.cos(si2*0.45+ph)*0.32
                    sz2 = math.sin(si2*0.45+ph)*0.32
                    sc2 = 0.4+0.3*abs(math.sin(t_now*0.4+si2*0.6))
                    glColor4f(0.35*sc2, 0.25*sc2, 0.08*sc2, 0.55)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(sx2, h+0.006, sz2)
                    for i in range(7):
                        sa = i*(2*math.pi/6)
                        glVertex3f(sx2+math.cos(sa)*0.04, h+0.006, sz2+math.sin(sa)*0.04)
                    glEnd()
                # Riak pertemuan air
                for ri in range(2):
                    rph2 = (t_now*0.5 + ri*0.5) % 1.0
                    rad2 = 0.06 + rph2*0.32
                    alpha2 = (1-rph2)*0.55
                    glColor4f(0.2, 0.6, 0.75, alpha2)
                    glBegin(GL_LINE_LOOP)
                    for si3 in range(20):
                        sa3 = si3*(2*math.pi/20)
                        glVertex3f(math.cos(sa3)*rad2, h+0.007, math.sin(sa3)*rad2*0.6)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
                # Rumput mangrove kecil di tepi
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                for gi in range(8):
                    ga = gi*(2*math.pi/8)+ph
                    gx2 = math.cos(ga)*0.36; gz2 = math.sin(ga)*0.36
                    sway2 = math.sin(t_now*1.1+gi*0.8+ph)*0.05
                    gh2 = 0.09+0.03*math.sin(gi*1.3)
                    bri2 = 0.4+0.4*abs(math.sin(t_now*0.7+gi*0.6))
                    glColor4f(0.1, bri2*0.8, bri2*0.35, 0.70)
                    glBegin(GL_TRIANGLES)
                    glVertex3f(gx2,        h+0.004, gz2)
                    glVertex3f(gx2+sway2+0.02, h+gh2, gz2)
                    glVertex3f(gx2+sway2-0.02, h+gh2, gz2)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            elif nama == "Muara Khatulistiwa":
                # Muara — air payau pertemuan laut & sungai, warna toska-hijau jernih
                _tile_overlay(0.04, 0.22, 0.28, 0.50)
                _tile_border(0.1, 0.65, 0.55, 0.75)
                glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                # Arus muara — lebar mengalir ke laut
                flow_m = math.sin(t_now*0.7+ph)*0.05
                for wi2 in range(4):
                    wfrac = wi2/4
                    wph2  = (t_now*0.6 + wfrac) % 1.0
                    wy2   = -0.40 + wph2*0.80
                    wa2   = (1-abs(wph2*2-1))*0.60
                    wc2   = 0.5+0.4*wph2
                    glColor4f(0.1, wc2*0.7, wc2*0.85, wa2)
                    glBegin(GL_QUADS)
                    glVertex3f(-0.40+flow_m, h+0.005, wy2-0.06)
                    glVertex3f( 0.40+flow_m, h+0.005, wy2-0.06)
                    glVertex3f( 0.40+flow_m, h+0.005, wy2+0.06)
                    glVertex3f(-0.40+flow_m, h+0.005, wy2+0.06)
                    glEnd()
                # Kilau permukaan muara — cahaya matahari tropis
                for ki2 in range(10):
                    kx3 = math.cos(ki2*0.65+ph+t_now*0.25)*0.30
                    kz3 = math.sin(ki2*0.65+ph+t_now*0.25)*0.30
                    ks2 = 0.3+0.65*abs(math.sin(t_now*2.2+ki2*0.9+ph))
                    glColor4f(0.6, 0.95, 0.85, ks2*0.55)
                    glBegin(GL_TRIANGLE_FAN)
                    glVertex3f(kx3, h+0.008, kz3)
                    for si4 in range(5):
                        sa4 = si4*(2*math.pi/4)
                        glVertex3f(kx3+math.cos(sa4)*0.03, h+0.008, kz3+math.sin(sa4)*0.03)
                    glEnd()
                # Riak bertumpuk
                for ri2 in range(3):
                    rph3 = (t_now*0.55 + ri2*0.33) % 1.0
                    rad3 = 0.07 + rph3*0.38
                    alpha3 = (1-rph3)*0.6
                    glColor4f(0.3, 0.80, 0.75, alpha3)
                    glBegin(GL_LINE_LOOP)
                    for si5 in range(24):
                        sa5 = si5*(2*math.pi/24)
                        # Elips — lebih lebar horizontal (karakteristik muara)
                        glVertex3f(math.cos(sa5)*rad3*1.2, h+0.007, math.sin(sa5)*rad3*0.7)
                    glEnd()
                glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
                # Akar bakau menonjol di tepi
                for mi in range(6):
                    ma = mi*(2*math.pi/6)+ph+0.3
                    mx2 = math.cos(ma)*0.38; mz2 = math.sin(ma)*0.38
                    msway = math.sin(t_now*0.9+mi*1.1+ph)*0.04
                    mh2   = 0.08+0.04*math.sin(mi*1.7)
                    mb2   = 0.35+0.40*abs(math.sin(t_now*0.6+mi*0.8))
                    glBlendFunc(GL_SRC_ALPHA, GL_ONE)
                    glColor4f(0.12, mb2*0.75, mb2*0.45, 0.72)
                    glBegin(GL_TRIANGLES)
                    glVertex3f(mx2,           h+0.004, mz2)
                    glVertex3f(mx2+msway+0.025, h+mh2, mz2)
                    glVertex3f(mx2+msway-0.025, h+mh2, mz2)
                    glEnd()
                    # Akar kecil menjalar
                    glColor4f(0.20, mb2*0.5, mb2*0.3, 0.50)
                    glBegin(GL_LINE_STRIP)
                    glVertex3f(mx2, h+0.004, mz2)
                    glVertex3f(mx2+0.06, h+0.004, mz2+0.04)
                    glVertex3f(mx2+0.10, h+0.004, mz2-0.02)
                    glEnd()
                    glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)

            else:
                # Default L3 — glow toska berkedip
                gd = 0.3+0.2*math.sin(t_now*1.5+ph)
                _tile_border(0.0, gd*2, gd*2.2, 0.55)
                _tile_bubbles(3, 0.0, 0.6, 0.7)

            glEnable(GL_LIGHTING)
            glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
            glDisable(GL_LIGHTING)
            glow_a = 0.4 + 0.3*math.sin(t_now*3.0+idx*0.7)
            glColor4f(w[0]*glow_a, w[1]*glow_a, w[2]*glow_a, 0.6)
            glBegin(GL_QUADS)
            glVertex3f(-.49,h+0.001, .49); glVertex3f(.49,h+0.001, .49)
            glVertex3f(.49,h+0.001,-.49); glVertex3f(-.49,h+0.001,-.49)
            glEnd()
            glColor4f(w[0], w[1], w[2], 0.8)
            glBegin(GL_QUADS)
            # Border neon tipis di sekeliling
            glVertex3f(-.49,h+0.002, .49); glVertex3f( .49,h+0.002, .49)
            glVertex3f( .49,h+0.002, .47); glVertex3f(-.49,h+0.002, .47)
            glVertex3f(-.49,h+0.002,-.47); glVertex3f( .49,h+0.002,-.47)
            glVertex3f( .49,h+0.002,-.49); glVertex3f(-.49,h+0.002,-.49)
            glVertex3f(-.49,h+0.002,-.49); glVertex3f(-.49,h+0.002, .49)
            glVertex3f(-.47,h+0.002, .49); glVertex3f(-.47,h+0.002,-.49)
            glVertex3f( .47,h+0.002,-.49); glVertex3f( .47,h+0.002, .49)
            glVertex3f( .49,h+0.002, .49); glVertex3f( .49,h+0.002,-.49)
            glEnd()
            glEnable(GL_LIGHTING)

        glPopMatrix()

    def _draw_pawn(self, p):
        # Sembunyikan pion jika sedang dimakan hiu
        if (getattr(self,'hiu_aktif',False) and
            getattr(self,'hiu_pid',None) == p.id and
            not getattr(self,'hiu_pion_visi',True)):
            return
        # Sembunyikan pion saat terseret arus deras (fase 2 & 3)
        if getattr(self,'arusderas_aktif',False):
            t_ad = getattr(self,'arusderas_t',0)
            if (getattr(self,'arusderas_target_id',None) == p.id and
                    0.8 <= t_ad < 3.2):
                return
        """Gambar bidak dengan posisi interpolasi + bayangan di bawah."""
        # Saat naik roket — pion digambar di posisi roket (transparan di luar)
        roket_aktif = (self.level == 2
                       and getattr(self,'roket_launch_aktif',False)
                       and getattr(self,'roket_pid',-1) == p.id)
        fase_r = getattr(self,'roket_fase','idle')

        x, y, z = self.get_pawn_pos_3d(p)
        # Offset tiap pion agar tidak menumpuk — pola 2x2 lebih lebar
        _offsets = [
            (-0.22, -0.22),  # P0 kiri-depan
            ( 0.22, -0.22),  # P1 kanan-depan
            (-0.22,  0.22),  # P2 kiri-belakang
            ( 0.22,  0.22),  # P3 kanan-belakang
        ]
        ox, oz = _offsets[p.id % 4]

        # Saat di dalam roket yang terbang — sembunyikan pion (ada di dalam roket)
        if roket_aktif and fase_r in ("naik", "turun"):
            return  # Pion tersembunyi di dalam roket

        # ── Bayangan di lantai ────────────────────────────
        glPushMatrix()
        glTranslatef(x + ox, 0.01, z + oz)
        glDisable(GL_LIGHTING)
        shadow_alpha = max(0.0, 0.45 - y * 0.35)
        glColor4f(0.0, 0.0, 0.0, shadow_alpha)
        glEnable(GL_BLEND)
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA)
        r_shadow = max(0.05, 0.16 - y * 0.05)
        glBegin(GL_TRIANGLE_FAN)
        glVertex3f(0, 0, 0)
        for i in range(17):
            a = i * (2 * math.pi / 16)
            glVertex3f(math.cos(a) * r_shadow, 0, math.sin(a) * r_shadow)
        glEnd()
        glEnable(GL_LIGHTING)
        glPopMatrix()

        # ── Bidak utama ───────────────────────────────────
        glPushMatrix()
        glTranslatef(x + ox, y + 0.07, z + oz)
        if self.pawn_anim_aktif and p.id == self.pawn_anim_pid:
            t = self.pawn_anim_t
            glRotatef(math.sin(math.pi * t) * 20, 0, 0, 1)
        glColor4f(*p.warna_gl)
        q = gluNewQuadric()

        # Gambar silinder badan + kepala dalam sub-push agar rotate tidak bocor
        glPushMatrix()
        glRotatef(-90, 1, 0, 0)
        gluCylinder(q, 0.07, 0.07, 0.26, 16, 2)
        gluDisk(q, 0, 0.07, 16, 1)
        glPopMatrix()

        # Kepala (sphere) di atas silinder
        glPushMatrix()
        glTranslatef(0, 0.26, 0)
        gluSphere(q, 0.10, 16, 16)
        glPopMatrix()

        gluDeleteQuadric(q)
        glColor4f(1.0, 1.0, 1.0, 1.0)  # Reset warna
        glPopMatrix()

    def _draw_house(self, idx, jml):
        """Gambar bangunan 3D — Level 1: Rumah/Hotel, Level 2: Stasiun/Koloni."""
        x, y, z = posisi_3d(idx)
        own = self.kepemilikan[idx]
        t_now = self.neon_t if hasattr(self,'neon_t') else 0.0

        if self.level == 3:
            glDisable(GL_LIGHTING)
            t3   = t_now
            wgl  = GROUP_COLORS.get(self.board_data[idx]["grup"],(0.1,0.7,0.8,1))
            rk,gk,bk = wgl[0],wgl[1],wgl[2]
            BSEG = 10

            def draw_coral_pillar(wx,wy,wz,sc):
                """Pilar karang Atlantis bioluminesen."""
                q3=gluNewQuadric()

                # Alas batu karang
                for si3 in range(BSEG):
                    a0=si3*(2*math.pi/BSEG); a1=(si3+1)*(2*math.pi/BSEG)
                    lt=0.55+0.45*math.cos(a0+0.4)
                    glColor3f(0.06*lt,0.18*lt,0.22*lt)
                    glBegin(GL_QUADS)
                    glVertex3f(wx+math.cos(a0)*0.12*sc,wy+0.022*sc,wz+math.sin(a0)*0.12*sc)
                    glVertex3f(wx+math.cos(a1)*0.12*sc,wy+0.022*sc,wz+math.sin(a1)*0.12*sc)
                    glVertex3f(wx+math.cos(a1)*0.12*sc,wy,          wz+math.sin(a1)*0.12*sc)
                    glVertex3f(wx+math.cos(a0)*0.12*sc,wy,          wz+math.sin(a0)*0.12*sc)
                    glEnd()
                glColor3f(0.08,0.22,0.26)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(wx,wy+0.022*sc,wz)
                for si3 in range(BSEG+1):
                    a=si3*(2*math.pi/BSEG)
                    glVertex3f(wx+math.cos(a)*0.12*sc,wy+0.022*sc,wz+math.sin(a)*0.12*sc)
                glEnd()

                # Badan silinder pilar
                for si3 in range(BSEG):
                    a0=si3*(2*math.pi/BSEG); a1=(si3+1)*(2*math.pi/BSEG)
                    lt=0.50+0.50*math.cos(a0+0.3)
                    glColor3f(max(0,rk*lt*1.6+0.04),max(0,gk*lt*1.4+0.12),max(0,bk*lt*1.4+0.14))
                    glBegin(GL_QUADS)
                    glVertex3f(wx+math.cos(a0)*0.065*sc,wy+0.32*sc, wz+math.sin(a0)*0.065*sc)
                    glVertex3f(wx+math.cos(a1)*0.065*sc,wy+0.32*sc, wz+math.sin(a1)*0.065*sc)
                    glVertex3f(wx+math.cos(a1)*0.065*sc,wy+0.022*sc,wz+math.sin(a1)*0.065*sc)
                    glVertex3f(wx+math.cos(a0)*0.065*sc,wy+0.022*sc,wz+math.sin(a0)*0.065*sc)
                    glEnd()

                # Retakan horizontal
                for ci3 in [0.12,0.22]:
                    glColor3f(0.04,0.10,0.13)
                    glBegin(GL_LINE_LOOP)
                    for si3 in range(BSEG):
                        a=si3*(2*math.pi/BSEG)
                        ww=0.012*math.sin(si3*2.1+wx)
                        glVertex3f(wx+math.cos(a)*(0.067*sc+ww),wy+ci3*sc,wz+math.sin(a)*(0.067*sc+ww))
                    glEnd()

                # Lumut alga
                alg=0.22+0.10*math.sin(t3*0.4+wx*2)
                for si3 in range(BSEG):
                    a0=si3*(2*math.pi/BSEG); a1=(si3+1)*(2*math.pi/BSEG)
                    glColor4f(0.02,alg*0.8,alg*0.5,0.55)
                    glBegin(GL_QUADS)
                    glVertex3f(wx+math.cos(a0)*0.070*sc,wy+0.18*sc, wz+math.sin(a0)*0.070*sc)
                    glVertex3f(wx+math.cos(a1)*0.070*sc,wy+0.18*sc, wz+math.sin(a1)*0.070*sc)
                    glVertex3f(wx+math.cos(a1)*0.070*sc,wy+0.022*sc,wz+math.sin(a1)*0.070*sc)
                    glVertex3f(wx+math.cos(a0)*0.070*sc,wy+0.022*sc,wz+math.sin(a0)*0.070*sc)
                    glEnd()

                # Mahkota pilar
                crown3=0.095*sc
                glColor3f(max(0,rk*1.5+0.06),max(0,gk*1.8+0.15),max(0,bk*1.8+0.18))
                for si3 in range(BSEG):
                    a0=si3*(2*math.pi/BSEG); a1=(si3+1)*(2*math.pi/BSEG)
                    glBegin(GL_QUADS)
                    glVertex3f(wx+math.cos(a0)*crown3,wy+0.345*sc,wz+math.sin(a0)*crown3)
                    glVertex3f(wx+math.cos(a1)*crown3,wy+0.345*sc,wz+math.sin(a1)*crown3)
                    glVertex3f(wx+math.cos(a1)*0.065*sc,wy+0.32*sc,wz+math.sin(a1)*0.065*sc)
                    glVertex3f(wx+math.cos(a0)*0.065*sc,wy+0.32*sc,wz+math.sin(a0)*0.065*sc)
                    glEnd()
                glColor3f(max(0,rk*1.3+0.05),max(0,gk*1.6+0.12),max(0,bk*1.6+0.15))
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(wx,wy+0.345*sc,wz)
                for si3 in range(BSEG+1):
                    a=si3*(2*math.pi/BSEG)
                    glVertex3f(wx+math.cos(a)*crown3,wy+0.345*sc,wz+math.sin(a)*crown3)
                glEnd()

                # Trisula di puncak — 3 ujung
                for ti3 in range(3):
                    ta3=ti3*(2*math.pi/3)+t3*0.08
                    tx3=wx+math.cos(ta3)*0.038*sc; tz3=wz+math.sin(ta3)*0.038*sc
                    tg3=0.40+0.40*math.sin(t3*1.5+ti3*1.2+wx*3)
                    glColor3f(max(0,rk*0.8+0.05),max(0,gk*1.2+0.10),max(0,bk*1.2+0.10))
                    glPushMatrix(); glTranslatef(tx3,wy+0.345*sc,tz3); glRotatef(-90,1,0,0)
                    gluCylinder(q3,0.007*sc,0.005*sc,0.080*sc,6,1); glPopMatrix()
                    glColor3f(max(0,tg3*rk+0.1),max(0,tg3*gk*1.5+0.2),max(0,tg3*bk*1.5+0.2))
                    glPushMatrix(); glTranslatef(tx3,wy+0.345*sc+0.080*sc,tz3); glRotatef(-90,1,0,0)
                    gluCylinder(q3,0.007*sc,0.0,0.028*sc,6,1); glPopMatrix()

                # Glow bioluminesen puncak
                gw3=0.38+0.32*math.sin(t3*2.0+wx*4)
                glColor3f(max(0,rk*0.2+gw3*0.1),max(0,gk*0.4+gw3*0.7),max(0,bk*0.4+gw3*0.8))
                glPushMatrix(); glTranslatef(wx,wy+0.345*sc+0.015*sc,wz)
                gluSphere(q3,0.026*sc,10,8); glPopMatrix()

                # Gelembung naik di pilar
                for bi3 in range(3):
                    bph3=(t3*0.55+bi3*0.33+wx)%1.0
                    bx3=wx+math.cos(bi3*2.1)*0.08*sc
                    bz3=wz+math.sin(bi3*1.7)*0.08*sc
                    bh3=wy+bph3*0.30*sc
                    glColor3f(max(0,rk*0.4+0.2),max(0,gk*0.7+0.2),max(0,bk*0.7+0.25))
                    glPushMatrix(); glTranslatef(bx3,bh3,bz3)
                    gluSphere(q3,0.010*sc*(0.5+bph3*0.5),6,4); glPopMatrix()

                gluDeleteQuadric(q3)

            # Posisi bangunan
            if jml == 1:
                draw_coral_pillar(x,     y, z,     1.0)
            elif jml == 2:
                draw_coral_pillar(x-0.16,y, z,     0.88)
                draw_coral_pillar(x+0.16,y, z,     0.88)
            elif jml == 3:
                draw_coral_pillar(x-0.16,y, z+0.10,0.82)
                draw_coral_pillar(x+0.16,y, z+0.10,0.82)
                draw_coral_pillar(x,     y, z-0.14,0.82)
            elif jml >= 4:
                draw_coral_pillar(x-0.15,y, z+0.13,0.76)
                draw_coral_pillar(x+0.15,y, z+0.13,0.76)
                draw_coral_pillar(x-0.15,y, z-0.13,0.76)
                draw_coral_pillar(x+0.15,y, z-0.13,0.76)

            # ── CITADEL ATLANTIS (bangunan max = 5) ──────────
            if jml >= 5:
                qs3=gluNewQuadric()
                pls5=0.5+0.3*math.sin(t3*1.2+idx*0.4)

                # Platform citadel
                glColor3f(0.06,0.20,0.25)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(x,y+0.003,z)
                for _i in range(13):
                    _a=_i*(2*math.pi/12)
                    glVertex3f(x+math.cos(_a)*0.32,y+0.003,z+math.sin(_a)*0.32)
                glEnd()
                glColor3f(0.0,pls5*0.8,pls5*0.9)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(x,y+0.004,z)
                for _i in range(13):
                    _a=_i*(2*math.pi/12)
                    glVertex3f(x+math.cos(_a)*0.29,y+0.004,z+math.sin(_a)*0.29)
                glEnd()

                # Menara utama
                glColor3f(max(0,rk*1.2+0.05),max(0,gk*1.5+0.10),max(0,bk*1.5+0.12))
                glPushMatrix(); glTranslatef(x,y,z); glRotatef(-90,1,0,0)
                gluCylinder(qs3,0.10,0.08,0.38,14,4); glPopMatrix()

                # Kubah setengah bola
                for _di in range(8):
                    _lat0=_di*(math.pi/2/8); _lat1=(_di+1)*(math.pi/2/8)
                    _r0=math.sin(_lat0)*0.10; _y0=math.cos(_lat0)*0.14
                    _r1=math.sin(_lat1)*0.10; _y1=math.cos(_lat1)*0.14
                    _ld=0.4+0.6*(_di/8)
                    glColor3f(max(0,rk*_ld*1.3+0.04),max(0,gk*_ld*1.6+0.08),max(0,bk*_ld*1.6+0.10))
                    glBegin(GL_QUADS)
                    for _seg in range(14):
                        _a0=_seg*(2*math.pi/14); _a1=(_seg+1)*(2*math.pi/14)
                        glVertex3f(x+math.cos(_a0)*_r0,y+0.38+_y0,z+math.sin(_a0)*_r0)
                        glVertex3f(x+math.cos(_a1)*_r0,y+0.38+_y0,z+math.sin(_a1)*_r0)
                        glVertex3f(x+math.cos(_a1)*_r1,y+0.38+_y1,z+math.sin(_a1)*_r1)
                        glVertex3f(x+math.cos(_a0)*_r1,y+0.38+_y1,z+math.sin(_a0)*_r1)
                    glEnd()

                # Kristal puncak
                cp3=0.55+0.40*math.sin(t3*2.5+idx)
                glColor3f(cp3*0.3+0.1,cp3*0.9,cp3)
                glPushMatrix(); glTranslatef(x,y+0.38+0.14+0.04,z); glRotatef(-90,1,0,0)
                gluCylinder(qs3,0.022,0.0,0.06,8,2); glPopMatrix()
                glColor3f(0.4*cp3,cp3,cp3*0.95)
                glPushMatrix(); glTranslatef(x,y+0.38+0.14+0.04,z)
                gluSphere(qs3,0.018,8,8); glPopMatrix()

                # 6 pilar mini sekeliling
                for _i in range(6):
                    _a=_i*(math.pi/3)+t3*0.04
                    draw_coral_pillar(x+math.cos(_a)*0.22,y,z+math.sin(_a)*0.22,0.48)

                gluDeleteQuadric(qs3)

            glColor3f(1,1,1)
            glEnable(GL_LIGHTING)
            return

        if self.level >= 2:
            glDisable(GL_LIGHTING)
            pls  = 0.7 + 0.3*math.sin(t_now*3.0 + idx*0.5)
            pls2 = 0.8 + 0.2*math.sin(t_now*5.0 + idx*0.8)
            wgl  = GROUP_COLORS.get(self.board_data[idx]["grup"],(0.3,0.6,1.0,1))
            rk,gk,bk = wgl[0],wgl[1],wgl[2]

            def draw_one_rocket(wx, wy, wz, sc):
                """Satu roket 3D di world pos (wx,wy,wz), scale sc."""
                q = gluNewQuadric()
                fa = 0.45 + 0.45*abs(math.sin(t_now*12 + wx*7))

                # 1) Pad landas (flat quad di tanah)
                glColor3f(0.12, 0.12, 0.16)
                s2 = 0.10*sc
                glBegin(GL_QUADS)
                glVertex3f(wx-s2, wy+0.001, wz-s2)
                glVertex3f(wx+s2, wy+0.001, wz-s2)
                glVertex3f(wx+s2, wy+0.001, wz+s2)
                glVertex3f(wx-s2, wy+0.001, wz+s2)
                glEnd()

                # 2) Glow ring dasar
                glColor3f(rk*pls, gk*pls, bk*pls)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(wx, wy+0.002, wz)
                for _i in range(13):
                    _a = _i*(2*math.pi/12)
                    glVertex3f(wx+math.cos(_a)*0.11*sc, wy+0.002, wz+math.sin(_a)*0.11*sc)
                glEnd()

                # 3) Api semburan (kerucut ke bawah dari dasar badan)
                glColor3f(1.0, 0.4*fa, 0.0)
                glPushMatrix()
                glTranslatef(wx, wy+0.06*sc, wz)
                glRotatef(90, 1,0,0)        # Putar agar menghadap ke bawah
                gluCylinder(q, 0.030*sc, 0.0, 0.09*sc*fa, 8, 2)
                glPopMatrix()

                # Api inti putih
                glColor3f(1.0, 0.9, 0.5)
                glPushMatrix()
                glTranslatef(wx, wy+0.06*sc, wz)
                glRotatef(90, 1,0,0)
                gluCylinder(q, 0.014*sc, 0.0, 0.05*sc*fa, 6, 1)
                glPopMatrix()

                # 4) Sirip / fin (4 segitiga di dasar badan)
                glColor3f(min(1,rk*0.8), min(1,gk*0.7), min(1,bk*0.7))
                for _fi in range(4):
                    _fa = _fi*(math.pi/2)
                    _fx = wx + math.cos(_fa)*0.06*sc
                    _fz = wz + math.sin(_fa)*0.06*sc
                    glBegin(GL_TRIANGLES)
                    glVertex3f(wx,       wy+0.06*sc, wz)
                    glVertex3f(_fx,      wy+0.06*sc, _fz)
                    glVertex3f(_fx,      wy,         _fz)
                    glEnd()

                # 5) Badan silinder utama (bawah → atas)
                glColor3f(min(1,rk*1.3+0.1), min(1,gk*1.3+0.1), min(1,bk*1.3+0.1))
                glPushMatrix()
                glTranslatef(wx, wy+0.06*sc, wz)
                glRotatef(-90, 1,0,0)       # Putar agar tegak ke atas
                gluCylinder(q, 0.055*sc, 0.045*sc, 0.23*sc, 12, 3)
                glPopMatrix()

                # 6) Stripe tengah badan
                glColor3f(min(1,rk*0.5+0.1), min(1,gk*0.5+0.1), min(1,bk*0.5+0.1))
                glPushMatrix()
                glTranslatef(wx, wy+0.14*sc, wz)
                glRotatef(-90, 1,0,0)
                gluCylinder(q, 0.058*sc, 0.058*sc, 0.025*sc, 12, 1)
                glPopMatrix()

                # 7) Nose cone (kerucut atas)
                glColor3f(min(1,rk*1.6+0.2), min(1,gk*1.6+0.2), min(1,bk*1.6+0.2))
                glPushMatrix()
                glTranslatef(wx, wy+0.29*sc, wz)
                glRotatef(-90, 1,0,0)
                gluCylinder(q, 0.045*sc, 0.0, 0.14*sc, 12, 4)
                gluDisk(q, 0, 0.045*sc, 12, 1)
                glPopMatrix()

                # 8) Jendela (sphere kecil di sisi depan)
                glColor3f(0.7, 0.92, 1.0)
                glPushMatrix()
                glTranslatef(wx, wy+0.21*sc, wz+0.048*sc)
                gluSphere(q, 0.022*sc, 8, 8)
                glPopMatrix()
                # Kilap jendela
                glColor3f(1.0, 1.0, 1.0)
                glPushMatrix()
                glTranslatef(wx, wy+0.224*sc, wz+0.056*sc)
                gluSphere(q, 0.009*sc, 6, 6)
                glPopMatrix()

                gluDeleteQuadric(q)

            # ── Posisi roket sesuai jumlah bangunan ──────────
            if jml == 1:
                draw_one_rocket(x, y, z, 1.0)
            elif jml == 2:
                draw_one_rocket(x-0.16, y, z,    0.86)
                draw_one_rocket(x+0.16, y, z,    0.86)
            elif jml == 3:
                draw_one_rocket(x-0.17, y, z+0.10, 0.80)
                draw_one_rocket(x+0.17, y, z+0.10, 0.80)
                draw_one_rocket(x,      y, z-0.15, 0.80)
            elif jml >= 4:
                draw_one_rocket(x-0.16, y, z+0.13, 0.74)
                draw_one_rocket(x+0.16, y, z+0.13, 0.74)
                draw_one_rocket(x-0.16, y, z-0.13, 0.74)
                draw_one_rocket(x+0.16, y, z-0.13, 0.74)

            # ── KOLONI: Space Fortress (jml 5) ────────────────
            if jml >= 5:
                qs = gluNewQuadric()
                # Fondasi hexagonal
                glColor3f(0.08*pls, 0.03, 0.15*pls)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(x, y+0.003, z)
                for _i in range(7):
                    _a = _i*(2*math.pi/6)
                    glVertex3f(x+math.cos(_a)*0.30, y+0.003, z+math.sin(_a)*0.30)
                glEnd()
                # Ring neon
                glColor3f(rk*pls2, gk*pls2, bk*pls2)
                glBegin(GL_TRIANGLE_FAN)
                glVertex3f(x, y+0.004, z)
                for _i in range(13):
                    _a = _i*(2*math.pi/12)
                    glVertex3f(x+math.cos(_a)*0.27, y+0.004, z+math.sin(_a)*0.27)
                glEnd()
                # Menara utama
                glColor3f(0.55*pls, 0.08, 0.85*pls)
                glPushMatrix(); glTranslatef(x, y, z); glRotatef(-90,1,0,0)
                gluCylinder(qs, 0.13, 0.10, 0.34, 16, 4); glPopMatrix()
                glColor3f(0.75*pls, 0.15, 1.0*pls)
                glPushMatrix(); glTranslatef(x, y+0.34, z)
                gluSphere(qs, 0.13, 16, 12); glPopMatrix()
                # Antena
                glColor3f(1.0*pls2, 0.85*pls2, 0.0)
                glPushMatrix(); glTranslatef(x, y+0.47, z); glRotatef(-90,1,0,0)
                gluCylinder(qs, 0.007, 0.003, 0.14, 6, 2); glPopMatrix()
                glColor3f(1.0, 0.9, 0.0)
                glPushMatrix(); glTranslatef(x, y+0.61, z)
                gluSphere(qs, 0.020, 8, 8); glPopMatrix()
                # 4 menara kecil
                for _i in range(4):
                    _a = _i*(math.pi/2)+math.pi/4
                    _tx = x+math.cos(_a)*0.17; _tz = z+math.sin(_a)*0.17
                    glColor3f(0.45*pls, 0.07, 0.70*pls)
                    glPushMatrix(); glTranslatef(_tx, y, _tz); glRotatef(-90,1,0,0)
                    gluCylinder(qs, 0.038, 0.028, 0.19, 8, 2); glPopMatrix()
                    glColor3f(0.65*pls, 0.12, 0.95*pls)
                    glPushMatrix(); glTranslatef(_tx, y+0.19, _tz)
                    gluSphere(qs, 0.048, 8, 8); glPopMatrix()
                # 4 roket kecil sekeliling benteng
                for _i in range(4):
                    _a = _i*(math.pi/2)
                    draw_one_rocket(x+math.cos(_a)*0.22, y, z+math.sin(_a)*0.22, 0.50)
                gluDeleteQuadric(qs)

            glColor3f(1, 1, 1)
            glEnable(GL_LIGHTING)
            return
        # ── LEVEL 1: Rumah/Hotel klasik ────────────────────
        if jml >= 5:
            # ── HOTEL: bangunan detail premium ────────────
            glPushMatrix()
            glTranslatef(x, 0.07, z)
            glDisable(GL_LIGHTING)

            W  = 0.40
            D  = 0.28
            Hw = 0.30
            Ha = 0.12

            # ── Fondasi abu ────────────────────────────────
            glColor3f(0.40, 0.38, 0.35)
            glBegin(GL_QUADS)
            glVertex3f(-W/2-0.02,0,-D/2-0.02); glVertex3f(W/2+0.02,0,-D/2-0.02)
            glVertex3f( W/2+0.02,0, D/2+0.02); glVertex3f(-W/2-0.02,0, D/2+0.02)
            glEnd()

            # ── Dinding utama (merah bata) ─────────────────
            glColor3f(0.82, 0.14, 0.10)
            glBegin(GL_QUADS)
            # Depan
            glVertex3f(-W/2,0,D/2); glVertex3f(W/2,0,D/2)
            glVertex3f( W/2,Hw,D/2); glVertex3f(-W/2,Hw,D/2)
            # Belakang
            glVertex3f(-W/2,0,-D/2); glVertex3f(-W/2,Hw,-D/2)
            glVertex3f( W/2,Hw,-D/2); glVertex3f(W/2,0,-D/2)
            # Kiri
            glVertex3f(-W/2,0,-D/2); glVertex3f(-W/2,0,D/2)
            glVertex3f(-W/2,Hw,D/2); glVertex3f(-W/2,Hw,-D/2)
            # Kanan
            glVertex3f(W/2,0,-D/2); glVertex3f(W/2,Hw,-D/2)
            glVertex3f(W/2,Hw,D/2); glVertex3f(W/2,0,D/2)
            glEnd()

            # ── Garis bata horizontal ──────────────────────
            glColor3f(0.60, 0.10, 0.07)
            for bh in [0.06, 0.12, 0.18, 0.24]:
                glBegin(GL_QUADS)
                glVertex3f(-W/2,bh,D/2+0.001); glVertex3f(W/2,bh,D/2+0.001)
                glVertex3f(W/2,bh+0.005,D/2+0.001); glVertex3f(-W/2,bh+0.005,D/2+0.001)
                glEnd()
                glBegin(GL_QUADS)
                glVertex3f(-W/2-0.001,bh,-D/2); glVertex3f(-W/2-0.001,bh,D/2)
                glVertex3f(-W/2-0.001,bh+0.005,D/2); glVertex3f(-W/2-0.001,bh+0.005,-D/2)
                glEnd()
                glBegin(GL_QUADS)
                glVertex3f(W/2+0.001,bh,-D/2); glVertex3f(W/2+0.001,bh,D/2)
                glVertex3f(W/2+0.001,bh+0.005,D/2); glVertex3f(W/2+0.001,bh+0.005,-D/2)
                glEnd()

            # ── Pintu utama (coklat gelap + kusen putih) ───
            glColor3f(0.35, 0.16, 0.06)
            glBegin(GL_QUADS)
            glVertex3f(-0.06,0,D/2+0.002); glVertex3f(0.06,0,D/2+0.002)
            glVertex3f(0.06,0.14,D/2+0.002); glVertex3f(-0.06,0.14,D/2+0.002)
            glEnd()
            # Arch pintu (setengah lingkaran — kotak putih di atas)
            glColor3f(0.95, 0.92, 0.86)
            glBegin(GL_QUADS)
            glVertex3f(-0.066,0.12,D/2+0.003); glVertex3f(0.066,0.12,D/2+0.003)
            glVertex3f(0.066,0.16,D/2+0.003); glVertex3f(-0.066,0.16,D/2+0.003)
            # Kusen kiri
            glVertex3f(-0.066,0,D/2+0.003); glVertex3f(-0.054,0,D/2+0.003)
            glVertex3f(-0.054,0.16,D/2+0.003); glVertex3f(-0.066,0.16,D/2+0.003)
            # Kusen kanan
            glVertex3f(0.054,0,D/2+0.003); glVertex3f(0.066,0,D/2+0.003)
            glVertex3f(0.066,0.16,D/2+0.003); glVertex3f(0.054,0.16,D/2+0.003)
            glEnd()
            # Kenop pintu emas
            glColor3f(1.0,0.85,0.15)
            glBegin(GL_QUADS)
            glVertex3f(0.038,0.07,D/2+0.004); glVertex3f(0.054,0.07,D/2+0.004)
            glVertex3f(0.054,0.085,D/2+0.004); glVertex3f(0.038,0.085,D/2+0.004)
            glEnd()

            # ── Jendela besar (3 di depan) ─────────────────
            for wx2, wy2 in [(-0.14,0.16),(0.0,0.16),(0.14,0.16),
                              (-0.14,0.07),(0.14,0.07)]:
                ww2 = 0.060; wh2 = 0.055
                # Frame putih
                glColor3f(0.95,0.92,0.86)
                glBegin(GL_QUADS)
                glVertex3f(wx2-ww2/2-0.006,wy2-0.005,D/2+0.002)
                glVertex3f(wx2+ww2/2+0.006,wy2-0.005,D/2+0.002)
                glVertex3f(wx2+ww2/2+0.006,wy2+wh2+0.005,D/2+0.002)
                glVertex3f(wx2-ww2/2-0.006,wy2+wh2+0.005,D/2+0.002)
                glEnd()
                # Kaca biru
                glColor3f(0.50,0.75,0.95)
                glBegin(GL_QUADS)
                glVertex3f(wx2-ww2/2,wy2,D/2+0.003)
                glVertex3f(wx2+ww2/2,wy2,D/2+0.003)
                glVertex3f(wx2+ww2/2,wy2+wh2,D/2+0.003)
                glVertex3f(wx2-ww2/2,wy2+wh2,D/2+0.003)
                glEnd()
                # Palang jendela
                glColor3f(0.95,0.92,0.86)
                glBegin(GL_QUADS)
                glVertex3f(wx2-0.003,wy2,D/2+0.004)
                glVertex3f(wx2+0.003,wy2,D/2+0.004)
                glVertex3f(wx2+0.003,wy2+wh2,D/2+0.004)
                glVertex3f(wx2-0.003,wy2+wh2,D/2+0.004)
                glVertex3f(wx2-ww2/2,wy2+wh2/2-0.003,D/2+0.004)
                glVertex3f(wx2+ww2/2,wy2+wh2/2-0.003,D/2+0.004)
                glVertex3f(wx2+ww2/2,wy2+wh2/2+0.003,D/2+0.004)
                glVertex3f(wx2-ww2/2,wy2+wh2/2+0.003,D/2+0.004)
                glEnd()

            # ── Atap (abu tua + overhang) ──────────────────
            glColor3f(0.30, 0.28, 0.26)
            glBegin(GL_QUADS)
            # Slope kiri
            glVertex3f(-W/2-0.02,Hw,D/2+0.02); glVertex3f(-W/2-0.02,Hw,-D/2-0.02)
            glVertex3f(0,Hw+Ha,-D/2-0.02); glVertex3f(0,Hw+Ha,D/2+0.02)
            # Slope kanan
            glVertex3f(W/2+0.02,Hw,D/2+0.02); glVertex3f(0,Hw+Ha,D/2+0.02)
            glVertex3f(0,Hw+Ha,-D/2-0.02); glVertex3f(W/2+0.02,Hw,-D/2-0.02)
            glEnd()
            # Gable
            glColor3f(0.72,0.12,0.09)
            glBegin(GL_TRIANGLES)
            glVertex3f(-W/2,Hw,D/2); glVertex3f(W/2,Hw,D/2); glVertex3f(0,Hw+Ha,D/2)
            glVertex3f(-W/2,Hw,-D/2); glVertex3f(W/2,Hw,-D/2); glVertex3f(0,Hw+Ha,-D/2)
            glEnd()
            # Puncak atap coklat gelap
            glColor3f(0.18,0.16,0.14)
            glBegin(GL_QUADS)
            glVertex3f(-0.015,Hw+Ha-0.01,D/2+0.02)
            glVertex3f( 0.015,Hw+Ha-0.01,D/2+0.02)
            glVertex3f( 0.015,Hw+Ha+0.01,-D/2-0.02)
            glVertex3f(-0.015,Hw+Ha+0.01,-D/2-0.02)
            glEnd()

            # ── 2 Cerobong asap ────────────────────────────
            glColor3f(0.55,0.38,0.28)
            for cx3 in [-W/4, W/4]:
                cw3 = 0.028
                glBegin(GL_QUADS)
                glVertex3f(cx3-cw3,Hw+Ha*0.4,D/6+cw3)
                glVertex3f(cx3+cw3,Hw+Ha*0.4,D/6+cw3)
                glVertex3f(cx3+cw3,Hw+Ha+0.09,D/6+cw3)
                glVertex3f(cx3-cw3,Hw+Ha+0.09,D/6+cw3)
                glVertex3f(cx3-cw3,Hw+Ha*0.4,D/6-cw3)
                glVertex3f(cx3-cw3,Hw+Ha+0.09,D/6-cw3)
                glVertex3f(cx3+cw3,Hw+Ha+0.09,D/6-cw3)
                glVertex3f(cx3+cw3,Hw+Ha*0.4,D/6-cw3)
                glVertex3f(cx3-cw3,Hw+Ha*0.4,D/6-cw3)
                glVertex3f(cx3-cw3,Hw+Ha*0.4,D/6+cw3)
                glVertex3f(cx3-cw3,Hw+Ha+0.09,D/6+cw3)
                glVertex3f(cx3-cw3,Hw+Ha+0.09,D/6-cw3)
                glVertex3f(cx3+cw3,Hw+Ha*0.4,D/6+cw3)
                glVertex3f(cx3+cw3,Hw+Ha*0.4,D/6-cw3)
                glVertex3f(cx3+cw3,Hw+Ha+0.09,D/6-cw3)
                glVertex3f(cx3+cw3,Hw+Ha+0.09,D/6+cw3)
                glEnd()
                glColor3f(0.30,0.28,0.26)
                glBegin(GL_QUADS)
                glVertex3f(cx3-cw3-0.005,Hw+Ha+0.09,D/6-cw3-0.005)
                glVertex3f(cx3+cw3+0.005,Hw+Ha+0.09,D/6-cw3-0.005)
                glVertex3f(cx3+cw3+0.005,Hw+Ha+0.09,D/6+cw3+0.005)
                glVertex3f(cx3-cw3-0.005,Hw+Ha+0.09,D/6+cw3+0.005)
                glEnd()

            # ── Tanda HOTEL di atas pintu ──────────────────
            glColor3f(1.0, 0.85, 0.10)
            glBegin(GL_QUADS)
            glVertex3f(-0.10,0.225,D/2+0.003); glVertex3f(0.10,0.225,D/2+0.003)
            glVertex3f( 0.10,0.255,D/2+0.003); glVertex3f(-0.10,0.255,D/2+0.003)
            glEnd()

            glEnable(GL_LIGHTING)
            glPopMatrix()

        else:
            # ── RUMAH: dinding + atap segitiga ────────────
            # Gambar jml rumah berjajar di atas kotak
            # Konsep PERULANGAN: gambar setiap rumah
            n      = jml
            jarak  = 0.22          # Jarak antar rumah
            mulai  = -(n-1) * jarak / 2  # Mulai dari tengah

            for ri in range(n):
                ox = mulai + ri * jarak

                glPushMatrix()
                glTranslatef(x + ox, 0.07, z)
                glDisable(GL_LIGHTING)

                W  = 0.16
                D  = 0.16
                Hw = 0.14
                Ha = 0.11

                # ── Fondasi (abu-abu gelap) ────────────────
                glColor3f(0.45, 0.42, 0.40)
                glBegin(GL_QUADS)
                glVertex3f(-W/2, -0.01, -D/2); glVertex3f(W/2, -0.01, -D/2)
                glVertex3f( W/2, -0.01,  D/2); glVertex3f(-W/2,-0.01,  D/2)
                glEnd()

                # ── Dinding depan (krem) ───────────────────
                glColor3f(0.94, 0.88, 0.76)
                glBegin(GL_QUADS)
                glVertex3f(-W/2, 0,  D/2); glVertex3f(W/2, 0,  D/2)
                glVertex3f( W/2, Hw, D/2); glVertex3f(-W/2,Hw, D/2)
                glEnd()
                # ── Dinding belakang ───────────────────────
                glColor3f(0.88, 0.82, 0.70)
                glBegin(GL_QUADS)
                glVertex3f(-W/2, 0, -D/2); glVertex3f(-W/2,Hw,-D/2)
                glVertex3f( W/2,Hw, -D/2); glVertex3f( W/2, 0,-D/2)
                glEnd()
                # ── Dinding kiri ───────────────────────────
                glColor3f(0.86, 0.80, 0.68)
                glBegin(GL_QUADS)
                glVertex3f(-W/2, 0, -D/2); glVertex3f(-W/2, 0,  D/2)
                glVertex3f(-W/2,Hw,  D/2); glVertex3f(-W/2,Hw,-D/2)
                glEnd()
                # ── Dinding kanan ──────────────────────────
                glBegin(GL_QUADS)
                glVertex3f(W/2, 0, -D/2); glVertex3f(W/2,Hw,-D/2)
                glVertex3f(W/2,Hw,  D/2); glVertex3f(W/2, 0, D/2)
                glEnd()

                # ── Garis bata horizontal (coklat tua tipis) ──
                glColor3f(0.68, 0.52, 0.38)
                for bh in [0.04, 0.08, 0.12]:
                    # Depan
                    glBegin(GL_QUADS)
                    glVertex3f(-W/2, bh,      D/2+0.001)
                    glVertex3f( W/2, bh,      D/2+0.001)
                    glVertex3f( W/2, bh+0.005,D/2+0.001)
                    glVertex3f(-W/2, bh+0.005,D/2+0.001)
                    glEnd()
                    # Kiri
                    glBegin(GL_QUADS)
                    glVertex3f(-W/2-0.001, bh,      -D/2)
                    glVertex3f(-W/2-0.001, bh,       D/2)
                    glVertex3f(-W/2-0.001, bh+0.005, D/2)
                    glVertex3f(-W/2-0.001, bh+0.005,-D/2)
                    glEnd()

                # ── Pintu (coklat merah) ───────────────────
                pw2 = 0.042; ph2 = 0.082
                glColor3f(0.50, 0.22, 0.08)
                glBegin(GL_QUADS)
                glVertex3f(-pw2/2, 0,    D/2+0.002)
                glVertex3f( pw2/2, 0,    D/2+0.002)
                glVertex3f( pw2/2, ph2,  D/2+0.002)
                glVertex3f(-pw2/2, ph2,  D/2+0.002)
                glEnd()
                # Kusen pintu (krem muda)
                glColor3f(0.95, 0.92, 0.85)
                glBegin(GL_QUADS)
                glVertex3f(-pw2/2-0.006, 0,       D/2+0.003)
                glVertex3f(-pw2/2,       0,       D/2+0.003)
                glVertex3f(-pw2/2,       ph2+0.006,D/2+0.003)
                glVertex3f(-pw2/2-0.006, ph2+0.006,D/2+0.003)
                glVertex3f( pw2/2,       0,       D/2+0.003)
                glVertex3f( pw2/2+0.006, 0,       D/2+0.003)
                glVertex3f( pw2/2+0.006, ph2+0.006,D/2+0.003)
                glVertex3f( pw2/2,       ph2+0.006,D/2+0.003)
                glVertex3f(-pw2/2-0.006, ph2,     D/2+0.003)
                glVertex3f( pw2/2+0.006, ph2,     D/2+0.003)
                glVertex3f( pw2/2+0.006, ph2+0.006,D/2+0.003)
                glVertex3f(-pw2/2-0.006, ph2+0.006,D/2+0.003)
                glEnd()
                # Kenop pintu kuning
                glColor3f(1.0, 0.85, 0.15)
                glBegin(GL_QUADS)
                glVertex3f(pw2/2-0.012, ph2*0.45,    D/2+0.004)
                glVertex3f(pw2/2-0.006, ph2*0.45,    D/2+0.004)
                glVertex3f(pw2/2-0.006, ph2*0.55,    D/2+0.004)
                glVertex3f(pw2/2-0.012, ph2*0.55,    D/2+0.004)
                glEnd()

                # ── Jendela depan (biru langit) ────────────
                ww2 = 0.032; wh2 = 0.030; wy2 = 0.09
                for wx2 in [-W/2+0.018, W/2-0.018-ww2]:
                    # Frame jendela putih
                    glColor3f(0.95, 0.93, 0.88)
                    glBegin(GL_QUADS)
                    glVertex3f(wx2-0.004, wy2-0.004,     D/2+0.002)
                    glVertex3f(wx2+ww2+0.004, wy2-0.004, D/2+0.002)
                    glVertex3f(wx2+ww2+0.004, wy2+wh2+0.004,D/2+0.002)
                    glVertex3f(wx2-0.004, wy2+wh2+0.004, D/2+0.002)
                    glEnd()
                    # Kaca jendela biru muda
                    glColor3f(0.55, 0.78, 0.95)
                    glBegin(GL_QUADS)
                    glVertex3f(wx2,      wy2,      D/2+0.003)
                    glVertex3f(wx2+ww2,  wy2,      D/2+0.003)
                    glVertex3f(wx2+ww2,  wy2+wh2,  D/2+0.003)
                    glVertex3f(wx2,      wy2+wh2,  D/2+0.003)
                    glEnd()
                    # Palang jendela putih (silang)
                    glColor3f(0.95, 0.93, 0.88)
                    glBegin(GL_QUADS)
                    glVertex3f(wx2+ww2/2-0.002, wy2,     D/2+0.004)
                    glVertex3f(wx2+ww2/2+0.002, wy2,     D/2+0.004)
                    glVertex3f(wx2+ww2/2+0.002, wy2+wh2, D/2+0.004)
                    glVertex3f(wx2+ww2/2-0.002, wy2+wh2, D/2+0.004)
                    glVertex3f(wx2,      wy2+wh2/2-0.002, D/2+0.004)
                    glVertex3f(wx2+ww2,  wy2+wh2/2-0.002, D/2+0.004)
                    glVertex3f(wx2+ww2,  wy2+wh2/2+0.002, D/2+0.004)
                    glVertex3f(wx2,      wy2+wh2/2+0.002, D/2+0.004)
                    glEnd()

                # ── Gable / segitiga samping ───────────────
                glColor3f(0.88, 0.82, 0.70)
                glBegin(GL_TRIANGLES)
                glVertex3f(-W/2, Hw,  D/2); glVertex3f(W/2, Hw,  D/2); glVertex3f(0, Hw+Ha,  D/2)
                glVertex3f(-W/2, Hw, -D/2); glVertex3f(W/2, Hw, -D/2); glVertex3f(0, Hw+Ha, -D/2)
                glEnd()

                # ── Atap merah/coklat ──────────────────────
                glColor3f(0.72, 0.18, 0.12)
                glBegin(GL_QUADS)
                # Slope kiri
                glVertex3f(-W/2-0.01, Hw,      D/2+0.01)
                glVertex3f(-W/2-0.01, Hw,     -D/2-0.01)
                glVertex3f(0,         Hw+Ha,  -D/2-0.01)
                glVertex3f(0,         Hw+Ha,   D/2+0.01)
                # Slope kanan
                glVertex3f(W/2+0.01,  Hw,      D/2+0.01)
                glVertex3f(0,         Hw+Ha,   D/2+0.01)
                glVertex3f(0,         Hw+Ha,  -D/2-0.01)
                glVertex3f(W/2+0.01,  Hw,     -D/2-0.01)
                glEnd()
                # Garis puncak atap (coklat gelap)
                glColor3f(0.50, 0.12, 0.08)
                glBegin(GL_QUADS)
                glVertex3f(-0.01, Hw+Ha-0.01,  D/2+0.01)
                glVertex3f( 0.01, Hw+Ha-0.01,  D/2+0.01)
                glVertex3f( 0.01, Hw+Ha+0.01, -D/2-0.01)
                glVertex3f(-0.01, Hw+Ha+0.01, -D/2-0.01)
                glEnd()

                # ── Cerobong asap ──────────────────────────
                glColor3f(0.55, 0.38, 0.28)
                cw2 = 0.022
                cx2 = W/4
                glBegin(GL_QUADS)
                # Depan cerobong
                glVertex3f(cx2-cw2, Hw+Ha*0.5, D/4+cw2)
                glVertex3f(cx2+cw2, Hw+Ha*0.5, D/4+cw2)
                glVertex3f(cx2+cw2, Hw+Ha+0.06,D/4+cw2)
                glVertex3f(cx2-cw2, Hw+Ha+0.06,D/4+cw2)
                # Belakang
                glVertex3f(cx2-cw2, Hw+Ha*0.5, D/4-cw2)
                glVertex3f(cx2-cw2, Hw+Ha+0.06,D/4-cw2)
                glVertex3f(cx2+cw2, Hw+Ha+0.06,D/4-cw2)
                glVertex3f(cx2+cw2, Hw+Ha*0.5, D/4-cw2)
                # Kiri
                glVertex3f(cx2-cw2, Hw+Ha*0.5, D/4-cw2)
                glVertex3f(cx2-cw2, Hw+Ha*0.5, D/4+cw2)
                glVertex3f(cx2-cw2, Hw+Ha+0.06,D/4+cw2)
                glVertex3f(cx2-cw2, Hw+Ha+0.06,D/4-cw2)
                # Kanan
                glVertex3f(cx2+cw2, Hw+Ha*0.5, D/4+cw2)
                glVertex3f(cx2+cw2, Hw+Ha*0.5, D/4-cw2)
                glVertex3f(cx2+cw2, Hw+Ha+0.06,D/4-cw2)
                glVertex3f(cx2+cw2, Hw+Ha+0.06,D/4+cw2)
                # Atas cerobong (abu)
                glEnd()
                glColor3f(0.35, 0.32, 0.30)
                glBegin(GL_QUADS)
                glVertex3f(cx2-cw2-0.004, Hw+Ha+0.06, D/4-cw2-0.004)
                glVertex3f(cx2+cw2+0.004, Hw+Ha+0.06, D/4-cw2-0.004)
                glVertex3f(cx2+cw2+0.004, Hw+Ha+0.06, D/4+cw2+0.004)
                glVertex3f(cx2-cw2-0.004, Hw+Ha+0.06, D/4+cw2+0.004)
                glEnd()

                glEnable(GL_LIGHTING)
                glPopMatrix()

        # ── Reset GL state setelah draw house ─────────────
        glEnable(GL_LIGHTING)
        glColor4f(1.0, 1.0, 1.0, 1.0)
        glDisable(GL_BLEND)
        glEnable(GL_BLEND)
    def _proyek_3d_ke_2d(self, x3, y3, z3):
        """
        Konsep: Proyeksi Perspektif (Matematika Matriks)
        Mengubah koordinat 3D dunia → koordinat 2D layar.
        Menggunakan matriks ModelView + Projection dari OpenGL.

        Langkah:
        1. Ambil matriks MVP (ModelView × Projection) dari OpenGL
        2. Transformasi titik 3D menjadi clip coordinates
        3. Bagi dengan w (perspective divide) → NDC (-1 to 1)
        4. Skalakan ke koordinat layar (pixel)
        """
        mv  = glGetDoublev(GL_MODELVIEW_MATRIX)
        prj = glGetDoublev(GL_PROJECTION_MATRIX)
        vp  = glGetIntegerv(GL_VIEWPORT)
        try:
            wx, wy, wz = gluProject(x3, y3, z3, mv, prj, vp)
            # Titik di belakang kamera: wz < 0 atau > 1 → skip
            if wz < 0.0 or wz > 1.0:
                return None
            # OpenGL: y dari bawah, pygame: y dari atas → balik
            px = int(wx)
            py = int(WIN_H - wy)
            # Buang titik yang sangat jauh di luar layar
            margin = 200
            if not (-margin < px < WIN_W + margin and -margin < py < WIN_H + margin):
                return None
            return (px, py)
        except Exception:
            return None

    def _update_pos2d_cache(self):
        """
        Konsep: CACHING + PERULANGAN
        Hitung dan simpan posisi 2D layar semua 40 kotak.
        Dipanggil sekali per frame setelah render 3D selesai.
        """
        self.pos2d_cache = {}
        for i in range(BOARD_SIZE):        # Konsep PERULANGAN
            x3, y3, z3 = posisi_3d(i)
            hasil = self._proyek_3d_ke_2d(x3, y3 + 0.3, z3)
            if hasil:
                self.pos2d_cache[i] = hasil

    def _cari_kotak_terdekat_mouse(self, mx, my):
        """
        Konsep: SEARCHING (Linear Search)
        Cari kotak papan yang paling dekat dengan posisi mouse.
        Iterasi semua kotak, hitung jarak Euclidean ke posisi 2D-nya.
        Return index kotak jika dalam radius 45px, else -1.
        """
        best_idx  = -1
        best_dist = 45   # Radius deteksi hover (pixel)

        # Konsep PERULANGAN: cek semua kotak
        for idx, (px, py) in self.pos2d_cache.items():
            # Hitung jarak Euclidean: √((x2-x1)² + (y2-y1)²)
            dist = math.sqrt((mx - px)**2 + (my - py)**2)
            if dist < best_dist:
                best_dist = dist
                best_idx  = idx

        return best_idx

    def _render_label_kotak(self, surf, dt):
        """
        Render label nama + info kotak yang di-hover mouse,
        dan label permanen di atas posisi pemain aktif.
        Konsep: Fade in/out dengan alpha interpolasi.
        """
        GL_W_area = WIN_W - UI_W   # Area 3D (kiri)

        # ── 1. Label permanen: posisi pemain aktif ─────────
        p_aktif = self.pemain[self.giliran]
        if p_aktif.aktif and p_aktif.posisi in self.pos2d_cache:
            px, py = self.pos2d_cache[p_aktif.posisi]
            # Guard: hanya render jika cukup jauh dari tepi agar label tidak terpotong
            if 60 < px < GL_W_area - 60 and 80 < py < int(WIN_H * 0.80):
                nama_kotak = self.board_data[p_aktif.posisi]["nama"]
                self._gambar_label(surf, px, py - 30,
                                   f"▶ {p_aktif.nama}", p_aktif.warna_py, 200)
                self._gambar_label(surf, px, py - 52,
                                   nama_kotak, (220, 220, 255), 160)

        # ── 2. Label hover mouse ───────────────────────────
        mx, my = pygame.mouse.get_pos()
        if mx < GL_W_area:   # Hanya di area 3D
            idx = self._cari_kotak_terdekat_mouse(mx, my)
            if idx != self.hover_kotak:
                self.hover_kotak = idx
                self.hover_alpha = 0.0   # Reset fade

            if idx >= 0:
                # Fade in: alpha naik ke 255
                self.hover_alpha = min(255, self.hover_alpha + dt * 600)
                alpha = int(self.hover_alpha)

                k      = self.board_data[idx]
                px, py = self.pos2d_cache[idx]

                # Guard: skip jika terlalu dekat tepi
                if not (60 < px < GL_W_area - 60 and 80 < py < int(WIN_H * 0.80)):
                    return

                # Warna sesuai grup properti
                wgl = GROUP_COLORS.get(k["grup"], (0.7, 0.7, 0.7, 1.0))
                wpy = (int(wgl[0]*255), int(wgl[1]*255), int(wgl[2]*255))

                # Baris 1: nama kotak
                self._gambar_label(surf, px, py - 40, k["nama"], wpy, alpha)

                # Baris 2: harga atau tipe
                if k["tipe"] == "properti":
                    own = self.kepemilikan[idx]
                    if own == -1:
                        info = f"Harga: {(kr if self.level==3 else (cr if self.level==2 else rp))(k['harga'] if self.level>=2 else k['harga']*1000)}"
                        winfo = (180, 255, 180)
                    else:
                        info = f"Milik: {self.pemain[own].nama}"
                        winfo = self.pemain[own].warna_py
                    self._gambar_label(surf, px, py - 20, info, winfo, alpha)
                elif k["tipe"] in ("stasiun", "utilitas"):
                    own = self.kepemilikan[idx]
                    fmt2 = kr if self.level == 3 else (cr if self.level == 2 else rp)
                    mult2 = 1 if self.level >= 2 else 1000
                    info = f"Milik: {self.pemain[own].nama}" if own >= 0 else (f"Harga: {fmt2(k['harga']*mult2)}" if getattr(self,'setting_tampil_harga',True) else k['nama'])
                    self._gambar_label(surf, px, py - 20, info, (200, 200, 255), alpha)
                elif k["tipe"] == "pajak":
                    fmt2 = kr if self.level == 3 else (cr if self.level == 2 else rp)
                    mult2 = 1 if self.level >= 2 else 1000
                    self._gambar_label(surf, px, py - 20,
                                       f"Bayar: {fmt2(k['sewa']*mult2)}", (255,160,160), alpha)
        else:
            # Mouse di luar area 3D: fade out
            self.hover_alpha = max(0, self.hover_alpha - dt * 400)
            self.hover_kotak = -1

    def _gambar_label(self, surf, cx, cy, teks, warna, alpha):
        """
        Gambar satu label teks dengan latar belakang semi-transparan
        di posisi (cx, cy) pada surface UI.
        """
        t  = self.fS.render(teks, True, warna)
        tw = t.get_width() + 12
        th = t.get_height() + 6

        # Guard: jangan render jika posisi akan keluar layar
        bx = cx - tw // 2
        by = cy - th // 2
        GL_W_area = WIN_W - UI_W
        if bx < 0 or by < 0 or bx + tw > GL_W_area or by + th > WIN_H:
            return

        # Latar label
        bg = pygame.Surface((tw, th), pygame.SRCALPHA)
        bg.fill((5, 8, 20, min(alpha, 200)))
        pygame.draw.rect(bg, (*warna, min(alpha, 150)), (0, 0, tw, th), 1, border_radius=4)

        surf.blit(bg, (cx - tw//2, cy - th//2))
        t.set_alpha(alpha)
        surf.blit(t, (cx - t.get_width()//2, cy - t.get_height()//2))

    def _setting_klik(self, pos):
        """Handle klik di dalam panel setting."""
        mx, my = pos
        if not hasattr(self,'_setting_rects'): return
        rects = self._setting_rects

        # Tombol tutup
        if 'close' in rects and rects['close'].collidepoint(mx,my):
            self.setting_aktif = False; return

        # Tab switch
        for tab_key in ('audio','gameplay','tampilan'):
            k = f'tab_{tab_key}'
            if k in rects and rects[k].collidepoint(mx,my):
                self.setting_tab = tab_key; return

        # AI speed buttons
        for spd in ('lambat','normal','cepat'):
            k = f'ai_{spd}'
            if k in rects and rects[k].collidepoint(mx,my):
                self._set_ai_speed(spd); return

        # FPS Cap
        for fv in (30,60,120,0):
            if f'fps_{fv}' in rects and rects[f'fps_{fv}'].collidepoint(mx,my):
                self.setting_fps_cap = fv; return

        # Kualitas Partikel
        for qv in ('rendah','sedang','tinggi'):
            if f'qual_{qv}' in rects and rects[f'qual_{qv}'].collidepoint(mx,my):
                self.setting_kualitas = qv; return

        # Toggles
        if 'tog_harga' in rects and rects['tog_harga'].collidepoint(mx,my):
            self.setting_tampil_harga = not getattr(self,'setting_tampil_harga',True); return
        if 'tog_efek_skill' in rects and rects['tog_efek_skill'].collidepoint(mx,my):
            self.setting_efek_skill = not getattr(self,'setting_efek_skill',True); return

        # Slider musik
        if 'slider_musik' in rects and rects['slider_musik'].collidepoint(mx,my):
            self.setting_drag = 'musik'; self._setting_drag_update(pos); return

        # Slider SFX
        if 'slider_sfx' in rects and rects['slider_sfx'].collidepoint(mx,my):
            self.setting_drag = 'sfx'; self._setting_drag_update(pos); return

        # Toggle musik
        if 'toggle_musik' in rects and rects['toggle_musik'].collidepoint(mx,my):
            self._toggle_musik(); return

    def _setting_drag_update(self, pos):
        """Update nilai slider saat di-drag."""
        mx, _ = pos
        if not hasattr(self,'_setting_rects'): return
        rects = self._setting_rects
        key = getattr(self,'setting_drag',None)
        if not key: return

        slider_key = f'slider_{key}'
        if slider_key not in rects: return
        sr = rects[slider_key]
        # Hitung rasio 0.0–1.0
        ratio = max(0.0, min(1.0, (mx - sr.x) / sr.width))

        if key == 'musik':
            self.musik_volume = round(ratio, 2)
            if getattr(self,'musik_mp3_mode',False):
                pygame.mixer.music.set_volume(self.musik_volume)
            elif self.musik_ch and self.musik_obj:
                self.musik_ch.set_volume(self.musik_volume)
        elif key == 'sfx':
            self.sfx_volume = round(ratio, 2)

    def _render_setting_panel(self, surf):
        """Panel Setting — Tab Audio & Gameplay, layout bersih tanpa overlap."""
        t_now  = pygame.time.get_ticks()/1000.0
        GL_W   = WIN_W - UI_W
        tab    = getattr(self,'setting_tab','audio')
        level  = getattr(self,'level',1)

        # Ukuran panel cukup besar
        pw, ph = 500, 400
        px_s   = GL_W//2 - pw//2
        py_s   = WIN_H//2 - ph//2

        # Overlay
        ov=pygame.Surface((WIN_W,WIN_H),pygame.SRCALPHA)
        ov.fill((0,0,0,170)); surf.blit(ov,(0,0))

        # Panel background
        panel=pygame.Surface((pw,ph),pygame.SRCALPHA)
        for i in range(ph):
            tg=i/ph
            if level==3: c=(int(2+8*tg),int(14+22*tg),int(32+26*tg),248)
            elif level==2: c=(int(4+9*tg),int(4+9*tg),int(22+24*tg),248)
            else: c=(int(4+10*tg),int(14+20*tg),int(6+12*tg),248)
            pygame.draw.line(panel,c,(0,i),(pw,i))
        msk=pygame.Surface((pw,ph),pygame.SRCALPHA)
        pygame.draw.rect(msk,(255,255,255,255),(0,0,pw,ph),border_radius=16)
        panel.blit(msk,(0,0),special_flags=pygame.BLEND_RGBA_MIN)

        # Warna aksen
        if level==3:   aksen=(0,200,220); aksen2=(100,240,250); dim=(40,55,80)
        elif level==2: aksen=(80,160,255); aksen2=(160,210,255); dim=(30,40,80)
        else:          aksen=(80,210,110); aksen2=(150,240,170); dim=(30,60,35)

        rects_local={}
        fLbl=get_font(12,bold=True); fVal=get_font(11); fSub=get_font(10)

        # ── HEADER ──────────────────────────────────────────
        HDR_H = 48
        hdr=pygame.Surface((pw,HDR_H),pygame.SRCALPHA)
        hdr.fill((*[c//3 for c in aksen],100))
        panel.blit(hdr,(0,0))
        pygame.draw.line(panel,(*aksen,200),(0,HDR_H),(pw,HDR_H),2)
        tHdr=get_font(15,bold=True).render("PENGATURAN",True,aksen2)
        panel.blit(tHdr,(pw//2-tHdr.get_width()//2,14))

        # ── TABS ────────────────────────────────────────────
        TAB_Y = HDR_H+2; TAB_H = 36
        tabs=[("audio","Audio"),("gameplay","Gameplay"),("tampilan","Tampilan")]
        tw=pw//3
        for ti,(tk,tl) in enumerate(tabs):
            aktif=(tk==tab)
            bg_col=(*[c//2 for c in aksen],180) if aktif else (*dim,120)
            pygame.draw.rect(panel,bg_col,(ti*tw,TAB_Y,tw,TAB_H))
            if aktif:
                pygame.draw.line(panel,(*aksen,240),(ti*tw,TAB_Y+TAB_H),(ti*tw+tw,TAB_Y+TAB_H),2)
            else:
                pygame.draw.line(panel,(*dim,80),(ti*tw,TAB_Y+TAB_H),(ti*tw+tw,TAB_Y+TAB_H),1)
            tT=get_font(11,bold=aktif).render(tl,True,aksen2 if aktif else (140,150,165))
            panel.blit(tT,(ti*tw+tw//2-tT.get_width()//2,TAB_Y+10))
            rects_local[f"tab_{tk}"]=pygame.Rect(px_s+ti*tw,py_s+TAB_Y,tw,TAB_H)

        pygame.draw.line(panel,(*aksen,60),(0,TAB_Y+TAB_H),(pw,TAB_Y+TAB_H),1)

        # ── KONTEN AREA ─────────────────────────────────────
        CONTENT_Y = TAB_Y+TAB_H+12
        SL_X=28; SL_W=pw-56; SL_H=10

        def draw_slider(panel,y,label,val,key,unit="%"):
            # Label + nilai
            panel.blit(fLbl.render(label,True,(220,232,245)),(SL_X,y))
            vt=fVal.render(f"{int(val*100)}{unit}",True,aksen2)
            panel.blit(vt,(pw-SL_X-vt.get_width(),y))
            # Track
            sy=y+22
            pygame.draw.rect(panel,(*dim,180),(SL_X,sy,SL_W,SL_H),border_radius=5)
            fw=int(SL_W*val)
            if fw>0:
                pygame.draw.rect(panel,(*aksen,230),(SL_X,sy,fw,SL_H),border_radius=5)
            # Knob
            kx=SL_X+fw
            pygame.draw.circle(panel,(255,255,255),(kx,sy+SL_H//2),11)
            pygame.draw.circle(panel,aksen,(kx,sy+SL_H//2),8)
            pygame.draw.circle(panel,(255,255,255),(kx,sy+SL_H//2),3)
            rects_local[f"slider_{key}"]=pygame.Rect(SL_X,sy-10,SL_W,SL_H+20)
            return sy+SL_H+8

        if tab=="audio":
            y=CONTENT_Y

            # Slider Musik
            bot=draw_slider(panel,y,"Volume Musik",self.musik_volume,"musik")
            y=bot+4

            # Toggle Musik
            tog_on=self.musik_aktif
            tog_col=(*aksen,210) if tog_on else (*dim,180)
            pygame.draw.rect(panel,tog_col,(SL_X,y,52,24),border_radius=12)
            pygame.draw.circle(panel,(255,255,255),(SL_X+38 if tog_on else SL_X+14,y+12),10)
            txt_tog="MUSIK ON" if tog_on else "MUSIK OFF"
            tTog=fSub.render(txt_tog,True,aksen2 if tog_on else (120,130,140))
            panel.blit(tTog,(SL_X+60,y+6))
            rects_local["toggle_musik"]=pygame.Rect(SL_X,y,52,24)
            y+=34

            pygame.draw.line(panel,(*dim,100),(SL_X,y),(pw-SL_X,y),1); y+=10

            # Slider SFX
            bot=draw_slider(panel,y,"Volume Efek Suara (SFX)",self.sfx_volume,"sfx")
            y=bot+2
            panel.blit(fSub.render("Suara dadu, beli, skill battle, dll.",True,(140,160,180)),(SL_X,y))
            y+=22

            pygame.draw.line(panel,(*dim,100),(SL_X,y),(pw-SL_X,y),1); y+=10

            # Shortcut info
            shorts=[("[M]","Toggle musik ON/OFF"),("[+]/[-]","Volume musik"),("[F10]","Buka/tutup panel")]
            for k2,v2 in shorts:
                tK2=fSub.render(k2,True,aksen2); tV2=fSub.render(v2,True,(150,170,190))
                panel.blit(tK2,(SL_X,y)); panel.blit(tV2,(SL_X+tK2.get_width()+8,y))
                y+=18

        elif tab=="gameplay":
            y=CONTENT_Y

            panel.blit(fLbl.render("Kecepatan AI",True,(220,232,245)),(SL_X,y))
            panel.blit(fSub.render("Delay sebelum AI mengambil keputusan",True,(140,160,180)),(SL_X,y+18))
            y+=42

            # Tombol kecepatan
            spd_opts=[
                ("lambat","LAMBAT","Delay: 4 detik",(80,160,240)),
                ("normal","NORMAL","Delay: 0.9 detik",(80,210,110)),
                ("cepat","CEPAT","Delay: 0.3 detik",(240,160,70)),
            ]
            ai_spd=getattr(self,"ai_speed","normal")
            bw=(pw-SL_X*2-16)//3; bh=52
            for bi,(sk,sl2,ss,sc) in enumerate(spd_opts):
                bx2=SL_X+bi*(bw+8); by2=y
                aktif2=(ai_spd==sk)
                bcol=(*sc,210) if aktif2 else (*dim,160)
                pygame.draw.rect(panel,bcol,(bx2,by2,bw,bh),border_radius=8)
                bdr2=(*sc,230) if aktif2 else (70,80,100,120)
                pygame.draw.rect(panel,bdr2,(bx2,by2,bw,bh),2,border_radius=8)
                tSL2=get_font(11,bold=True).render(sl2,True,(255,255,255) if aktif2 else (150,160,175))
                tSS2=fSub.render(ss,True,(230,240,255) if aktif2 else (100,110,120))
                panel.blit(tSL2,(bx2+bw//2-tSL2.get_width()//2,by2+8))
                panel.blit(tSS2,(bx2+bw//2-tSS2.get_width()//2,by2+28))
                rects_local[f"ai_{sk}"]=pygame.Rect(px_s+bx2,py_s+by2,bw,bh)
            y+=bh+14

            pygame.draw.line(panel,(*dim,100),(SL_X,y),(pw-SL_X,y),1); y+=10

            # Detail delay
            panel.blit(fLbl.render("Detail Delay Saat Ini :",True,(220,232,245)),(SL_X,y)); y+=20
            detail={"lambat":("4.0d","2.0d","2.0d"),"normal":("0.9d","0.4d","0.4d"),"cepat":("0.3d","0.15d","0.15d")}[ai_spd]
            for lbl3,val3 in [("Lempar dadu",detail[0]),("Putuskan beli",detail[1]),("Akhiri giliran",detail[2])]:
                tK3=fSub.render(f"  {lbl3}",True,(150,170,190))
                tV3=fSub.render(val3,True,aksen2)
                panel.blit(tK3,(SL_X,y)); panel.blit(tV3,(pw-SL_X-tV3.get_width(),y)); y+=17

            y+=8
            pygame.draw.line(panel,(*dim,100),(SL_X,y),(pw-SL_X,y),1); y+=10
            shorts2=[("[F1]","AI Lambat (4 detik)"),("[F2]","AI Normal (0.9 detik)"),("[F3]","AI Cepat (0.3 detik)")]
            for k3,v3 in shorts2:
                tK3=fSub.render(k3,True,aksen2); tV3=fSub.render(v3,True,(150,170,190))
                panel.blit(tK3,(SL_X,y)); panel.blit(tV3,(SL_X+tK3.get_width()+8,y)); y+=17

        # ════════════════════════════════════════════════
        elif tab=="tampilan":
            y = CONTENT_Y

            def draw_btn_grp(lbl,opts,val_attr,key_pfx,cols=None):
                nonlocal y
                panel.blit(fLbl.render(lbl,True,(220,232,245)),(SL_X,y))
                cur=str(getattr(self,val_attr,""))
                n=len(opts); bw3=(pw-SL_X*2-(n-1)*5)//n; bh3=32
                for bi,(ov,ol) in enumerate(opts):
                    bx3=SL_X+bi*(bw3+5); by3=y+20
                    on3=(cur==str(ov))
                    c3=cols[bi] if cols else aksen
                    pygame.draw.rect(panel,(*c3,200 if on3 else 0),(bx3,by3,bw3,bh3),border_radius=7)
                    if not on3:
                        pygame.draw.rect(panel,(*dim,160),(bx3,by3,bw3,bh3),border_radius=7)
                    pygame.draw.rect(panel,(*c3,230 if on3 else 80),(bx3,by3,bw3,bh3),2,border_radius=7)
                    tB3=get_font(10,bold=on3).render(ol,True,(255,255,255) if on3 else (140,152,168))
                    panel.blit(tB3,(bx3+bw3//2-tB3.get_width()//2,by3+bh3//2-tB3.get_height()//2))
                    rects_local[f"{key_pfx}_{ov}"]=pygame.Rect(px_s+bx3,py_s+by3,bw3,bh3)
                y+=62

            def draw_tog(lbl,val_attr,tog_key):
                nonlocal y
                cur=getattr(self,val_attr,True)
                pygame.draw.rect(panel,(*aksen,200) if cur else (*dim,180),(SL_X,y+2,52,24),border_radius=12)
                pygame.draw.circle(panel,(255,255,255),(SL_X+38 if cur else SL_X+14,y+14),10)
                panel.blit(fLbl.render(lbl,True,(220,232,245)),(SL_X+62,y+4))
                tOn=fSub.render("ON" if cur else "OFF",True,aksen2 if cur else (110,120,130))
                panel.blit(tOn,(pw-SL_X-tOn.get_width(),y+6))
                # Konversi langsung ke koordinat layar
                rects_local[f"tog_{tog_key}"]=pygame.Rect(px_s+SL_X,py_s+y+2,52,24)
                y+=34

            # Resolusi — info saja (tidak bisa diubah langsung)
            panel.blit(fLbl.render("Resolusi",True,(220,232,245)),(SL_X,y))
            res_txt = fSub.render(f"Saat ini: {WIN_W}×{WIN_H}  (ubah di kode: WIN_W, WIN_H)",True,(140,160,180))
            panel.blit(res_txt,(SL_X,y+20))
            y+=50
            pygame.draw.line(panel,(*dim,80),(SL_X,y-4),(pw-SL_X,y-4),1)

            # FPS Cap
            draw_btn_grp("Batas FPS",
                [(30,"30"),(60,"60"),(120,"120"),(0,"∞")],
                "setting_fps_cap","fps",
                cols=[(200,120,40),(80,200,100),(100,160,255),(180,80,220)])
            pygame.draw.line(panel,(*dim,80),(SL_X,y-4),(pw-SL_X,y-4),1)

            # Kualitas Partikel
            draw_btn_grp("Kualitas Partikel",
                [("rendah","Rendah"),("sedang","Sedang"),("tinggi","Tinggi")],
                "setting_kualitas","qual",
                cols=[(80,180,80),(80,160,220),(220,140,40)])
            pygame.draw.line(panel,(*dim,80),(SL_X,y-4),(pw-SL_X,y-4),1)

            # Toggle
            draw_tog("Tampilkan Harga Kotak","setting_tampil_harga","harga")
            draw_tog("Efek Layar Skill Battle","setting_efek_skill","efek_skill")

            pygame.draw.line(panel,(*dim,80),(SL_X,y-2),(pw-SL_X,y-2),1)
            panel.blit(fSub.render("⚠  Perubahan FPS berlaku langsung.",True,(160,180,120)),(SL_X,y+2))

        # ── TOMBOL TUTUP ────────────────────────────────────
        cx2=pw-22; cy2=20
        pygame.draw.circle(panel,(180,55,55,220),(cx2,cy2),14)
        pygame.draw.circle(panel,(220,80,80,200),(cx2,cy2),14,2)
        tX=get_font(12,bold=True).render("X",True,(255,255,255))
        panel.blit(tX,(cx2-tX.get_width()//2,cy2-tX.get_height()//2))
        rects_local["close"]=pygame.Rect(px_s+cx2-14,py_s+cy2-14,28,28)

        # Border
        gw2=int(160+80*math.sin(t_now*2))
        pygame.draw.rect(panel,(*aksen,min(200,gw2)),(0,0,pw,ph),2,border_radius=16)

        # Shadow + blit
        sh2=pygame.Surface((pw+14,ph+16),pygame.SRCALPHA)
        pygame.draw.rect(sh2,(0,0,0,80),(7,9,pw,ph),border_radius=16)
        surf.blit(sh2,(px_s-7,py_s)); surf.blit(panel,(px_s,py_s))

        # Konversi rect Audio (slider/toggle) ke koordinat layar
        for k4 in ("slider_musik","slider_sfx","toggle_musik"):
            if k4 in rects_local:
                r4=rects_local[k4]
                rects_local[k4]=pygame.Rect(r4.x+px_s,r4.y+py_s,r4.width,r4.height)

        self._setting_rects=rects_local

    def _render_popup_badai_laut(self, surf):
        """Popup kartu BADAI LAUT — menampilkan damage ke semua pemain."""
        pad = getattr(self,'popup_badai',None)
        if not pad: return
        t_now  = pygame.time.get_ticks()/1000.0
        sisa   = max(0.0, pad["timer"])
        durasi = pad["durasi"]
        hits   = pad.get("hits",[])
        GL_W   = WIN_W - UI_W
        pw, ph = 520, 240 + len(hits)*28
        px_c   = GL_W//2 - pw//2
        py_c   = WIN_H//2 - ph//2

        # Alpha fade
        if sisa > durasi-0.35: alpha = int(255*(durasi-sisa)/0.35)
        elif sisa < 0.45: alpha = int(255*sisa/0.45)
        else: alpha = 255
        alpha = max(0,min(255,alpha))
        if alpha < 5: return

        surf.set_clip(pygame.Rect(0,0,GL_W,WIN_H))

        # Flip
        flip_in=0.45; flip_out=0.35
        if sisa > durasi-flip_in: scaleX = max(0.0,min(1.0,1.0-(sisa-(durasi-flip_in))/flip_in))
        elif sisa < flip_out: scaleX = max(0.0,sisa/flip_out)
        else: scaleX = 1.0
        eff_w = max(4,int(pw*abs(scaleX))); offx=(pw-eff_w)//2

        # Overlay biru badai
        ov=pygame.Surface((GL_W,WIN_H),pygame.SRCALPHA)
        ov.fill((0,15,40,int(180*alpha/255))); surf.blit(ov,(0,0))

        # Partikel ombak mengitari kartu
        cx_c=px_c+pw//2; cy_c=py_c+ph//2
        part=pygame.Surface((GL_W,WIN_H),pygame.SRCALPHA)
        for pi in range(24):
            ang=(pi/24)*2*math.pi+t_now*1.2
            dist=200+35*math.sin(t_now*0.7+pi*0.4)
            ppx=cx_c+int(math.cos(ang)*dist)
            ppy=cy_c+int(math.sin(ang)*dist*0.38)
            blink=0.4+0.6*abs(math.sin(t_now*2.5+pi))
            a_p=int(min(255,160*blink*alpha/255))
            if 0<ppx<GL_W and 0<ppy<WIN_H and a_p>8:
                pygame.draw.circle(part,(60,min(255,140+pi*4),min(255,200+pi*2),a_p),(ppx,ppy),max(2,3+pi%4))
        surf.blit(part,(0,0))

        # Kartu
        card=pygame.Surface((eff_w,ph),pygame.SRCALPHA)
        for i in range(ph):
            t_g=i/ph
            pygame.draw.line(card,(int(3+8*t_g),int(20+25*t_g),int(50+25*t_g),255),(0,i),(eff_w,i))
        msk=pygame.Surface((eff_w,ph),pygame.SRCALPHA)
        pygame.draw.rect(msk,(255,255,255,255),(0,0,eff_w,ph),border_radius=14)
        card.blit(msk,(0,0),special_flags=pygame.BLEND_RGBA_MIN)
        def cx(x): return max(0,min(eff_w-1,int(x*eff_w/pw)))

        if scaleX>0.3:
            # Plankton latar
            for si in range(30):
                seed=si*5113; blink_s=0.3+0.7*abs(math.sin(t_now*(0.6+si*0.10)+si))
                br=int(35+blink_s*75)
                pygame.draw.circle(card,(int(br*0.3),int(br*0.7),br,br),
                    (cx(int(8+abs(seed*1021)%(pw-16))),int(6+abs(seed*3539)%(ph-12))),1)

            # Ikon BADAI LAUT — awan gelap + ombak + kilat (bukan orb biru)
            orb_x=cx(pw-85); orb_y=62
            # Awan badai berlapis — gelap kelabu biru
            for gr in range(5):
                pygame.draw.circle(card,(20,int(35+gr*12),int(70+gr*16),max(0,24-gr*4)),
                    (orb_x,orb_y),38+gr*5)
            pygame.draw.circle(card,(15,45,90,210),(orb_x,orb_y),30)
            pygame.draw.circle(card,(22,65,120,160),(orb_x,orb_y),20)
            # Tonjolan awan atas — 3 gundukan
            for ci in range(3):
                ca = -math.pi*0.6 + ci*(math.pi*0.6)
                cx_cl = orb_x+int(math.cos(ca)*16)
                cy_cl = orb_y+int(math.sin(ca)*8)-6
                pygame.draw.circle(card,(30,60,110,160),(cx_cl,cy_cl),12)
            # 3 ombak bergulir di bawah awan
            for wi2 in range(3):
                wave_t = (t_now*1.5 + wi2*0.4) % 1.0
                wy = orb_y + 12 + wi2*6
                wave_col = int(100+wave_t*100)
                pygame.draw.arc(card,(40,wave_col,min(255,wave_col+60)),
                    (orb_x-22+wi2*4, wy-5, 44-wi2*4, 12), 0, math.pi, 3)
            # Kilat zigzag — berkedip
            lph = (t_now*2.5) % 1.0
            if lph < 0.3:
                la = int((1-lph/0.3)*230)
                pts_l = [(orb_x-4,orb_y-14),(orb_x+5,orb_y-2),
                         (orb_x-2,orb_y+5),(orb_x+7,orb_y+16)]
                pygame.draw.lines(card,(220,235,255,la),False,pts_l,2)
                # Glow kilat
                pygame.draw.circle(card,(180,200,255,la//3),(orb_x+1,orb_y+1),10)
            # Ring arus luar putar lambat
            for arc_i in range(3):
                rot=arc_i*math.pi*0.67 + t_now*1.2
                for pt in range(8):
                    pa=rot+pt*0.38; pr2=38+arc_i*7
                    ax2=orb_x+int(pr2*math.cos(pa))
                    ay2=orb_y+int(pr2*math.sin(pa)*0.6)
                    a2=max(0,int(100-pt*11))
                    if a2>0 and 0<ax2<eff_w and 0<ay2<ph:
                        pygame.draw.circle(card,(50,int(120+arc_i*20),int(180+arc_i*15),a2),(ax2,ay2),2)

            # Header
            hdr=pygame.Surface((eff_w,40),pygame.SRCALPHA); hdr.fill((0,40,100,70))
            card.blit(hdr,(0,0))
            fLbl=pygame.font.SysFont("Arial",10,bold=True)
            tLbl=fLbl.render("SKILL CARD  -  BADAI LAUT",True,(80,180,240))
            tLbl.set_alpha(min(255,int(alpha*0.85))); card.blit(tLbl,(cx(14),13))

            # Judul
            fJ=get_font(28,bold=True)
            for gof,gcol in [(3,(0,20,60)),(2,(0,50,110)),(1,(0,90,160))]:
                tg=fJ.render("BADAI LAUT",True,gcol)
                tg.set_alpha(min(255,int(alpha*gof*0.2))); card.blit(tg,(cx(14)+gof,48+gof))
            gw_t=int(140+90*math.sin(t_now*1.8))
            tJ=fJ.render("BADAI LAUT",True,(60,gw_t,min(255,gw_t+50)))
            tJ.set_alpha(min(255,alpha)); card.blit(tJ,(cx(14),48))

            # Garis neon
            gl_w=int(eff_w*0.68)
            for gx_i in range(gl_w):
                frac=abs(gx_i-gl_w//2)/(gl_w//2+1)
                ag=int(alpha*(1-frac**2)*0.75)
                if ag>0: pygame.draw.line(card,(60,160,220,min(255,ag)),(cx(14)+gx_i,84),(cx(14)+gx_i,85))

            # Separator
            pygame.draw.line(card,(60,120,180,50),(cx(12),96),(cx(pw-12),96),1)

            # SEMUA TARGET kena damage
            fN=pygame.font.SysFont("Arial",11,bold=True)
            fD=pygame.font.SysFont("Arial",10)
            tAll=fN.render("SEMUA PEMAIN TERKENA :",True,(100,180,220))
            tAll.set_alpha(min(255,int(alpha*0.8))); card.blit(tAll,(cx(14),102))

            # List pemain yang kena
            for hi,hit in enumerate(hits):
                hy=126+hi*28
                wt=tuple(hit["warna"])
                pygame.draw.circle(card,wt,(cx(22),hy+9),7)
                pygame.draw.circle(card,(255,255,255),(cx(22),hy+9),7,1)
                tHn=fN.render(hit["nama"],True,(min(255,wt[0]+80),min(255,wt[1]+80),255))
                tHn.set_alpha(min(255,alpha)); card.blit(tHn,(cx(35),hy+2))
                # Damage pill merah-oranye
                pill_w2=cx(160); pill_h2=18
                pill2=pygame.Surface((pill_w2,pill_h2),pygame.SRCALPHA)
                pygame.draw.rect(pill2,(120,20,0,min(180,alpha)),(0,0,pill_w2,pill_h2),border_radius=5)
                pygame.draw.rect(pill2,(220,80,40,min(160,alpha)),(0,0,pill_w2,pill_h2),1,border_radius=5)
                card.blit(pill2,(cx(170),hy+1))
                fmt_fn = kr if self.level >= 2 else rp
                tDmg=fD.render(f"-{fmt_fn(hit['dmg'])}",True,(255,160,100))
                tDmg.set_alpha(min(255,alpha))
                card.blit(tDmg,(cx(170)+(pill_w2-tDmg.get_width())//2,hy+3))

            # Progress bar
            bar_y2=ph-20; bw2=eff_w-cx(36); prog2=max(0.0,sisa/durasi)
            pygame.draw.rect(card,(0,20,50,min(200,int(alpha*0.5))),(cx(18),bar_y2,bw2,6),border_radius=3)
            if prog2>0:
                gc2=int(120+100*math.sin(t_now*2.8))
                pygame.draw.rect(card,(60,gc2,min(255,int(gc2*1.2)),min(255,int(alpha*0.9))),
                    (cx(18),bar_y2,int(bw2*prog2),6),border_radius=3)
            tTm2=pygame.font.SysFont("Arial",10).render(f"{max(0,int(sisa))}s",True,(80,160,200))
            card.blit(tTm2,(cx(18)+bw2+6,bar_y2-1))

            # Corner brackets
            for bxc,byc,dxc,dyc in [(4,4,1,1),(eff_w-4,4,-1,1),(4,ph-4,1,-1),(eff_w-4,ph-4,-1,-1)]:
                cl=min(18,eff_w//4,ph//4)
                pygame.draw.line(card,(60,160,220,200),(bxc,byc),(bxc+dxc*cl,byc),2)
                pygame.draw.line(card,(60,160,220,200),(bxc,byc),(bxc,byc+dyc*cl),2)
            gw_bdr=int(130+100*math.sin(t_now*2.2))
            pygame.draw.rect(card,(60,gw_bdr,min(255,int(gw_bdr*1.2)),min(200,alpha)),(0,0,eff_w,ph),2,border_radius=14)

        if alpha<255:
            fo=pygame.Surface((eff_w,ph),pygame.SRCALPHA); fo.fill((0,0,0,255-alpha)); card.blit(fo,(0,0))
        sh=pygame.Surface((eff_w+14,ph+16),pygame.SRCALPHA)
        pygame.draw.rect(sh,(0,0,0,85),(7,9,eff_w,ph),border_radius=14)
        surf.blit(sh,(px_c+offx-7,py_c)); surf.blit(card,(px_c+offx,py_c))
        surf.set_clip(None)

    def _render_popup_arus_deras(self, surf):
        """Kartu ARUS DERAS — tema Atlantis bawah laut natural."""
        pad = getattr(self,'popup_arus_deras',None)
        if not pad:
            return
        t_now  = pygame.time.get_ticks() / 1000.0
        sisa   = max(0.0, pad["timer"])
        durasi = pad["durasi"]
        nama   = pad["nama"]
        mundur = pad["mundur"]
        warna_tgt = tuple(pad["warna"])
        GL_W   = WIN_W - UI_W
        pw, ph = 580, 260
        px_c   = GL_W//2 - pw//2
        py_c   = WIN_H//2 - ph//2

        # Alpha fade
        if sisa > durasi - 0.35:
            alpha = int(255*(durasi-sisa)/0.35)
        elif sisa < 0.45:
            alpha = int(255*sisa/0.45)
        else:
            alpha = 255
        alpha = max(0, min(255, alpha))
        if alpha < 5:
            return

        surf.set_clip(pygame.Rect(0, 0, GL_W, WIN_H))

        # Flip scale
        flip_in = 0.45; flip_out = 0.35
