            flip_in_dur  = 0.45
            flip_out_dur = 0.35
            if sisa > durasi - flip_in_dur:
                flip_prog = 1.0 - (sisa - (durasi - flip_in_dur)) / flip_in_dur
                flip_scaleX = max(0.0, min(1.0, flip_prog))
            elif sisa < flip_out_dur:
                flip_scaleX = max(0.0, sisa / flip_out_dur)
