                        pygame.draw.rect(btn_beli,(*bd_col,200),(0,0,btn_w,btn_h),2,border_radius=20)
                        fBtn=pygame.font.SysFont("Arial",13,bold=True)
                        tb=fBtn.render(lbl_beli,True,txt_col); btn_beli.blit(tb,(btn_w//2-tb.get_width()//2,btn_h//2-tb.get_height()//2))
                        pop.blit(btn_beli,(18,btn_y))
                        btn_lwt=pygame.Surface((btn_w,btn_h),pygame.SRCALPHA)
