                        btn_lwt.blit(mask_btn,(0,0),special_flags=pygame.BLEND_RGBA_MIN)
                        pygame.draw.rect(btn_lwt,(200,80,80,180),(0,0,btn_w,btn_h),2,border_radius=20)
                        tn2=fBtn.render("Lewati",True,(255,200,200)); btn_lwt.blit(tn2,(btn_w//2-tn2.get_width()//2,btn_h//2-tn2.get_height()//2))
